-- Poems batch 320
INSERT OR IGNORE INTO poems (id,title,author,dynasty,collection,collection_id,rhythmic,tags,excerpt,length,source_path,paragraphs) VALUES
('e7f55f8c-61ef-486b-9e72-c76202f7426b','赤壁懷古','蘇轍','宋','宋诗','song-poetry','','["\u957f\u6c5f"]','新破荆州得水軍，鼓行夏口氣如雲。',64,'全唐诗/poet.song.48000.json','["新破荆州得水軍，鼓行夏口氣如雲。", "千艘已共長江嶮，百勝安知赤壁焚。", "觜距方强要一鬥，君臣已定勢三分。", "古來伐國須觀釁，意突成功所未聞。"]'),
('3fe18afc-8aa1-40a1-8cc1-be882c6ba23b','自黄州還江州','蘇轍','宋','宋诗','song-poetry','','["\u5e90\u5c71"]','身浮一葉返湓城，凌犯風濤日夜行。',64,'全唐诗/poet.song.48000.json','["身浮一葉返湓城，凌犯風濤日夜行。", "把酒獨斟從睡重，還家漸近覺身輕。", "岸回樊口依稀見，日出廬山紫翠橫。", "家在庾公樓下泊，舟人遥指岸如頳。"]'),
('58ca3557-cc94-4b0b-94fc-62ee9f38c15b','江州五咏 射蛟浦','蘇轍','宋','宋诗','song-poetry','','[]','萬騎巡遊遍，千帆破浪輕。',48,'全唐诗/poet.song.48000.json','["萬騎巡遊遍，千帆破浪輕。", "射蛟江水赤，教戰越人驚。", "山轉樓船影，岸摧連弩聲。", "祈招無爲賦，酣寢盡平生。"]'),
('8f206c93-e8ad-4e05-a2dd-dbc4b020943e','江州五咏 浪井','蘇轍','宋','宋诗','song-poetry','','[]','江波浮陣雲，岸壁立青鐵。',48,'全唐诗/poet.song.48000.json','["江波浮陣雲，岸壁立青鐵。", "胡爲井中泉，涌浪時驚發。", "水性本無定，得止自澄澈。", "誰爲女媧手，補此天地裂。"]'),
('4f1909f4-1451-4307-8e1a-898d5f76daf6','江州五咏 庾樓','蘇轍','宋','宋诗','song-poetry','','[]','元規情不薄，上客有殷生。',48,'全唐诗/poet.song.48000.json','["元規情不薄，上客有殷生。", "夜半酒將罷，公來坐不驚。", "舞翻江月迥，談落麈毛輕。", "塵世風流盡，高樓空此名。"]'),
('db61d921-276f-4bae-816a-b28920023090','江州五咏 東湖','蘇轍','宋','宋诗','song-poetry','','["\u5e90\u5c71"]','讀書廬山中，作郡廬山下。',48,'全唐诗/poet.song.48000.json','["讀書廬山中，作郡廬山下。", "平湖浸山脚，雲峰對虛榭。", "紅蕖紛欲落，白鳥時來下。", "猶思隠居勝，亂石驚湍瀉。"]'),
('0e94e0fe-d3f6-46d2-a0b6-839cd9017f48','江州五咏 琵琶亭','蘇轍','宋','宋诗','song-poetry','','[]','湓江莫雨晴，孤舟暝將發。',48,'全唐诗/poet.song.48000.json','["湓江莫雨晴，孤舟暝將發。", "夜聞胡琴語，展轉不成別。", "草堂寄東林，雅意存北闕。", "潸然涕泗下，安用無生說。"]'),
('320e51d1-520d-4ced-877c-a7f3643192d6','不到東西二林','蘇轍','宋','宋诗','song-poetry','','[]','山北東西寺，高人永遠師。',48,'全唐诗/poet.song.48000.json','["山北東西寺，高人永遠師。", "來遊亦前定，回首獨移時。", "社散白蓮盡，山空玄鶴悲。", "何年陶靖節，溪上送行遲。"]'),
('ac1510a0-ec0f-4a55-91b4-b6ccd0681b3b','遊廬山山陽七咏 開先瀑布','蘇轍','宋','宋诗','song-poetry','','["\u5e90\u5c71"]','山上流泉自作溪，行逢石缺瀉虹霓。',64,'全唐诗/poet.song.48000.json','["山上流泉自作溪，行逢石缺瀉虹霓。", "定知雲外波瀾闊，飛到峰前本末齊。", "入海明河驚照曜，倚天長劍失提携。", "誰來卧枕莓苔石，一洗塵心萬斛泥。"]'),
('5b82021a-a9b5-414a-b3c7-be56f837cc3b','遊廬山山陽七咏 潄玉亭','蘇轍','宋','宋诗','song-poetry','','["\u5e90\u5c71"]','山回不見落銀潢，餘溜喧豗響石塘。',64,'全唐诗/poet.song.48000.json','["山回不見落銀潢，餘溜喧豗響石塘。", "目亂珠璣濺空谷，足寒雷電繞飛梁。", "入瓶銅鼎春茶白，接竹齋厨午飯香。", "從此出山都不棄，滿田粳稻插新秧。"]'),
('b2c56a21-cc9a-4529-bac7-15d1c67453c5','遊廬山山陽七咏 簡寂觀','蘇轍','宋','宋诗','song-poetry','','["\u5e90\u5c71"]','山行但覺鳥聲殊，漸近神仙簡寂居。',64,'全唐诗/poet.song.48000.json','["山行但覺鳥聲殊，漸近神仙簡寂居。", "門外長溪凈客足，山腰苦笋助盤蔬。", "喬松定有藏丹處，大石仍存拜斗餘。", "弟子蒼髯年八十，養生世世授遺書。"]'),
('1bcf2f07-ce58-4ca0-b792-03e001a322c8','遊廬山山陽七咏 歸宗寺','蘇轍','宋','宋诗','song-poetry','','["\u5e90\u5c71"]','來聽歸宗早晚鐘，疲勞懶上紫霄峰。',64,'全唐诗/poet.song.48000.json','["來聽歸宗早晚鐘，疲勞懶上紫霄峰。", "墨池漫疊溪中石，白塔微分嶺上松。", "佛宇爭推一山甲，僧厨坐待十方供。", "欲遊山北東西寺，巖谷相連更幾重。"]'),
('ee091c01-1a72-4614-969d-68501769de68','遊廬山山陽七咏 萬杉寺','蘇轍','宋','宋诗','song-poetry','','["\u5e90\u5c71"]','萬木青杉一手栽，滿堂白佛九天來。',64,'全唐诗/poet.song.48000.json','["萬木青杉一手栽，滿堂白佛九天來。", "涓涓石溜供厨足，矗矗山屏繞寺開。", "半榻松陰秋簟冷，一杯香飯午鐘催。", "安眠飽食平生事，不待山僧喚始迴。"]'),
('3e159750-62a2-4dc6-acf4-b4f4404c2292','遊廬山山陽七咏 三峽石橋','蘇轍','宋','宋诗','song-poetry','','["\u5e90\u5c71"]','三峽波濤飽泝沿，過橋雷電記當年。',64,'全唐诗/poet.song.48000.json','["三峽波濤飽泝沿，過橋雷電記當年。", "江聲仿佛瞿唐口，石角參差灧澦前。", "應有夜猿啼古木，已將秋葉作歸船。", "老僧未省遊巴蜀，松下相逢問信然。"]'),
('9d1d0beb-3390-474e-9688-fd54013af87b','遊廬山山陽七咏 白鶴觀','蘇轍','宋','宋诗','song-poetry','','["\u5e90\u5c71"]','五老相携欲上天，玄猿白鶴盡疑仙。',64,'全唐诗/poet.song.48000.json','["五老相携欲上天，玄猿白鶴盡疑仙。", "浮雲有意藏山頂，流水無聲入稻田。", "古木微風時起籟，諸峰落日盡生烟。", "歸鞍草草還城市，慚愧幽人正醉眠。"]'),
('062beb9a-7b53-4688-b3e4-00ba6b062afe','南康阻風遊東寺','蘇轍','宋','宋诗','song-poetry','','[]','欲涉彭蠡湖，南風未相許。',120,'全唐诗/poet.song.48000.json','["欲涉彭蠡湖，南風未相許。", "扁舟厭摇蕩，古寺慰行旅。", "重湖面南軒，驚浪卷前浦。", "霏微雪陣散，顛倒玉山舞。", "一風輒九日，未悉土囊怒。", "百里斷行舟，仰看飛鴻度。", "故人念征役，一飯語平素。", "竹色凈飛濤，松聲亂秋雨。", "我生足憂患，十載不安處。", "南北已兼忘，遲速何須數。"]'),
('28e544bd-5d29-43ff-9284-b8cd8d0c3eea','寄題陳憲郎中竹軒','蘇轍','宋','宋诗','song-poetry','','[]','家有修篁綠滿軒，趨庭詩禮舊忘言。',64,'全唐诗/poet.song.48000.json','["家有修篁綠滿軒，趨庭詩禮舊忘言。", "凌霜自得良朋友，過雨時添好子孫。", "試翦輕筠扶野步，旋收凉葉煮清樽。", "風流共道勝桑梓，鄰里何妨種百根。"]'),
('1a20d410-0988-4923-bb26-1cdc4d7575f3','次韵孔武仲到官後見寄','蘇轍','宋','宋诗','song-poetry','','[]','舉楫同千里，繫舟時一言。',48,'全唐诗/poet.song.48000.json','["舉楫同千里，繫舟時一言。", "共嗟蓬作屋，願就席爲門。", "行役身先困，征商思益昏。", "僅同登壟斷，何止服車轅。"]'),
('1900849d-da2f-4d8a-9079-1c2c71aa8928','次韵筠守毛維瞻司封觀修城三首  其一','蘇轍','宋','宋诗','song-poetry','','[]','北垣荆棘舊成堆，留待公來次第開。',64,'全唐诗/poet.song.48000.json','["北垣荆棘舊成堆，留待公來次第開。", "車馬已通城下路，榛蕪盡付冶家灰。", "異時碧瓦千門合，應記紅旌百度來。", "自笑裨諶便曠野，肩輿飛蓋許追陪。"]'),
('6a37418f-4a5c-4408-ac0e-2778ed94b9cd','次韵筠守毛維瞻司封觀修城三首  其二','蘇轍','宋','宋诗','song-poetry','','[]','撥棄案頭文字堆，曉晴山色四門開。',64,'全唐诗/poet.song.48000.json','["撥棄案頭文字堆，曉晴山色四門開。", "究懷民事老雖壯，俯首山城心已灰。", "荆棘燒殘桑柘出，狐狸去盡犬鷄來。", "規模先遣通蹊隧，後乘應容衆客陪。"]'),
('b0c31ff9-7484-4a11-81cd-ed3d1f351341','次韵筠守毛維瞻司封觀修城三首  其三','蘇轍','宋','宋诗','song-poetry','','[]','山脚侵城起阜堆，繞城徼道斬新開。',64,'全唐诗/poet.song.48000.json','["山脚侵城起阜堆，繞城徼道斬新開。", "闉闍半壞驚潮信，隍壑初深見劫灰。", "蟻聚千夫曾幾日，鱗差萬瓦看將來。", "史君才力輕山郡，朝論行聞急召陪。"]'),
('1b13f2c9-8742-4586-b346-c06e584c1164','次子瞻夜字韵作中秋對月二篇一以贈王郎二以寄子瞻  其一','蘇轍','宋','宋诗','song-poetry','','["\u957f\u6c5f"]','平明坐曹黄昏歸，終歲得閑惟有夜。',160,'全唐诗/poet.song.48000.json','["平明坐曹黄昏歸，終歲得閑惟有夜。", "已邀明月出牆東，更遣清風掃庭下。", "城上青鬟四山合，門前白練長江瀉。", "誰家高會吹參差，鄰婦悲歌舂罷亞。", "二年憂患今已過，一夜清光天所借。", "西京詩句出蘇李，南國風流數王謝。", "已隨孤棹去中原，肯顧新科求上舍。", "讀書本自比嵇鍛，學劍要須問曹蔗。", "清觴灧灧君莫違，佳句駸駸予已怕。", "狂夫猖狂終累人，不返行遭親黨駡。"]'),
('80ae4de9-5d38-47e8-ac20-b94d78a993b0','次子瞻夜字韵作中秋對月二篇一以贈王郎二以寄子瞻  其二','蘇轍','宋','宋诗','song-poetry','','[]','十年秋月照相思，相從祇有彭門夜。',160,'全唐诗/poet.song.48000.json','["十年秋月照相思，相從祇有彭門夜。", "露侵笳鼓思城闕，寒迫魚龍舞潭下。", "厭厭夜飲歡自足，落落襟懷向人瀉。", "秋深河來巨野溢，水乾樓起滕王亞。", "北海孔公雖好客，河內寇尹那得借。", "是非朝野忽紛紜，得喪芳菲一開謝。", "明月多情還入門，流水何知空繞舍。", "晨餐江市富鱣魴，夜宿山村足梨蔗。", "坐隅鵩鳥不須問，牆外蝮蛇猶足怕。", "婁公見唾行自乾，馮老尚多誰定駡。"]'),
('2813939a-b38d-45d8-b06a-3494bda26122','次韵王適食茅栗','蘇轍','宋','宋诗','song-poetry','','[]','相從萬里試南餐，對案長思苜蓿盤。',64,'全唐诗/poet.song.48000.json','["相從萬里試南餐，對案長思苜蓿盤。", "山栗滿籃兼白黑，村醪入口半甜酸。", "久聞牛尾何曾試，竊比鷄頭意未安。", "故國霜蓬如碗大，夜來彈劍似馮驩。"]'),
('4d719c39-7cc2-49a6-9a05-73b17164eb88','過毛國鎮夜飲','蘇轍','宋','宋诗','song-poetry','','[]','風格照人華省郎，江山繞郭古仙鄉。',64,'全唐诗/poet.song.48000.json','["風格照人華省郎，江山繞郭古仙鄉。", "漫傳鉛鼎八百歲，未比金釵十二行。", "不動歌聲人已醉，旋聞詩句夜初長。", "簿書撥盡知餘力，道院清虛頃未嘗。"]'),
('b836c944-1c6e-4b7e-85de-ce45452aef55','次韵毛國鎮趙景仁唱和三首一贈毛一贈趙一自咏  其一','蘇轍','宋','宋诗','song-poetry','','[]','治劇從容緩策銜，鈴軒無事日清談。',64,'全唐诗/poet.song.48000.json','["治劇從容緩策銜，鈴軒無事日清談。", "隼旟畫戟明千里，紙帳繩床自一庵。", "金奏屢陳容客和，玉山不動看賓酣。", "我來邂逅逢寬政，忘却漂流身在南。"]'),
('9b304f8c-85d7-462b-9aa9-eda985ace7f2','次韵毛國鎮趙景仁唱和三首一贈毛一贈趙一自咏  其二','蘇轍','宋','宋诗','song-poetry','','[]','一紙新詩過雁銜，醒然何異接君談。',64,'全唐诗/poet.song.48000.json','["一紙新詩過雁銜，醒然何異接君談。", "奉親魚蟹兼臨海，退食琴書定有庵。", "一別經年真似夢，多憂不飲亦如酣。", "共君友契非今日，蔽芾棠陰自劍南。"]'),
('2e5f8d82-70b6-4978-bb64-f905f1bc8955','次韵毛國鎮趙景仁唱和三首一贈毛一贈趙一自咏  其三','蘇轍','宋','宋诗','song-poetry','','[]','遠謫江湖舳尾銜，到來辛苦向誰談。',64,'全唐诗/poet.song.48000.json','["遠謫江湖舳尾銜，到來辛苦向誰談。", "畏人野鶴長依嶺，厭事山僧祇住庵。", "黄雀頓來成一飽，白醪新熟喜初酣。", "疏頑近日尤堪笑，坐任飄風去自南。"]'),
('d9ff1acd-4da6-45e4-9ba5-c644e072c262','再和三首  其一','蘇轍','宋','宋诗','song-poetry','','[]','穴鼠何須窶數銜，粗官不用苦高談。',64,'全唐诗/poet.song.48000.json','["穴鼠何須窶數銜，粗官不用苦高談。", "夜傾綠蟻風吹竹，晝擁黄紬雪覆庵。", "每作微詞還自笑，偶漸餘潤亦成酣。", "公詩精絕非倫擬，自古騷人盡在南。"]'),
('16e38c5b-0ac1-4afb-a78e-435685515354','再和三首  其二','蘇轍','宋','宋诗','song-poetry','','[]','燕窠泥土一春銜，慚愧封侯止立談。',64,'全唐诗/poet.song.48000.json','["燕窠泥土一春銜，慚愧封侯止立談。", "舊隠尚聞存竹徑，歸休但要葺茅庵。", "釣船夢想沿溪泛，酒盞遥思向日酣。", "强欲遲留依幕府，吳公行恐召河南。"]'),
('fa159313-5d03-4775-987c-fc1ffb55d916','再和三首  其三','蘇轍','宋','宋诗','song-poetry','','[]','天教窮困欲誰銜，生事那須一一談。',64,'全唐诗/poet.song.48000.json','["天教窮困欲誰銜，生事那須一一談。", "自笑豐年塵滿甑，不堪雨後菌生庵。", "士師憔悴經三黜，陶令幽憂付一酣。", "他日歸耕若相憶，尺書頻寄北山南。"]'),
('945ec161-2a80-4066-a2dd-a78fd715ba05','次韵王適州學新修水閣','蘇轍','宋','宋诗','song-poetry','','[]','黄鐘巨挺兩舂容，何幸幽居近學宮。',64,'全唐诗/poet.song.48000.json','["黄鐘巨挺兩舂容，何幸幽居近學宮。", "坐對江山增浩氣，力追齊魯欲同風。", "頌詩聞道求何武，家法行看試左雄。", "欲伴少年遊矍相，奔軍慚愧恐詞窮。"]'),
('df4b9f4e-d6a0-4f04-92a2-94e5fdef43c3','次韵毛君九日','蘇轍','宋','宋诗','song-poetry','','[]','山脚侵城盡是臺，登高處處喜崔嵬。',64,'全唐诗/poet.song.48000.json','["山脚侵城盡是臺，登高處處喜崔嵬。", "手拈霜菊香無奈，面拂江風酒自開。", "幕府尊罍雲裏集，民家歌吹靜中來。", "定知勝却陶彭澤，悵望籬邊白日頹。"]'),
('7f932f8e-6fe3-4fd7-b450-25909766d13a','次韵毛君感事書懷','蘇轍','宋','宋诗','song-poetry','','[]','種棠經歲便成科，秋雨調勻氣漸和。',64,'全唐诗/poet.song.48000.json','["種棠經歲便成科，秋雨調勻氣漸和。", "才力有餘嫌事少，風情無限覺詩多。", "長松更老仍添節，古井雖深自不波。", "宴坐山房人豈識，一尊聊且慰蹉跎。"]'),
('80a05148-e4d0-42bc-9ac9-d47949e4e4aa','次韵毛君見督和詩','蘇轍','宋','宋诗','song-poetry','','[]','新詩落紙一城傳，顧我疏蕪豈足編。',32,'全唐诗/poet.song.48000.json','["新詩落紙一城傳，顧我疏蕪豈足編。", "他日杜陵詩集裏，韋迢略見兩三篇。"]'),
('e82180ed-1dcd-4fa8-b095-0d35e6e4993f','次韵毛君山房遣興','蘇轍','宋','宋诗','song-poetry','','[]','欲就陽崖暖，新開石磴斜。',192,'全唐诗/poet.song.48000.json','["欲就陽崖暖，新開石磴斜。", "誰言太守宅，自是野人家。", "燕坐收心鑑，冥觀閱界沙。", "退公長寂寞，外物自喧嘩。", "缺徑移松補，斜陽種竹遮。", "白雲生後礎，孤鶩伴殘霞。", "破悶時尋鶴，呼眠亦任鴉。", "喜聞糟出甕，屢問菊開花。", "古井元依斗，丹砂舊養芽。", "蚍蜉頻上案，猿狖巧分樝。", "客到扁舟遠，年侵兩鬢華。", "心摇掛風旆，眼暗隔輕紗。", "强撥橫肱睡，來從插版衙。", "隠居慚棄擲，勝地每咨嗟。", "頑鈍終何取，彫磨豈復加。", "焦先夙所尚，圜舍恰如蝸。"]'),
('e5a06dc1-f190-44db-a1ce-f011c5b850c3','和胡教授蒙太守策試諸生','蘇轍','宋','宋诗','song-poetry','','[]','著籍初同闕里多，采芹先致魯風和。',64,'全唐诗/poet.song.48000.json','["著籍初同闕里多，采芹先致魯風和。", "欲將大策觀胸膽，盡召中堂列雁鵝。", "終日正言何忌諱，幾人餘力尚委蛇。", "豈惟太守知爲政，仍見先生善設科。"]'),
('11abb1a3-e404-416a-a17b-68c5cd0b34b2','和毛君州宅八咏 鳳凰山','蘇轍','宋','宋诗','song-poetry','','[]','山川蟠踞偶成形，威鳳低回久未行。',32,'全唐诗/poet.song.48000.json','["山川蟠踞偶成形，威鳳低回久未行。", "更種梧桐真可致，高飛性似伯夷清。"]'),
('b186ef44-324e-4139-a8f2-6584c00bdb07','和毛君州宅八咏 披仙亭','蘇轍','宋','宋诗','song-poetry','','[]','仙翁舊住蜀江邊，千歲歸來一鶴翩。',32,'全唐诗/poet.song.48000.json','["仙翁舊住蜀江邊，千歲歸來一鶴翩。", "城郭已非人事改，凄凉遺迹但披仙。"]'),
('4d013813-a573-4d22-b0da-acf03f61189b','和毛君州宅八咏 方沼亭','蘇轍','宋','宋诗','song-poetry','','[]','池上茅檐覆水低，早來秋雨尚虹霓。',32,'全唐诗/poet.song.48000.json','["池上茅檐覆水低，早來秋雨尚虹霓。", "敗荷折葦飛鴻下，正憶漁舟泊故溪。"]'),
('27c45835-9f29-4e5f-8cdc-e1e7f9c88721','和毛君州宅八咏 翠樾亭','蘇轍','宋','宋诗','song-poetry','','[]','一夜飛霜點綠苔，曉庭黄葉掃成堆。',32,'全唐诗/poet.song.48000.json','["一夜飛霜點綠苔，曉庭黄葉掃成堆。", "檐間翠樾彫疏盡，却放牆東好月來。"]'),
('1ce869fe-6123-41da-b3f0-94f067f02464','和毛君州宅八咏 李八百洞','蘇轍','宋','宋诗','song-poetry','','[]','洞府山川百里賒，洞門藤蔓鎖烟霞。',32,'全唐诗/poet.song.48000.json','["洞府山川百里賒，洞門藤蔓鎖烟霞。", "神仙不與人間異，弟妹還應共一家。"]'),
('ab30845f-0f95-42ce-a98b-63b6fd19e7cc','和毛君州宅八咏 煉丹井','蘇轍','宋','宋诗','song-poetry','','[]','鑿井燒丹八百年，塵緣消盡果初圓。',32,'全唐诗/poet.song.48000.json','["鑿井燒丹八百年，塵緣消盡果初圓。", "石床蘚甃人安在，綠水團團一片天。"]'),
('205c447b-0cd7-4042-a81c-0f3f2672413c','和毛君州宅八咏 磨劍池','蘇轍','宋','宋诗','song-poetry','','[]','神仙鑄劍本無硎，岸石班班尚鐵鉎。',32,'全唐诗/poet.song.48000.json','["神仙鑄劍本無硎，岸石班班尚鐵鉎。", "天上少年仍狡獪，不須還爾對方平。"]'),
('a8701a33-7420-4f72-9f42-b043ee9a3698','和毛君州宅八咏 山房','蘇轍','宋','宋诗','song-poetry','','[]','岸幘携筇夜夜來，蒲團紙帳竹香臺。',32,'全唐诗/poet.song.48000.json','["岸幘携筇夜夜來，蒲團紙帳竹香臺。", "直須覓取僧爲伴，更爲開庵斸草萊。"]'),
('924d73c2-b3a3-4e26-a742-3053a1fa8d45','次韵毛君病中菊未開','蘇轍','宋','宋诗','song-poetry','','[]','病肺秋深霧雨傷，舊繒故絮喜清凉。',64,'全唐诗/poet.song.48000.json','["病肺秋深霧雨傷，舊繒故絮喜清凉。", "菊花金粟未曾吐，桂酒鵝兒空自黄。", "草木亦知年有閏，風霜漸近月方陽。", "得詩聞道維摩病，欲到毗耶言已忘。"]'),
('6299582d-5afb-4ffe-86a2-9bf7fcafaaa5','雨中宿酒務','蘇轍','宋','宋诗','song-poetry','','[]','微官終日守糟缸，風雨凄凉夜渡江。',64,'全唐诗/poet.song.48000.json','["微官終日守糟缸，風雨凄凉夜渡江。", "早歲謬知儒術貴，安眠近喜壯心降。", "夜深唧唧醅鳴甕，睡起蕭蕭葉打窗。", "阮籍作官都爲酒，不須分別恨南邦。"]'),
('69f733e7-0b99-4959-beae-c3762fa88e0a','次韵毛君經旬不用鞭扑','蘇轍','宋','宋诗','song-poetry','','[]','共喜秋深酒未醇，官曹休假不須旬。',64,'全唐诗/poet.song.48000.json','["共喜秋深酒未醇，官曹休假不須旬。", "政寬境內棠陰合，訟去庭中草色新。", "不惜牛刀時一割，已因鼷鼠發千鈞。", "歲終誰爲公書考，豈止江西第一人。"]'),
('2e6d62f9-6181-48d0-95fc-75c393281835','次韵李撫辰屯田修州門','蘇轍','宋','宋诗','song-poetry','','[]','六月江濤壁壘頹，蒼崖翠甓就新臺。',64,'全唐诗/poet.song.48000.json','["六月江濤壁壘頹，蒼崖翠甓就新臺。", "咄嗟雙闕還依舊，咫尺羣山信有材。", "畫戟風生兩衙退，飛橋日出萬人來。", "不因毀圮催興築，誰見雍容治劇才。"]'),
('baa574be-4f62-4670-87bf-f2466c30a2c4','飲酒過量肺疾復作','蘇轍','宋','宋诗','song-poetry','','[]','朝蒙麴塵居，夜傍糟床卧。',240,'全唐诗/poet.song.48000.json','["朝蒙麴塵居，夜傍糟床卧。", "鼻香黍麥熟，眼亂瓶罌過。", "囊中衣已空，口角涎虛墮。", "啜嘗未云足，盜釂恐深坐。", "使君信寬仁，高會慰寒餓。", "西樓適新成，明月猶半破。", "擁檐青山橫，拂檻流水播。", "雕槃貯霜實，銀盎薦秋糯。", "共言文字歡，豈待紅裙佐。", "惟知醍醐滑，不悟頗羅大。", "夜歸肺增漲，晨起脾失磨。", "情懷忽牢落，藥餌費調和。", "衰年足奇窮，一醉仍坎坷。", "清尊自不惡，多病欲何奈。", "聞公話少年，舉白不論個。", "歌吟雜嘲謔，笑語爭掀簸。", "平明起相視，銳氣曾未挫。", "達人遺形骸，駑馬懷豆莝。", "不知逃世網，但解憂歲課。", "不見獨醒人，終費招魂些。"]'),
('a976b4da-63f0-4bdf-afe1-fdbc0676204b','衢州趙閱道少師濯纓亭','蘇轍','宋','宋诗','song-poetry','','[]','掛冠纓上已無塵，猶愛溪光碧照人。',64,'全唐诗/poet.song.48000.json','["掛冠纓上已無塵，猶愛溪光碧照人。", "點檢舊遊黄石在，掃除諸念白鷗親。", "一尊父老囊金盡，三徑松筠生事貧。", "他日南公數人物，丹青添入縣圖新。"]'),
('f7b7feb1-d3d5-49b6-8712-ded4d3d5955f','茶花二首  其一','蘇轍','宋','宋诗','song-poetry','','[]','黄蘗春芽大麥粗，傾山倒谷採無餘。',64,'全唐诗/poet.song.48000.json','["黄蘗春芽大麥粗，傾山倒谷採無餘。", "久疑殘枿陽和盡，尚有幽花霰雪初。", "耿耿清香崖菊淡，依依秀色嶺梅如。", "經冬結子猶堪種，一畝荒園試爲鉏。"]'),
('bedfce64-a1c9-4ec5-8199-7a30749ab001','茶花二首  其二','蘇轍','宋','宋诗','song-poetry','','[]','細嚼花鬚味亦長，新芽一粟葉間藏。',64,'全唐诗/poet.song.48000.json','["細嚼花鬚味亦長，新芽一粟葉間藏。", "稍經臘雪侵肌瘦，旋得春雷發地狂。", "開落空山誰比數，烝烹來歲最先嘗。", "枝枯葉硬天真在，踏遍牛羊未改香。"]'),
('d6c64750-2daa-4337-bc6c-c3e42947c994','次韵毛君山房即事十首  其一','蘇轍','宋','宋诗','song-poetry','','[]','案牘稀疏意自開，夜闌幽夢曉方回。',32,'全唐诗/poet.song.48000.json','["案牘稀疏意自開，夜闌幽夢曉方回。", "青苔紅葉騷人事，時見詩筒去又來。"]'),
('50faabd2-150a-4fa1-b681-492ab8e6905a','次韵毛君山房即事十首  其二','蘇轍','宋','宋诗','song-poetry','','[]','東晉仙人借舊山，定應天意許公閒。',32,'全唐诗/poet.song.48000.json','["東晉仙人借舊山，定應天意許公閒。", "郡人欲問史君處，笑指峰巒紫翠間。"]'),
('5be23cfc-28ed-4e84-b0f3-c7b67f8e72a3','次韵毛君山房即事十首  其三','蘇轍','宋','宋诗','song-poetry','','[]','蛩知秋候時鳴壁，香礙蒲簾不出門。',32,'全唐诗/poet.song.48000.json','["蛩知秋候時鳴壁，香礙蒲簾不出門。", "隠几無言心有得，南窗晴日暖侵軒。"]'),
('409ed7c5-bab7-407f-a1ab-c0083045d179','次韵毛君山房即事十首  其四','蘇轍','宋','宋诗','song-poetry','','[]','溪山付與醉中仙，美酒何曾斗十千。',32,'全唐诗/poet.song.48000.json','["溪山付與醉中仙，美酒何曾斗十千。", "就得江邊賤魚稻，閑官未用苦相憐。"]'),
('5cc72db3-bc3b-4e89-a4c1-a89f25d171ba','次韵毛君山房即事十首  其五','蘇轍','宋','宋诗','song-poetry','','[]','忘身先要解忘名，分別須臾起不平。',32,'全唐诗/poet.song.48000.json','["忘身先要解忘名，分別須臾起不平。", "請看早朝霜入屨，何如卧聽打衙聲。"]'),
('33be6106-7168-402c-9ed5-8666c39aa8bc','次韵毛君山房即事十首  其六','蘇轍','宋','宋诗','song-poetry','','[]','禽哢秋來不復圓，桐陰霜後亦成穿。',32,'全唐诗/poet.song.48000.json','["禽哢秋來不復圓，桐陰霜後亦成穿。", "黄花强欲招酣飲，白髮偏工報老年。"]'),
('5043fd50-e658-4e4a-b25e-b25b6e1b081b','次韵毛君山房即事十首  其七','蘇轍','宋','宋诗','song-poetry','','[]','邂逅清歡屢不期，病來無奈羽觴飛。',32,'全唐诗/poet.song.48000.json','["邂逅清歡屢不期，病來無奈羽觴飛。", "醉乘籃轝江邊去，長伴漁舟月下歸。"]'),
('c7b96b61-1f51-4f8f-aed8-91cab655a522','次韵毛君山房即事十首  其八','蘇轍','宋','宋诗','song-poetry','','[]','醉裏題詩偏韵惡，秋來勸酒益杯深。',32,'全唐诗/poet.song.48000.json','["醉裏題詩偏韵惡，秋來勸酒益杯深。", "不才多病俱非敵，綠綺緣何得報金。"]'),
('c6c6061e-c63b-4a7b-94fb-8a8083be48a5','次韵毛君山房即事十首  其九','蘇轍','宋','宋诗','song-poetry','','[]','庵中獨宿雨垂垂，永夜無人款竹扉。',32,'全唐诗/poet.song.48000.json','["庵中獨宿雨垂垂，永夜無人款竹扉。", "灰冷銅爐香欲滅，床頭一點葛燈微。"]'),
('42cb3a2a-4883-40b1-a3ae-32a7c2a55899','次韵毛君山房即事十首  其一○','蘇轍','宋','宋诗','song-poetry','','[]','觸事隨緣不用多，華堂玉食奈憂何。',32,'全唐诗/poet.song.48000.json','["觸事隨緣不用多，華堂玉食奈憂何。", "美人未厭山阿陋，薜荔爲裳带女蘿。"]'),
('342838a3-5975-406b-a2fa-d77f03ce67f2','再和十首  其一','蘇轍','宋','宋诗','song-poetry','','[]','澗草巖花日日開，江南秋盡似春回。',32,'全唐诗/poet.song.48000.json','["澗草巖花日日開，江南秋盡似春回。", "旋開還落無人顧，惟有山蜂暖尚來。"]'),
('f38401e9-7bc4-467b-bce6-b507365d9c32','再和十首  其二','蘇轍','宋','宋诗','song-poetry','','[]','江上孤城面面山，居人也自不曾閑。',32,'全唐诗/poet.song.48000.json','["江上孤城面面山，居人也自不曾閑。", "蜂遊蟻聚知何事，日夜長橋南北間。"]'),
('c564d477-a849-40e9-884b-21cbccfaabf1','再和十首  其三','蘇轍','宋','宋诗','song-poetry','','[]','城郭村墟共水雲，槿籬竹屋映柴門。',32,'全唐诗/poet.song.48000.json','["城郭村墟共水雲，槿籬竹屋映柴門。", "隠居亦有高人在，岸幘無言倚釣軒。"]'),
('fac6d0a2-0160-4098-856e-c6e1f8e18703','再和十首  其四','蘇轍','宋','宋诗','song-poetry','','[]','一官疏散自疑仙，三考應成醉日千。',32,'全唐诗/poet.song.48000.json','["一官疏散自疑仙，三考應成醉日千。", "早病固須閑地著，多憂長被達人憐。"]'),
('c2b89962-0443-414b-add3-793844472841','再和十首  其五','蘇轍','宋','宋诗','song-poetry','','[]','養生尤復要功圓，溜滴南溪石自穿。',32,'全唐诗/poet.song.48000.json','["養生尤復要功圓，溜滴南溪石自穿。", "近見牢山陳道士，微言約我更三年。"]'),
('a306f205-92fb-46ce-9291-23a0fcffa3b9','再和十首  其六','蘇轍','宋','宋诗','song-poetry','','[]','張公詩社見公名，白首山城嘆不平。',32,'全唐诗/poet.song.48000.json','["張公詩社見公名，白首山城嘆不平。", "坐客要聞新樂府，應須湓口琵琶聲。"]'),
('759b65cc-2e05-492e-8877-2f6a5de99cea','再和十首  其七','蘇轍','宋','宋诗','song-poetry','','[]','高情日與故山期，鴻鵠誰言也倦飛。',32,'全唐诗/poet.song.48000.json','["高情日與故山期，鴻鵠誰言也倦飛。", "且聽漁人强哺啜，坐中羈客畏公歸。"]'),
('fbe1d9e1-9fda-415e-94f5-3bf4848d6fac','再和十首  其八','蘇轍','宋','宋诗','song-poetry','','[]','天爲多才故欲禁，府門摧落漲江深。',32,'全唐诗/poet.song.48000.json','["天爲多才故欲禁，府門摧落漲江深。", "鼎新翠壁排精鐵，涌出飛樓直百金。"]'),
('105742e4-4f5f-4d5d-8022-26b2e452664d','再和十首  其九','蘇轍','宋','宋诗','song-poetry','','["\u957f\u6c5f"]','樓上青山繞四垂，畫橋百步引朱扉。',32,'全唐诗/poet.song.48000.json','["樓上青山繞四垂，畫橋百步引朱扉。", "落成當與公同上，一看長江白練微。"]'),
('4dea7111-e259-4342-abc2-d15ee6924ce0','再和十首  其一○','蘇轍','宋','宋诗','song-poetry','','[]','歌舞留賓意自多，華燈數問夜如何。',32,'全唐诗/poet.song.48000.json','["歌舞留賓意自多，華燈數問夜如何。", "白頭病客無才思，慣卧茅檐長薜蘿。"]'),
('fafcd6cc-d7b7-49aa-aa00-0a5a32f52ee4','筠州二咏 牛尾狸','蘇轍','宋','宋诗','song-poetry','','[]','首如狸，尾如牛，攀條捷險如猱猴。',96,'全唐诗/poet.song.48000.json','["首如狸，尾如牛，攀條捷險如猱猴。", "橘柚爲漿栗爲餱，筋肉不足惟膏油。", "深居簡出善自謀，尋蹤發窟并執囚，蓄租分散身爲羞。", "松薪瓦甑烝浮浮，壓入糟盎肥欲流，熊肪羊酪真比儔。", "引筯將舉訊何尤，無功竊食人所仇。"]'),
('8b40617d-b9b3-4d8d-8e46-7ef79b69ac1b','筠州二咏 黄雀','蘇轍','宋','宋诗','song-poetry','','[]','秋風下，黄雀飛。',120,'全唐诗/poet.song.48000.json','["秋風下，黄雀飛。", "禾田熟，黄雀肥。", "羣飛蔽空日色薄，逡巡百頃禾爲稀，翾翻巧捷多且微。", "精丸妙繳舉輒違，乘時席勢不可揮。", "一朝風雨寒霏霏，肉多翅重天時非，農夫舉網驚合圍。", "懸頸繫足膚無衣，百個同缶仍相依，頭顱萬里行不歸。", "北方居人厭羔豨，咀噍聊發一笑欷。"]'),
('da92b5e4-994e-49c6-9959-b67f2df08393','和毛君新葺囷庵船齋','蘇轍','宋','宋诗','song-poetry','','[]','厭居華屋住東庵，真味全勝食薺甘。',224,'全唐诗/poet.song.48000.json','["厭居華屋住東庵，真味全勝食薺甘。", "多病維摩長隠几，無心彌勒便同龕。", "誤遊田舍空成笑，謬入僧房即欲參。", "風霽不知吹有萬，月明聊共影成三。", "齋如小舫才容住，室類空囷定不貪。", "擁褐放衙人寂寂，脫巾漉酒鬢鬖鬖。", "畫囊書帙堆窗案，藥裹瓢樽挂壁藍。", "檐竹風霜曾不到，盆花蜂蝶未全諳。", "公餘野鵲驚初睡，賓醉佳人笑劇談。", "勸客巨觥那得避，和詩難韵不容探。", "曉來霏霧連江氣，冬後溫風带嶺嵐。", "去國屢成還蜀夢，忘憂惟有對公酣。", "終身狥祿知何益，投檄歸耕貧未堪。", "借我此庵泥藥竈，古書鴻寶試淮南。"]'),
('7431f09c-fd76-4e9d-9fb7-67cc4dddba22','寒雨','蘇轍','宋','宋诗','song-poetry','','[]','江南殊氣候，冬雨作春寒。',48,'全唐诗/poet.song.48000.json','["江南殊氣候，冬雨作春寒。", "冰雪期方遠，蕉絺意始闌。", "未妨溪草綠，先恐嶺梅殘。", "忽發中原念，貂裘據錦鞍。"]'),
('4155ec98-d8a2-4b98-858b-54333189e213','積雨二首  其一','蘇轍','宋','宋诗','song-poetry','','[]','山雨無時歇，江波上岸流。',48,'全唐诗/poet.song.48000.json','["山雨無時歇，江波上岸流。", "泥深未免出，橋斷更堪憂。", "房淺鄰糟甕，宵寒攬絮裘。", "朝來勢未已，歸路恐操舟。"]'),
('79fa68a0-8544-4d18-8a64-0340f1bf42c5','積雨二首  其二','蘇轍','宋','宋诗','song-poetry','','[]','微陽力尚淺，未解破重陰。',48,'全唐诗/poet.song.48000.json','["微陽力尚淺，未解破重陰。", "雲氣山川滿，江流日夜深。", "凍牙生滯穗，餘潤及重衾。", "泥濘沉車轂，農輸絕苦心。"]'),
('0f9aec13-1fd4-4a04-9667-2963a2f86642','戲贈李朝散','蘇轍','宋','宋诗','song-poetry','','[]','江霧霏霏作雪天，樽前醉倒不知寒。',32,'全唐诗/poet.song.48000.json','["江霧霏霏作雪天，樽前醉倒不知寒。", "後堂桃李春猶晚，試覓酥花子細看。"]'),
('3217f937-b1e8-4bec-be62-82a0f48defa4','戲答','蘇轍','宋','宋诗','song-poetry','','[]','銀瓶瀉酒正霜天，玉麈生風夜更寒。',32,'全唐诗/poet.song.48000.json','["銀瓶瀉酒正霜天，玉麈生風夜更寒。", "下客不辭投轄飲，好花猶恐隔簾看。"]'),
('02b35646-4748-47fd-b990-b2653ec8bac0','臨江蕭氏家寶堂','蘇轍','宋','宋诗','song-poetry','','[]','高人不解作生涯，唯有中堂書五車。',64,'全唐诗/poet.song.48000.json','["高人不解作生涯，唯有中堂書五車。", "竹簡多於孔氏壁，牙籤新似鄴侯家。", "田園豈是子孫計，青紫今爲里巷誇。", "富貴早知皆有命，君應未厭十年賒。"]'),
('89d8ddb5-31e2-495c-bf90-4b34242fa9e5','和蕭刓察推賀族叔司理登科還鄉四首  其一','蘇轍','宋','宋诗','song-poetry','','[]','家聲籍籍大江西，臨老揮毫捧御題。',32,'全唐诗/poet.song.48000.json','["家聲籍籍大江西，臨老揮毫捧御題。", "得意何殊少年樂，還家不惜醉如泥。"]'),
('b49c126b-fc70-43a0-b238-c2d7819c0f17','和蕭刓察推賀族叔司理登科還鄉四首  其二','蘇轍','宋','宋诗','song-poetry','','[]','讀盡家藏萬卷書，蕭然華髮宦遊初。',32,'全唐诗/poet.song.48000.json','["讀盡家藏萬卷書，蕭然華髮宦遊初。", "區區獄掾何須愧，聊把春秋試緒餘。"]'),
('c7b75c63-6dee-4598-9806-6e23a2c9ba74','和蕭刓察推賀族叔司理登科還鄉四首  其三','蘇轍','宋','宋诗','song-poetry','','[]','作官未減讀書勤，簿領從今日日新。',32,'全唐诗/poet.song.48000.json','["作官未減讀書勤，簿領從今日日新。", "汗簡韋編誰付予，傳家應有下帷人。"]'),
('b2812c43-ba23-406f-8ba1-077d3f544aeb','和蕭刓察推賀族叔司理登科還鄉四首  其四','蘇轍','宋','宋诗','song-poetry','','[]','巷南諸子足才賢，邂逅相逢秀句傳。',32,'全唐诗/poet.song.48000.json','["巷南諸子足才賢，邂逅相逢秀句傳。", "强作短章同寄與，異時見我一依然。"]'),
('f7b2136a-7b33-4810-9f4a-c785adce55f3','次韵吳厚秀才見贈三首  其一','蘇轍','宋','宋诗','song-poetry','','[]','騷人思苦骨巖巖，百里携詩相就談。',64,'全唐诗/poet.song.48000.json','["騷人思苦骨巖巖，百里携詩相就談。", "故作微詞挑遷客，不嫌春雨濕歸衫。", "少年舊喜登高賦，老病今成見敵慚。", "問我近來誰復可，對君聊擬誦周南。"]'),
('ef76d261-1c61-4d46-bfb9-cc037a05fc75','次韵吳厚秀才見贈三首  其二','蘇轍','宋','宋诗','song-poetry','','[]','久欲歸田計未成，羨君負郭足爲生。',64,'全唐诗/poet.song.48000.json','["久欲歸田計未成，羨君負郭足爲生。", "躬耕不用千鍾祿，高卧誰知萬里征。", "已覺安閑真樂事，可憐辛苦盡浮名。", "隠居便作江南計，爲覓佳山早寄聲。"]'),
('b689de2b-992f-484e-9f0d-4a8c98e12c9f','次韵吳厚秀才見贈三首  其三','蘇轍','宋','宋诗','song-poetry','','[]','一卷新詩錦一端，掉頭吟諷識芳酸。',64,'全唐诗/poet.song.48000.json','["一卷新詩錦一端，掉頭吟諷識芳酸。", "哀歌永夜悲牛角，朗咏扁舟笑杏壇。", "間發笙簧猶可擬，棄捐斤斧定知難。", "繼君高韵君應笑，咀嚼歸途久據鞍。"]'),
('351578c7-9aaa-4c62-a738-8f10901d4a5e','次韵毛君燒松花六絕  其一','蘇轍','宋','宋诗','song-poetry','','[]','茅庵紙帳學僧眠，爐爇松花取易然。',32,'全唐诗/poet.song.48000.json','["茅庵紙帳學僧眠，爐爇松花取易然。", "唯有未能忘酒在，手傾金盞鬥垂蓮。"]'),
('01cfc297-1b36-4127-91ae-9fe95b0b20af','次韵毛君燒松花六絕  其二','蘇轍','宋','宋诗','song-poetry','','[]','餠雜松黄二月天，盤敲松子早霜寒。',32,'全唐诗/poet.song.48000.json','["餠雜松黄二月天，盤敲松子早霜寒。", "山家一物都無棄，狼籍乾花最後般。"]'),
('241cc2b1-806b-4543-b82e-11a3fcd0e1be','次韵毛君燒松花六絕  其三','蘇轍','宋','宋诗','song-poetry','','[]','松老香多氣自嚴，餘烟勃鬰透疏簾。',32,'全唐诗/poet.song.48000.json','["松老香多氣自嚴，餘烟勃鬰透疏簾。", "須臾過盡惟灰在，借問誰收一番炎。"]'),
('0adccfae-1441-400e-a0e6-75cbf782d1fe','次韵毛君燒松花六絕  其四','蘇轍','宋','宋诗','song-poetry','','[]','美人寒甚懶開扉，金作松花插羃䍦。',32,'全唐诗/poet.song.48000.json','["美人寒甚懶開扉，金作松花插羃䍦。", "幾度低頭疑墮落，青烟已斷未消時。"]'),
('994328ba-0b1d-4f98-9d9b-f8680ae69f62','次韵毛君燒松花六絕  其五','蘇轍','宋','宋诗','song-poetry','','[]','枯萼鱗皴不復堅，重重正似半開蓮。',32,'全唐诗/poet.song.48000.json','["枯萼鱗皴不復堅，重重正似半開蓮。", "曾經樵舍磚爐見，未許邦君畫閤然。"]'),
('89a68fa3-f892-460e-b091-f9073238edc9','次韵毛君燒松花六絕  其六','蘇轍','宋','宋诗','song-poetry','','[]','黄蠟供炊自一家，錙銖貧富遞矜誇。',32,'全唐诗/poet.song.48000.json','["黄蠟供炊自一家，錙銖貧富遞矜誇。", "都城爭買方薪貴，却顧松花已自奢。"]'),
('95255486-6beb-4d35-87d6-bbbd3078a348','陪毛君遊黄仙觀','蘇轍','宋','宋诗','song-poetry','','[]','李叟仙居仍近市，黄公道院亦依城。',64,'全唐诗/poet.song.48000.json','["李叟仙居仍近市，黄公道院亦依城。", "定應昔日山林地，未有今時鷄犬聲。", "白鶴翻飛終不返，黄冠憔悴只躬耕。", "試從車騎尋遺迹，恐有居人解養生。"]'),
('299531cb-7f2a-496a-bc5b-4a05e977b689','次韵王適梅花','蘇轍','宋','宋诗','song-poetry','','[]','江梅似欲競新年，照水窺林態愈妍。',64,'全唐诗/poet.song.48000.json','["江梅似欲競新年，照水窺林態愈妍。", "霜重清香渾欲滴，月明素質自生烟。", "未成細實酸猶薄，半落南枝意可憐。", "誰寫江西風物樣，徐家舊有數枝傳。"]'),
('e68fab42-d688-4473-8db1-94fff099b7de','次韵王適春雪二首  其一','蘇轍','宋','宋诗','song-poetry','','[]','江南春候寒猶劇，細雨風吹作雪花。',64,'全唐诗/poet.song.48000.json','["江南春候寒猶劇，細雨風吹作雪花。", "中夜窗扉初晃漾，平明草木半低斜。", "潤催江柳排金綠，光雜山茶點絳葩。", "老病不堪乘曉出，紛紛能使髮增華。"]'),
('70f7cf27-1808-4b19-9ac9-fc7c1c0393e9','次韵王適春雪二首  其二','蘇轍','宋','宋诗','song-poetry','','[]','春雪飄摇旋不成，依稀履迹散空庭。',32,'全唐诗/poet.song.48000.json','["春雪飄摇旋不成，依稀履迹散空庭。", "山藏複閣猶殘白，日照南峰已半青。"]'),
('d87ac9e8-a379-4149-ad43-aa4fcf5ed999','毛君惠溫柑荔支二絕  其一','蘇轍','宋','宋诗','song-poetry','','["\u6d1e\u5ead\u6e56"]','楚山黄橘彈丸小，未識洞庭三寸柑。',32,'全唐诗/poet.song.48000.json','["楚山黄橘彈丸小，未識洞庭三寸柑。", "不有風流吳越客，誰令千里送江南。"]'),
('703a6938-272d-4005-8784-4736b0ed655f','毛君惠溫柑荔支二絕  其二','蘇轍','宋','宋诗','song-poetry','','[]','荔子生紅無奈遠，陳家曬白到猶難。',32,'全唐诗/poet.song.48000.json','["荔子生紅無奈遠，陳家曬白到猶難。", "雖無驛騎紅塵起，尚得佳人一笑歡。"]'),
('54c5c416-29d3-4343-8191-4cfdff8be811','次韵王適遊真如寺','蘇轍','宋','宋诗','song-poetry','','[]','江上春雨過，城中春草深。',120,'全唐诗/poet.song.48000.json','["江上春雨過，城中春草深。", "擾擾市井塵，悠悠溪谷心。", "東郊大愚山，自古薝蔔林。", "微言久不聞，墜緒誰當尋。", "道俗數百人，請聞海潮音。", "齋罷車馬散，萬籟俱消沉。", "新亭面南山，積霧開重陰。", "蕭然偶有得，懷抱方愔愔。", "我坐米鹽間，日被塵垢侵。", "不知山中趣，强作山中吟。"]'),
('fb999aea-0748-46e9-93ef-92160ce62fbe','次韵王適新燕','蘇轍','宋','宋诗','song-poetry','','[]','好雨纖纖潤客衣，新來雙燕力猶微。',64,'全唐诗/poet.song.48000.json','["好雨纖纖潤客衣，新來雙燕力猶微。", "似嫌春早無人見，故待簾開掠地飛。", "南國花期知不遠，中原寒劇未應歸。", "養雛不怕巢成早，記取朝朝爲啟扉。"]'),
('09a94c06-ef43-411e-89c2-4849bc633085','官居即事','蘇轍','宋','宋诗','song-poetry','','[]','官局紛紜簿領迷，生緣瑣細老農齊。',64,'全唐诗/poet.song.48000.json','["官局紛紜簿領迷，生緣瑣細老農齊。", "偷安旋種十年木，肉食還須五母鷄。", "對酒不嘗憐酤榷，釣魚無術漫臨溪。", "此身已分長貧賤，執爨縫裳愧老妻。"]'),
('b4bdfe13-a596-427a-9f39-5c163aefa35f','陪毛君夜遊北園','蘇轍','宋','宋诗','song-poetry','','[]','池塘草生春尚淺，桃李飛花初片片。',160,'全唐诗/poet.song.48000.json','["池塘草生春尚淺，桃李飛花初片片。", "一尊花下夜忘歸，燈火尋春畏春晚。", "春風暗度人不知，滿園紅白已離披。", "江南春雨少晴日，露坐青天能幾時。", "折花只恐傷花意，携客就花花定喜。", "落蕊飄香翠袖中，交柯接葉燈光裏。", "雨練風柔雪不如，精神炫轉影扶疏。", "夜看飛燕勝朝日，月暗還須明月珠。", "美人勸我殊非惡，明日雨來無此樂。", "醉歸不用怕山公，馬上接䍦先倒著。"]'),
('172e08c6-2b95-46a4-9c8d-a688caec51b6','山橙花口號','蘇轍','宋','宋诗','song-poetry','','[]','故鄉寒食荼䕷發，百和香濃村巷深。',32,'全唐诗/poet.song.48000.json','["故鄉寒食荼䕷發，百和香濃村巷深。", "漂泊江南春欲盡，山橙仿佛慰人心。"]'),
('1e200ba1-43f5-467c-ad40-caedf6db05f6','次韵馮弋同年','蘇轍','宋','宋诗','song-poetry','','[]','細雨濛濛江霧昏，坐曹聊且免泥奔。',32,'全唐诗/poet.song.48000.json','["細雨濛濛江霧昏，坐曹聊且免泥奔。", "賣鹽酤酒知同病，一笑何勞賦北門。"]'),
('046ff703-785d-4e85-8e3c-9323e7914cbb','送王適徐州赴舉','蘇轍','宋','宋诗','song-poetry','','[]','送別江南春雨淫，北方誰是子知音。',64,'全唐诗/poet.song.48000.json','["送別江南春雨淫，北方誰是子知音。", "性如白玉燒猶冷，文似朱弦叩愈深。", "萬里同舟寬老病，一杯分袂發悲吟。", "明年榜上看名姓，楊柳春風正似今。"]'),
('61807a8d-d48a-469c-b539-73cf44c4cc4c','遊吳氏園','蘇轍','宋','宋诗','song-poetry','','[]','細雨作寒晴便暖，好風吹袂意初佳。',64,'全唐诗/poet.song.48000.json','["細雨作寒晴便暖，好風吹袂意初佳。", "清池解洗春心熱，紅艷能添醉眼花。", "紫竹暗生岷岫笋，山丹强比洛人家。", "憐渠巧與閑官便，申退來遊未覺賒。"]'),
('96869a26-67ca-47dd-bf59-32a911fdd62b','江州周寺丞泳夷亭','蘇轍','宋','宋诗','song-poetry','','["\u5e90\u5c71"]','行過廬山不得上，湓江城邊一惆悵。',96,'全唐诗/poet.song.48000.json','["行過廬山不得上，湓江城邊一惆悵。", "羨君山下有夷亭，千巖萬壑長相向。", "山中李生好讀書，出山作郡山前居。", "手開平湖浸山脚，未肯即與廬山疏。", "道州一去應嫌遠，千里思山夢中見。", "青山長見恐君嫌，要須罷郡歸來看。"]'),
('f08f92bf-d433-406c-9a3a-ab6f8adfc0bb','次韵毛君遊陳氏園','蘇轍','宋','宋诗','song-poetry','','[]','增築園亭草木新，損花風雨怨頻頻。',64,'全唐诗/poet.song.48000.json','["增築園亭草木新，損花風雨怨頻頻。", "篔簹似欲迎初暑，芍藥猶堪送晚春。", "薄暮出城仍有伴，携壺藉草更無巡。", "歸軒有喜知誰見，道上從橫滿醉人。"]'),
('10b3d60b-1567-4720-88a8-7c50f445760b','江漲','蘇轍','宋','宋诗','song-poetry','','[]','山中三日雨，江水一丈高。',168,'全唐诗/poet.song.48000.json','["山中三日雨，江水一丈高。", "崩騰沒洲渚，淫溢浸蓬蒿。", "凌晨我有適，出門舟自操。", "中廛已易肆，下道先容舠。", "鷄犬萃墳冢，牛羊逾圈牢。", "厨薪散流枿，囷米爲浮糟。", "卧席不遑卷，剝繭仍未繅。", "老弱但坐視，閭里將安逃。", "徙居共擾擾，來勢方滔滔。", "嗟余偶同病，哀爾爲生勞。", "晴日慰人願，寒風送驚濤。", "藩籬出舊趾，蠃蚌遺平皋。", "流竄非擇地，艱難理宜遭。", "胡爲苦戚戚，一夕生二毛。"]'),
('be9b7168-e379-4116-b00f-df114cc8beba','和子瞻鐵拄杖','蘇轍','宋','宋诗','song-poetry','','["\u6d1e\u5ead\u6e56"]','截竹爲杖瘦且輕，石堅竹破誤汝行。',160,'全唐诗/poet.song.48000.json','["截竹爲杖瘦且輕，石堅竹破誤汝行。", "削木爲杖輕且好，道遠木折恐不到。", "閩君鐵杖七尺長，色如黑蛇氣如霜。", "提携但恐汝無力，撞堅過嶮安能傷。", "柳公雖老尚强健，閉門却掃不復將。", "知公足力無險阻，憐公未有登山侶。", "回生四海惟一身，袖中長劍爲兩人。", "洞庭漫天不覺過，半酣起舞驚鬼神。", "願公此杖亦如此，適意遨遊日千里。", "歸來倚壁示時人，海外蒼茫空自記。"]'),
('e275ab34-db43-4b4b-b5d9-a7b5312880ef','競渡','蘇轍','宋','宋诗','song-poetry','','[]','史君欲聽榜人謳，一夜江波拍岸流。',64,'全唐诗/poet.song.48000.json','["史君欲聽榜人謳，一夜江波拍岸流。", "父老不知招屈恨，少年爭作弄潮遊。", "長鯨破浪聊堪比，小旆逆風殊未收。", "角勝爭先非老事，凭欄寓目思悠悠。"]'),
('ebe8ab08-134a-4e78-ab59-f691875b227d','登郡譙偶見姜應明司馬醉歸','蘇轍','宋','宋诗','song-poetry','','[]','蒼然莫色映樓臺，江市遊人夜未迴。',32,'全唐诗/poet.song.48000.json','["蒼然莫色映樓臺，江市遊人夜未迴。", "何處酒仙無一事，肩輿鼾睡過橋來。"]'),
('a704f840-40d8-49d8-962e-339c110c8987','送姜司馬','蘇轍','宋','宋诗','song-poetry','','[]','七歲立談明主前，江湖晚節弄漁船。',64,'全唐诗/poet.song.48000.json','["七歲立談明主前，江湖晚節弄漁船。", "鬥鷄誰識城東老，喪馬方知塞上賢。", "生計未成歸去咏，草書時發醉中顛。", "當年不解看齊物，氣踴如山誰見憐。"]'),
('ed09d398-d15d-4831-9683-eb0543768f6f','寄題趙㞦承事戲綵堂','蘇轍','宋','宋诗','song-poetry','','[]','春晚安輿遍浙東，永嘉別乘喜無窮。',64,'全唐诗/poet.song.48000.json','["春晚安輿遍浙東，永嘉別乘喜無窮。", "橐裝已笑分諸子，吏道何勞問薛公。", "堂上壽樽諸掾集，室中禪論衲僧通。", "興闌却返林泉去，幕府長留孝弟風。"]'),
('bca33b7f-5894-46c2-adc8-d1ff48ca41fa','次韵溫守李鈞見寄兼簡毛大夫','蘇轍','宋','宋诗','song-poetry','','[]','梁苑相從簿領中，清風相逐畫船東。',64,'全唐诗/poet.song.48000.json','["梁苑相從簿領中，清風相逐畫船東。", "婆娑江海凌雲鶴，飲啄籠樊失渚鴻。", "別後丹砂迷舊訣，愁來白髮變衰翁。", "此間詩老仍勍敵，正憶高吟酒盞空。"]'),
('394247e7-54a4-4bac-a59f-66c2b144f409','次韵洞山克文長老','蘇轍','宋','宋诗','song-poetry','','[]','無地容錐卓，年來轉覺貧。',48,'全唐诗/poet.song.48000.json','["無地容錐卓，年來轉覺貧。", "偶知珠在手，一任甑生塵。", "竄逐非關性，顛狂却甚真。", "此心誰復識，試語洞山人。"]'),
('2abe3eff-810a-4688-a4bd-a8cc41c9348b','試院唱酬十一首 戲呈試官呂防','蘇轍','宋','宋诗','song-poetry','','[]','新秋風月正凉天，空館相看學坐禪。',64,'全唐诗/poet.song.48000.json','["新秋風月正凉天，空館相看學坐禪。", "滿榻詩書愁病眼，隔牆砧杵思高眠。", "霜飛一葉凋瓊玉，風繞雙松奏管絃。", "聞道熊羆歸夢數，侵天闈棘漫森然。"]'),
('cc991ecd-5ba0-4a7d-a4aa-fe9d206cd2db','試院唱酬十一首 次韵呂君豐城寶氣亭','蘇轍','宋','宋诗','song-poetry','','[]','紫氣飛空不自謀，誰憐黽勉匣中留。',64,'全唐诗/poet.song.48000.json','["紫氣飛空不自謀，誰憐黽勉匣中留。", "西山猛獸橫行甚，北海長鯨何日收。", "星斗不堪供醉舞，蛟龍會看反重湫。", "功成變化無蹤迹，望斷中原百尺樓。"]'),
('7bedaaf1-f623-4303-b12a-174915ff4b68','試院唱酬十一首 次韵呂君見贈','蘇轍','宋','宋诗','song-poetry','','[]','偶然傾蓋接清言，不覺門前晝漏傳。',64,'全唐诗/poet.song.48000.json','["偶然傾蓋接清言，不覺門前晝漏傳。", "老病低摧方伏櫪，壯心堅銳正當年。", "莫嫌客舍一杯酒，試論灊山三祖禪。", "明日程文堆几案，只應衰懶得安眠。"]'),
('2cc1376b-8740-4564-9800-8f396719c3ad','試院唱酬十一首 次韵呂君興善寺靜軒','蘇轍','宋','宋诗','song-poetry','','[]','自恨尋山計苦遲，年過四十始知非。',64,'全唐诗/poet.song.48000.json','["自恨尋山計苦遲，年過四十始知非。", "小軒迎客如招隠，野鳥窺人自識機。", "窗外竹深孤鶴下，階前菊秀晚蜂飛。", "老僧戰勝長幽寂，瘦骨緣何未肯肥。"]'),
('91dc7e01-edb8-48df-a861-77485121dcc2','試院唱酬十一首 觀試進士呈試官','蘇轍','宋','宋诗','song-poetry','','[]','松庭散朝日，棘戶啟秋風。',72,'全唐诗/poet.song.48000.json','["松庭散朝日，棘戶啟秋風。", "鵠鷺紛來下，旌旗儼未攻。", "馳詞看倚馬，餘力送征鴻。", "逸足誰先到，孤標想暗空。", "晶熒雙鏡並，高下片言公。", "老病方耽睡，飛沉一夢中。"]'),
('cbbc82a0-ff21-41d5-92f0-59f0616460b7','試院唱酬十一首 次前韵','蘇轍','宋','宋诗','song-poetry','','[]','南國號多士，幾人洙泗風。',72,'全唐诗/poet.song.48000.json','["南國號多士，幾人洙泗風。", "英材自入彀，壞陣不勞攻。", "文縟山藏豹，飛高弋慕鴻。", "蚩妍歸品藻，得失付虛空。", "考行先推本，登賢旋奏公。", "期君緩歸轡，一醉鹿鳴中。"]'),
('9ade5bbf-af3f-43e0-8d74-ee4c058bca9b','試院唱酬十一首 戲呈試官','蘇轍','宋','宋诗','song-poetry','','[]','只隔牆東便是家，悁悁還似在天涯。',64,'全唐诗/poet.song.48000.json','["只隔牆東便是家，悁悁還似在天涯。", "客心不耐聽松雨，歸信猶堪飲菊花。", "翦燭看書良寂寞，披沙見玉忽喧嘩。", "自慚空館難留客，試問姮娥稍駐車。"]'),
('25538888-7a10-47f5-9b76-c575890ade24','試院唱酬十一首 次前韵三首 其一','蘇轍','宋','宋诗','song-poetry','','[]','老去在家同出家，楞伽四卷即生涯。',64,'全唐诗/poet.song.48000.json','["老去在家同出家，楞伽四卷即生涯。", "粗詩怪我心猶壯，細字憐君眼未花。", "霜落初驚衾簟冷，酒酣猶喜笑言嘩。", "歸心知有三秋恨，莫學匆匆下坂車。"]'),
('f9d4ba0e-5cb8-4e7e-9d6e-e24511b24e96','試院唱酬十一首 次前韵三首 其二','蘇轍','宋','宋诗','song-poetry','','[]','門前溪水似漁家，流浪江湖歸未涯。',64,'全唐诗/poet.song.48000.json','["門前溪水似漁家，流浪江湖歸未涯。", "邂逅高人來說法，支離枯木旋開花。", "諸生試罷書如積，劇縣歸時訟正嘩。", "安得騎鯨從李白，試看牛女轉雲車。"]'),
('dcb980b5-cfe0-40a6-94b6-a069406ce444','試院唱酬十一首 次前韵三首 其三','蘇轍','宋','宋诗','song-poetry','','[]','濁醪能使客忘家，屈指歸期已有涯。',64,'全唐诗/poet.song.48000.json','["濁醪能使客忘家，屈指歸期已有涯。", "魚化昨宵驚細雨，鹿鳴他日飲寒花。", "已諳江上肴蔬薄，莫笑衙前鼓笛嘩。", "太守况兼鄉曲舊，會須投轄止行車。"]'),
('644d7688-daa5-4c23-8aa5-0a2e777cd446','試院唱酬十一首 試罷後偶作','蘇轍','宋','宋诗','song-poetry','','[]','重門閉不開，烏鳥相呼樂。',96,'全唐诗/poet.song.48000.json','["重門閉不開，烏鳥相呼樂。", "晨暉轉簾影，微風響松末。", "喧嘩適已定，寂歷方有覺。", "人生竟何事，外物巧相縛。", "當時不自悟，已過空成怍。", "耕耘亦何苦，遊宦殊自惡。", "棄彼既已誤，就此良應錯。", "誰能即兩忘，隨緣更無作。"]'),
('68b6e824-6707-4d94-8699-d64437fc75a1','放榜後次韵毛守見招','蘇轍','宋','宋诗','song-poetry','','[]','飽食安眠愧不材，疏簾翠帟幸相陪。',64,'全唐诗/poet.song.48000.json','["飽食安眠愧不材，疏簾翠帟幸相陪。", "深居正厭銀袍亂，失喜初聞鐵鎖開。", "佳句徑蒙探古錦，小槽仍報滴新醅。", "諸人欲見風流伯，不用招呼亦自來。"]'),
('b0e6de9a-96ba-4966-b732-61efd1c59d08','送毛滂齋郎','蘇轍','宋','宋诗','song-poetry','','[]','先志承顔善養親，束裝騎馬試爲臣。',64,'全唐诗/poet.song.48000.json','["先志承顔善養親，束裝騎馬試爲臣。", "酒腸天予渾無敵，詩律家傳便出人。", "擁鼻高吟方自得，折腰奔走漸勞神。", "歸來一笑須勤取，花發陳吳二月春。"]'),
('3fb38b5a-25fd-4214-92fc-49d66550aee1','燕貢士','蘇轍','宋','宋诗','song-poetry','','[]','泮水生芹藻，干旄在浚城。',96,'全唐诗/poet.song.48000.json','["泮水生芹藻，干旄在浚城。", "桑鴞同變響，苹鹿共和鳴。", "秋晚槐先墮，霜多桂向榮。", "清尊助勸駕，急管發歡聲。", "勇銳青衿士，淹通白髮生。", "芬芳雜蘭菊，變化等鵾鯨。", "去日衣冠盛，歸時里巷驚。", "坐中詞賦客，愧爾一經明。"]'),
('18d51eec-6432-49b9-8cac-c474dd474afe','次韵毛君清居探菊','蘇轍','宋','宋诗','song-poetry','','[]','眼前黄葉畏秋霜，耳畔啼蛩怨夜長。',64,'全唐诗/poet.song.48000.json','["眼前黄葉畏秋霜，耳畔啼蛩怨夜長。", "佳節欣聞近萸菊，清商試爲奏伊凉。", "疏狂久笑謀生拙，貧病應憐爲口忙。", "今日共君拚一醉，從教人道亦高陽。"]'),
('d7315d04-0898-4fc4-a070-3c5fe8b7aa39','次韵毛君見贈','蘇轍','宋','宋诗','song-poetry','','[]','江國騷人不耐秋，夜吟清句曉相投。',64,'全唐诗/poet.song.48000.json','["江國騷人不耐秋，夜吟清句曉相投。", "鋒藏豈願囊中脫，尾斷終非俎上羞。", "擇地何年真得意，餔糟是處可同遊。", "南遷尚有公知我，人事何須更預謀。"]'),
('9cb8b3e8-b6a6-4cb7-808f-68aeb3b1bd21','次韵毛君偶成','蘇轍','宋','宋诗','song-poetry','','[]','年來衰病正相兼，薄宦奔馳尚未厭。',64,'全唐诗/poet.song.48000.json','["年來衰病正相兼，薄宦奔馳尚未厭。", "詩句空多渾漫興，俗緣已重不須添。", "聱牙向物知難合，疏懶憐公獨未嫌。", "時聽淵明咏歸去，猶應爲我故遲淹。"]'),
('bdde4d09-7f64-418c-83bb-1f79e8da218a','孔平仲著作江州官舍小庵','蘇轍','宋','宋诗','song-poetry','','[]','近山不作看山計，引水新成照水庵。',64,'全唐诗/poet.song.48000.json','["近山不作看山計，引水新成照水庵。", "閉口忘言中自飽，安心度日更誰參。", "簡編圍繞穿書蠹，窗戶低回作繭蠶。", "我亦一軒容膝住，敝裘粗飯有餘甘。"]'),
('db140975-aafb-4543-a1ca-60f387c12b86','送饒州周沃秀才免解','蘇轍','宋','宋诗','song-poetry','','[]','少年工作賦，中歲復窮經。',48,'全唐诗/poet.song.48000.json','["少年工作賦，中歲復窮經。", "驥老終知道，劍埋新發硎。", "束裝鄰里助，答策友朋聽。", "還似臨淄貢，隨風起北溟。"]'),
('108caaf6-9cec-4d7b-a7b9-4181f97f1423','雪中洞山黄蘗二禪師相訪','蘇轍','宋','宋诗','song-poetry','','[]','江南氣暖冬未回，北風吹雪真快哉。',70,'全唐诗/poet.song.48000.json','["江南氣暖冬未回，北風吹雪真快哉。", "雪中訪我二大士，試問此雪從何來。", "君不見六月赤日起冰雹，又不見臘月幽谷寒花開。", "紛然變化一彈指，不妨明鏡無纖埃。"]'),
('22d683ad-e576-4117-bc0b-f0601dd18ffc','毛國鎮生日二絕  其一','蘇轍','宋','宋诗','song-poetry','','[]','生日元同小趙公，里閭相接往還通。',32,'全唐诗/poet.song.48000.json','["生日元同小趙公，里閭相接往還通。", "怪公日夜歸心切，欲寄此生丹竈中。"]'),
('a4afa6f0-c538-463f-8086-e639c2f78f28','毛國鎮生日二絕  其二','蘇轍','宋','宋诗','song-poetry','','[]','聞公歸橐尚空虛，近送楞嚴十卷書。',32,'全唐诗/poet.song.48000.json','["聞公歸橐尚空虛，近送楞嚴十卷書。", "心地本無生滅處，定逢生日亦如如。"]'),
('d0fd5bb7-f339-416d-9baf-f5d43cbd2a73','次韵毛君將歸','蘇轍','宋','宋诗','song-poetry','','[]','疏傅思歸不待時，孟軻出晝苦行遲。',64,'全唐诗/poet.song.48000.json','["疏傅思歸不待時，孟軻出晝苦行遲。", "新詩尚許留章句，故事誰從問典彝。", "金馬尚應堪避世，石泉未信可忘饑。", "不才似我真當去，零落衡茅隔雍岐。"]'),
('a1bb9e13-0dcc-42d6-a3fa-c02d2642f8f0','送楊騰山人','蘇轍','宋','宋诗','song-poetry','','[]','胸中萬卷書，不如一囊錢。',144,'全唐诗/poet.song.48000.json','["胸中萬卷書，不如一囊錢。", "不見楊夫子，歲晚走道邊。", "夜歸空床卧，兩手摩涌泉。", "窗前雪花落，真火中自然。", "渙然發微潤，飛上崑崙顛。", "霏霏雨甘露，稍稍流丹田。", "閉目內自視，色如黄金妍。", "至陽不獨凝，當與純陰堅。", "一窮百不遂，此事終無緣。", "君看抱朴子，共推古神仙。", "無錢買丹砂，遺恨盈塵編。", "歸去守茅屋，道成要有年。"]'),
('5d95f62e-6d6f-4776-8dff-7e595502b771','次韵子瞻與安節夜坐三首  其一','蘇轍','宋','宋诗','song-poetry','','[]','前山積雪暮崢嶸，燕坐微聞落瓦聲。',64,'全唐诗/poet.song.48000.json','["前山積雪暮崢嶸，燕坐微聞落瓦聲。", "共對一尊通夜語，相看萬里故鄉情。", "信歸嶺上寒梅遠，恨極江南春草生。", "明日青銅添白髮，且須醉睡倒燈檠。"]'),
('78f52119-0294-4936-b4a7-45f6c42e717c','次韵子瞻與安節夜坐三首  其二','蘇轍','宋','宋诗','song-poetry','','[]','少年高論苦崢嶸，老學寒蟬不復聲。',64,'全唐诗/poet.song.48000.json','["少年高論苦崢嶸，老學寒蟬不復聲。", "目斷家山空記路，手披禪冊漸忘情。", "功名久已知前錯，婚嫁猶須畢此生。", "家世讀書難便廢，漫留案上鐵燈檠。"]'),
('4d0dcdad-2ddd-4d29-ba28-4eb8f83ad974','次韵子瞻與安節夜坐三首  其三','蘇轍','宋','宋诗','song-poetry','','[]','謫官似我無歸計，落第憐渠有屈聲。',64,'全唐诗/poet.song.48000.json','["謫官似我無歸計，落第憐渠有屈聲。", "握手天涯同一笑，倚門歲晚不勝情。", "黄岡俯仰成陳迹，白首蹉跎畏後生。", "歸去且安南巷樂，莫看歌舞醉長檠。"]'),
('bf5fa367-ef03-46c9-a333-f5ab7b80449c','次韵毛君上書求歸未報','蘇轍','宋','宋诗','song-poetry','','[]','白髮憂民带減圍，頻聞慷慨賦將歸。',64,'全唐诗/poet.song.48000.json','["白髮憂民带減圍，頻聞慷慨賦將歸。", "近傳道士連三咽，久悟禪門第一機。", "夜永庵中詩自得，日高門外客來稀。", "此心素定誰能勸，祗有丁寧詔莫違。"]'),
('b81b69d1-6e15-4f9c-8791-9e3f247a5a7b','次韵毛君絕句','蘇轍','宋','宋诗','song-poetry','','[]','中池有士閉重關，夜發天光走玉環。',32,'全唐诗/poet.song.48000.json','["中池有士閉重關，夜發天光走玉環。", "白日對人人不識，幅巾破褐任塵漫。"]'),
('c17fcc20-cff5-4d48-baa1-d762f3e64453','次韵毛君留別','蘇轍','宋','宋诗','song-poetry','','[]','問天乞得不訾身，屈指人間今幾人。',64,'全唐诗/poet.song.48000.json','["問天乞得不訾身，屈指人間今幾人。", "魚縱江潭真窟宅，鶴飛松嶺倍精神。", "清風吹雨停歸騎，舊圃留花送晚春。", "自號白雲知有意，便從丹竈拂埃塵。"]'),
('afe1471e-06cb-446a-99b2-f5ebb8fdc9eb','送毛君致仕還鄉','蘇轍','宋','宋诗','song-poetry','','[]','古人避世事，豈問家有無。',192,'全唐诗/poet.song.48000.json','["古人避世事，豈問家有無。", "但言鴻鵠性，不受樊籠拘。", "公家昔盛時，阡陌連三衢。", "倉廩濟寒餓，婚嫁營羈孤。", "千金赴高義，脫手曾須臾。", "晚爲二千石，得不償所逋。", "撫掌不復言，但以文字娛。", "我恨見公遲，冉冉垂霜鬚。", "高吟看落筆，劇飲驚倒壺。", "負罪不自知，適意忘憂虞。", "忽聞叩天閽，言旋故山廬。", "朋友不及謀，親戚亦驚呼。", "人生各有意，何暇問俗徒。", "嗟我好奇節，嘆公真丈夫。", "天高片帆遠，目斷清風徂。", "惟應東宮保，迎笑相携扶。"]'),
('4e4f713f-f27c-44dd-a2e0-6744b95acd7e','贈景福順長老二首  其一','蘇轍','宋','宋诗','song-poetry','','[]','屈指江西老，多言劍外人。',48,'全唐诗/poet.song.48000.json','["屈指江西老，多言劍外人。", "身心已無著，鄉黨漫相親。", "竄逐知何取，周旋意甚真。", "仍將大雷雨，一洗百生塵。"]'),
('cbc135fe-a755-40c7-880c-981909176ae7','贈景福順長老二首  其二','蘇轍','宋','宋诗','song-poetry','','[]','念昔先君子，南遊四十年。',48,'全唐诗/poet.song.48000.json','["念昔先君子，南遊四十年。", "相看順老在，想見訥師賢。", "歲曆風輪轉，禪心海月圓。", "常情計延促，無語對潸然。"]'),
('dee47195-2414-41a0-9d31-79761230aa19','次韵孔平仲著作見寄四首  其一','蘇轍','宋','宋诗','song-poetry','','[]','昔在京城南，成均對茅屋。',216,'全唐诗/poet.song.48000.json','["昔在京城南，成均對茅屋。", "清晨屣履過，不顧車擊轂。", "時有江南生，能使多士服。", "同儕畏鋒銳，兄弟更馳逐。", "文成劇翻水，賦罷有餘燭。", "連收頷底髭，未耗髀中肉。", "飛騰困中路，黽勉啄場粟。", "歸來九江上，家有十畝竹。", "一官粗包裹，萬卷中自足。", "還如白司馬，日聽杜鵑哭。", "我來萬里外，命與江波觸。", "罪重慚故人，囊空仰微祿。", "已爲達士笑，尚謂愚者福。", "米鹽日草草，奔走常碌碌。", "尺書慰貧病，佳句爛珪玉。", "多難畏人知，胡爲强題目。", "徂年慕桑梓，歸念寄鴻鵠。", "但願洗餘愆，躬耕江一曲。"]'),
('1fe4aa34-feed-4b57-9363-874b77ce1f51','次韵孔平仲著作見寄四首  其二','蘇轍','宋','宋诗','song-poetry','','["\u5e90\u5c71"]','共居天地間，大類一間屋。',216,'全唐诗/poet.song.48000.json','["共居天地間，大類一間屋。", "推排出高下，何異車轉轂。", "死生本晝夜，禍福固倚伏。", "誰令塵垢昏，浪與紛華逐。", "譬如薪中火，外照不自燭。", "感君探至道，勸我減粱肉。", "虛心有遺味，實腹不須粟。", "芬敷謝桃杏，清勁比松竹。", "息微知氣定，睡少驗神足。", "胡爲嗜一飽，坐使百神哭。", "要知丹砂異，不受腥腐觸。", "可憐山林姿，自縛斗升祿。", "君看出世士，肯屑世間福。", "寧從市井遊，與衆同碌碌。", "不願束冠裳，腰金佩鳴玉。", "斯人今何在，未易識凡目。", "恐在廬山中，飛翔逐黄鵠。", "試用物色尋，應歌紫芝曲。"]'),
('3745d6a3-dfbc-4ccb-a70f-3d3db3aaedd2','次韵孔平仲著作見寄四首  其三','蘇轍','宋','宋诗','song-poetry','','["\u5e90\u5c71"]','百病侵形骸，漸老同破屋。',216,'全唐诗/poet.song.48000.json','["百病侵形骸，漸老同破屋。", "中有一寸空，能用輻與轂。", "忽如丹砂走，不受凡火伏。", "前瞻已不遠，後躡愈難逐。", "將炊甑中飯，未悟窗下燭。", "聰明役聲形，口腹嗜魚肉。", "塵泥翳泉井，荆棘敗禾粟。", "未知按妙指，漫欲理絲竹。", "廬山多名緇，過客禮白足。", "達觀等存亡，世俗强歌哭。", "確然金石心，不畏蚊蚋觸。", "順忍爲裳衣，供施謝榮祿。", "真人我自有，渡海笑徐福。", "衆皆指庸庸，自顧非碌碌。", "愧君詩意厚，桃李報瓊玉。", "舉網羅衆禽，有獲非一目。", "喧啾定無用，要自取黄鵠。", "君看大方家，慎勿留一曲。"]'),
('240cd81e-9e73-4c62-b9f4-7589b60acf6d','次韵孔平仲著作見寄四首  其四','蘇轍','宋','宋诗','song-poetry','','[]','治生非所長，兒女驚滿屋。',216,'全唐诗/poet.song.48000.json','["治生非所長，兒女驚滿屋。", "作官又迂疏，不望載朱轂。", "因緣罣罪罟，未許即潛伏。", "空餘讀書病，日與古人逐。", "老妻憐眼昏，入夜屏燈燭。", "上官念貧寠，時節饋醪肉。", "衰年類蒲柳，世事劇麻粟。", "數日望歸田，寄語先栽竹。", "文章亦細事，勤苦定何足。", "君詩四相攻，欲看守陴哭。", "愧無即墨巧，不解火牛觸。", "自非太學生，彫琢事干祿。", "安心已近道，閉口豈非福。", "胡爲調狂詞，玉石相落碌。", "腹中抱丹砂，舌下潄白玉。", "作詩雖云好，未免亂心目。", "奕秋教二人，不取志鴻鵠。", "摩詰非不言，遺韵寄終曲。"]'),
('b622a535-eb6e-4778-85ff-45c85dbc79bb','陰晴不定簡唐覲祕校并敖吳二君五首  其一','蘇轍','宋','宋诗','song-poetry','','[]','積雨春連夏，新晴忽復陰。',48,'全唐诗/poet.song.48000.json','["積雨春連夏，新晴忽復陰。", "江痕漲猶在，梅氣潤相侵。", "蕉紵還須脫，圖書漸不禁。", "江南舊風俗，愁絕北來心。"]'),
('bb2f223c-ec75-4c4f-a2a4-4bd8bbe439fc','陰晴不定簡唐覲祕校并敖吳二君五首  其二','蘇轍','宋','宋诗','song-poetry','','[]','蠶眠初上簇，麥熟正磨鎌。',48,'全唐诗/poet.song.48000.json','["蠶眠初上簇，麥熟正磨鎌。", "雲氣重重合，江流夜夜添。", "薦饑人甚困，多病我仍兼。", "欲就橋南宿，單衣莫雨霑。"]'),
('e7c0b731-e801-4c2d-be76-983cca1fc509','陰晴不定簡唐覲祕校并敖吳二君五首  其三','蘇轍','宋','宋诗','song-poetry','','[]','漲江方斷渡，小棹信輕生。',48,'全唐诗/poet.song.48000.json','["漲江方斷渡，小棹信輕生。", "貧賤誰憐汝，漂浮空自驚。", "一官終竊食，何計早歸耕。", "忽發騷人恨，凄凉久未平。"]'),
('b798e772-eab8-42f2-b220-ffa8f32db802','陰晴不定簡唐覲祕校并敖吳二君五首  其四','蘇轍','宋','宋诗','song-poetry','','[]','西鄰豫章客，病骨瘦欒欒。',48,'全唐诗/poet.song.48000.json','["西鄰豫章客，病骨瘦欒欒。", "清夜眠孤枕，終朝飽一簞。", "雨多愁不出，講罷未應餐。", "約我晴相過，門前泥欲乾。"]'),
('718e4f2a-be7f-40d4-bb7f-7cde699d4010','陰晴不定簡唐覲祕校并敖吳二君五首  其五','蘇轍','宋','宋诗','song-poetry','','[]','二子薪中楚，相携泮上遊。',48,'全唐诗/poet.song.48000.json','["二子薪中楚，相携泮上遊。", "虀鹽聊度日，爻象久忘憂。", "寂寞君何病，驅馳我自羞。", "何時采芹處，永日看鳬鷗。"]'),
('8c52bf61-4165-4d6f-b466-93835bbdf462','雨後遊大愚','蘇轍','宋','宋诗','song-poetry','','[]','風光四月尚春餘，淫雨初乾積潦除。',64,'全唐诗/poet.song.48000.json','["風光四月尚春餘，淫雨初乾積潦除。", "古寺蕭條仍負郭，閑官疏散亦肩輿。", "摘茶戶外烝黄葉，掘笋林中間綠蔬。", "一飽人生真易足，試營茅屋傍僧居。"]'),
('8eb4c7a8-0132-4d7d-a082-a7c831ce9469','送高安羅令審禮','蘇轍','宋','宋诗','song-poetry','','[]','一邑憂勞水旱中，牛刀閑暇似無功。',64,'全唐诗/poet.song.48000.json','["一邑憂勞水旱中，牛刀閑暇似無功。", "政成仍喜新蠶熟，歸去還將舊橐空。", "清白久聞誇父老，沉埋誰爲訴諸公。", "謫居長恨交遊少，悵望肩輿又欲東。"]'),
('cfa0a3b8-b40f-439f-8e29-fbdc0b99692d','送唐覲','蘇轍','宋','宋诗','song-poetry','','[]','溪上幽居少四鄰，西家幸有著書人。',64,'全唐诗/poet.song.48000.json','["溪上幽居少四鄰，西家幸有著書人。", "經年食菜誰憐瘦，終日題詩自不貧。", "身在江湖釣竿地，心馳蘭會戰車塵。", "此行便有飛騰處，笑殺年來老病身。"]'),
('e3f6e000-0ac1-4cfa-b5d1-8a03557cae18','次韵唐覲送姜應明謁新昌杜簿','蘇轍','宋','宋诗','song-poetry','','[]','夫子雖窮氣浩然，輕簑短笠傲江天。',64,'全唐诗/poet.song.48000.json','["夫子雖窮氣浩然，輕簑短笠傲江天。", "薄遊到處唯耽酒，歸去無心苦問田。", "泮上講官殊不俗，山中老簿亦疑仙。", "相從未足還辭去，欲向曹溪更問禪。"]'),
('fb7bba12-d6e1-4f89-a73e-496e8a61872a','新種芭蕉','蘇轍','宋','宋诗','song-poetry','','[]','芭蕉移種未多時，濯濯芳莖已數圍。',64,'全唐诗/poet.song.48000.json','["芭蕉移種未多時，濯濯芳莖已數圍。", "畢竟空心何所有，欹傾大葉不勝肥。", "蕭騷莫雨鳴山樂，狼籍秋霜脫敝衣。", "堂上幽人觀幻久，逢人指示此身非。"]'),
('f7e7eb77-e55f-487b-b971-16e71b566e7c','次韵姜應明黄蘗山中見寄','蘇轍','宋','宋诗','song-poetry','','[]','垂老閑居味更深，此身隨世任浮沉。',64,'全唐诗/poet.song.48000.json','["垂老閑居味更深，此身隨世任浮沉。", "北窗未厭曲肱卧，西洛能傳擁鼻吟。", "疋馬徬徨猶寄食，敝裘安樂信無心。", "我今漂泊還相似，同愧高僧支道林。"]'),
('a42a9e87-b40e-4247-93e2-a05c710c562e','次韵黄大臨秀才見寄','蘇轍','宋','宋诗','song-poetry','','[]','故人聚散霜前葉，往事眇茫風際烟。',64,'全唐诗/poet.song.48000.json','["故人聚散霜前葉，往事眇茫風際烟。", "遊宦一生非有己，隠居萬事不由天。", "崎嶇檻穽方謀食，嘯傲山林肯計年。", "頼已將心問盧老，相逢他日笑風顛。"]'),
('502bdaeb-57f8-4a0f-b815-158b40588053','次韵李朝散遊洞山二首  其一','蘇轍','宋','宋诗','song-poetry','','[]','古寺依山占幾峰，精廬仿佛類天宮。',64,'全唐诗/poet.song.48000.json','["古寺依山占幾峰，精廬仿佛類天宮。", "三年欲到官爲礙，百里相望意自通。", "無事佛僧何處著，人羣鳥獸不妨同。", "眼前簿領何時脫，一笑相看丈室中。"]'),
('36da72ee-209c-4f87-b4b8-8152d6a4995f','次韵李朝散遊洞山二首  其二','蘇轍','宋','宋诗','song-poetry','','[]','僧老經時不出山，法堂延客未曾關。',64,'全唐诗/poet.song.48000.json','["僧老經時不出山，法堂延客未曾關。", "心開寶月嬋娟處，身寄浮雲出沒間。", "休夏巾瓶誰與共，迎秋水石不勝閑。", "近來寄我金剛頌，欲指胸中無所還。"]'),
('135ec04d-d2cc-4354-b62a-54f16feb7b75','簡學中諸生','蘇轍','宋','宋诗','song-poetry','','[]','泮水秋生藻荇凉，莫窗燈火亂螢光。',64,'全唐诗/poet.song.48000.json','["泮水秋生藻荇凉，莫窗燈火亂螢光。", "圖書粗足惟須讀，菽粟才供且自强。", "羽籥暗催新節物，弦歌不廢近詩章。", "腐儒最喜南遷後，仍見西雝白鷺行。"]'),
('cb22a32a-dfe7-4466-9047-c1058816d97d','以蜜酒送柳真公','蘇轍','宋','宋诗','song-poetry','','[]','床頭釀酒一年餘，氣味全非卓氏壚。',32,'全唐诗/poet.song.48000.json','["床頭釀酒一年餘，氣味全非卓氏壚。", "送與幽人試嘗看，不應知是百花鬚。"]'),
('75c8c839-6e3f-4ec4-b4da-8d37f4c16d83','次韵柳見答','蘇轍','宋','宋诗','song-poetry','','[]','桂酒無人寄豫章，羈愁牢落遣誰當。',64,'全唐诗/poet.song.48000.json','["桂酒無人寄豫章，羈愁牢落遣誰當。", "烹煎崖蜜真牽强，慚愧山蜂久蓄藏。", "江上鱠鱸橙正熟，山頭吹帽菊初香。", "漂流異日俱陳迹，笑說過從想未忘。"]'),
('ba366303-0b53-4974-8371-c51dbcd7333d','披仙亭晚飲','蘇轍','宋','宋诗','song-poetry','','[]','落日欲沒多雲烟，南山暝鴉歸北山。',64,'全唐诗/poet.song.48000.json','["落日欲沒多雲烟，南山暝鴉歸北山。", "樓臺城上半明滅，燈火橋頭初往還。", "江西八月熱猶在，坐中遷客頭欲班。", "何時解網聽歸去，黄花白酒疏籬間。"]'),
('64030ac5-bc6a-4e30-aed3-84a60af8f4a6','余居高安三年每晨入莫出輒過聖壽訪聰長老謁方子明浴頭笑語移刻而歸歲月既久作一詩記之','蘇轍','宋','宋诗','song-poetry','','[]','朝來賣酒江南市，日莫歸爲江北人。',64,'全唐诗/poet.song.48000.json','["朝來賣酒江南市，日莫歸爲江北人。", "禪老未嫌參請數，漁舟空怪往來頻。", "每慚菜飯分齋鉢，時乞香泉洗病身。", "世味漸消婚嫁了，幅巾絳褐許相親。"]'),
('1f20e5be-feb3-444e-ba0a-13753276d31e','次韵子瞻感舊見寄','蘇轍','宋','宋诗','song-poetry','','[]','少年耽世味，徘徊不能去。',144,'全唐诗/poet.song.48000.json','["少年耽世味，徘徊不能去。", "老來悟前非，尚愧昔遊處。", "君才最高峙，鶴行鷄羣中。", "我雖非君對，顧以兄弟同。", "結髮皆讀書，明月入我牖。", "縱橫萬餘卷，臨紙但揮手。", "學成竟無用，掩卷空自疑。", "却尋故山友，重赴幽居期。", "秋風送餘熱，冉冉如人老。", "衣裘當及時，田廬亦須早。", "種竹竹生笋，種稻稻亦成。", "浩歌歸來曲，曲終有遺聲。"]'),
('88cf1135-1333-4f25-87b9-3dcb1e7217ea','次韵和人豐歲','蘇轍','宋','宋诗','song-poetry','','[]','風雨迎寒欲勞農，今年真不負元豐。',64,'全唐诗/poet.song.48000.json','["風雨迎寒欲勞農，今年真不負元豐。", "蓋藏共荷官無擾，眠食安知帝有功。", "草笠黄冠將蜡祀，羔羊朋酒亦豳風。", "請君早具躋堂飲，退食委蛇正自公。"]'),
('820bb5e2-9be3-4d43-a61b-57e394d00c09','同孔常父作張夫人詩','蘇轍','宋','宋诗','song-poetry','','[]','女子勿言弱，男兒何必强。',288,'全唐诗/poet.song.48000.json','["女子勿言弱，男兒何必强。", "君看張夫人，身舉十五喪。", "頭上脫笄珥，篋中斥襦裳。", "築墳連丘山，松柏鬰蒼蒼。", "親戚不爲助，涕泣感道傍。", "昔有王氏老，身爲尚書郎。", "親死棄不葬，簪裾日翱翔。", "白骨委廬陵，宦遊在岐陽。", "一旦有丈夫，軒軒類佯狂。", "相面識心腹，開口言災祥。", "嗟汝平生事，不了令誰當。", "汝身暖絲綿，汝口甘稻粱。", "衣食未嘗廢，此事乃可忘。", "一言中肝心，投身拜其床。", "傍人漫不知，相視空茫茫。", "終言汝不悛，物理久必償。", "兒女病手足，相隨就淪亡。", "鄙夫本愚悍，過耳風吹牆。", "明年及前期，長子憂骭瘍。", "一麾守巴峽，雙柩還故鄉。", "弱息雖僅存，蹣跚亦非良。", "誰言天地寬，網目固自張。", "古事遠不信，近事世所詳。", "企張非求福，禍敗當懲王。"]'),
('506acf08-9be5-490e-ac0f-26f1b5d56126','次烟字韵答黄庭堅','蘇轍','宋','宋诗','song-poetry','','[]','病卧江干鬚带雪，老捻書卷眼生烟。',64,'全唐诗/poet.song.48000.json','["病卧江干鬚带雪，老捻書卷眼生烟。", "貧如陶令仍耽酒，窮似湘纍不問天。", "令弟近應憐廢學，大兄昔許叩延年。", "比聞蔬茹隨僧供，相見能容醉後顛。"]'),
('93fef965-2328-43fe-b43d-7cdde8e98924','東軒長老二絕  其一','蘇轍','宋','宋诗','song-poetry','','[]','東軒正似虛空樣，何處人家籠解盛。',32,'全唐诗/poet.song.48000.json','["東軒正似虛空樣，何處人家籠解盛。", "縱使盛來無處著，雪堂自有老師兄。"]'),
('eaae7075-be91-4074-88a7-eebeeaeb1cd9','東軒長老二絕  其二','蘇轍','宋','宋诗','song-poetry','','[]','擔頭挑得黄州籠，行過圓通一笑開。',32,'全唐诗/poet.song.48000.json','["擔頭挑得黄州籠，行過圓通一笑開。", "却到山前人已寂，亦無一物可擔迴。"]'),
('67d08937-8802-4bc3-ae6c-52b2465270f7','題方子明道人東窗','蘇轍','宋','宋诗','song-poetry','','[]','紙窗雲葉浄，香篆細烟青。',48,'全唐诗/poet.song.48000.json','["紙窗雲葉浄，香篆細烟青。", "客到催茶磨，泉聲響石瓶。", "禪關敲每應，丹訣問無經。", "贈我刀圭藥，年來髮變星。"]'),
('ac69ca5c-b792-4931-ba19-20a0a50d20d3','次前韵','蘇轍','宋','宋诗','song-poetry','','[]','閉門何所事，毛髮日青青。',48,'全唐诗/poet.song.48000.json','["閉門何所事，毛髮日青青。", "齒折登山屐，塵生貰酒瓶。", "調心開貝葉，救病讀難經。", "定起無人見，寒燈一點星。"]'),
('10c1c5bc-f794-4155-8291-3804f86b2b56','迎寄王適','蘇轍','宋','宋诗','song-poetry','','[]','投竄千山恨不深，扁舟夏涉氣如烝。',64,'全唐诗/poet.song.48000.json','["投竄千山恨不深，扁舟夏涉氣如烝。", "重來疋馬君何事，歸去飛鴻我未能。", "養氣經年惟脫粟，讀書終夜有寒燈。", "安心且作衰慵伴，海底鯤魚會化鵬。"]'),
('84ded648-7359-4d11-b585-abdcdfcc657d','王度支陶挽詞二首  其一','蘇轍','宋','宋诗','song-poetry','','[]','風蹟殊不昧，聲名豈偶然。',48,'全唐诗/poet.song.48000.json','["風蹟殊不昧，聲名豈偶然。", "長途催騄驥，爽氣激鷹鸇。", "薏苡成遺恨，松楸卜遠年。", "凄凉故吏盡，誰泣鬣封前。"]'),
('79e19306-03de-4642-9029-ff0e588bf57a','王度支陶挽詞二首  其二','蘇轍','宋','宋诗','song-poetry','','[]','京塵昔傾蓋，江國見佳城。',48,'全唐诗/poet.song.48000.json','["京塵昔傾蓋，江國見佳城。", "零落舊冠劍，艱難孝弟兄。", "存亡看世俗，意氣憶平生。", "曉鐸知人恨，幽音亦未平。"]'),
('f447d78e-9c7b-4298-92af-362a0d24c487','次韵陳師仲主簿見寄','蘇轍','宋','宋诗','song-poetry','','[]','朽株難刻畫，枯葉任凋零。',48,'全唐诗/poet.song.48000.json','["朽株難刻畫，枯葉任凋零。", "舊友頻相問，村酤獨未醒。", "山牙收細茗，江實得流萍。", "頗似申屠子，都忘足被刑。"]'),
('fd58bffe-399b-4044-b2a1-2bf607bfcef7','寄題江渙長官南園茅齋','蘇轍','宋','宋诗','song-poetry','','[]','白髮辛勤困小邦，塵勞坐使壯心降。',64,'全唐诗/poet.song.48000.json','["白髮辛勤困小邦，塵勞坐使壯心降。", "河陽罷後成南圃，彭澤歸來卧北窗。", "畦畔草生親荷鍤，床頭酒熟自傾缸。", "因君遣我添歸興，舊有茅茨濯錦江。"]'),
('dd5c7b51-cbaa-4b9b-beb3-fd30127527e1','咏霜二首  其一','蘇轍','宋','宋诗','song-poetry','','[]','江南雪不到，霜露滿山村。',48,'全唐诗/poet.song.48000.json','["江南雪不到，霜露滿山村。", "紙被欺氈厚，茅檐笑瓦溫。", "何曾凝沼淥，有意隔朝暾。", "底日身無事，高眠不出門。"]'),
('06cb4de6-7980-41fd-9a9b-34adebde3147','咏霜二首  其二','蘇轍','宋','宋诗','song-poetry','','[]','清霜欺客病，乘夜逼窗扉。',48,'全唐诗/poet.song.48000.json','["清霜欺客病，乘夜逼窗扉。", "坐睡依爐暖，細聲聞葉飛。", "蕉絺空滿篋，砧杵旋催衣。", "起看庭前草，松筠未覺非。"]'),
('a293d054-9faf-432c-9bcd-ab3ed5f59640','次韵吳厚秀才見寄','蘇轍','宋','宋诗','song-poetry','','[]','壯心摧折漸無餘，早歲爲文老不如。',64,'全唐诗/poet.song.48000.json','["壯心摧折漸無餘，早歲爲文老不如。", "登木求魚知我拙，循窠覓兔笑君疏。", "清尊獨酌夜方半，白髮潛生歲欲除。", "久恐交親還往絕，床頭猶喜數行書。"]'),
('808ec09e-524d-49d7-824a-adf7ced423a3','乾荔支','蘇轍','宋','宋诗','song-poetry','','[]','含露迎風惜不嘗，故將赤日損容光。',32,'全唐诗/poet.song.48000.json','["含露迎風惜不嘗，故將赤日損容光。", "紅消白瘦香猶在，想見當年十八娘。"]'),
('88ee9cd3-735a-442b-a432-f6d29639ab4a','次韵王適元日并示曹煥二首  其一','蘇轍','宋','宋诗','song-poetry','','[]','井底屠酥浸舊方，床頭冬釀壓瓊漿。',64,'全唐诗/poet.song.48000.json','["井底屠酥浸舊方，床頭冬釀壓瓊漿。", "舊來喜與門前客，終日同爲酒後狂。", "老大心情今已盡，塵埃鬢髮亦無光。", "江南留滯歸何日，萬里逢春思故鄉。"]'),
('eed27e66-86f5-4659-be8c-43e674fecac4','次韵王適元日并示曹煥二首  其二','蘇轍','宋','宋诗','song-poetry','','[]','放逐三年未遣回，復驚爆竹起春雷。',64,'全唐诗/poet.song.48000.json','["放逐三年未遣回，復驚爆竹起春雷。", "祈年粗有樽中桂，寄遠仍持嶺上梅。", "莫笑牛狸抵羊酪，漫將崖蜜代官醅。", "二君未肯嫌貧病，猶得衰顔一笑開。"]'),
('eb930ad3-62c1-4d75-a2fa-675288cd45dc','寄梅仙觀楊智遠道士','蘇轍','宋','宋诗','song-poetry','','[]','道師近在真人峰，欲往見之路無從。',144,'全唐诗/poet.song.48000.json','["道師近在真人峰，欲往見之路無從。", "去年許我入城市，塵埃暗天待不至。", "莫往莫來勞我心，道書寄我千黄金。", "繭衣肉食思慮短，文字滿前看不見。", "口傳指授要有時，脫去羅網當見之。", "梅翁漢朝南昌尉，手摩龍鱗言世事。", "一朝拂衣去不還，身騎白驎翳紅鸞。", "我今雖復墮塵土，道師何不與我語。", "他年策足投名山，相逢拍手一破顔。"]'),
('c8d9f2d3-16fb-495e-85fc-6c6efed4c2f7','春雪','蘇轍','宋','宋诗','song-poetry','','[]','溫風吹破臘，留雪惱新春。',120,'全唐诗/poet.song.48000.json','["溫風吹破臘，留雪惱新春。", "信逐殘梅到，花從半夜勻。", "旋消微覆瓦，狂下亦欺人。", "壓竹時聞落，埋萱久未伸。", "山川濛不解，樓觀洗成新。", "擁褐僧方睡，開門客屢嚬。", "爨烟知歲稔，履迹笑吾貧。", "畦凍初生韭，泥融正賣薪。", "寒魚爭就汕，燭酒頗無巡。", "預喜田宜麥，槃餐餠餌頻。"]'),
('23d7790d-d662-4af6-b5bb-e39f6caabfbc','贈石臺問長老二絕  其一','蘇轍','宋','宋诗','song-poetry','','[]','法達曾經見老盧，半生勤苦一朝虛。',32,'全唐诗/poet.song.48000.json','["法達曾經見老盧，半生勤苦一朝虛。", "心通口誦方無礙，笑把吳鸞細字書。"]'),
('92214d19-ec3e-46c2-978b-9cced11a0900','贈石臺問長老二絕  其二','蘇轍','宋','宋诗','song-poetry','','[]','蒲團布衲一繩床，心地虛明睡自亡。',32,'全唐诗/poet.song.48000.json','["蒲團布衲一繩床，心地虛明睡自亡。", "長伴空中月天子，東方行道到西方。"]'),
('95f8c308-1e62-43a7-8449-6b4e610cabf0','和毛國鎮白雲莊五咏 掬泉軒','蘇轍','宋','宋诗','song-poetry','','[]','卜築高深已有山，起居清潤可無泉。',64,'全唐诗/poet.song.48000.json','["卜築高深已有山，起居清潤可無泉。", "穿牆白練秋聲細，照屋清銅曉色鮮。", "已放魚蝦嫌跳擲，更除蘋藻任漪漣。", "只應明月中霄下，長共禪心相向圓。"]'),
('f898cbba-4244-4dc8-a1e6-e5c0d926d2a5','和毛國鎮白雲莊五咏 平溪堂','蘇轍','宋','宋诗','song-poetry','','[]','清溪似與隠君謀，故入堂前漫不收。',64,'全唐诗/poet.song.48000.json','["清溪似與隠君謀，故入堂前漫不收。", "盥手從今休汲井，浮觴取意便臨流。", "花漂澗谷來應遠，石激琴箏久未休。", "莫把朱欄强圍繞，山家事事要清幽。"]'),
('d6783966-8ff9-4bd1-bfb4-6a3620cbab7c','和毛國鎮白雲莊五咏 眺遠臺','蘇轍','宋','宋诗','song-poetry','','[]','山似高人長遠人，不登高處見無因。',64,'全唐诗/poet.song.48000.json','["山似高人長遠人，不登高處見無因。", "築臺土石無多子，照眼峰巒得許新。", "陣馬奔騰時絕遠，風濤舒卷忽無垠。", "白雲自是逃名處，猶恐此中藏隠淪。"]'),
('de6fd278-bcbd-4a16-83e0-a37a3b4c42d1','和毛國鎮白雲莊五咏 濯纓庵','蘇轍','宋','宋诗','song-poetry','','[]','臨池濯足惜泉清，纓上無塵且强名。',64,'全唐诗/poet.song.48000.json','["臨池濯足惜泉清，纓上無塵且强名。", "橫木爲橋便獨往，結茅依島類天成。", "往還漸少人誰識，寢食無爲身轉輕。", "有似三吳朱處士，釣魚誰與話西征。"]'),
('98eb0c64-1265-4379-b099-c8e419173849','和毛國鎮白雲莊五咏 白雲莊偶題','蘇轍','宋','宋诗','song-poetry','','[]','歸去携家住白雲，雲中猿鶴許同羣。',64,'全唐诗/poet.song.48000.json','["歸去携家住白雲，雲中猿鶴許同羣。", "陶公酒後詩偏好，疏傅金餘客屢醺。", "芒屩潛行逐漁釣，壺漿時出勞耕耘。", "却看人世應微笑，未熟黄粱晝夢紛。"]'),
('e64e4634-16e9-4ef2-97a0-717f0124b019','次韵王適落日江上二首  其一','蘇轍','宋','宋诗','song-poetry','','[]','寒烟羃清江，漁唱扁舟上。',48,'全唐诗/poet.song.48000.json','["寒烟羃清江，漁唱扁舟上。", "江轉少人家，自此知安往。", "維舟倚叢薄，明月獨相向。", "欲曉醉應醒，還逐輕鷗揚。"]'),
('bb0dd047-63ad-428d-839a-3588962596a5','次韵王適落日江上二首  其二','蘇轍','宋','宋诗','song-poetry','','[]','稍息南市喧，初上東山月。',48,'全唐诗/poet.song.48000.json','["稍息南市喧，初上東山月。", "潛魚忽驚踴，饑雁時斷絕。", "落葉誤投籤，繁霜疑積雪。", "苦寒良難久，愛此元氣潔。"]'),
('2cecb398-3320-457f-8c06-0fdb9b8d347d','張秀才見寫陋容','蘇轍','宋','宋诗','song-poetry','','[]','潦倒形骸山上樗，每經風雨輒凋疏。',64,'全唐诗/poet.song.48000.json','["潦倒形骸山上樗，每經風雨輒凋疏。", "勞君爲寫支離狀，異日長看老病初。", "落筆縱橫中自喜，賦形深穩妙無餘。", "偶然挂壁低頭笑，俱幻何妨彼亦如。"]'),
('6a9e1698-c885-4277-bd01-9a4961d3a8fb','同王適曹煥遊清居院步還所居','蘇轍','宋','宋诗','song-poetry','','[]','身爲江城吏，心似野田叟。',168,'全唐诗/poet.song.48000.json','["身爲江城吏，心似野田叟。", "尋僧忽忘歸，飽食莫携手。", "畏人久成性，路繞古城後。", "茅茨遠相望，鷄犬亦時有。", "人還市井罷，日落狐兔走。", "迴風吹橫烟，燒火卷林藪。", "草深徑漸惡，荆棘時挂肘。", "褰裳涉沮洳，斜絕汙池口。", "投荒分岑寂，欹側吾自取。", "二君獨何爲，經歲坐相守。", "遊從乏車騎，飲食厭菘韭。", "周旋未忍棄，辛苦亦何負。", "歸來倚南窗，試挹樽中酒。", "笑問黄泥行，此味還同否。"]'),
('6b13edae-74ed-4300-a500-6f3cebc43ee3','次韵王適春雨','蘇轍','宋','宋诗','song-poetry','','[]','久遭客禁往還稀，風雨蕭條只自知。',64,'全唐诗/poet.song.48000.json','["久遭客禁往還稀，風雨蕭條只自知。", "春色有情猶入眼，客愁無頼巧侵眉。", "山僧寄語收茶日，野老留人供社時。", "久住不須嫌寂寞，此間偏與拙相宜。"]'),
('d1670d91-4a30-46de-ada5-4b135b353c05','和子瞻蜜酒歌','蘇轍','宋','宋诗','song-poetry','','[]','蜂王舉家千萬口，黄蠟爲糧蜜爲酒。',128,'全唐诗/poet.song.48000.json','["蜂王舉家千萬口，黄蠟爲糧蜜爲酒。", "口銜澗水拾花鬚，沮洳滿房何不有。", "山中醉飽誰得知，割脾分蜜曾無遺。", "調和知與酒同法，試投麴糵真相宜。", "城中禁酒如禁盜，三百青銅愁杜老。", "先生年來無俸錢，一斗徑須囊一倒。", "餔糟不聽漁父言，煉蜜深愧仙人傳。", "掉頭不問辟穀藥，忍饑不如長醉眠。"]'),
('89522c57-cc49-434e-8655-ff563437f3e2','次韵講律李司理憲見贈','蘇轍','宋','宋诗','song-poetry','','[]','强將羔雁聘黄晞，破褐疏巾倚夕暉。',64,'全唐诗/poet.song.48000.json','["强將羔雁聘黄晞，破褐疏巾倚夕暉。", "禮律縱橫開卷盡，虀鹽冷落待賢非。", "日高几案弦歌罷，夜永窗扉燈火微。", "猶喜江邊莫春近，舞雩風雨得同歸。"]'),
('40897e86-1e35-4e69-9ad2-01ab583781a9','次韵王適遊陳氏園','蘇轍','宋','宋诗','song-poetry','','[]','宿雨晴來春已晚，衆花飄盡野猶香。',64,'全唐诗/poet.song.48000.json','["宿雨晴來春已晚，衆花飄盡野猶香。", "舞雩便可同沂上，飲禊何妨似洛陽。", "新圃近聞穿沼闊，漲江初喜放舟長。", "年來簿領縈人甚，何計相隨入醉鄉。"]'),
('4921837b-39bb-47b0-9ece-94ef285b0b57','答孔平仲二偈  其一','蘇轍','宋','宋诗','song-poetry','','[]','熟睡將經作枕頭，君家事業太悠悠。',32,'全唐诗/poet.song.48000.json','["熟睡將經作枕頭，君家事業太悠悠。", "要須睡著元非睡，未可昏昏便爾休。"]'),
('57bbaa88-d703-4890-8c8f-efa3d75cecb4','答孔平仲二偈  其二','蘇轍','宋','宋诗','song-poetry','','[]','龜毛兔角號空虛，既被無收豈是無。',32,'全唐诗/poet.song.48000.json','["龜毛兔角號空虛，既被無收豈是無。", "自有真無遍諸有，燈光何礙也嫌渠。"]'),
('b3d4a62b-2772-4539-8acd-7d28a4842f76','次韵柳真公閑居春日','蘇轍','宋','宋诗','song-poetry','','[]','春寒漸欲減衣綿，雨勢冥冥水拍天。',64,'全唐诗/poet.song.48000.json','["春寒漸欲減衣綿，雨勢冥冥水拍天。", "一局無言消日永，新詩得意許人傳。", "惜花田地應慵掃，護筍藩籬可細編。", "好事報君知我喜，同官欲到得閑眠。"]'),
('cabef3f4-6880-48c1-85ad-277330fac82f','次韵王適東軒即事三首  其一','蘇轍','宋','宋诗','song-poetry','','[]','新竹依牆未出尋，牆東桃李却成林。',64,'全唐诗/poet.song.48000.json','["新竹依牆未出尋，牆東桃李却成林。", "池塘草長初饒夢，村落鶑啼恰稱心。", "江滿船頭朝欲轉，泥融屐齒莫尤深。", "閉門憐子成書癖，試買村醪相伴斟。"]'),
('22d677f2-c7a0-45d5-9f1c-f4617539f726','次韵王適東軒即事三首  其二','蘇轍','宋','宋诗','song-poetry','','[]','眼看東鄰五畝花，茅檐竹戶野人家。',64,'全唐诗/poet.song.48000.json','["眼看東鄰五畝花，茅檐竹戶野人家。", "過牆每欲隨飛蝶，歸舍誰憐已莫鴉。", "幽客偶來成晚飯，野僧何日寄新茶。", "三年氣味長如此，歸計遲遲也自嘉。"]'),
('33bcbee2-4987-440a-8c53-88e8adab802e','次韵王適東軒即事三首  其三','蘇轍','宋','宋诗','song-poetry','','[]','北園春草徑微微，未用頻教剪棘茨。',64,'全唐诗/poet.song.48000.json','["北園春草徑微微，未用頻教剪棘茨。", "蜂陣紛紛初養蜜，鶑巢淺淺欲生兒。", "客情流水兼山遠，歸夢遊絲向日遲。", "懶病相將渾欲慣，頼君索我强裁詩。"]'),
('18fdc203-101c-4a60-82ef-ab8050ede0a0','送李憲司理還新喻','蘇轍','宋','宋诗','song-poetry','','[]','采芹芹已老，浴沂沂尚寒。',48,'全唐诗/poet.song.48000.json','["采芹芹已老，浴沂沂尚寒。", "蒯緱長嘆息，苜蓿正闌干。", "黄卷忘憂易，青衫行路難。", "歸耕未有計，且復調閑官。"]'),
('02f861ec-3919-43e0-a5eb-1b99787cbdf8','問黄蘗長老疾','蘇轍','宋','宋诗','song-poetry','','[]','四大俱非五藴空，身心河岳盡消鎔。',32,'全唐诗/poet.song.48000.json','["四大俱非五藴空，身心河岳盡消鎔。", "病根何處容他住，日夜還將藥石攻。"]'),
('837d3f2b-82c6-433a-9a37-07146c9b8b93','復次烟字韵答黄大臨庭堅見寄二首  其一','蘇轍','宋','宋诗','song-poetry','','[]','水竹遮藏自一川，日高茅屋始炊烟。',64,'全唐诗/poet.song.48000.json','["水竹遮藏自一川，日高茅屋始炊烟。", "犬牙舂米新秋後，麥粒烝茶欲社天。", "冠蓋只今成棄物，杉松他日記栽年。", "定應笑我勞生在，卯睡聞呼衣爲顛。"]'),
('e43c97af-094e-45ef-b6e8-669d3b8fdf08','復次烟字韵答黄大臨庭堅見寄二首  其二','蘇轍','宋','宋诗','song-poetry','','[]','十載勞思寤寐間，新詩態度比雲烟。',64,'全唐诗/poet.song.48000.json','["十載勞思寤寐間，新詩態度比雲烟。", "清風吹我無千里，明月隨人共一天。", "歸去林泉應避暑，北征道路恐經年。", "與君共愧知時鶴，養子先依黑柏顛。"]'),
('f0e62425-d019-469d-812c-8063612d5fc2','次韵子瞻臨皋新葺南堂五絕  其一','蘇轍','宋','宋诗','song-poetry','','[]','江聲六月撼長堤，雪嶺千重過屋西。',32,'全唐诗/poet.song.48000.json','["江聲六月撼長堤，雪嶺千重過屋西。", "一葉軒昂方斷渡，南堂蕭散夢寒溪。"]'),
('884b9988-4f33-4c1a-b711-ae4dafdfc846','次韵子瞻臨皋新葺南堂五絕  其二','蘇轍','宋','宋诗','song-poetry','','[]','旅食三年已是家，堂成非陋亦非華。',32,'全唐诗/poet.song.48000.json','["旅食三年已是家，堂成非陋亦非華。", "何方道士知人意，授與爐中一粒砂。"]'),
('d46ad787-b006-44e9-91ea-5ef9a6a7d9d3','次韵子瞻臨皋新葺南堂五絕  其三','蘇轍','宋','宋诗','song-poetry','','[]','北牖清風正滿床，東坡野菜漫充腸。',32,'全唐诗/poet.song.48000.json','["北牖清風正滿床，東坡野菜漫充腸。", "華池自有醍醐味，丈室仍聞薝蔔香。"]'),
('8551f1d8-ad83-423f-ad9a-b742028c73e5','次韵子瞻臨皋新葺南堂五絕  其四','蘇轍','宋','宋诗','song-poetry','','[]','鄰人漸熟容賒酒，故客親留爲種蔬。',32,'全唐诗/poet.song.48000.json','["鄰人漸熟容賒酒，故客親留爲種蔬。", "住穩不論歸有日，船通何患出無車。"]'),
('21f103f3-9982-4fca-b297-007c07fc4a9d','次韵子瞻臨皋新葺南堂五絕  其五','蘇轍','宋','宋诗','song-poetry','','[]','客去知公醉欲眠，酒醒寒月墮江烟。',32,'全唐诗/poet.song.48000.json','["客去知公醉欲眠，酒醒寒月墮江烟。", "床頭復有三升蜜，貧困相資恐是天。"]'),
('4bfe5893-b9ed-43bd-8adf-83d59cf3c6e1','次韵王適大水','蘇轍','宋','宋诗','song-poetry','','[]','高安昔到歲方閏，大水初去城如墟。',160,'全唐诗/poet.song.48000.json','["高安昔到歲方閏，大水初去城如墟。", "危譙墮地瓦破裂，長橋斷纜船逃逋。", "漂浮隙穴亂羣蟻，奔走沙礫摧嘉蔬。", "里閭破散兵火後，飲食敝陋魚蝦餘。", "投荒豈復有便地，遇災祗復傷羸軀。", "人言西有蛟蜃穴，閏年每與風雷俱。", "漫溝溢壑恣游蕩，傾崖拔木曾須臾。", "鷄豚浪走不復保，老稚裸泣空長吁。", "滯留再與茲水會，淪胥未哂斯民愚。", "人生所遇偶然耳，得失何用分錙銖。"]'),
('69358637-7258-4a77-a766-21b2f08854bb','贈三局能師二絕  其一','蘇轍','宋','宋诗','song-poetry','','[]','得失從來似偶然，因師聊復問行年。',32,'全唐诗/poet.song.48000.json','["得失從來似偶然，因師聊復問行年。", "此生竟墮陰陽數，方信修行力未全。"]'),
('c628dca7-4141-416d-b4da-6f2c652222d7','贈三局能師二絕  其二','蘇轍','宋','宋诗','song-poetry','','[]','旅食江干秋復春，歸耕未遂不勝貧。',32,'全唐诗/poet.song.48000.json','["旅食江干秋復春，歸耕未遂不勝貧。", "憑師細考何年月，可買山田養病身。"]'),
('069c339a-6c6f-4f9c-8cfc-a541f67e3546','臨川陳憲大夫挽詞二首  其一','蘇轍','宋','宋诗','song-poetry','','[]','一時冠蓋盛臨川，直亮推公益友先。',64,'全唐诗/poet.song.48000.json','["一時冠蓋盛臨川，直亮推公益友先。", "淡泊朱絲初少味，蕭疏翠竹久彌鮮。", "崎嶇處世曾何病，奔走成功亦偶然。", "天理更疏終不失，雍雍今見子孫賢。"]'),
('27a40ec9-a567-4f86-bbdd-dfa9e319da47','臨川陳憲大夫挽詞二首  其二','蘇轍','宋','宋诗','song-poetry','','[]','五月扁舟憶過門，哀憐逐客爲招魂。',64,'全唐诗/poet.song.48000.json','["五月扁舟憶過門，哀憐逐客爲招魂。", "開樽不惜清泉潔，揮汗相看白雨翻。", "病起清言驚苦瘦，歸休尺牘尚相存。", "秋風灑涕松楸外，談笑猶疑對竹軒。"]'),
('e450c4ea-9000-47f6-b416-431c7c7506d0','次韵知郡賈蕃大夫思歸','蘇轍','宋','宋诗','song-poetry','','[]','江城漂泊最多時，邂逅誰令長者期。',64,'全唐诗/poet.song.48000.json','["江城漂泊最多時，邂逅誰令長者期。", "得坎浮槎應有命，投林驚鵲且安枝。", "何年笑語還留客，終日勤勞數問兒。", "鈴閣清虛非此比，秋風歸興恐非宜。"]'),
('59ab2e58-82af-4e4e-91eb-bfac254299ef','久不作詩呈王適','蘇轍','宋','宋诗','song-poetry','','[]','憐君多病仍經暑，笑我微官長坐曹。',64,'全唐诗/poet.song.48000.json','["憐君多病仍經暑，笑我微官長坐曹。", "落日東軒談不足，秋風北棹意空勞。", "懶將詞賦占掛臆，頻夢江湖把蟹螯。", "筆硯生塵空度日，他年何用繼離騷。"]'),
('f14626eb-9b24-45e2-a0e2-ce696b951cc3','喜王鞏承事北歸','蘇轍','宋','宋诗','song-poetry','','[]','同罪南遷驚最遠，乘流北下喜先歸。',64,'全唐诗/poet.song.48000.json','["同罪南遷驚最遠，乘流北下喜先歸。", "謂言一笑秋風後，却顧千山驛路非。", "嶺外雲烟隨夢遠，江邊魚蟹爲人肥。", "還家嫁女都無事，卧讀詩書盡掩扉。"]'),
('b24012f3-a456-4763-879a-bd678f2c8a99','予初到筠即於酒務庭中種竹四叢杉二本及今三年二物皆茂秋八月洗竹培杉偶賦短篇呈同官','蘇轍','宋','宋诗','song-poetry','','[]','種竹成叢杉出檐，三年慰我病厭厭。',64,'全唐诗/poet.song.48000.json','["種竹成叢杉出檐，三年慰我病厭厭。", "剪除亂葉風初好，封植孤根笋自添。", "高節不知塵土辱，堅姿試待雪霜霑。", "屬君留取障斜日，仍記當年此滯淹。"]'),
('dda4b588-d785-4c3f-8a15-b05164e8aa3c','和王鞏見寄三首  其一','蘇轍','宋','宋诗','song-poetry','','[]','南遷春及秋，江湖未云半。',48,'全唐诗/poet.song.48000.json','["南遷春及秋，江湖未云半。", "逮此歸路長，始悟行日遠。", "幽憂脫沉痼，清夢驚婉娩。", "行行逢故人，笑語雜悲泫。"]'),
('4cd80c96-62c2-4a91-9c66-10dce107dcc7','和王鞏見寄三首  其二','蘇轍','宋','宋诗','song-poetry','','[]','江秋北風多，歸帆未應駛。',48,'全唐诗/poet.song.48000.json','["江秋北風多，歸帆未應駛。", "天寒雁南向，家書空滿紙。", "契闊幸安平，婚嫁須纓珥。", "交遊何爲者，空復念君至。"]'),
('5ab7253f-d6af-4318-832f-8efe5fef54d0','和王鞏見寄三首  其三','蘇轍','宋','宋诗','song-poetry','','[]','折葉每安心，連環非所計。',48,'全唐诗/poet.song.48000.json','["折葉每安心，連環非所計。", "感君扁舟返，念我一廛廢。", "懷思樂全老，疇昔忘言契。", "丹砂儻已成，白首願終惠。"]'),
('ae50b66c-fd59-40c4-af46-c0439493d10a','復次韵','蘇轍','宋','宋诗','song-poetry','','["\u6ed5\u738b\u9601"]','滕王閣在誰携手，徐孺湖寬可放情。',64,'全唐诗/poet.song.48000.json','["滕王閣在誰携手，徐孺湖寬可放情。", "楚客解書南國恨，秦箏助發上林鶑。", "繫匏獨負杯中物，擁鼻知逢洛下生。", "問得長鬚添夢想，蓬窗燈火達天明。"]'),
('a0bafd7e-5dbd-46ee-8ddd-deecf8427859','孔毅父封君挽詞二首  其一','蘇轍','宋','宋诗','song-poetry','','[]','交契良人厚，家風季婦賢。',48,'全唐诗/poet.song.48000.json','["交契良人厚，家風季婦賢。", "詩書中有助，蘋藻歲無愆。", "象服期他日，恩封屬此年。", "神傷自不覺，弔客問潸然。"]'),
('b1810aa1-bdcc-4bb3-9bfa-0752a3804921','孔毅父封君挽詞二首  其二','蘇轍','宋','宋诗','song-poetry','','[]','別日笑言重，歸來藥餌憂。',48,'全唐诗/poet.song.48000.json','["別日笑言重，歸來藥餌憂。", "鍾歌掩不試，貝葉亂誰收。", "恨極囊封在，情多壟木稠。", "埋文應自作，一一記徽猷。"]'),
('483af2ce-59a9-45df-8343-f7ea002f7ff7','上高息軒起亭二絕  其一','蘇轍','宋','宋诗','song-poetry','','[]','山下清溪溪上市，溪光山色映人烟。',32,'全唐诗/poet.song.48000.json','["山下清溪溪上市，溪光山色映人烟。", "幽亭正在人聲裏，長與溪山共寂然。"]'),
('58849f2b-0007-4b98-b19f-9e38cbf33d85','上高息軒起亭二絕  其二','蘇轍','宋','宋诗','song-poetry','','[]','溪父起收罾下鯉，山翁起賣焙中茶。',32,'全唐诗/poet.song.48000.json','["溪父起收罾下鯉，山翁起賣焙中茶。", "長官亦與人俱起，笑擁黄紬放早衙。"]'),
('179c75d4-30bf-43de-9dea-b41a198d03be','九月十一日書事','蘇轍','宋','宋诗','song-poetry','','[]','東牆瘦菊早開花，九日金鈿已自嘉。',64,'全唐诗/poet.song.48000.json','["東牆瘦菊早開花，九日金鈿已自嘉。", "黍麥候遲初響罋，米鹽法細未還家。", "潑醅昨夜驚泉涌，洗盞今晨聽婦誇。", "歸採茱萸重一醉，不須怪問日時差。"]'),
('cfa7c3b2-b4a9-4a61-8d10-450818163a76','和王適寒夜讀書','蘇轍','宋','宋诗','song-poetry','','[]','久從市井役，百事廢不理。',144,'全唐诗/poet.song.48000.json','["久從市井役，百事廢不理。", "感君讀書篇，惜此寒夜晷。", "殷勤附燈燭，黽勉就圖史。", "逡巡揖虞夏，汗漫馳劉李。", "斯文家舊物，早歲夙從事。", "一從慕羶腥，中棄如敝屣。", "今夕亦何夕，忽如舊遊至。", "終篇再三嘆，推枕不成寐。", "人生無百年，所欲知有幾。", "懸知未必得，奔走若趨市。", "微言寄翰墨，開卷入心耳。", "胡爲棄不收，所逐在難覬。"]'),
('5cf4d127-c944-40a9-a307-8c06d961e222','和王適新葺小室','蘇轍','宋','宋诗','song-poetry','','[]','向日堂東一室存，竹爲窗壁席爲門。',64,'全唐诗/poet.song.48000.json','["向日堂東一室存，竹爲窗壁席爲門。", "心如白月光長照，氣結丹砂體自溫。", "飯軟莫嫌紅米賤，酒香故取潑醅渾。", "他年一笑同誰說，伴我三年江上村。"]'),
('fa7d32af-96c8-4f77-ba0b-8922ee1512e1','病中賈大夫相訪因遊中宮僧舍二首  其一','蘇轍','宋','宋诗','song-poetry','','[]','江城寒氣入肌膚，得告歸來强自扶。',64,'全唐诗/poet.song.48000.json','["江城寒氣入肌膚，得告歸來强自扶。", "五馬獨能尋杜老，一床深愧致文殊。", "體虛正覺身如幻，談劇能令病自無。", "明日出門還擾擾，年來真畏酒家壚。"]'),
('fb1a3741-a9ff-45b8-a97c-9a4b1b6555e2','病中賈大夫相訪因遊中宮僧舍二首  其二','蘇轍','宋','宋诗','song-poetry','','[]','東鄰修竹野僧家，亂柳枯桑一徑斜。',64,'全唐诗/poet.song.48000.json','["東鄰修竹野僧家，亂柳枯桑一徑斜。", "逐客慣曾迂短策，使君何事駐高牙。", "蕭條已似連村塢，邂逅應容設晚茶。", "慚愧病夫無氣力，隔牆空聽吏兵嘩。"]'),
('e356c526-532a-4e1d-a470-ab4c389e086b','和王適炙背讀書','蘇轍','宋','宋诗','song-poetry','','[]','少年讀書處，寒夜冷無火。',96,'全唐诗/poet.song.48000.json','["少年讀書處，寒夜冷無火。", "老來百事慵，炙背但空坐。", "眼昏愁細書，把卷惟恐卧。", "寒衣補故褐，家釀熟新糯。", "微微窗影斜，曖曖雲陰過。", "昏然偶成寐，鼻息已無奈。", "兒童更笑呼，書冊正前墮。", "衰懶今自由，不復問冬課。"]'),
('5a07cf26-a9e3-4c76-9048-864b0e13a03e','同王適賦雪','蘇轍','宋','宋诗','song-poetry','','[]','北風吹雨雨不斷，遍滿虛空作飛霰。',256,'全唐诗/poet.song.48000.json','["北風吹雨雨不斷，遍滿虛空作飛霰。", "紙窗獨卧不成眠，茅屋無聲時一泫。", "鳥烏錯莫寒未起，庭戶空明夜驚旦。", "重樓複閣爛生光，絕澗連山漫不見。", "夾砌雙杉洗更碧，滿田碧草埋應爛。", "城中閉戶無履迹，市上孤烟數晨爨。", "細排玉箸短垂檐，暗結輕冰時入研。", "撥灰有客顧尊俎，迹兔何人試鷹犬。", "未容行役掃車轂，應有老農歌麥飯。", "一來江城若俄頃，四見白花飛面旋。", "坐看酒甕誰敢嘗，歸踏冰泥屢成濺。", "年來橋板斷不屬，莫出肩輿足憂患。", "到家昏黑空自笑，訴婦勤勞每長嘆。", "床頭有酒未用沽，囊裏無錢不勞算。", "更令雪片大如手，終勝溪瘴長熏眼。", "謁告猶能不出門，典衣共子成高宴。"]'),
('3b55531d-b7b8-4ded-a986-5ffb6d7de96e','除夜','蘇轍','宋','宋诗','song-poetry','','[]','老去不自覺，歲除空一驚。',48,'全唐诗/poet.song.48000.json','["老去不自覺，歲除空一驚。", "深知無得喪，久已罷經營。", "黄卷譏前失，清樽借後生。", "何年遂疏懶，伏臘任躬耕。"]'),
('99ae057c-a5c3-4299-9d11-4e994121b4b6','種蘭','蘇轍','宋','宋诗','song-poetry','','[]','蘭生幽谷無人識，客種東軒遺我香。',64,'全唐诗/poet.song.48000.json','["蘭生幽谷無人識，客種東軒遺我香。", "知有清芬能解穢，更憐細葉巧凌霜。", "根便密石秋芳早，叢倚修筠午蔭凉。", "欲遣蘼蕪共堂下，眼前長見楚詞章。"]'),
('6190c654-e5f4-4584-9a6f-a69be32ff9bc','上元夜','蘇轍','宋','宋诗','song-poetry','','[]','新春收積雨，明月澹微雲。',48,'全唐诗/poet.song.48000.json','["新春收積雨，明月澹微雲。", "照水疏燈出，因風遠樂聞。", "天涯仍有節，人事竟何分。", "賣酒真拘束，何時一醉醺。"]'),
('a71327d1-bd09-48cd-b699-1be718bd7ad3','次韵王適上元夜二首  其一','蘇轍','宋','宋诗','song-poetry','','[]','燈光欲凝不驚風，月色初晴若發蒙。',64,'全唐诗/poet.song.48000.json','["燈光欲凝不驚風，月色初晴若發蒙。", "羈客不眠詩未就，遊人半醉夜方中。", "荒城熠耀相明滅，野水芙蓉亂白紅。", "知欲訪僧同寂寂，應憐病懶畏爞爞。"]'),
('25d33755-c14f-4968-a607-0cc238287a63','次韵王適上元夜二首  其二','蘇轍','宋','宋诗','song-poetry','','[]','宿雨初乾試火城，端居無計伴遊行。',64,'全唐诗/poet.song.48000.json','["宿雨初乾試火城，端居無計伴遊行。", "厭看門外繁星動，想見僧窗一點明。", "老罷逢春無樂事，夢回孤枕有鄉情。", "重因佳句思樊口，一紙家書百鎰輕。"]'),
('3edf0519-28a6-4ddf-8a97-cd93766f5d04','王子立與遲等遊陳家園橋敗幾不成行晚自酒務往見之明日雨作偶爾成咏','蘇轍','宋','宋诗','song-poetry','','[]','桃李城東近不遥，偶聞花發喜相邀。',64,'全唐诗/poet.song.48000.json','["桃李城東近不遥，偶聞花發喜相邀。", "斷橋似欲妨佳思，好雨猶能借此朝。", "隨分開樽依綠草，偶然信馬及餘瓢。", "重來莫道無閑暇，紫燕黄鸝日漸嬌。"]'),
('ffbe8bde-49a6-409c-a91f-7bcf4ae4b4e4','幽蘭花  其一','蘇轍','宋','宋诗','song-poetry','','[]','李徑桃蹊次第開，穠香百和襲人來。',32,'全唐诗/poet.song.48000.json','["李徑桃蹊次第開，穠香百和襲人來。", "春風欲擅秋風巧，催出幽蘭繼落梅。"]'),
('1a0912fe-8997-4747-9bc3-2978fe331ef1','幽蘭花  其二','蘇轍','宋','宋诗','song-poetry','','[]','珍重幽蘭開一枝，清香耿耿聽猶疑。',32,'全唐诗/poet.song.48000.json','["珍重幽蘭開一枝，清香耿耿聽猶疑。", "定應欲較香高下，故取羣芳競發時。"]'),
('2d128459-5741-4cf2-a876-cdbcffa6c46c','胡長史祠堂','蘇轍','宋','宋诗','song-poetry','','[]','白首青衫仍隠居，晚拋環堵就安輿。',64,'全唐诗/poet.song.48000.json','["白首青衫仍隠居，晚拋環堵就安輿。", "生芻忽改烝嘗地，函丈空悲講解餘。", "弟子璵璠相照耀，兒孫松桂共扶疏。", "我來恨不瞻遺老，空怪鄉鄰盡讀書。"]'),
('79c4f633-b51e-4aa0-be79-d8dc5c878c88','孫賓叟道人','蘇轍','宋','宋诗','song-poetry','','[]','萬里飄然不繫舟，酒壚一笑便相投。',32,'全唐诗/poet.song.48000.json','["萬里飄然不繫舟，酒壚一笑便相投。", "千金不換金丹訣，何事惟須一布裘。"]'),
('58348b77-91ae-416a-8d9e-605333b7d434','新橋','蘇轍','宋','宋诗','song-poetry','','[]','六月長橋斷不收，朱欄初喜映春流。',64,'全唐诗/poet.song.48000.json','["六月長橋斷不收，朱欄初喜映春流。", "虹腰宛轉三百尺，鯨背參差十五舟。", "入市樵蘇看絡繹，歸家鹽酪免遲留。", "病夫最與民同喜，卯酉匆匆無復憂。"]'),
('9c0518e0-35a3-428d-b278-ff04036181de','曾子宣郡太挽詞二首  其一','蘇轍','宋','宋诗','song-poetry','','[]','族大徽音遠，年高福祚多。',48,'全唐诗/poet.song.48000.json','["族大徽音遠，年高福祚多。", "生兒盡龍虎，封國裂山河。", "象服驚初揜，埋文信不磨。", "送車江郭滿，咽絕聽哀歌。"]'),
('1b27668b-f6ef-496c-8729-9dc93e955624','曾子宣郡太挽詞二首  其二','蘇轍','宋','宋诗','song-poetry','','[]','安輿遍西北，丹旐歷江湖。',48,'全唐诗/poet.song.48000.json','["安輿遍西北，丹旐歷江湖。", "存沒終無憾，哀榮兩得俱。", "新封崇馬鬣，餘福薦浮圖。", "家法蘋蘩在，空堂始一虞。"]'),
('67a7b8ea-daa6-4196-92ee-3deed1d0b7d0','曾子固舍人挽詞','蘇轍','宋','宋诗','song-poetry','','[]','少年漂泊馬光祿，末路騫騰朱會稽。',64,'全唐诗/poet.song.48000.json','["少年漂泊馬光祿，末路騫騰朱會稽。", "儒術遠追齊稷下，文詞近比漢京西。", "平生碑版無容繼，此日銘詩誰爲題。", "試數廬陵門下士，十年零落曉星低。"]'),
('fdccd5a9-5d96-4488-821f-734d3436d91d','次韵王適一百五日太平寺看花二絕  其一','蘇轍','宋','宋诗','song-poetry','','[]','遍入僧房花照眼，細尋芳徑蝶隨行。',32,'全唐诗/poet.song.48000.json','["遍入僧房花照眼，細尋芳徑蝶隨行。", "歸時不怕江波晚，新有橋虹水上橫。"]'),
('2c340026-0515-4d5f-ad73-cbf958ed47c0','次韵王適一百五日太平寺看花二絕  其二','蘇轍','宋','宋诗','song-poetry','','[]','小檻明窗曾不住，閑花芳草遣誰栽。',32,'全唐诗/poet.song.48000.json','["小檻明窗曾不住，閑花芳草遣誰栽。", "但須匹馬尋幽勝，携取清樽到處開。"]'),
('a752fba9-ca6e-4141-8887-7de4b68ddff1','又次韵遊小雲居','蘇轍','宋','宋诗','song-poetry','','[]','溪上浮花片片輕，泝流登岸得山行。',64,'全唐诗/poet.song.48000.json','["溪上浮花片片輕，泝流登岸得山行。", "僧房幽絕雲居小，春日陰晴野色明。", "永遠林棲真有道，溺沮耕養亦忘情。", "此身此意何年遂，空使常談笑老生。"]'),
('eb07e416-b84e-493f-a092-7d634eafb4d2','次韵秦觀梅花','蘇轍','宋','宋诗','song-poetry','','[]','病夫毛骨日凋槁，愁見米鹽惟醉倒。',128,'全唐诗/poet.song.48000.json','["病夫毛骨日凋槁，愁見米鹽惟醉倒。", "忽傳騷客賦寒梅，感物傷春同懊惱。", "江邊不識朔風勁，牆頭亦有南枝早。", "未開素質夜先明，半落清香春更好。", "鄰家小婦學閑媚，靚妝惟有長眉掃。", "孤芳已與飛霰競，結子仍先百花老。", "苦遭橫笛亂飛英，不見遊人醉芳草。", "可憐物性空自知，羞作繁華助芒昊。"]'),
('5cb61c39-3fe8-4e6e-bb1b-1b07de17c419','復次前韵答潛師','蘇轍','宋','宋诗','song-poetry','','[]','憐君古木依巖槁，西江飲盡須彌倒。',128,'全唐诗/poet.song.48000.json','["憐君古木依巖槁，西江飲盡須彌倒。", "野花幽草亦何爲，嶮韵高篇空自惱。", "萬點浮溪輒長嘆，一枝過嶺仍誇早。", "拾香不忍遊塵汙，嚼蕊更憐真味好。", "道人遇物心有得，瓦竹相敲緣自掃。", "誰知真妄了不妨，令我至今思璉老。", "妙明精覺昔未識，但向閑窗看詩草。", "浮雲時起鳥四飛，畢竟安能亂清昊。"]'),
('8a0ca1e6-5a39-4d83-b6dc-3c2148911ef7','景福順老夜坐道古人搐鼻語','蘇轍','宋','宋诗','song-poetry','','[]','中年聞道覺前非，邂逅仍逢老順師。',64,'全唐诗/poet.song.48000.json','["中年聞道覺前非，邂逅仍逢老順師。", "搐鼻徑參真面目，掉頭不受別鉗鎚。", "枯藤破衲公何事，白酒青鹽我是誰。", "慚愧東軒殘月上，一杯甘露滑如飴。"]'),
('984ff6c2-c902-44b4-98a9-8090d9184244','畫枕屏','蘇轍','宋','宋诗','song-poetry','','[]','繩床竹簟曲屏風，野水遥山霧雨濛。',32,'全唐诗/poet.song.48000.json','["繩床竹簟曲屏風，野水遥山霧雨濛。", "長有灘頭釣魚叟，伴人閑卧寂寥中。"]'),
('0b41fd97-35c9-4a8c-bd90-77b88364f1df','次韵王適留別','蘇轍','宋','宋诗','song-poetry','','[]','遠謫勞君兩度行，復將文字試平衡。',64,'全唐诗/poet.song.48000.json','["遠謫勞君兩度行，復將文字試平衡。", "干時豈爲斗升祿，聞道應忘寵辱驚。", "未了新書誰與讀，重留佳句不勝情。", "决科事畢知君喜，俗學消磨意自清。"]'),
('b2db41e6-d9a9-4968-9845-7f151a24fdd2','次韵子瞻特來高安相別先寄遲适遠却寄邁迨過遯','蘇轍','宋','宋诗','song-poetry','','[]','老兄騎騾日百里，據鞍作詩若翻水。',160,'全唐诗/poet.song.48000.json','["老兄騎騾日百里，據鞍作詩若翻水。", "忽吟春草思惠連，因之亦夢添丁子。", "羣兒競長堪一笑，老馬卧餐何日起。", "聞兄盡室皆舊人，見面未曾惟遯耳。", "遲年最長二十六，已能幹父窮愁裏。", "豫兒揚眉稍剛勁，黨子溫純無慍喜。", "我兄憔悴我亦窮，門戶久長真待爾。", "但令戢戢見頭角，甑倒囊空定何耻。", "家藏萬卷須盡讀，此外一簪無所恃。", "船中未用廢詩書，閉窗莫看江山美。"]'),
('637fdbf2-56c4-46c3-b27b-0f147efd2853','次韵子瞻端午日與遲适遠三子出遊','蘇轍','宋','宋诗','song-poetry','','[]','人生逾四十，朝日已過午。',120,'全唐诗/poet.song.48000.json','["人生逾四十，朝日已過午。", "一違少壯樂，日迫老病苦。", "丹心變爲灰，白髮粲可數。", "惟當理鉏耰，教子蓺稷黍。", "誰令觸網羅，展轉在荆楚。", "平生手足親，但作十日語。", "朝遊隔提携，夜卧困烝煮。", "未歌棠棣詩，已治芻靈祖。", "士生際風雲，富貴若騎虎。", "奈何貧賤中，所欲空齟齬。"]'),
('d730c963-012c-4c28-9faf-f7bd53aaf3c7','次韵子瞻留別三首  其一','蘇轍','宋','宋诗','song-poetry','','[]','公來十日坐東軒，手自披雲出朝日。',64,'全唐诗/poet.song.48000.json','["公來十日坐東軒，手自披雲出朝日。", "山川滿目竟何有，波浪翻天同一濕。", "諸門迭出驚異狀，間道懷歸終舊壁。", "此行千里隔江河，何人更問維摩疾。"]'),
('3d470fdc-9ef4-44e0-a964-bbdae68b3488','次韵子瞻留別三首  其二','蘇轍','宋','宋诗','song-poetry','','[]','野人性似修行僧，長願幽居近林麓。',64,'全唐诗/poet.song.48000.json','["野人性似修行僧，長願幽居近林麓。", "南遷無計脫簪組，西歸誰爲栽松竹。", "頭上白雲即飛蓋，耳畔清泉當鳴玉。", "洛川猶是冠蓋林，更願高飛逐黄鵠。"]'),
('85624ad3-34a9-4ae5-b2e1-91a8179cd1e9','次韵子瞻留別三首  其三','蘇轍','宋','宋诗','song-poetry','','[]','東西南北無住身，羯末封胡四男子。',64,'全唐诗/poet.song.48000.json','["東西南北無住身，羯末封胡四男子。", "彫鎪不遣治章句，爛熳先令飽文字。", "疏慵嗟我厲之人，生子夜中惟恐似。", "傳家粗足不願餘，同駕柴車還我里。"]'),
('7599f8b8-3ba1-410a-84b9-958913dbc666','次韵子瞻行至奉新見寄','蘇轍','宋','宋诗','song-poetry','','[]','四年候公書，長視飛鴻背。',96,'全唐诗/poet.song.48000.json','["四年候公書，長視飛鴻背。", "十日留公談，欲作白蓮會。", "匏瓜一遭繫，賣酒長不在。", "夜歸步江漘，明月照清瀨。", "心開忽自得，語異竟非背。", "一尊談笑間，萬事寂寥外。", "欲同千里行，奈此一官礙。", "何年真耦耕，舉世無此大。"]'),
('43ecac27-cfa4-4789-bb3c-b726f089548e','贈醫僧鑒清二絕  其一','蘇轍','宋','宋诗','song-poetry','','[]','肘後醫方老更精，鬚眉白盡氣彌清。',32,'全唐诗/poet.song.48000.json','["肘後醫方老更精，鬚眉白盡氣彌清。", "只應救病能無病，豈是平生學養生。"]'),
('33c3804d-a4b7-4a11-8fea-39acd5ea41ff','贈醫僧鑒清二絕  其二','蘇轍','宋','宋诗','song-poetry','','[]','門人久作開堂老，庭檜看成合抱圍。',32,'全唐诗/poet.song.48000.json','["門人久作開堂老，庭檜看成合抱圍。", "他日浴堂歸洗背，回頭還解放光輝。"]'),
('84b8603a-32b7-4de4-8142-273fd3b78d2f','贈醫僧善正','蘇轍','宋','宋诗','song-poetry','','[]','老怯江邊瘴癘鄉，城東時喜到公房。',64,'全唐诗/poet.song.48000.json','["老怯江邊瘴癘鄉，城東時喜到公房。", "歷言五藏如經眼，欲去三彭自有方。", "身厭遠遊安靜默，術因多病更深長。", "時時爲我談尊宿，曾入南公古道場。"]'),
('97c7c6f5-4915-4318-9f3e-567b92ee3f4e','食菱','蘇轍','宋','宋诗','song-poetry','','[]','野沼漲清泉，烏菱不直錢。',48,'全唐诗/poet.song.48000.json','["野沼漲清泉，烏菱不直錢。", "蟹肥螯正滿，石破髓初堅。", "節物秋風早，樽罍夜月偏。", "令人思淮上，小舫藕如椽。"]'),
('4e6607c2-dc0a-4999-ac03-1f0fa1b94ee4','留滯高安四年有餘忽得信聞當除官真揚間偶成小詩書于屋壁','蘇轍','宋','宋诗','song-poetry','','[]','數間茅屋久蹉跎，四見秋風入薜蘿。',64,'全唐诗/poet.song.48000.json','["數間茅屋久蹉跎，四見秋風入薜蘿。", "北棹偶然追雁羽，南公誰復伴漁蓑。", "三年賈傅驚吾老，九歲劉郎愧爾多。", "此去仍家江海上，不妨一葉弄清波。"]'),
('28018a67-f89b-4ab8-86f3-515e7f3db4c2','洪休上人少年讀書以多病出家居泐潭爲馬祖修塔以三絕句來謁答一首','蘇轍','宋','宋诗','song-poetry','','[]','早除郎將少年狂，祖塔結緣歸故鄉。',32,'全唐诗/poet.song.48000.json','["早除郎將少年狂，祖塔結緣歸故鄉。", "習氣未消餘業在，逢人依舊琢詩章。"]'),
('b35cf60c-8f22-4833-9594-4014eebf10da','勉子瞻失幹子二首  其一','蘇轍','宋','宋诗','song-poetry','','[]','人生本無有，衆幻妄聚耳。',96,'全唐诗/poet.song.48000.json','["人生本無有，衆幻妄聚耳。", "手足非吾親，何况妻與子。", "偶來似可樂，强作室家喜。", "忽去未免悲，欣成要矜毀。", "君家兩歲兒，畢竟何自始。", "變化違初心，涕泗劇翻水。", "吾儕近始悟，造物聊復試。", "道力竟未完，聰明信難恃。"]'),
('e2dc353a-8653-4f11-8650-bec332d26306','勉子瞻失幹子二首  其二','蘇轍','宋','宋诗','song-poetry','','[]','破甑不復顧，彼無愛甑心。',96,'全唐诗/poet.song.48000.json','["破甑不復顧，彼無愛甑心。", "棄璧負赤子，始驗愛子深。", "誠知均非我，胡爲有不能。", "一從三界遊，久被百物侵。", "朝與喜怒交，莫與寵辱臨。", "四物皆不勝，生死獨未曾。", "不經大火燒，孰爲真黄金。", "棄置父子恩，長住旃檀林。"]'),
('4ebb57d5-6399-47fc-9887-17b2dddce0d7','偶遊大愚見餘杭明雅照師舊識子瞻能言西湖舊遊將行賦詩送之','蘇轍','宋','宋诗','song-poetry','','["\u897f\u6e56"]','五年賣鹽酒，勝事不復知。',288,'全唐诗/poet.song.48000.json','["五年賣鹽酒，勝事不復知。", "城東古道場，蕭瑟寒松姿。", "出遊誠偶爾，相逢亦不期。", "西軒吳越僧，弛擔未多時。", "言住西湖中，巖谷涵清漪。", "却背閭井喧，曲盡水石奇。", "昔年蘇夫子，杖屨無不之。", "三百六十寺，處處題清詩。", "麋鹿盡相識，况乃比丘師。", "辯凈二老人，精明吐琉璃。", "笑言每忘去，蒲褐相依隨。", "門人几杖立，往往聞談詞。", "風雲一解散，變化何不爲。", "辯入三昧火，卯塔長松欹。", "凈老不復出，麈尾清風施。", "蘇公得罪去，布衣拂霜髭。", "空存壁間字，鬰屈蟠蛟螭。", "知我即兄弟，微官此棲遲。", "問何久自苦，五斗寧免饑。", "俯首笑不答，且爾聊敖嬉。", "我兄次公狂，我復長康癡。", "反復自爲計，定知山中宜。", "但欲畢婚娶，每爲故人疑。", "君歸漫灑掃，野鶴非長羈。"]'),
('c80ab9a1-ba06-403f-b11f-894e9435bd97','將移績溪令','蘇轍','宋','宋诗','song-poetry','','[]','坐看酒壚今五年，恩移巖邑稍西還。',64,'全唐诗/poet.song.48000.json','["坐看酒壚今五年，恩移巖邑稍西還。", "他年貧富隨天與，何日身心聽我閒。", "山栗似拳應自飽，蜂糖如土不須慳。", "仲卿意向桐鄉好，身後烝嘗亦此間。"]'),
('09c4f8d8-b2e1-412e-bdc9-4be6a0bca4e2','約洞山文老夜話','蘇轍','宋','宋诗','song-poetry','','[]','山中十月定多寒，纔過開爐便出山。',64,'全唐诗/poet.song.48000.json','["山中十月定多寒，纔過開爐便出山。", "堂衆久參緣自熟，郡人迎請怪忙還。", "問公勝法須時見，要我清談有夜闌。", "今夕客房應不睡，欲隨明月到林間。"]'),
('2fb81535-edc4-44bc-b585-48c2181ac891','將之績溪夢中賦泊舟野步','蘇轍','宋','宋诗','song-poetry','','[]','扁舟逢野岸，試出步崇岡。',48,'全唐诗/poet.song.48000.json','["扁舟逢野岸，試出步崇岡。", "山轉得幽谷，人家餘夕陽。", "被畦多綠茹，堆屋剩黄粱。", "深羨安居樂，誰令志四方。"]'),
('5e03b951-9bfd-4cdb-b927-178f02395274','謝洞山石臺遠來訪別','蘇轍','宋','宋诗','song-poetry','','[]','竄逐深山無友朋，往還但有兩三僧。',64,'全唐诗/poet.song.48000.json','["竄逐深山無友朋，往還但有兩三僧。", "共遊渤澥無邊處，扶出須彌最上層。", "未盡俗緣終引去，稍諳真際自虛澄。", "坐令顛老時奔走，竊比韓公愧未能。"]'),
('2dc24445-b038-4ab0-85bb-9d808ff47d26','贈方子明道人','蘇轍','宋','宋诗','song-poetry','','[]','水銀成銀利十倍，丹砂爲金世無對。',128,'全唐诗/poet.song.48000.json','["水銀成銀利十倍，丹砂爲金世無對。", "此人靳術不肯傳，闔戶泥牆畏天戒。", "今子何爲與我言，人生貧富寧非天。", "鉗鎚橐籥枉心力，虀鹽布被隨因緣。", "我來江西晚聞道，一言契我心所好。", "廓然正若太虛空，平生伎倆都除掃。", "子言舊事凈慈師，未斷有爲非凈慈。", "此術要將救饑耳，人人有命何憂饑。"]'),
('de7936e4-b478-44c1-bd71-6a25b924ec8b','回寄聖壽聰老','蘇轍','宋','宋诗','song-poetry','','[]','五年依止白蓮社，百度追尋丈室遊。',64,'全唐诗/poet.song.48000.json','["五年依止白蓮社，百度追尋丈室遊。", "睡待磨茶長展轉，病蒙煎藥久遲留。", "贊公夜宿詩仍作，巽老堂成記許求。", "回首萬緣俱一夢，故應此物未沉浮。"]'),
('9f5cb093-5da6-4a15-a3df-7d6dd1c2084b','乘小舟出筠江二首  其一','蘇轍','宋','宋诗','song-poetry','','[]','短舫漂浮真似葉，小蓬低淺僅如巢。',64,'全唐诗/poet.song.48000.json','["短舫漂浮真似葉，小蓬低淺僅如巢。", "幽吟但覺山川走，困睡不知風雨交。", "紅飯白醪供醉飽，青簑黄篛可纏包。", "一竿鶴髮他年事，萬斛龍驤任見嘲。"]'),
('235f4cc6-b378-4e4c-bc95-e1b90d8a71a4','乘小舟出筠江二首  其二','蘇轍','宋','宋诗','song-poetry','','[]','宦遊欲學林間鵲，每到新年旋疊巢。',64,'全唐诗/poet.song.48000.json','["宦遊欲學林間鵲，每到新年旋疊巢。", "蓬篛籠船聊似屋，漁樵把臂便成交。", "不妨袖裏携詩卷，尚可床頭置藥包。", "古史欲成身愈困，客來未免答譏嘲。"]'),
('34ac87c9-d0cb-412c-a146-199157cc9008','寄題孔氏顔樂亭','蘇轍','宋','宋诗','song-poetry','','[]','顔巷久已空，顔井固不遷。',144,'全唐诗/poet.song.48000.json','["顔巷久已空，顔井固不遷。", "荆榛翳蔓草，中有百尺泉。", "誰復飲此水，裹飯耕廢田。", "有賢孔氏孫，芟夷發清源。", "廢床見綆刻，古甃昏苔痕。", "引缸注瓢樽，千歲忽復然。", "嗟哉古君子，至此良獨難。", "口腹不擇味，四體不擇安。", "遇物一皆可，孰爲我憂患。", "阮生未忘酒，嵇生未忘鍛。", "欲忘富貴樂，託物僅自完。", "無託中自得，嗟哉彼誠賢。"]'),
('94792e38-e5f4-48b9-a23e-8a4e78554dab','徐孺亭','蘇轍','宋','宋诗','song-poetry','','[]','徐君鬰鬰澗底松，陳君落落堂上棟。',160,'全唐诗/poet.song.48000.json','["徐君鬰鬰澗底松，陳君落落堂上棟。", "澗深松茂不遭伐，堂毀棟折傷其躬。", "二人出處勢不合，譬如日月行西東。", "胡爲賓主兩相好，一榻挂壁吹清風。", "人生遇合何必同，一朝利盡更相攻。", "先號後笑不須怪，外物未可疑心胸。", "比干諫死微子去，自古不辨汙與隆。", "我來故國空嘆息，城東舊宅生茅蓬。", "平湖十頃照清廟，獨畫徐子遺陳公。", "二人皆合配社稷，胡不相對祠堂中。"]'),
('680613c2-faff-4d44-8fc5-99f7e660f240','滕王閣','蘇轍','宋','宋诗','song-poetry','','["\u957f\u6c5f", "\u6ed5\u738b\u9601"]','客從筠溪來，欹仄困一葉。',192,'全唐诗/poet.song.48000.json','["客從筠溪來，欹仄困一葉。", "忽逢章貢餘，滉蕩天水接。", "風霜出洲渚，草木見毫末。", "勢奔西山浮，聲動古城嶪。", "樓觀却相倚，山川互開闔。", "心驚魚龍會，目送鳬雁滅。", "遥瞻客帆久，更悟江流闊。", "史君東魯儒，府有徐孺榻。", "高談對賓旅，確論精到骨。", "餘思屬湖山，登臨寄遺堞。", "驕王應笑滕，狂客亦憐勃。", "萬錢罄一飯，千金賣豐碣。", "豪風相凌蕩，俳語終倉猝。", "事往空長江，人來逐飛楫。", "短篇竟蕪陋，絕景費彈壓。", "但當倒罌瓶，一醉付江月。"]'),
('887dfbf3-a13b-40e5-a2be-c01cfd6c17c3','次韵道潛南康見寄','蘇轍','宋','宋诗','song-poetry','','[]','一葉追隨魚與龍，紅粳白酒幸年豐。',64,'全唐诗/poet.song.48000.json','["一葉追隨魚與龍，紅粳白酒幸年豐。", "也知山色遥相待，苦畏君詩欲見攻。", "乘興風帆終日去，尋幽蠟屐及春同。", "請君先入開先寺，待濯清溪看玉虹。"]'),
('3f9418f7-3969-4f06-84a0-ba7649ca5d1b','車浮','蘇轍','宋','宋诗','song-poetry','','[]','寒魚得汕便爲家，兩兩方舟載小車。',64,'全唐诗/poet.song.48000.json','["寒魚得汕便爲家，兩兩方舟載小車。", "謀食旋遭芳餌誤，求安仍值積薪遮。", "情存未免人先得，欲盡要令物莫加。", "身似虛舟任千里，世間何處有罦罝。"]'),
('e767dbb0-0fc2-4f1a-bc40-5e2d0f448e5c','題都昌清隠禪院','蘇轍','宋','宋诗','song-poetry','','[]','北風江上落潮痕，恨不乘舟便到門。',64,'全唐诗/poet.song.48000.json','["北風江上落潮痕，恨不乘舟便到門。", "樓觀飛翔山斷際，松筠陰翳水來源。", "升堂猿鳥晨窺坐，乞食帆檣莫繞村。", "誰道溪巖許深處，一番行草認元昆。"]'),
('88f6a1aa-69b3-4c4c-8e75-d233cd1d53e7','逢章戶掾赴澧州','蘇轍','宋','宋诗','song-poetry','','[]','江船不厭窄，船窄始宜行。',48,'全唐诗/poet.song.48000.json','["江船不厭窄，船窄始宜行。", "風裏長先過，灘頭一倍輕。", "迎親無惡處，祿養勝躬耕。", "澧上春蘭早，猶堪弔屈生。"]'),
('75590109-7f59-40fb-8e34-52d39d5c558b','除夜泊彭蠡湖遇大風雪','蘇轍','宋','宋诗','song-poetry','','["\u5e90\u5c71"]','莫發鄡陽市，曉榜彭蠡口。',288,'全唐诗/poet.song.48000.json','["莫發鄡陽市，曉榜彭蠡口。", "微風吹人衣，霧繞廬山首。", "舟人釋篙笑，此是風伯候。", "杙舟未及深，飛沙忽狂走。", "暗空轉車轂，淥水起岡阜。", "衆帆落高張，斷纜已不救。", "我舟舊如山，此日亦何有。", "老心畏波瀾，歸卧塞窗牖。", "土囊一已發，萬竅無不奏。", "初疑丘山裂，復恐蛟蜃鬥。", "鼓鍾相轟豗，戈甲互磨叩。", "雲霓黑旗展，林木萬弩彀。", "曳柴眩人心，振旅擁軍後。", "或爲羈雌吟，或作蒼兕吼。", "衆音雜呼吸，異出殊圈臼。", "中宵變凝冽，飛霰集粉糅。", "蕭騷蓬響乾，晃蕩窗光透。", "堅凝忽成積，澎湃殊未究。", "紵縞鋪前洲，瓊瑰琢遥岫。", "山川莽同色，高下齊一覆。", "淵深竄魚鼈，野曠絕鳴汙。", "孤舟四鄰斷，餘食數升糗。", "寒虀僅盈盎，腊肉不滿豆。", "敝裘擁衾眠，微火拾薪構。"]'),
('a05ac877-6cc2-4ddd-86cc-f26ecca4f33f','正旦夜夢李士寧過我談說神怪久之草草爲具仍以一小詩贈之','蘇轍','宋','宋诗','song-poetry','','[]','先生惠然肯見客，旋買雞豚旋烹炙。',32,'全唐诗/poet.song.48000.json','["先生惠然肯見客，旋買雞豚旋烹炙。", "人間飲食未須嫌，歸去蓬壺却無吃。"]'),
('a0d5c5b7-e7f6-4fcf-ad0d-40da1a8ad8e2','舟中風雪五絕  其一','蘇轍','宋','宋诗','song-poetry','','[]','北風吹雪密還稀，雪勢漸多風力微。',32,'全唐诗/poet.song.48000.json','["北風吹雪密還稀，雪勢漸多風力微。", "孤棹獨依銀世界，山川路絕欲安歸。"]'),
('2f0961be-e38e-47b3-85fd-4f4b240a7391','舟中風雪五絕  其二','蘇轍','宋','宋诗','song-poetry','','[]','曉風吹浪作銀山，夜雪爭妍布玉田。',32,'全唐诗/poet.song.48000.json','["曉風吹浪作銀山，夜雪爭妍布玉田。", "風力漸衰波更惡，通宵撼我正安眠。"]'),
('b45891a6-8000-4f3d-b02f-3c67d01bd9df','舟中風雪五絕  其三','蘇轍','宋','宋诗','song-poetry','','[]','擁纜埋蓬不見船，船窗一點莫燈然。',32,'全唐诗/poet.song.48000.json','["擁纜埋蓬不見船，船窗一點莫燈然。", "幽人永夜歌黄竹，頼有丹砂暖寸田。"]'),
('64486db2-ea0f-4c2f-9722-97042772f0d1','舟中風雪五絕  其四','蘇轍','宋','宋诗','song-poetry','','[]','濁醪粗飯不成歡，白浪飛花雪作團。',32,'全唐诗/poet.song.48000.json','["濁醪粗飯不成歡，白浪飛花雪作團。", "窗外時來一雙鴨，沉浮笑我不禁寒。"]'),
('bbe5056a-d200-4334-a904-4f0a4f516192','舟中風雪五絕  其五','蘇轍','宋','宋诗','song-poetry','','["\u5e90\u5c71"]','江面澄清雪未融，扁舟蕩漾水無蹤。',32,'全唐诗/poet.song.48000.json','["江面澄清雪未融，扁舟蕩漾水無蹤。", "篙師不用匆匆去，遍看廬山羣玉峰。"]'),
('31e153b2-309c-416b-b4f1-20d3594541bc','題南康太守宅五老亭','蘇轍','宋','宋诗','song-poetry','','[]','五老高閑不入城，開軒肯就史君迎。',64,'全唐诗/poet.song.48000.json','["五老高閑不入城，開軒肯就史君迎。", "坐中莫著閑賓客，物外新成六弟兄。", "雲氣飄浮衣袂舉，泉流灑落佩環聲。", "岌然終日俱無語，靜壽相看意自明。"]'),
('8c8b330e-6da2-487f-9542-bb9c466ccb4e','書廬山劉顗宮苑屋壁三絕  其一','蘇轍','宋','宋诗','song-poetry','','["\u5e90\u5c71"]','山西舊將本書生，歸老巖間未厭兵。',32,'全唐诗/poet.song.48000.json','["山西舊將本書生，歸老巖間未厭兵。", "卧聞布水中宵起，錯認邊風萬馬聲。"]'),
('ffb4abb6-df83-4366-83c0-17b712619ceb','書廬山劉顗宮苑屋壁三絕  其二','蘇轍','宋','宋诗','song-poetry','','["\u5e90\u5c71"]','雕弓挂壁恥言勛，出入樵漁便作羣。',32,'全唐诗/poet.song.48000.json','["雕弓挂壁恥言勛，出入樵漁便作羣。", "五馬親來看射虎，不愁醉尉惱將軍。"]'),
('099c451c-895f-4b62-9728-3e84069ce4a3','書廬山劉顗宮苑屋壁三絕  其三','蘇轍','宋','宋诗','song-poetry','','["\u5e90\u5c71"]','肩輿已棄躡風騅，舊物仍存楊柳枝。',32,'全唐诗/poet.song.48000.json','["肩輿已棄躡風騅，舊物仍存楊柳枝。", "一曲清歌近尤好，五陵故態未全衰。"]'),
('8fca8b8b-42c8-4cbb-b3ef-7630972f821f','再遊廬山三首  其一','蘇轍','宋','宋诗','song-poetry','','["\u5e90\u5c71"]','當年五月訪廬山，山翠溪聲寢食間。',64,'全唐诗/poet.song.48000.json','["當年五月訪廬山，山翠溪聲寢食間。", "藤杖復隨春色到，寒泉頓與客心閑。", "巖頭懸布煎茶足，峽口驚雷泛葉慳。", "待得前村新雨遍，扁舟應逐好風還。"]'),
('0d0acc84-9f6d-4945-92b9-092d4f68e8cd','再遊廬山三首  其二','蘇轍','宋','宋诗','song-poetry','','["\u5e90\u5c71"]','憶自栖賢夜入城，道邊蘭若一僧迎。',64,'全唐诗/poet.song.48000.json','["憶自栖賢夜入城，道邊蘭若一僧迎。", "偶然不到終遺恨，特地來遊慰昔情。", "海外聲聞安至此，堂中天鼓爲誰鳴。", "匆匆復向深山去，一盞醍醐飽粟罌。"]'),
('83d14663-e710-4294-a6f1-0524f083f3b7','再遊廬山三首  其三','蘇轍','宋','宋诗','song-poetry','','["\u5e90\u5c71"]','此山巖谷不知重，赤眼浮圖自一峰。',64,'全唐诗/poet.song.48000.json','["此山巖谷不知重，赤眼浮圖自一峰。", "芒蹻隨僧踐黄葉，曉光消雪墮長松。", "石泉試飲先師錫，午飯歸尋下寺鐘。", "勝處轉多渾恐忘，出山惟見白雲濃。"]'),
('a567e128-c4e8-478a-ae77-52b266b877d9','汲陽阻風','蘇轍','宋','宋诗','song-poetry','','[]','鍾陵距池陽，相望千里內。',96,'全唐诗/poet.song.48000.json','["鍾陵距池陽，相望千里內。", "江神欺我貧，屢作風雨礙。", "欲投皖公宿，三日逢一噫。", "孤篷面空山，朝食淡無菜。", "白醪幸餘瀝，黄卷漫相對。", "饑吟非吾病，疾走老所戒。", "焦先近不遠，蝸舍聞尚在。", "區區問養生，借我一帆快。"]'),
('1016146b-be6b-4b16-a407-61b0a1a7a59c','張嘉祐','蘇轍','宋','宋诗','song-poetry','','[]','道人何爲者，陽狂時放言。',96,'全唐诗/poet.song.48000.json','["道人何爲者，陽狂時放言。", "寶塔昔所構，鐵券今尚存。", "漫浪難究悉，孰知彼根源。", "草庵劣容膝，俯仰拳肩跟。", "無食輒行乞，一飽常閉門。", "爾來二十年，未嘗變寒溫。", "嗟哉豈徒然，此意未易言。", "偶來一笑喜，但恐笑我昏。"]'),
('b7b69034-2f56-4159-b257-593b2dc88f8f','至池州贈陳鼎秀才','蘇轍','宋','宋诗','song-poetry','','[]','淮陽學舍舊相依，常誦曹溪第一機。',64,'全唐诗/poet.song.48000.json','["淮陽學舍舊相依，常誦曹溪第一機。", "却到江西心有悟，回看過去事皆非。", "孤舟遠適身如寄，二頃躬耕道自肥。", "欲看齊山君去否，閑中徒侶近來稀。"]'),
('4a71fe2f-592c-4b33-86c0-9cf6d2661bbc','次韵遲初入宣河','蘇轍','宋','宋诗','song-poetry','','[]','遠客安長道，低蓬稱小溪。',48,'全唐诗/poet.song.48000.json','["遠客安長道，低蓬稱小溪。", "雲添濕帆雨，舟滯沒篙泥。", "草綠耕牛健，村深候鳥啼。", "陶翁方作令，歸去未成題。"]'),
('54c3c0c4-b2b6-4f2b-ac05-eeb93cd60239','次韵侯宣州利建招致政汪大夫','蘇轍','宋','宋诗','song-poetry','','[]','社甕壺漿接四鄰，肩輿拄杖試紅塵。',64,'全唐诗/poet.song.48000.json','["社甕壺漿接四鄰，肩輿拄杖試紅塵。", "慣眠林下三竿日，來看城中萬井春。", "世上升沉無限事，樽前强健不資身。", "經過已足知公政，長見車中有老人。"]'),
('4f6bf591-d188-4181-a705-98169bd1ec08','次韵侯宣城疊嶂樓雙溪閣長篇','蘇轍','宋','宋诗','song-poetry','','[]','作官如負擔，一負當且弛。',240,'全唐诗/poet.song.48000.json','["作官如負擔，一負當且弛。", "不知息肩處，妄問道遠邇。", "我乘章江流，却入宛溪水。", "捨舟陟崔嵬，行路極句已。", "名都便欲過，佳處頼公指。", "仰攀疊嶂高，俯閱雙溪美。", "不悟身乘空，但覺風吹耳。", "雲烟變遥壑，歌吹聞近市。", "倦遊得清曠，行役有新喜。", "公言頃榛穢，斬伐從我始。", "堰水種蒲蓮，開山蒔梅李。", "擁本待成陰，養花要食子。", "遺風揖桓謝，父老邀黄綺。", "邦人魚依蒲，食客莪在芷。", "春陰迫寒食，謂我姑且止。", "嗟余去鄉國，屢把刀環視。", "感公鵠鷺修，憐我鳬鴨庳。", "異邦逢故人，寧復固辭理。", "高談雲漢上，爛醉笙歌裏。", "落日盡公歡，推挽未應起。"]'),
('ced79bac-aa5d-4a56-a7a7-8bd2a57112a3','初到績溪視事三日出城南謁二祠遊石照偶成四小詩呈諸同官 梓桐廟','蘇轍','宋','宋诗','song-poetry','','[]','行年五十治丘民，初學催科愧廟神。',64,'全唐诗/poet.song.48000.json','["行年五十治丘民，初學催科愧廟神。", "無限青山不容隠，却看黄卷自憐貧。", "雨餘嶺上雲披絮，石淺溪頭水蹙鱗。", "指點縣城如手大，門前五柳正摇春。"]'),
('95be044c-60f6-4a64-9d35-6ff65fb7d3aa','初到績溪視事三日出城南謁二祠遊石照偶成四小詩呈諸同官 汪王廟','蘇轍','宋','宋诗','song-poetry','','[]','石門南出衆山巔，沃壤清溪自一川。',64,'全唐诗/poet.song.48000.json','["石門南出衆山巔，沃壤清溪自一川。", "老令舊諳田事樂，春耕正及雨晴天。", "可憐鞭撻終無補，早向叢祠乞有年。", "歸告仇梅省文字，麥苗含穗欲蠶眠。"]'),
('c7b02493-97ea-4f49-8249-be291a4d1d82','初到績溪視事三日出城南謁二祠遊石照偶成四小詩呈諸同官 石照二首 其一','蘇轍','宋','宋诗','song-poetry','','[]','行盡清溪到碧峰，陰崖翠壁畫杉松。',32,'全唐诗/poet.song.48000.json','["行盡清溪到碧峰，陰崖翠壁畫杉松。", "故留石照邀行客，上徹青山最後重。"]'),
('d7f0583d-bd00-4b78-969b-d27a52379549','初到績溪視事三日出城南謁二祠遊石照偶成四小詩呈諸同官 石照二首 其二','蘇轍','宋','宋诗','song-poetry','','[]','雨開石照正新磨，鳥度猿攀野客過。',32,'全唐诗/poet.song.48000.json','["雨開石照正新磨，鳥度猿攀野客過。", "忽見塵容應笑我，年來底事白鬚多。"]'),
('12d8394f-ee63-42f5-9cd3-7788d2b2adb7','縣中諸花多交代江君所栽牡丹已過芍藥方盛偶寄小詩','蘇轍','宋','宋诗','song-poetry','','[]','偶來山邑便成家，慚愧潘生滿縣花。',64,'全唐诗/poet.song.48000.json','["偶來山邑便成家，慚愧潘生滿縣花。", "想見清樽檻邊飲，尚留佳句壁間誇。", "根株未老年年好，艷色方穠日日加。", "聞道北遊無意味，春深河上足風沙。"]'),
('556b4ed6-9ce8-412d-961c-50aa07c39514','楊主簿日本扇','蘇轍','宋','宋诗','song-poetry','','[]','扇從日本來，風非日本風。',72,'全唐诗/poet.song.48000.json','["扇從日本來，風非日本風。", "風非扇中出，問風本何從。", "風亦不自知，當復問太空。", "空若是風穴，既自與物同。", "同物豈空性，是物非風宗。", "但執日本扇，風來自無窮。"]'),
('adfafc11-8775-4f84-9630-4b2d949cb536','次韵答人幽蘭','蘇轍','宋','宋诗','song-poetry','','[]','幽花耿耿意羞春，紉佩何人香滿身。',32,'全唐诗/poet.song.48000.json','["幽花耿耿意羞春，紉佩何人香滿身。", "一寸芳心須自保，長松百尺有爲薪。"]'),
('9b1dae06-142e-4da5-b30d-6bfdc0d6ab99','次韵江法曹山間小酌','蘇轍','宋','宋诗','song-poetry','','[]','高情不奈簿書圍，行揖青山肯見隨。',64,'全唐诗/poet.song.48000.json','["高情不奈簿書圍，行揖青山肯見隨。", "綠野逢花將盡日，清樽迨我正閑時。", "檐間雙燕欲生子，葉底新梅初滿枝。", "笑殺華陽窮縣令，床頭酒盡只嚬眉。"]'),
('c0fab001-70f1-4dfc-8526-0426d72ea9dd','官舍小池有鸂鶒遺二小雛二首  其一','蘇轍','宋','宋诗','song-poetry','','[]','半畝清池藻荇香，一雙鸂鶒競悠揚。',64,'全唐诗/poet.song.48000.json','["半畝清池藻荇香，一雙鸂鶒競悠揚。", "來從碧澗巢安在，飛過重城母自將。", "野鳥似非官舍物，宰君昔是釣魚郎。", "直言愧比奇章老，得縣無心更激昂。"]'),
('174a2449-06e3-486f-81c3-8e9dcc046a50','官舍小池有鸂鶒遺二小雛二首  其二','蘇轍','宋','宋诗','song-poetry','','[]','清池定誰至，鸂鶒自來馴。',48,'全唐诗/poet.song.48000.json','["清池定誰至，鸂鶒自來馴。", "知我無傷意，憐渠解托身。", "橋陰棲息穩，島外往來頻。", "勿食遊鱼子，從交長細鱗。"]'),
('7d31fa65-44cf-4729-b873-3cd0375bf9ab','次韵答人見寄','蘇轍','宋','宋诗','song-poetry','','[]','對案青山雲氣騰，天將隙地養無能。',64,'全唐诗/poet.song.48000.json','["對案青山雲氣騰，天將隙地養無能。", "窗扉迎署梅將溜，虛市無人冷欲冰。", "寂默忘言慚社燕，毰毸困睡比春鷹。", "深知大府容衰病，復值年來蠶麥登。"]'),
('00e35ee4-c798-43bf-95df-c6a2bcb9acc5','次韵答人檻竹','蘇轍','宋','宋诗','song-poetry','','[]','猗猗元自直，落落不須扶。',48,'全唐诗/poet.song.48000.json','["猗猗元自直，落落不須扶。", "密節風吹展，清陰月共鋪。", "叢長傲霜雪，根瘦耻泥塗。", "更種愁無地，應須剪碧蘆。"]'),
('ee4722e1-2337-442c-8bee-f897dd8d325e','次韵王薦推官見寄','蘇轍','宋','宋诗','song-poetry','','[]','可憐衰病孰爲媒，私喜鄰邦得俊才。',64,'全唐诗/poet.song.48000.json','["可憐衰病孰爲媒，私喜鄰邦得俊才。", "玉案愧無酬錦繡，木瓜却用報瓊瑰。", "風流似欲傳諸謝，格律猶應學老梅。", "始信山川出才士，扁舟新自宛溪來。"]'),
('96a25a12-338f-4471-99b3-443298568cbd','郭尉愿惇夫以琳上人書詩爲示次韵','蘇轍','宋','宋诗','song-poetry','','[]','勉强冠裳四十餘，同官早歲亦山居。',64,'全唐诗/poet.song.48000.json','["勉强冠裳四十餘，同官早歲亦山居。", "朝來過我三竿日，袖有幽僧數紙書。", "家住一廛何計反，官供五斗未應無。", "聞渠秋後來相訪，脫粟藜羹只自如。"]'),
('b626fbf0-1b82-49eb-9eee-89c992944cd8','次韵汪琛監簿見贈','蘇轍','宋','宋诗','song-poetry','','[]','連宵暑雨氣如秋，過客不來誰與遊。',64,'全唐诗/poet.song.48000.json','["連宵暑雨氣如秋，過客不來誰與遊。", "頼有澹臺肯相顧，坐令彭澤未能休。", "琴疏不辦彈新曲，學廢誰令致束修。", "慚愧邑人憐病懶，共成清凈勸遲留。"]'),
('af6219e0-cdbf-4856-ad68-f3c2d904a4e3','周昉畫美人歌','蘇轍','宋','宋诗','song-poetry','','[]','深宮美人百不知，飲酒食肉事遊嬉。',160,'全唐诗/poet.song.48000.json','["深宮美人百不知，飲酒食肉事遊嬉。", "彈絲吹竹舞羅衣，曲終對鏡理鬢眉。", "岌然高髻玉釵垂，雙鬟窈窕萼葉微。", "宛轉躑躅從嬰兒，倚楹俯檻皆有姿。", "擁扇執拂知從誰，瘦者飛燕肥玉妃。", "俯仰向背樂且悲，九重深遠安得窺。", "周生執筆心坐馳，流傳人間眩心脾。", "飛瓊小玉雲霧幃，長風吹開忽見之。", "夢魂清夜那復追，老人衰朽百事非。", "展卷一笑亦胡爲，持付少年良所宜。"]'),
('0942ac86-db63-4758-8373-59576805a1a5','病中郭尉見訪','蘇轍','宋','宋诗','song-poetry','','[]','偶成三日寒兼熱，知是多聞力未全。',64,'全唐诗/poet.song.48000.json','["偶成三日寒兼熱，知是多聞力未全。", "却問藥王求妙劑，慚非摩詰已虛圓。", "勞公强說修行漸，顧我方爲病垢纏。", "應是床頭有新酒，欲邀佳客故留連。"]'),
('1c1a26c7-db28-420b-af7e-7956cbbda0b9','病後','蘇轍','宋','宋诗','song-poetry','','[]','一經寒熱攻骸骨，正似兵戈過室廬。',64,'全唐诗/poet.song.48000.json','["一經寒熱攻骸骨，正似兵戈過室廬。", "柱木支撐終未穩，筋皮收拾久猶疏。", "芭蕉張王要須朽，雲氣浮游畢竟虛。", "頼有衣中珠尚在，病中點檢亦如如。"]'),
('a35cddc3-5c9f-484f-ba01-11100db37dce','復病三首  其一','蘇轍','宋','宋诗','song-poetry','','[]','病作日短至，病消秋氣初。',48,'全唐诗/poet.song.48000.json','["病作日短至，病消秋氣初。", "山深足氛瘴，俗儉少肴蔬。", "藥亂曾何補，心安當自除。", "朝廷閔流落，已是脫遷居。"]'),
('3cd6e871-bcbe-479d-b93c-161897af899d','復病三首  其二','蘇轍','宋','宋诗','song-poetry','','[]','寒作埋冰雪，熱攻投火湯。',48,'全唐诗/poet.song.48000.json','["寒作埋冰雪，熱攻投火湯。", "今生那有此，宿業未應亡。", "委順一無損，力爭徒自傷。", "頹然付一榻，是處得清凉。"]'),
('e94940d8-050b-476a-b1c5-afc1d43e649a','復病三首  其三','蘇轍','宋','宋诗','song-poetry','','[]','一病五十日，復爾當解官。',48,'全唐诗/poet.song.48000.json','["一病五十日，復爾當解官。", "不才歸亦樂，無食去猶難。", "黽勉人應笑，低徊意已闌。", "舊師摩詰老，把卷靜中看。"]'),
('511bfda1-4f47-4aa8-a76c-f10071f25a3b','送琳長老還大明山','蘇轍','宋','宋诗','song-poetry','','[]','身老與世疏，但有世外緣。',240,'全唐诗/poet.song.48000.json','["身老與世疏，但有世外緣。", "五年客江西，掃軌謝往還。", "依依二三老，示我馬祖禪。", "身心忽明曠，不受垢污纏。", "偶成江東遊，欲別空悽然。", "緣散衆亦去，飄若風中烟。", "華陽本荒邑，緇素明星懸。", "偶然得老尉，舊依育王山。", "璉公善知識，不見十九年。", "我昔未聞道，問以所入門。", "告我從信入，授我普眼篇。", "冉冉百尺松，起自一寸根。", "南歸髮盡白，尺書今始傳。", "不知鄰邑中，乃有門人賢。", "百里走相訪，觸熱汗雨翻。", "懷中出詩卷，清絕如斷蟬。", "我適病寒熱，氣力才綿綿。", "空齋默相向，欲語不能宣。", "未暇答佳意，歸錫鏘金環。", "空有維摩病，愧無維摩言。"]'),
('0bd0fcfd-87f9-4ff5-b6e3-ae4593928bdf','病退','蘇轍','宋','宋诗','song-poetry','','["\u8861\u5c71"]','冷枕單衣小竹床，卧聞秋雨滴心凉。',64,'全唐诗/poet.song.48000.json','["冷枕單衣小竹床，卧聞秋雨滴心凉。", "此間本凈何須洗，是病皆空豈有方。", "示疾維摩元自在，放身南嶽離思量。", "病根欲去真元在，中夜夢遊何有鄉。"]'),
('fe5562cc-6950-434f-aaec-7f3665ed9f0d','病後白髮','蘇轍','宋','宋诗','song-poetry','','[]','枯木自少葉，不堪經曉霜。',48,'全唐诗/poet.song.48000.json','["枯木自少葉，不堪經曉霜。", "病添衰髮白，梳落細絲長。", "筋力從凋朽，肝心罷激昂。", "勢如秋後雨，一度一凄凉。"]'),
('9f5cdc9c-b6ba-432b-9679-8005be3509ae','答琳長老寄幽蘭白朮黄精三本二絕  其一','蘇轍','宋','宋诗','song-poetry','','[]','谷深不見蘭生處，追逐微風偶得之。',32,'全唐诗/poet.song.48000.json','["谷深不見蘭生處，追逐微風偶得之。", "解脫清香本無染，更因一嗅識真如。"]'),
('3a1b3ee2-6cf6-4bbe-85ae-1b5baba05715','答琳長老寄幽蘭白朮黄精三本二絕  其二','蘇轍','宋','宋诗','song-poetry','','[]','老僧似識衆生病，久在山中養藥苗。',32,'全唐诗/poet.song.48000.json','["老僧似識衆生病，久在山中養藥苗。", "白朮黄精遠相寄，知非象馬費柔調。"]'),
('e538f949-ff72-4ecd-8d92-5fd8759217c6','次韵侯宣城題疊嶂樓','蘇轍','宋','宋诗','song-poetry','','[]','小邑來時路，宣城最近鄰。',48,'全唐诗/poet.song.48000.json','["小邑來時路，宣城最近鄰。", "樓臺百年舊，花竹一番新。", "登覽春深日，凝思病後身。", "何時對樽酒，重爲洗埃塵。"]'),
('12a55ec5-9fe9-49f6-ae69-3e0f3b689bd1','初聞得校書郎示同官三絕  其一','蘇轍','宋','宋诗','song-poetry','','[]','讀書猶記少年狂，萬卷縱橫曬腹囊。',32,'全唐诗/poet.song.48000.json','["讀書猶記少年狂，萬卷縱橫曬腹囊。", "奔走半生頭欲白，今年始得校書郎。"]'),
('c1ebb9d0-0cef-43e2-b981-8d827883741a','初聞得校書郎示同官三絕  其二','蘇轍','宋','宋诗','song-poetry','','[]','百家小邑萬重山，慚愧斯民愛長官。',32,'全唐诗/poet.song.48000.json','["百家小邑萬重山，慚愧斯民愛長官。", "粳稻如雲梨棗熟，暫留聊復爲加餐。"]'),
('cb475db2-e024-4ea4-b6d8-6a6682679a83','初聞得校書郎示同官三絕  其三','蘇轍','宋','宋诗','song-poetry','','[]','病後濁醪都少味，老來歡意苦無多。',32,'全唐诗/poet.song.48000.json','["病後濁醪都少味，老來歡意苦無多。", "臨行寂寞空相對，不作新詩奈客何。"]'),
('c7c1ab38-08bd-4f4e-b977-7853e5687a08','績溪二咏 豁然亭','蘇轍','宋','宋诗','song-poetry','','[]','南看城市北看山，每到令人意豁然。',64,'全唐诗/poet.song.48000.json','["南看城市北看山，每到令人意豁然。", "碧瓦千家新過雨，青松萬壑正生烟。", "經秋卧病聞斤響，此日登臨負酒船。", "徑請諸君作佳句，壁間題我此詩先。"]'),
('19f25814-0892-4408-a223-45ce34924f9d','績溪二咏 翠眉亭','蘇轍','宋','宋诗','song-poetry','','[]','誰安雙嶺曲彎彎，眉勢低臨戶牖間。',64,'全唐诗/poet.song.48000.json','["誰安雙嶺曲彎彎，眉勢低臨戶牖間。", "斜擁千畦鋪淥水，稍分八字放遥山。", "愁霏宿雨峰巒濕，笑卷晴雲草木閑。", "忽憶故鄉銀色界，舉頭千里見蒼顔。"]'),
('11b42dc9-f2f7-4945-a8b5-192a4c66aaf1','辭靈惠廟歸過新興院書其屋壁','蘇轍','宋','宋诗','song-poetry','','[]','來時稻葉針鋒細，去日黄花黍粒粗。',64,'全唐诗/poet.song.48000.json','["來時稻葉針鋒細，去日黄花黍粒粗。", "久病終慚多敝政，豐年猶喜慰耕夫。", "青山片片添紅葉，淥水星星照白鬚。", "東觀校讎非老事，眼昏那復競鉛朱。"]'),
('6ea1c23f-728b-47c6-a705-9df481a93ea8','郭尉惠古鏡','蘇轍','宋','宋诗','song-poetry','','[]','凜如秋月照虛空，遇水留形處處同。',32,'全唐诗/poet.song.48000.json','["凜如秋月照虛空，遇水留形處處同。", "一瞬自成千億月，精神依舊滿胸中。"]'),
('75851a84-892c-4484-a497-f19d3ffdd89c','歙縣歲寒堂','蘇轍','宋','宋诗','song-poetry','','[]','檻外甘棠錦繡屏，長松何者擅亭名。',64,'全唐诗/poet.song.48000.json','["檻外甘棠錦繡屏，長松何者擅亭名。", "浮花過眼無多日，勁節凌寒盡此生。", "暗長茯苓根自大，旋收金粉氣尤清。", "長官不用求琴譜，但聽風吹作弄聲。"]'),
('61565468-a46f-4136-a4e6-1837ccb4d8c0','邵武游氏老人三清堂紫芝','蘇轍','宋','宋诗','song-poetry','','[]','黑龜赤鳳早逢師，白髮蒼顔老不衰。',64,'全唐诗/poet.song.48000.json','["黑龜赤鳳早逢師，白髮蒼顔老不衰。", "丹鼎一丸深自祕，紫芝三葉却先知。", "烟熏晴日雲容薄，色凝秋霜玉性奇。", "何日刀圭救羸病，盡芟荆棘種交梨。"]'),
('b38d2b5e-526d-4813-a3ac-88f09979d3e4','神宗皇帝挽詞三首  其一','蘇轍','宋','宋诗','song-poetry','','[]','稽古堯無作，勤邦禹有功。',48,'全唐诗/poet.song.48000.json','["稽古堯無作，勤邦禹有功。", "政新天地力，事改漢唐風。", "禮樂寰中盛，梯航海外通。", "華封徒有誦，龍御忽乘空。"]'),
('ebc0fed7-5330-41b5-ae63-d67978a85cfc','神宗皇帝挽詞三首  其二','蘇轍','宋','宋诗','song-poetry','','[]','承平終不處，付託重艱難。',48,'全唐诗/poet.song.48000.json','["承平終不處，付託重艱難。", "統接神孫正，人依聖母安。", "橋山封劍佩，原廟見衣冠。", "萬國纏哀處，嵩陽檜柏寒。"]'),
('ccd5c029-c217-4883-b8e4-d1c5089ddd33','神宗皇帝挽詞三首  其三','蘇轍','宋','宋诗','song-poetry','','[]','取士忘疏賤，量書廢寢興。',48,'全唐诗/poet.song.48000.json','["取士忘疏賤，量書廢寢興。", "芻言本何益，玉殿最先登。", "日角依俙想，堯言涕泗稱。", "龍髯遠莫及，零淚凍成冰。"]'),
('383d0fc2-91e8-4282-ba75-a4b6eb43c0eb','舟過嚴陵灘將謁祠登臺舟人夜解及明已遠至桐廬望桐君山寺縹緲可愛遂以小舟遊之二絕  其一','蘇轍','宋','宋诗','song-poetry','','[]','扁舟怱草出山來，慚愧嚴公舊釣臺。',32,'全唐诗/poet.song.48000.json','["扁舟怱草出山來，慚愧嚴公舊釣臺。", "舟子未應知此恨，夢中飛楫定誰催。"]'),
('cfe46d8f-7486-4c24-95e3-712c803b36c0','舟過嚴陵灘將謁祠登臺舟人夜解及明已遠至桐廬望桐君山寺縹緲可愛遂以小舟遊之二絕  其二','蘇轍','宋','宋诗','song-poetry','','[]','嚴公釣瀨不容看，猶喜桐君有故山。',32,'全唐诗/poet.song.48000.json','["嚴公釣瀨不容看，猶喜桐君有故山。", "多病未須尋藥錄，從今學取衲僧閒。"]'),
('1b5bf0ec-f6cb-4ac5-9dff-e1005b1ba7d7','泝潮二首  其一','蘇轍','宋','宋诗','song-poetry','','[]','潮來海若一長呼，潮去蕭條一吸餘。',64,'全唐诗/poet.song.48000.json','["潮來海若一長呼，潮去蕭條一吸餘。", "初見千艘委泥土，忽浮萬斛泝空虛。", "映山少避曾非久，借勢前行却自如。", "天地尚遭人意料，乘時使氣定粗疏。"]'),
('f72aca6e-7f5c-4880-8ca4-ecf1b29a6fdf','泝潮二首  其二','蘇轍','宋','宋诗','song-poetry','','[]','疋練縈回出海門，黄泥先變碧波渾。',64,'全唐诗/poet.song.48000.json','["疋練縈回出海門，黄泥先變碧波渾。", "初來似欲傾滄海，正滿真能倒百源。", "流枿飛騰竟何在，扁舟睥睨久仍存。", "自慚不作山林計，來往終隨萬物奔。"]'),
('4b59198d-6e01-46e2-a1c7-28646d5255ac','贈王復處士','蘇轍','宋','宋诗','song-poetry','','[]','候潮門外王居士，平昔交遊遍海涯。',64,'全唐诗/poet.song.48000.json','["候潮門外王居士，平昔交遊遍海涯。", "本種杉松爲老計，晚將亭榭付鄰家。", "爲生有道終安隠，好事來遊空嘆嗟。", "猶有東坡舊詩卷，忻然對客展龍蛇。"]'),
('e579d7a7-a660-4d89-ab5e-5ac225bfed9d','張惕山人即昔所謂惠思師也余舊識之於京師忽來相訪茫然不復省徐自言其故戲作二小詩贈之  其一','蘇轍','宋','宋诗','song-poetry','','[]','昔日高僧今白衣，人生變化定難知。',32,'全唐诗/poet.song.48000.json','["昔日高僧今白衣，人生變化定難知。", "故人相見不相識，空怪解吟無本詩。"]'),
('03eb5436-5e49-41de-b4fb-8b54cf92308f','張惕山人即昔所謂惠思師也余舊識之於京師忽來相訪茫然不復省徐自言其故戲作二小詩贈之  其二','蘇轍','宋','宋诗','song-poetry','','["\u957f\u6c5f"]','聽誦長江近章句，喜逢澄觀已冠巾。',32,'全唐诗/poet.song.48000.json','["聽誦長江近章句，喜逢澄觀已冠巾。", "醉吟揮弄清潮水，誰信從前戒律人。"]'),
('f4b06db3-2ee2-4d0b-ae55-e9ee566bc324','次韵子瞻送楊傑主客奉詔同高麗僧遊錢塘','蘇轍','宋','宋诗','song-poetry','','[]','人言長安遠如日，三韓住處朝日赤。',128,'全唐诗/poet.song.48000.json','["人言長安遠如日，三韓住處朝日赤。", "飛帆走馬入齊梁，却渡吳江食吳橘。", "玉門萬里唯言九，行人淚墮陽關酒。", "佛法西來到此間，遍滿曾如屈伸手。", "出家王子身心虛，飄然渡海如過渠。", "遠來忽見傾盆雨，屬國真逢戴角魚。", "至人無心亦無法，一物不見誰爲敵。", "東海東邊定有無，拍手笑作中朝客。"]'),
('f84bc88d-d852-4b78-9a27-1a54763af6b6','寄龍井辯才法師三絕  其一','蘇轍','宋','宋诗','song-poetry','','[]','我兄教我過東吳，遺墨山間無處無。',32,'全唐诗/poet.song.48000.json','["我兄教我過東吳，遺墨山間無處無。", "忽報冬潮催出堰，俗緣深重道心粗。"]'),
('7726a100-f90c-4d99-9c98-aba44c5c3720','寄龍井辯才法師三絕  其二','蘇轍','宋','宋诗','song-poetry','','[]','山色青冥葉未紅，湖光凝碧曉無風。',32,'全唐诗/poet.song.48000.json','["山色青冥葉未紅，湖光凝碧曉無風。", "行窮上下兩天竺，望斷南山龍井龍。"]'),
('666f09e2-cc2b-46c6-a6f4-4c8f09a16a57','寄龍井辯才法師三絕  其三','蘇轍','宋','宋诗','song-poetry','','[]','井水中藏東海魚，側盆翻雨洗凡夫。',32,'全唐诗/poet.song.48000.json','["井水中藏東海魚，側盆翻雨洗凡夫。", "隔山欲共公相見，莫道從來一滴無。"]'),
('1951aab5-412e-4c5f-a6ef-80a13c59ed6f','元絳參政挽詞','蘇轍','宋','宋诗','song-poetry','','[]','吳越朝天功在民，當年卿相亦仁人。',64,'全唐诗/poet.song.48000.json','["吳越朝天功在民，當年卿相亦仁人。", "曾孫終與元豐政，故老猶知異代因。", "吏治清明開白日，文詞俊發吐青春。", "鄴都從事堂中客，涕灑高原柏子新。"]'),
('15380d19-3ac3-483a-9b8b-422819a0e565','過王介同年墓','蘇轍','宋','宋诗','song-poetry','','[]','平生使氣坐生風，徐叩方知學有功。',64,'全唐诗/poet.song.48000.json','["平生使氣坐生風，徐叩方知學有功。", "應奉讀書無復忘，虞翻忤物自甘窮。", "埋根射策久彌奮，投老爲邦悍莫攻。", "墳木未須驚已拱，少年我亦作衰翁。"]'),
('dcb32114-a461-4004-ad41-523c2d751730','將遊金山寄元長老','蘇轍','宋','宋诗','song-poetry','','[]','粗砂施佛佛欣受，怪石供僧僧不嫌。',32,'全唐诗/poet.song.48000.json','["粗砂施佛佛欣受，怪石供僧僧不嫌。", "空手遠來還要否，更無一物可增添。"]'),
('26b4eab1-8724-4ef9-be46-a48ddef90d59','元老見訪留坐具而去戲作一絕調之','蘇轍','宋','宋诗','song-poetry','','[]','石霜舊奪裴休笏，坐具只今君自留。',32,'全唐诗/poet.song.48000.json','["石霜舊奪裴休笏，坐具只今君自留。", "留放書房還會否，受降曾不費戈矛。"]'),
('dfe3f95b-f9d1-4d41-8674-3e4a0ff690be','元老和示小詩自謂非戰之罪復作一絕并坐具還之','蘇轍','宋','宋诗','song-poetry','','[]','請君却領彌天具，不欲終收陷虎名。',32,'全唐诗/poet.song.48000.json','["請君却領彌天具，不欲終收陷虎名。", "莫道昏沉非戰罪，何如不戰屈人兵。"]'),
('9bc661f2-5d68-4242-ae53-532f402f2cae','子瞻與長老擇師相遇於竹西石塔之間屢以絕句贈之又留書邀轍同作遂以一絕繼之','蘇轍','宋','宋诗','song-poetry','','[]','遠老陶翁好弟兄，虎溪廬阜久逢迎。',32,'全唐诗/poet.song.48000.json','["遠老陶翁好弟兄，虎溪廬阜久逢迎。", "何須更要經平子，清議從來貴士衡。"]'),
('199351bf-a781-41c8-b883-bbb7d510f3f0','高郵贈別杜介供奉','蘇轍','宋','宋诗','song-poetry','','[]','淮南魚米年年賤，直便歸休無俸錢。',64,'全唐诗/poet.song.48000.json','["淮南魚米年年賤，直便歸休無俸錢。", "錦背圖書何益事，塵生弦筦正參禪。", "逢人未廢一樽酒，送客長隨百里船。", "世上得如君自在，不須開府事開邊。"]'),
('34a1c75a-de51-4c0d-9bca-b181f6faf394','答王定國問疾','蘇轍','宋','宋诗','song-poetry','','["\u957f\u6c5f"]','五年竄南荒，頑質不伏病。',288,'全唐诗/poet.song.48000.json','["五年竄南荒，頑質不伏病。", "吸清吐濁穢，氣練骨隨勁。", "澹然久忘歸，寂寂就遐屏。", "國恩念流落，牽挽畀鄰境。", "葉舟泝長江，藤鞋過重嶺。", "峽深蔦蘿惡，山嶮崖石橫。", "恢台夏初發，氛霧秋愈盛。", "菘薤食有時，豚羔詎曾省。", "門開訟氓入，日晏鴂舌競。", "肝脾得寒熱，冰炭迫晨暝。", "俚醫固空疏，蠻覡劇粗猛。", "老妻但坐哭，遺語未肯聽。", "長子亦在床，一卧昏不醒。", "思歸未可得，即死副前定。", "如如性終在，冉冉歲將冷。", "筋骸稍輕安，冠服强披整。", "餘方厭苓朮，日食禁醪茗。", "髮衰亂隨櫛，骨瘦空看影。", "簿書勉復親，環玦非所請。", "馬老固伏櫪，槎流舊安井。", "凌兢就輕車，邂逅出修綆。", "此生誠夢幻，俯仰成吊慶。", "故人枉新詩，萬里慰孤耿。", "賞音我非曠，斫鼻君真郢。"]'),
('d897fdbf-d85f-443e-afd9-0fb735b248d6','和子瞻次孫覺諫議韵題邵伯閘上斗野亭見寄','蘇轍','宋','宋诗','song-poetry','','[]','扁舟未遽解，坐待兩閘平。',120,'全唐诗/poet.song.48000.json','["扁舟未遽解，坐待兩閘平。", "濁水汙人思，野寺爲我清。", "昔遊有遺咏，枯墨存高甍。", "故人獨未來，一樽誰與傾。", "北風吹微雲，莫寒依月生。", "前望邗溝路，却指鐵甕城。", "茅檐卜茲地，江水供晨烹。", "試問東坡翁，畢老幾此行。", "奔馳力不足，隠約性自明。", "早爲歸耕計，免慚老僧榮。"]'),
('e43417aa-577e-49df-9dae-2c367f0883d4','次韵子瞻題泗州監倉東軒二首  其一','蘇轍','宋','宋诗','song-poetry','','[]','肩輿嫋嫋渡浮梁，吏隠知君寄一倉。',64,'全唐诗/poet.song.48000.json','["肩輿嫋嫋渡浮梁，吏隠知君寄一倉。", "十里遥看飛皂蓋，小軒相對有壺漿。", "清霄往往投車轄，永日霏霏散篆香。", "留滯淮南久仍樂，莫年何意復爲郎。"]'),
('36deefb5-0ed1-4bd4-ac65-767953fee94c','次韵子瞻題泗州監倉東軒二首  其二','蘇轍','宋','宋诗','song-poetry','','[]','萬斛塵飛日爲霾，無心退食自成齋。',64,'全唐诗/poet.song.48000.json','["萬斛塵飛日爲霾，無心退食自成齋。", "梅生紅粟初迎臘，魚躍銀刀正出淮。", "卧病空看帆度磧，誦詩猶記雪填階。", "夾河南北俱形勝，且借高城作兩崖。"]'),
('e15c61f2-ec3c-43d2-bf94-91d8caee151f','答顔復國博','蘇轍','宋','宋诗','song-poetry','','[]','歲晚河冰留畫船，一軒修竹喜蕭然。',64,'全唐诗/poet.song.48000.json','["歲晚河冰留畫船，一軒修竹喜蕭然。", "詩詞溫厚新成格，道論精微近入禪。", "病後不勝清醑釅，別時仍得舊書傳。", "欲成古史須咨考，陋巷何因接尺椽。"]'),
('2549a85b-7c3b-4061-a41b-b906e0648caa','次韵王定民宣德','蘇轍','宋','宋诗','song-poetry','','[]','彭城寺壁看詩來，顔氏瓢樽偶共開。',64,'全唐诗/poet.song.48000.json','["彭城寺壁看詩來，顔氏瓢樽偶共開。", "茅屋未完先鑿沼，竹林成後想宜梅。", "新詩妙絕難爲繼，高論微低得共陪。", "第一詞人生不識，茲行尚喜揖君才。"]'),
('b5e1cc58-6b40-4d6c-bc4f-4402225f0a84','河冰','蘇轍','宋','宋诗','song-poetry','','[]','扁舟多艱虞，與我平日類。',216,'全唐诗/poet.song.48000.json','["扁舟多艱虞，與我平日類。", "初乘滂洋流，旋涉凍淺地。", "日西陰風作，夜半流澌至。", "悄然孤寂枕，覺此凝冽氣。", "河聲噤不喧，燈花結復墜。", "忽來觸舟去，聲與裂帛似。", "平明發窗扉，吏卒殭未起。", "奔騰陣馬過，洶涌晴雲駛。", "紛紛散環玦，卷卷浮席被。", "匯流忽騰蹙，曲岸相撐抵。", "欹危起丘山，汗漫接洲沚。", "連艘恣凌轣，千槌競紛委。", "剛强初悍頑，潰散終披靡。", "掃除就虛曠，沿泝弄清泚。", "我行無疾徐，乘流得坎止。", "偶然追還期，愧此墮千指。", "陰陽有定數，開塞亦常理。", "窮冬治舟行，嗟此豈天意。"]'),
('c10f5e51-5ab6-473b-8648-a665f46e0504','復賦河冰四絕  其一','蘇轍','宋','宋诗','song-poetry','','[]','客心凜凜怯寒冰，擁褐無言夜漏深。',32,'全唐诗/poet.song.48000.json','["客心凜凜怯寒冰，擁褐無言夜漏深。", "河伯似知歸意速，風號西北故相禁。"]'),
('68bd1662-2cf8-4db0-8ee7-f7950be9aa2a','復賦河冰四絕  其二','蘇轍','宋','宋诗','song-poetry','','[]','春來歸夢劇飛鳬，夜半流澌擁舳艫。',32,'全唐诗/poet.song.48000.json','["春來歸夢劇飛鳬，夜半流澌擁舳艫。", "似勝去年彭蠡口，雪封廬岳浪翻湖。"]'),
('70106b8a-48df-4a51-ac27-c7fbada932e5','復賦河冰四絕  其三','蘇轍','宋','宋诗','song-poetry','','[]','朝來縣令借長船，仍遣千夫上下牽。',32,'全唐诗/poet.song.48000.json','["朝來縣令借長船，仍遣千夫上下牽。", "不惜瓊瑶分衆手，貪看雪片滿河壖。"]'),
('2cdedb29-e9b7-4f3f-adad-905c3dd0a08f','復賦河冰四絕  其四','蘇轍','宋','宋诗','song-poetry','','[]','輕紈破碎珮環流，顛倒鏘鳴亂觸舟。',32,'全唐诗/poet.song.48000.json','["輕紈破碎珮環流，顛倒鏘鳴亂觸舟。", "解紼投篙曾不顧，不知何處擁汀洲。"]'),
('bb1f1b8e-cf4f-46ca-bc55-f24b014e3160','河冰稍解喜呈王適','蘇轍','宋','宋诗','song-poetry','','[]','留滯江湖白髮生，西歸猶苦凍崢嶸。',64,'全唐诗/poet.song.48000.json','["留滯江湖白髮生，西歸猶苦凍崢嶸。", "春風未到冰先解，河水初深船自輕。", "去國偶然經晝夢，逢人稍欲問都城。", "羈鴻共有成行喜，雙鯉應將尺素迎。"]'),
('ba36cce7-dc46-4c07-ad02-0dc8bf96401e','河冰復結復次前韵','蘇轍','宋','宋诗','song-poetry','','[]','懊惱河冰散復生，徂年近已失崢嶸。',64,'全唐诗/poet.song.48000.json','["懊惱河冰散復生，徂年近已失崢嶸。", "身留短舫厭厭睡，目送飛鴻一一輕。", "引縴低徊疑上坂，打凌辛苦甚攻城。", "東風憐我歸心速，稍變楊梢百里迎。"]'),
('7eddfbe1-1094-4c89-a748-97f35b232b87','題南都留守妙峰亭','蘇轍','宋','宋诗','song-poetry','','[]','我登妙峰亭，欲訪德雲師。',168,'全唐诗/poet.song.48000.json','["我登妙峰亭，欲訪德雲師。", "春陽被原野，濉渙含流澌。", "未復桃李色，稍增松桂姿。", "孑孑東來檣，冉冉將安之。", "萬物委天運，此身免奔馳。", "悵然懷舊遊，一丘覆茅茨。", "清冷久沮洳，文雅空頹隳。", "提携二三子，醉倒春風吹。", "不見妙峰處，安知德雲期。", "南遷久忘反，有獲空自知。", "歸來覽新構，恍然發深思。", "遠行極南海，此地初不移。", "酌我一斗酒，盡公終日嬉。", "德雲非公歟，相對欲無詞。"]'),
('9167dd06-1137-4b4f-b2a9-791a56949b81','次韵發運路昌衡淮南見山堂','蘇轍','宋','宋诗','song-poetry','','[]','疊石初成得賜環，未應苔蘚上蒼顔。',64,'全唐诗/poet.song.48000.json','["疊石初成得賜環，未應苔蘚上蒼顔。", "據鞍華岳旌旄裏，回首淮山夢想間。", "烽火日傳西塞靜，丘陵應伴壯心閑。", "終南太白皆公有，肯向庭中更作山。"]'),
('0957c8bb-7a57-494a-9295-d3b65b19dd99','送戴朝議歸蜀中','蘇轍','宋','宋诗','song-poetry','','[]','岷山招我早歸來，劍閣橫空未易回。',64,'全唐诗/poet.song.48000.json','["岷山招我早歸來，劍閣橫空未易回。", "北叟忽驚鶗鴂晚，西轅欲及海棠開。", "避仇賦客親耕耒，因亂詩翁著酒杯。", "但愛江山無一事，爲言父老莫相猜。"]'),
('64c3c2f3-962c-41f3-90ec-7a58a5b35f56','後省初成直宿呈子瞻二首  其一','蘇轍','宋','宋诗','song-poetry','','[]','掖垣初罷斧斤響，棟宇猶聞松桂香。',64,'全唐诗/poet.song.48000.json','["掖垣初罷斧斤響，棟宇猶聞松桂香。", "江海蹔來俱野客，雲霄並直愧華堂。", "月明似與人烟遠，風細微聞禁漏長。", "諫草未成眠未穩，始知天上極清凉。"]'),
('0fc2fdcc-0039-4927-9885-a74c8bf8c3a6','後省初成直宿呈子瞻二首  其二','蘇轍','宋','宋诗','song-poetry','','[]','射策當年偶一時，對床夜雨失前期。',64,'全唐诗/poet.song.48000.json','["射策當年偶一時，對床夜雨失前期。", "廬間還往無多地，夢裏追尋亦自疑。", "螭墨屢乾朝已久，囊封希上出猶遲。", "茅檐半破松筠老，歸念蕭然欲語誰。"]'),
('58d87151-caef-4652-bdb0-349c2148268a','次韵子瞻送陳睦龍圖出守潭州','蘇轍','宋','宋诗','song-poetry','','[]','海上石橋餘折棟，大舶記君過鐵甕。',160,'全唐诗/poet.song.48000.json','["海上石橋餘折棟，大舶記君過鐵甕。", "東行萬里若乘空，老蜃長鯨應入鞚。", "波摇風卷卧不起，免教髀肉鞍磨痛。", "歸來過我話艱苦，驚汗津津尚流汞。", "海涯風物畫成圖，錯落天吳兼紫鳳。", "至今想象隔人世，往往風濤吹晝夢。", "長沙欲往厭飛楫，幸有千兵作迎送。", "文章清逸世少比，科第崢嶸聲自重。", "遠行屢屈衆所嘆，出祖誰攀車欲動。", "明朝鼓角背王城，莫聽單于吹曉弄。"]'),
('fe52ed25-1a86-4a0a-9d41-0f675971786d','送千之侄西歸','蘇轍','宋','宋诗','song-poetry','','[]','京洛東遊歲月深，相逢初喜解微吟。',64,'全唐诗/poet.song.48000.json','["京洛東遊歲月深，相逢初喜解微吟。", "夢中助我生池草，別後同誰飲竹林。", "文字承家憐女在，風流似舅慰人心。", "便將格律傳諸弟，王謝諸人無古今。"]'),
('6aacefa4-7a48-4ed5-b1d6-9e8b56743b09','駕幸親賢宅贈隨駕諸公','蘇轍','宋','宋诗','song-poetry','','[]','日日南風夜氣煩，一聲鳴䟆萬人看。',64,'全唐诗/poet.song.48000.json','["日日南風夜氣煩，一聲鳴䟆萬人看。", "禁溝飛水清黄道，凉殿分冰遍從官。", "急雨未成昏觀闕，微飆稍覺泛和鑾。", "相看揮汗塵埃裏，散髮何人舊不冠。"]'),
('07718bf9-7886-4851-98c8-e743d750ca46','次韵子瞻飲道者院池上','蘇轍','宋','宋诗','song-poetry','','[]','雨氣凉侵殿，河流滲入池。',48,'全唐诗/poet.song.48000.json','["雨氣凉侵殿，河流滲入池。", "黄粱瀹魚子，白酒瀉鵝兒。", "風細初生袖，塵清免汙眉。", "郊行不易得，拂壁看題詩。"]'),
('ab5594cc-2301-4499-8127-efb9e05efac9','答孔平仲惠蕉布二絕  其一','蘇轍','宋','宋诗','song-poetry','','[]','裘葛終年累已輕，薄蕉如霧氣尤清。',32,'全唐诗/poet.song.48000.json','["裘葛終年累已輕，薄蕉如霧氣尤清。", "應知浣濯衣稜敗，少助晨趨萃蔡聲。"]'),
('1d5adedc-8607-4db0-921b-ba39568f37bc','答孔平仲惠蕉布二絕  其二','蘇轍','宋','宋诗','song-poetry','','[]','燈籠白葛扇裁紈，身似山僧不似官。',32,'全唐诗/poet.song.48000.json','["燈籠白葛扇裁紈，身似山僧不似官。", "更得雙蕉縫直掇，都人渾作道人看。"]'),
('f42ecaa2-2298-4094-8db7-b2b58c503ebd','次韵朱光庭司諫喜雨','蘇轍','宋','宋诗','song-poetry','','[]','焦枯連夏火，洗濯待秋霖。',48,'全唐诗/poet.song.48000.json','["焦枯連夏火，洗濯待秋霖。", "都邑溝渠凈，郊原黍豆深。", "流膏侵地軸，晴意動風琴。", "誰似臣居易，先成喜雨箴。"]'),
('333a1b5e-da35-41f5-a672-5f9502c7e11d','次韵光庭省中書事','蘇轍','宋','宋诗','song-poetry','','[]','放浪江湖久惰慵，安排誰置從官中。',64,'全唐诗/poet.song.48000.json','["放浪江湖久惰慵，安排誰置從官中。", "粗疏空與延和對，開納初還貞觀風。", "二鄙兵消真帝力，四方雨足自天功。", "時將一勺傾滄海，漫使人知達四聰。"]'),
('906f342e-dd91-4d6d-b57a-1d6cda7662b6','送張恕朝奉南京簽判二首  其一','蘇轍','宋','宋诗','song-poetry','','[]','楚蟹吳柑初著霜，梁園官酒試羔羊。',64,'全唐诗/poet.song.48000.json','["楚蟹吳柑初著霜，梁園官酒試羔羊。", "老如計相非無齒，清似留侯未却糧。", "杖屨稍通賓客過，殽蔬要遣子孫嘗。", "詔書委曲如公意，幕府新除朱紱郎。"]'),
('0565de59-d002-4746-9dbb-9eb5c7e48677','送張恕朝奉南京簽判二首  其二','蘇轍','宋','宋诗','song-poetry','','[]','朱紱還家罷倚門，留都無事最宜親。',64,'全唐诗/poet.song.48000.json','["朱紱還家罷倚門，留都無事最宜親。", "下車趨走驚鄰舍，决獄平反慰老人。", "相見只今多邂逅，舊遊他日半埃塵。", "何年重起扁舟興，會作東湖十日賓。"]'),
('faa11b6d-bbf8-4db5-b399-bfe38ffb61d6','送賈訥朝奉通判眉州','蘇轍','宋','宋诗','song-poetry','','[]','歸念長依落日邊，壺漿今見逆新官。',64,'全唐诗/poet.song.48000.json','["歸念長依落日邊，壺漿今見逆新官。", "聲傳已覺謳歌遍，身到前知政令寬。", "民病賢人來已暮，時平蜀道本無難。", "明年我欲修桑梓，爲賞庭前荔子丹。"]'),
('e7498b1e-f799-49e5-bd9f-708e4e5c85a9','次韵黄庭堅學士猩毛筆','蘇轍','宋','宋诗','song-poetry','','[]','不悟身邊一斗紅，聖賢隨世亦時中。',32,'全唐诗/poet.song.48000.json','["不悟身邊一斗紅，聖賢隨世亦時中。", "何人知有中書巧，縛送能書陳孟公。"]'),
('43948129-479e-46ae-be6d-abd68ac65d59','李誠之待制挽詞二首  其一','蘇轍','宋','宋诗','song-poetry','','[]','脫遺章句事經綸，滿腹龍蛇自屈伸。',64,'全唐诗/poet.song.48000.json','["脫遺章句事經綸，滿腹龍蛇自屈伸。", "南駕威聲傳絕域，西征舊恨失姦臣。", "空留諫疏驚頹靡，終託詩詞話苦辛。", "直氣如雲未應盡，一雙嗣子亦騏驎。"]'),
('be7b028b-a361-4046-b136-a8cf157016e1','李誠之待制挽詞二首  其二','蘇轍','宋','宋诗','song-poetry','','["\u897f\u6e56"]','濟南風物在西湖，湖上逢公初下車。',64,'全唐诗/poet.song.48000.json','["濟南風物在西湖，湖上逢公初下車。", "談笑樽前伏齊虜，旌旗門外聽除書。", "一封未奏先焚草，三黜歸來便種蔬。", "淚落西堂歌酒地，杉松空見歲寒餘。"]'),
('dae73c1b-5c37-45ce-a804-83353c5815ea','司馬溫公挽詞四首  其一','蘇轍','宋','宋诗','song-poetry','','[]','白髮三朝舊，青山一布衾。',48,'全唐诗/poet.song.48000.json','["白髮三朝舊，青山一布衾。", "封章留帝所，德澤在人心。", "未起謳吟切，來歸顧託深。", "楊公不久住，天意定難忱。"]'),
('d6929dfc-2f8e-40f0-a51a-7d89669ffce3','司馬溫公挽詞四首  其二','蘇轍','宋','宋诗','song-poetry','','[]','决策傳賢際，危言變法初。',48,'全唐诗/poet.song.48000.json','["决策傳賢際，危言變法初。", "紛紛看往事，一一驗遺書。", "富貴終何有，清貧只自如。", "西州不忍過，行哭便回車。"]'),
('00815833-4917-4557-8ed8-3e69f2230d37','司馬溫公挽詞四首  其三','蘇轍','宋','宋诗','song-poetry','','[]','區區非爲己，懇懇欲忘生。',48,'全唐诗/poet.song.48000.json','["區區非爲己，懇懇欲忘生。", "力盡心終在，身亡勢亦成。", "遺民拋劍戟，故老半公卿。", "魏丙生前友，俱傳漢相名。"]'),
('9a116238-f317-4f54-bd50-38ebbfdf9454','司馬溫公挽詞四首  其四','蘇轍','宋','宋诗','song-poetry','','[]','少年真狷淺，射策本粗疏。',48,'全唐诗/poet.song.48000.json','["少年真狷淺，射策本粗疏。", "欲廣忠言地，先收衆棄餘。", "流離見更化，邂逅捧除書。", "趙孟終知厥，他人恐駡予。"]'),
('76f0f0a0-275f-408a-9474-26fc7e2f8b4e','送表弟程之元知楚州','蘇轍','宋','宋诗','song-poetry','','[]','與君外兄弟，初如一池魚。',144,'全唐诗/poet.song.48000.json','["與君外兄弟，初如一池魚。", "中年雲雨散，各異澗谷居。", "客舍復相從，語極長唏噓。", "青衫奉朝謁，白髮驚晨梳。", "百年不堪把，一樽歡有餘。", "清言我未厭，昨夜聞除書。", "淮南旱已久，疲民食田蔬。", "詔發上供米，仍疏古邗渠。", "要須賢使君，均此積歲儲。", "徑乘兩槳去，不待五馬車。", "別離難重陳，勞徠不可徐。", "政成得召節，歲晚當歸歟。"]'),
('73ecdac1-ac1b-480e-bf17-51f27c821a0d','送王震給事知蔡州','蘇轍','宋','宋诗','song-poetry','','[]','朝廷入忘返，冠蓋如雲屯。',120,'全唐诗/poet.song.48000.json','["朝廷入忘返，冠蓋如雲屯。", "賢哉貴公子，獨以民社言。", "西臺出命書，落筆波濤翻。", "東臺典封駁，坐惜日月奔。", "試劇得上蔡，高卧强東藩。", "旱歲獨多麥，時雨如傾盆。", "鈴軒省鞭抶，幕府多壺樽。", "逡巡文字樂，斥去簿領煩。", "賜環行當至，坐席恐未溫。", "三槐日成陰，富貴屬曾孫。"]'),
('5108e485-3462-4799-90ba-98885ee38062','送王廷老朝散知虢州','蘇轍','宋','宋诗','song-poetry','','[]','滿腹貯精神，觸手會衆理。',216,'全唐诗/poet.song.48000.json','["滿腹貯精神，觸手會衆理。", "一廢十五年，直坐才多爾。", "我昔遊宋城，憶始識君子。", "簿書填丘山，賓客亂峰螘。", "出尋城下宅，屢屣床前履。", "清談如鋸木，落屑紛相委。", "解頤自有樂，置酒姑且止。", "逡巡破黄封，婉娩歌皓齒。", "風高熊正白，霜落蟹初紫。", "夜闌意未厭，河斜客忘起。", "歸來笑僮僕，熟醉未曾爾。", "江湖一流蕩，歡意日頹弛。", "西還經舊遊，相逢值新喜。", "詔催西州牧，門有朱轓柅。", "都城挽不住，山賊近方侈。", "提刀索崖谷，援桴動閭里。", "居家百無與，王事非有己。", "何日却休官，復飲梁王市。"]'),
('3fb624a5-9035-44fd-99c9-8dfa76528827','送魯有開中大知洺州次子瞻韵','蘇轍','宋','宋诗','song-poetry','','[]','仲連雖不仕，而非綺與園。',240,'全唐诗/poet.song.48000.json','["仲連雖不仕，而非綺與園。", "逡巡笑談間，屢解戰鬥繁。", "子敬識二孫，長揖鼓鼙喧。", "意氣感周郎，振策起江村。", "二賢繼英風，千載爲高門。", "曾孫事仁祖，風義夙所敦。", "臺閣餘故事，父老稱遺言。", "白髮識公子，十載友元昆。", "婆娑久不試，俯仰色愈溫。", "五馬忽嘶鳴，朱輪夾征軒。", "旌旄隔河至，部曲幾人存。", "銅虎不可留，芻狗行當燔。", "秋潦决河防，遺黎化驚魂。", "憂心念千里，何暇把一樽。", "西城叩門別，南風吹帽翻。", "嗟我限出謁，未敢逾短垣。", "新晴水尚壯，想見民驚奔。", "安得萬丈堤，止此百里渾。", "姑爾救一境，誰當理其源。", "百聞貴一見，尺書爲我論。"]'),
('9bcb8101-b6fa-45c0-b3f7-f47bb639589b','送陳侗同年知陝府','蘇轍','宋','宋诗','song-poetry','','[]','上書乞江淮，得請臨關河。',168,'全唐诗/poet.song.48000.json','["上書乞江淮，得請臨關河。", "所得非所願，親友或相訶。", "丈夫志四方，所遇常逶迤。", "况當國西屏，形勝古來多。", "崑渠涌北郭，華岳垂東阿。", "羌虜昔未平，驛騎如飛梭。", "間諜時出沒，關梁苦誰何。", "爾來一清凈，西望多麥禾。", "魏絳方和戎，先零正投戈。", "秦人釋重負，道路聞行歌。", "便當卧齋閤，次第除網羅。", "時時一嘯咏，未用勤催科。", "諸孤寄吳越，食口如雁鵝。", "時分橐中金，何必手自摩。"]'),
('79cbd9e3-0404-42b9-9659-e07d3b2d5fc9','次韵李曼朝散得郡西歸留別二首  其一','蘇轍','宋','宋诗','song-poetry','','[]','風波定後得西歸，烏鵲喧呼里巷知。',64,'全唐诗/poet.song.48000.json','["風波定後得西歸，烏鵲喧呼里巷知。", "未熟黄粱驚破夢，相看白髮信乘危。", "豚肩尚有冬深味，蠶器應逢市合時。", "父老爲公留臘酒，不須猶唱式微詩。"]'),
('b42bb37f-29fb-4526-a8ad-66f673ed372b','次韵李曼朝散得郡西歸留別二首  其二','蘇轍','宋','宋诗','song-poetry','','[]','懷印徒行尚故衣，邸中掾史見猶疑。',64,'全唐诗/poet.song.48000.json','["懷印徒行尚故衣，邸中掾史見猶疑。", "千人上塚鄉關動，五馬行春雨澤隨。", "醉裏墜車初未覺，道中破甑復誰悲。", "西行漫遣親朋喜，早賦陶翁歸去詩。"]'),
('41399c12-e739-4622-afb2-f82eca5bc6c1','送程建用宣德西歸','蘇轍','宋','宋诗','song-poetry','','[]','昔與君同巷，參差對柴荆。',216,'全唐诗/poet.song.48000.json','["昔與君同巷，參差對柴荆。", "艱難奉老母，弦歌教諸生。", "藜藿飽臧獲，布褐均弟兄。", "貧賤理則窮，禮義日益明。", "我親本知道，家有月旦評。", "逡巡戶牖間，時聞嘆息聲。", "善惡不可誣，孝弟神所聽。", "我見此家人，處約能和平。", "它年彼君子，豈復地上行。", "爾來三十年，遺語空自驚。", "松阡映天末，苦淚緣冠纓。", "子親八十五，皤然老人星。", "安輿及祿養，平反慰中情。", "月俸雖不多，足備甘與輕。", "今年復考課，得秩真代耕。", "倚門老鶴望，策馬飛鴻征。", "歸來歲云莫，手奉屠蘇觥。", "我詩不徒作，以遺鄉黨銘。"]'),
('c6382703-a3bb-4443-be31-8495eeb1d5b0','次韵子瞻杜介供奉送魚','蘇轍','宋','宋诗','song-poetry','','[]','天街雪霽初通駟，禁籞冰開漸躍魚。',64,'全唐诗/poet.song.48000.json','["天街雪霽初通駟，禁籞冰開漸躍魚。", "十尾煩君穿細柳，一杯勸我芼青蔬。", "寒樽獨酌偶逢客，佳句相酬不用書。", "江海歸來叨禁近，空令同巷往來疏。"]'),
('07529dfe-1ab1-47cf-9d48-d42278b2671c','次韵子瞻招王蘧朝請晚飲','蘇轍','宋','宋诗','song-poetry','','[]','矯矯公孫才不貧，白駒衝雪喜新春。',64,'全唐诗/poet.song.48000.json','["矯矯公孫才不貧，白駒衝雪喜新春。", "忽過銀闕迷歸路，誤認瑶臺尋故人。", "訪我不嫌泥正滑，留君深愧酒非醇。", "歸時九陌鋪寒月，清絕空教僕御顰。"]'),
('d1fe252b-6c2f-41bd-bddf-33b5c7606fa7','子瞻與李公麟宣德共畫翠石古木老僧謂之憩寂圖題其後','蘇轍','宋','宋诗','song-poetry','','[]','東坡自作蒼蒼石，留取長松待伯時。',32,'全唐诗/poet.song.48000.json','["東坡自作蒼蒼石，留取長松待伯時。", "只有兩人嫌未足，更收前世杜陵詩。"]'),
('5cab7b74-f05c-4d7f-bd41-a89744474d66','王君貺宣徽挽詞三首  其一','蘇轍','宋','宋诗','song-poetry','','[]','妙年收賈傅，白首貴王陽。',48,'全唐诗/poet.song.48000.json','["妙年收賈傅，白首貴王陽。", "志氣文章在，功名歲月長。", "遺孫依舊德，故吏滿諸方。", "河朔三持節，斯民定不忘。"]'),
('1041d5d7-702e-4a61-b93b-04f203a55e1b','王君貺宣徽挽詞三首  其二','蘇轍','宋','宋诗','song-poetry','','[]','謫墮神仙侶，飛翔鸞鳳姿。',48,'全唐诗/poet.song.48000.json','["謫墮神仙侶，飛翔鸞鳳姿。", "舊逢黄石老，陰許赤松期。", "歷歷僧伽記，申申鄧傅詞。", "翻然歸海嶠，無復世人知。"]'),
('37c7897d-cb51-4938-a4fc-40b11d6e976c','王君貺宣徽挽詞三首  其三','蘇轍','宋','宋诗','song-poetry','','[]','從軍在河上，仗鉞喜公來。',48,'全唐诗/poet.song.48000.json','["從軍在河上，仗鉞喜公來。", "幕府方閑暇，歌鐘得縱陪。", "它年老賓佐，過國泣樓臺。", "猶有墳碑在，仍令故客開。"]'),
('cf45c43d-dc2f-4cdb-9bab-a5fb7a6d36b3','送杜介歸揚州','蘇轍','宋','宋诗','song-poetry','','[]','揚州繁麗非前世，城郭蕭條却古風。',64,'全唐诗/poet.song.48000.json','["揚州繁麗非前世，城郭蕭條却古風。", "尚有花畦春雨後，不妨水調月明中。", "東都甲第非嫌汝，北牖羲皇自屬翁。", "清洛放船經月事，急先鶗鴂繞芳叢。"]'),
('fc4bea84-5f8b-4da3-a169-0355d5782a73','次韵子瞻與鄧聖求承旨同直翰苑懷武昌西山舊遊','蘇轍','宋','宋诗','song-poetry','','[]','我遊齊安十日回，東坡桃李初未栽。',224,'全唐诗/poet.song.48000.json','["我遊齊安十日回，東坡桃李初未栽。", "扁舟亂流入樊口，山雨未止淫黄梅。", "寒溪聞有古精舍，相與推挽登崔嵬。", "山深縣令喜客至，寺荒蔓草生經臺。", "黄鵝白酒得野餽，藤床竹簟無纖埃。", "可憐遷客畏人見，共怪青山誰爲堆。", "行驚晚照催出谷，中止亂石傾餘罍。", "古今相望兩令尹，文詞灑落千山隈。", "野人豈復識遺趣，過客時爲剜蒼苔。", "五年留滯屐齒禿，一朝揮手船頭開。", "玉堂却憶昔遊處，笑問五柳應彫摧。", "滿朝文士蚤貴達，憑凌霄漢乘風雷。", "入參祕殿出華省，何曾著足空山來。", "漂流邂逅覽遺躅，耳中尚有江聲哀。"]'),
('4eec5012-6210-4a01-9f04-4b462d45afc0','送楊孟容朝奉西歸','蘇轍','宋','宋诗','song-poetry','','[]','三十始去家，四十初南遷。',144,'全唐诗/poet.song.48000.json','["三十始去家，四十初南遷。", "五十復還朝，白髮正紛然。", "故人從西來，鞍馬何聯翩。", "握手得一笑，喜我猶生全。", "別離多憂患，夢覺非因緣。", "惟餘歸耕計，粗有山下田。", "久糜太倉粟，空愧鄉黨賢。", "老兄富治行，令德齊高年。", "幸此民事清，未厭軍壘偏。", "父老携壺漿，稚子迎道邊。", "應有故相識，問我何當旋。", "君恩閔衰病，歸駕行將鞭。"]'),
('483da448-fa78-4183-a54d-1a450cdff4d6','次韵孔武仲學士見贈','蘇轍','宋','宋诗','song-poetry','','[]','羨君耽讀書，日夜論今古。',144,'全唐诗/poet.song.48000.json','["羨君耽讀書，日夜論今古。", "雖復在家人，不見釋手處。", "意求五車盡，未惜雙目苦。", "蓬萊倚霄漢，簡冊充棟宇。", "學成擅囷倉，筆落走風雨。", "破籠閉野鶴，短草藏文虎。", "鬢鬚忽半白，兒女無復乳。", "知君不能薦，愧我終何補。", "偶來相就談，日落久未去。", "歸鞍得新詩，佳句爛如組。", "古風棄雕琢，遺味比樂府。", "且復調塤篪，泠然五音舉。"]'),
('924e50c4-f8ac-4c3d-a318-0b720b4a2208','送家定國朝奉西歸','蘇轍','宋','宋诗','song-poetry','','[]','我懷同門友，勢如曉天星。',144,'全唐诗/poet.song.48000.json','["我懷同門友，勢如曉天星。", "老去髮垂素，隠居山更青。", "退翁聯科第，俯仰三十齡。", "仕官守鄉國，出入奉家庭。", "鵠鷺性本靜，芷蘭深自馨。", "新詩得高趣，衆耳昏未聽。", "笑我老憂患，奔走如流萍。", "冠裳强包裹，齒髮坐凋零。", "晚春首歸路，朱轓照長亭。", "縣令迎使君，綵服導輜軿。", "長嘆或垂涕，平反知有令。", "此樂我已亡，雖達終不寧。"]'),
('7f5dc5cf-771a-47dd-ad15-e6cb5486ddd8','次韵劉貢父省上示同會二首  其一','蘇轍','宋','宋诗','song-poetry','','[]','流落江湖東復西，歸來未洗足間泥。',64,'全唐诗/poet.song.48000.json','["流落江湖東復西，歸來未洗足間泥。", "偶隨鵬翼培風上，時得衙香滿袖携。", "落筆逡巡看儤直，醉吟清絕許分題。", "相望魯衛雖兄弟，終畏鄰封大國齊。"]'),
('f5974cad-b05b-40ac-8652-e57b2a19f98f','次韵劉貢父省上示同會二首  其二','蘇轍','宋','宋诗','song-poetry','','[]','掖垣不復限東西，賓客來衝霧雨泥。',64,'全唐诗/poet.song.48000.json','["掖垣不復限東西，賓客來衝霧雨泥。", "白酒黄封開瀲灧，朱櫻青籠落提携。", "五花愧我連書判，三道高君免試題。", "誰遣松蒿同一谷，凌雲他日恐難齊。"]'),
('9b725132-07d4-4e35-a907-42562feb14bf','次韵孔武仲三舍人省上','蘇轍','宋','宋诗','song-poetry','','[]','君不見西都校書宗室叟，東魯高談鼓瑟手。',91,'全唐诗/poet.song.48000.json','["君不見西都校書宗室叟，東魯高談鼓瑟手。", "偶然同我西掖垣，並立曉班分左右。", "龍文百斛世無價，瓦釜枵然但升斗。", "諸兄落落不可望，兩季幸肯分餘光。", "大孔奮飛自南鄉，聯翩羣雁相追翔，渠家冠蓋尤堂堂。"]'),
('316a4d6c-c5ef-4b8a-a901-3eb066bf98bb','送顧子敦奉使河朔','蘇轍','宋','宋诗','song-poetry','','[]','去年送君使河東，今年送君使河北。',160,'全唐诗/poet.song.48000.json','["去年送君使河東，今年送君使河北。", "連年東北少安居，慷慨憐君色自得。", "河流西决不入土，千里汗漫敗原隰。", "壯夫奔亡老稚死，粟麥無苗安取食。", "君憂臣辱自古然，自說過門三不入。", "忠誠一發鬼神輔，心念既通謀計集。", "堤防旋立村落定，波浪欲收蛟蜃泣。", "二年歸國未爲久，故舊相看髮猶黑。", "成功豈在延世下，好勇真令腐儒服。", "此時爲國頌河平，當使君名長不沒。"]'),
('2796dc4b-d2a1-414e-8923-4099560751ab','席上再送','蘇轍','宋','宋诗','song-poetry','','[]','人言虎頭癡，勇作河朔遊。',96,'全唐诗/poet.song.48000.json','["人言虎頭癡，勇作河朔遊。", "黄河六七月，不辨馬與牛。", "單車徑北渡，橫身障西流。", "虎頭亦不癡，志在萬戶侯。", "徜徉歷三邊，歸借坐上籌。", "腰垂黄金印，不受白髮羞。", "此計雖落落，但問有志不。", "臨岐且一醉，行役方未休。"]'),
('98272aba-8604-44b4-b53e-c0c235174a0b','次韵孔文仲舍人酴醾','蘇轍','宋','宋诗','song-poetry','','[]','蒼蛇凍不死，輕素暖仍歸。',72,'全唐诗/poet.song.48000.json','["蒼蛇凍不死，輕素暖仍歸。", "落蕊時吹面，繁香自撲幃。", "光凝真照夜，枝軟或牽衣。", "似厭風霾苦，應思霧雨霏。", "開樽迎最盛，掃地見初稀。", "頼有清陰在，金波肯發揮。"]'),
('895a2eaf-eaf3-405a-ab88-c5d55c7d57f0','送錢承制赴廣東都監','蘇轍','宋','宋诗','song-poetry','','[]','家聲遠繼河西守，遊宦多便嶺外官。',64,'全唐诗/poet.song.48000.json','["家聲遠繼河西守，遊宦多便嶺外官。", "南海無波閑鬥舸，北堂多暇得羞蘭。", "忽聞常棣歌離索，應寄寒梅報好安。", "它日扁舟定歸計，仍將犀玉付江湍。"]'),
('14b0e94c-e145-4fde-b5ce-333b72c16e5a','次韵曾子開舍人四月一二日扈從二首  其一','蘇轍','宋','宋诗','song-poetry','','[]','萬人齊仗足聲勻，翠輦徐行不動塵。',64,'全唐诗/poet.song.48000.json','["萬人齊仗足聲勻，翠輦徐行不動塵。", "夾道歡呼通老稚，從官雜遝數徐陳。", "旌旗稍放龍蛇卷，旒冕初看日月新。", "天遣雨師先灑道，農夫不復誤占辛。"]'),
('016e8047-e7b1-4b81-8cbd-6fd7e9e83657','次韵曾子開舍人四月一二日扈從二首  其二','蘇轍','宋','宋诗','song-poetry','','[]','衣冠雙日款蓬萊，簾脫瓊鉤扇不開。',64,'全唐诗/poet.song.48000.json','["衣冠雙日款蓬萊，簾脫瓊鉤扇不開。", "清曉逮驚三殿啟，翠華遥自九天來。", "晨光稍稍侵黄蓋，瑞霧霏霏著禁槐。", "千兩翟車觀禮罷，歸時滿載德風迴。"]'),
('40dfbd63-d306-4ba8-9604-0e71494254f3','再和二首  其一','蘇轍','宋','宋诗','song-poetry','','[]','病起江南力未勻，强將冠劍拂埃塵。',64,'全唐诗/poet.song.48000.json','["病起江南力未勻，强將冠劍拂埃塵。", "木鷄自笑真無用，芻狗何勞收已陳。", "行從鑾旗風日細，側聽廟樂管絃新。", "誰知四載勤勞後，併舉成功祚泣辛。"]'),
('1f31c570-c652-4058-804e-ce2b2cf4a4bd','再和二首  其二','蘇轍','宋','宋诗','song-poetry','','[]','宸心惻惻念汙萊，南籞西池閉不開。',64,'全唐诗/poet.song.48000.json','["宸心惻惻念汙萊，南籞西池閉不開。", "長樂鳴鞘千乘出，顧成薦鬯萬方來。", "從臣暗泣新宮柳，父老行依輦路槐。", "雙闕影斜朱戶啟，都人留看屬車回。"]'),
('7845d5a0-26c3-4099-a9a7-5a7c69b1f6b9','次韵張昌言給事省中直宿','蘇轍','宋','宋诗','song-poetry','','[]','還家未暇拂塵衣，携被重來趁落暉。',64,'全唐诗/poet.song.48000.json','["還家未暇拂塵衣，携被重來趁落暉。", "省戶鳴騶久分散，宮槐栖鵲共翻飛。", "周廬見月風霾靜，斜漢橫空星斗稀。", "多病心身怯清禁，故山依約夢西歸。"]'),
('54cbad75-c782-4613-b544-2d1bb0c76f48','次韵貢父子開直宿','蘇轍','宋','宋诗','song-poetry','','[]','擲簡摇毫氣吐虹，興餘庭藥咏殘紅。',32,'全唐诗/poet.song.48000.json','["擲簡摇毫氣吐虹，興餘庭藥咏殘紅。", "今宵文字知無幾，鼾睡簾中笑二公。"]'),
('42b2c602-8cba-4e59-90bc-435d6923a53b','去年冬轍以起居郎入侍邇英講不逾時遷中書舍人雖忝冒愈深而瞻望清光與日俱遠追記當時所見作四絕句呈同省諸公  其一','蘇轍','宋','宋诗','song-poetry','','[]','邇英肅肅曉霜清，玉宇時聞槁葉零。',32,'全唐诗/poet.song.48000.json','["邇英肅肅曉霜清，玉宇時聞槁葉零。", "風過都城吹廣內，萬人笑語落中庭。"]'),
('add7f44f-69b2-485b-ba42-b7219b022b97','去年冬轍以起居郎入侍邇英講不逾時遷中書舍人雖忝冒愈深而瞻望清光與日俱遠追記當時所見作四絕句呈同省諸公  其二','蘇轍','宋','宋诗','song-poetry','','[]','銅瓶灑遍不勝寒，雨點勻圓凍未乾。',32,'全唐诗/poet.song.48000.json','["銅瓶灑遍不勝寒，雨點勻圓凍未乾。", "回首曈矓朝日上，槐龍對舞覆衣冠。"]'),
('4cdd06f3-bf65-43f5-9379-ba652818e6e1','去年冬轍以起居郎入侍邇英講不逾時遷中書舍人雖忝冒愈深而瞻望清光與日俱遠追記當時所見作四絕句呈同省諸公  其三','蘇轍','宋','宋诗','song-poetry','','[]','早歲西廂跪直言，起迎天步晚臨軒。',32,'全唐诗/poet.song.48000.json','["早歲西廂跪直言，起迎天步晚臨軒。", "何知老侍曾孫聖，欲泣龍髯吐復吞。"]'),
('41f6c79a-a25e-46f8-aa95-f19408c8bdd2','去年冬轍以起居郎入侍邇英講不逾時遷中書舍人雖忝冒愈深而瞻望清光與日俱遠追記當時所見作四絕句呈同省諸公  其四','蘇轍','宋','宋诗','song-poetry','','[]','講罷淵然似不勝，詩書默已契天心。',32,'全唐诗/poet.song.48000.json','["講罷淵然似不勝，詩書默已契天心。", "高宗問答終垂世，未信諸儒測淺深。"]'),
('d37e82d6-7688-496f-979e-ad8f4d87a14c','次韵張問給事喜雨','蘇轍','宋','宋诗','song-poetry','','[]','已收蠶麥無多日，旋喜山川同一雲。',64,'全唐诗/poet.song.48000.json','["已收蠶麥無多日，旋喜山川同一雲。", "禾黍趁時青覆壠，池塘流潤淥生文。", "兩宮尚廢清晨集，中禁初消永夜薰。", "倉粟半空民望足，深耕疾耨肯忘君。"]'),
('1ebb9265-23c2-474f-b497-cdef39ab0f95','次韵宋構朝請歸守彭城','蘇轍','宋','宋诗','song-poetry','','[]','得郡迎親願不違，書來無復寄當歸。',64,'全唐诗/poet.song.48000.json','["得郡迎親願不違，書來無復寄當歸。", "馬馳未覺西南遠，烏哺何辭日夜飛。", "湖水欲平官舍好，茶征初復訟氓稀。", "平反聞道加餐飯，五褲應須換破衣。"]'),
('08234f64-7915-4c5a-a461-70fe536d3e71','次韵劉貢父西掖種竹','蘇轍','宋','宋诗','song-poetry','','[]','竹迷誰定知迷否，趁取滂沱好雨初。',64,'全唐诗/poet.song.48000.json','["竹迷誰定知迷否，趁取滂沱好雨初。", "栽向鳳池吹律處，斸從芸閣殺青餘。", "迎風一嘯朝回早，弄月相差直宿疏。", "應怪籍咸林下客，相看不飲作除書。"]'),
('c14aaa35-5e8b-4d7e-9a09-4d155839c02c','次韵劉貢父省中獨直','蘇轍','宋','宋诗','song-poetry','','[]','簾深巧爲隔朝暾，竹密時能引雀喧。',64,'全唐诗/poet.song.48000.json','["簾深巧爲隔朝暾，竹密時能引雀喧。", "朝罷宿酲還續夢，靜中諸妄稍歸根。", "坐曹聞道仍分省，出沐誰當與比軒。", "竹簟茅檐它日事，重因遺咏記君恩。"]'),
('8c72598d-c3d6-4108-848f-42e26eaa6cfa','得告家居次韵貢父見寄','蘇轍','宋','宋诗','song-poetry','','[]','君恩賜告許歸來，雨後中庭有綠苔。',64,'全唐诗/poet.song.48000.json','["君恩賜告許歸來，雨後中庭有綠苔。", "起問日高三丈久，卧聞車過九門開。", "泥封連日傳新語，腕脫知君有軼才。", "待得晴乾追後乘，未應塵土熱如灰。"]'),
('5baccc7f-273e-4578-822d-473cfdec7aa9','黄幾道郎中同年挽詞二首  其一','蘇轍','宋','宋诗','song-poetry','','[]','溫恭天賦此心良，惠愛人知政術長。',64,'全唐诗/poet.song.48000.json','["溫恭天賦此心良，惠愛人知政術長。", "井水無波任瓶綆，牛刀投隙應宮商。", "分符出遍名城守，携被歸從華省郎。", "不到汝陰遺恨遠，坐令湖水減清光。"]'),
('34c6f9ed-4186-4807-b9fc-2fadca8a9ac6','黄幾道郎中同年挽詞二首  其二','蘇轍','宋','宋诗','song-poetry','','[]','早歲相從能幾時，淮陽花發正遊嬉。',64,'全唐诗/poet.song.48000.json','["早歲相從能幾時，淮陽花發正遊嬉。", "鳴弓矍相人如堵，席地滄浪柳作帷。", "十載舊游真是夢，一時佳客尚存誰。", "遥聞葬日車千兩，漬酒綿中寄一悲。"]'),
('7c96487b-db5e-4d69-8fc8-34acdc3b4705','和王定國寄劉貢父','蘇轍','宋','宋诗','song-poetry','','[]','度嶺當年惜遠行，過淮今日似前生。',64,'全唐诗/poet.song.48000.json','["度嶺當年惜遠行，過淮今日似前生。", "留連秋思江侵海，摇蕩春心花滿城。", "欲寄尺書慵把筆，偶聞佳句獨含情。", "何時復看清虛會，醉聽秦箏促柱聲。"]'),
('fc963e3e-3741-4034-9f5f-0188c4dcb5ff','故濮陽太守贈光祿大夫王君正路挽詞二首  其一','蘇轍','宋','宋诗','song-poetry','','[]','落落承平佐，英英嗣世風。',48,'全唐诗/poet.song.48000.json','["落落承平佐，英英嗣世風。", "芝蘭託庭戶，鸞鵠峙椅桐。", "結客賢豪際，傾財緩急中。", "悲傷聞故老，淪謝未衰翁。"]'),
('639f844f-ecb6-4de1-bd4d-ea74eb9c5a2e','故濮陽太守贈光祿大夫王君正路挽詞二首  其二','蘇轍','宋','宋诗','song-poetry','','[]','吳中試良守，濮上繼嘉聲。',48,'全唐诗/poet.song.48000.json','["吳中試良守，濮上繼嘉聲。", "平賦權家恨，蠲租盜俗清。", "家貧久未葬，身去獨留名。", "天報多男子，終存好弟兄。"]'),
('b3018c85-e31b-43d6-b016-ca3de784cbd2','韓幹三馬','蘇轍','宋','宋诗','song-poetry','','[]','老馬側立鬃尾垂，御者高拱持青絲。',160,'全唐诗/poet.song.48000.json','["老馬側立鬃尾垂，御者高拱持青絲。", "心知後馬有爭意，兩耳微起如立錐。", "中馬直視翹右足，眼光未動心先馳。", "僕夫旋作奔佚想，右手正控黄金羈。", "雄姿駿發最後馬，回身奮鬣真權奇。", "圉人頓轡屹山立，未聽决驟爭雄雌。", "物生先後亦偶爾，有心何者能忘之。", "畫師韓幹豈知道，畫馬不獨畫馬皮。", "畫出三馬腹中事，似欲譏世人莫知。", "伯時一見笑不語，告我韓幹非畫師。"]'),
('8f524164-f72b-44d3-9a79-8ab0718b7672','書郭熙橫卷','蘇轍','宋','宋诗','song-poetry','','[]','鳳閣鸞臺十二屏，屏上郭熙題姓名。',198,'全唐诗/poet.song.48000.json','["鳳閣鸞臺十二屏，屏上郭熙題姓名。", "崩崖斷壑人不到，枯松野葛相欹傾。", "黄散給舍多肉食，食罷起愛飛泉清。", "皆言古人不復見，不知北門待詔白髮垂冠纓。", "袖中短軸纔半幅，慘澹百里山川橫。", "巖頭古寺擁雲木，沙尾漁舟浮晚晴。", "遥山可見不知處，落霞斷雁俱微明。", "十年江海興不淺，滿帆風雨通宵行。", "投篙椓杙便止宿，買魚沽酒相逢迎。", "歸來朝中亦何有，包裹觀闕圍重城。", "日高困睡心有適，夢中時作東南征。", "眼前欲擬要真物，拂拭束絹付與汾陽生。"]'),
('497bd39d-c061-4298-bb0d-1d0312b1a85d','題王生畫三蠶蜻蜓二首  其一','蘇轍','宋','宋诗','song-poetry','','[]','饑蠶未得食，宛轉不自持。',48,'全唐诗/poet.song.48000.json','["饑蠶未得食，宛轉不自持。", "食蠶聲如雨，但食無復知。", "老蠶不復食，矯首有所思。", "君畫三蠶意，還知使者誰。"]'),
('0dd7c6f2-ca52-49e4-a243-079fcbfb5a30','題王生畫三蠶蜻蜓二首  其二','蘇轍','宋','宋诗','song-poetry','','[]','蜻蜓飛翾翾，向空無所著。',48,'全唐诗/poet.song.48000.json','["蜻蜓飛翾翾，向空無所著。", "忽然逢飛蚊，驗爾饑火作。", "一飽困竹稍，凝然反冥寞。", "若無饑渴患，何貴一簞樂。"]'),
('64fcab87-2642-4547-8887-4dd44a3b1a50','贈寫真李道士','蘇轍','宋','宋诗','song-poetry','','[]','君不見景靈六殿圖功臣，進賢大羽東西陳。',147,'全唐诗/poet.song.48000.json','["君不見景靈六殿圖功臣，進賢大羽東西陳。", "能令將相長在世，自古獨有曹將軍。", "嵩高李師掉頭笑，自言弄筆通前身。", "百年遺像誰復識，滿朝冠劍多偉人。", "據鞍一見心有得，臨窗相對疑通神。", "十年江海鬚半脫，歸來俯仰慚簪紳。", "一揮七尺倚牆立，客來顧我誠似君。", "金章紫綬本非有，綠蓑黄篛甘長貧。", "如何畫作白衣老，置之茅屋全吾真。"]'),
('0ea8cf82-13fc-4a29-8f9b-7432092096b5','次韵子瞻題郭熙平遠二絕  其一','蘇轍','宋','宋诗','song-poetry','','[]','亂山無盡水無邊，田舍漁家共一川。',32,'全唐诗/poet.song.48000.json','["亂山無盡水無邊，田舍漁家共一川。", "行遍江南識天巧，臨窗開卷兩茫然。"]'),
('bab27e5d-fac1-4054-9ce5-22ae6a2d6720','次韵子瞻題郭熙平遠二絕  其二','蘇轍','宋','宋诗','song-poetry','','[]','斷雲斜日不勝秋，付與騷人滿目愁。',32,'全唐诗/poet.song.48000.json','["斷雲斜日不勝秋，付與騷人滿目愁。", "父老如今亦才思，一蓑風雨釣槎頭。"]'),
('f1cde1c0-3f14-4087-965c-a0cf95343664','次韵錢勰待制秋懷','蘇轍','宋','宋诗','song-poetry','','[]','壯心老自消，秋思悲不怨。',120,'全唐诗/poet.song.48000.json','["壯心老自消，秋思悲不怨。", "中懷不堪七，那用日食萬。", "朝陽凈塗潦，白露霑草蔓。", "夾衣搜故褚，酒債積新券。", "狙猿便林藪，冠带愁檻圈。", "夢追赤松游，食我青精飯。", "歸心久已爾，佳句聊復勸。", "近聞洮東將，間出邊馬健。", "裨王坐受縛，右袂行將獻。", "念此愧無功，歸歟適吾願。"]'),
('eba8e26a-bb5b-4a90-8ae6-88305087bdfd','宿滎陽甯氏園','蘇轍','宋','宋诗','song-poetry','','[]','喧卑背城市，曠蕩臨溪水。',48,'全唐诗/poet.song.48000.json','["喧卑背城市，曠蕩臨溪水。", "車流泝絕壁，河潤及桃李。", "居人有佳思，過客得新喜。", "中橋一回顧，欲入迷所自。"]'),
('19b91d74-572b-434d-94c5-86daab74a2f2','滎陽唐高祖太宗石刻像','蘇轍','宋','宋诗','song-poetry','','[]','誰言膚寸像，勝力妙人天。',48,'全唐诗/poet.song.48000.json','["誰言膚寸像，勝力妙人天。", "欲療衆生病，陰扶濟世賢。", "身微須覆護，眼凈照幾先。", "豈爲成功報，猶應歷劫緣。"]'),
('d6a0cfd7-193d-4ec3-b97e-d61cb2312da7','次韵劉貢父從駕','蘇轍','宋','宋诗','song-poetry','','[]','一經空記弟傳兄，舊德終慚比長卿。',64,'全唐诗/poet.song.48000.json','["一經空記弟傳兄，舊德終慚比長卿。", "扈駕聯翩來接武，登科先後憶題名。", "竹林共集連諸子，棣萼相輝頼友生。", "它日都門俱引去，不應廣受獨華榮。"]'),
('12339bcb-4bdd-4b29-842f-64f9e7112fb5','次韵劉貢父和韓康公憶其弟持國二首  其一','蘇轍','宋','宋诗','song-poetry','','[]','霜風瑟瑟卷梧蕉，燕處超然夜寂寥。',64,'全唐诗/poet.song.48000.json','["霜風瑟瑟卷梧蕉，燕處超然夜寂寥。", "羽客信來丹鼎具，石淙夢斷水聲遥。", "赤松作伴誰當見，黄鵠高飛未易招。", "劍履終身定何益，勤勞付與沛中蕭。"]'),
('a1a7319d-c04d-4c85-bf9b-d4b208d297ed','次韵劉貢父和韓康公憶其弟持國二首  其二','蘇轍','宋','宋诗','song-poetry','','[]','愛君憂世老彌深，特操要須得失臨。',64,'全唐诗/poet.song.48000.json','["愛君憂世老彌深，特操要須得失臨。", "晚歲飛騰推有德，故鄉安穩信無心。", "小邦近似西山隠，元氣終當北斗斟。", "聖主方求三世舊，老臣何止一遺簪。"]'),
('2c014a05-cb81-4526-9e55-f667f5613f61','聞京東有道人號賀郎中者唐人也其徒有識之者作詩寄之','蘇轍','宋','宋诗','song-poetry','','[]','賀老稽山去不還，鏡湖獨棹釣魚船。',64,'全唐诗/poet.song.48000.json','["賀老稽山去不還，鏡湖獨棹釣魚船。", "南來太白尋無處，却作郎官又幾年。", "岱下迎鸞驚典謁，蒙山施藥愍耕田。", "試窮脚力追行迹，亦使今生識地仙。"]'),
('1fbac690-44db-4053-81eb-d80b0231121b','送家安國赴成都教授三絕  其一','蘇轍','宋','宋诗','song-poetry','','[]','城西社下老劉君，春服舞雩今幾人。',32,'全唐诗/poet.song.48000.json','["城西社下老劉君，春服舞雩今幾人。", "白髮弟兄驚我在，喜君游宦亦天倫。"]'),
('b5180e9f-b0aa-4e62-be7f-613ea54bf8cf','送家安國赴成都教授三絕  其二','蘇轍','宋','宋诗','song-poetry','','[]','垂白相逢四十年，猖狂情味老俱闌。',32,'全唐诗/poet.song.48000.json','["垂白相逢四十年，猖狂情味老俱闌。", "論兵頓似前賢語，莫作當年故目看。"]'),
('009c6c5f-e797-479e-b711-ef3baa9147c5','送家安國赴成都教授三絕  其三','蘇轍','宋','宋诗','song-poetry','','[]','石室多年款志平，新書久溷里中生。',32,'全唐诗/poet.song.48000.json','["石室多年款志平，新書久溷里中生。", "遣師今見朝廷意，文律還應似兩京。"]'),
('9cdfe247-b1dd-41a9-82e5-c1b5fefc2902','送歐陽辯','蘇轍','宋','宋诗','song-poetry','','[]','我年十九識君翁，鬚髮白盡顴頰紅。',240,'全唐诗/poet.song.48000.json','["我年十九識君翁，鬚髮白盡顴頰紅。", "奇姿雲卷出翠阜，高論河决生清風。", "我時少年豈知道，因緣父兄願承教。", "文章疏略未足云，舉止猖狂空自笑。", "公家多士如牛毛，揚眉抵掌氣相高。", "下客逡巡愧知己，流枿低昂隨所遭。", "却來京洛三十載，重到公家二君在。", "伯亡仲逝無由追，淚落數行心破碎。", "京城東西正十里，雨落泥深旱塵起。", "衣冠纏繞類春蠶，一歲相從知有幾。", "去年叔爲尚書郎，家傳舊業行有望。", "今年季作澶淵吏，米鹽騷屑何當起。", "前輩今無一二存，後來幸有風流似。", "黄河西行淤沒屋，桑柘如雲麥禾熟。", "年豐事少似宜君，飽讀遺書心亦足。"]'),
('4d4cf7c5-da96-468d-9545-1ba9c5c5b148','送韓康公歸許州','蘇轍','宋','宋诗','song-poetry','','[]','功成不願居，身退有餘勇。',120,'全唐诗/poet.song.48000.json','["功成不願居，身退有餘勇。", "心安里閭適，望益縉紳重。", "朝爲北闕辭，莫犯南河凍。", "人知疏公達，王命顯父送。", "百壺山泉溢，千兩春雷動。", "旋聞二季賢，繼以一章控。", "詔書未云可，廷論已爭竦。", "茲行迫寒食，歸及掃先壟。", "萬人擁道看，一子腰金從。", "爾曹勿驚嗟，令德勸勤種。"]'),
('afe592c8-3311-4b95-a87a-59a5c9e5b3ec','三日上辛祈穀除日宿齋戶部右曹元日賦三絕句寄呈子瞻兄  其一','蘇轍','宋','宋诗','song-poetry','','[]','七度江南自作年，去年初喜奉椒槃。',32,'全唐诗/poet.song.48000.json','["七度江南自作年，去年初喜奉椒槃。", "冬來誤入文昌省，連日齋居未許還。"]'),
('04397003-aa4d-44f7-80f1-72c69c7f9e41','三日上辛祈穀除日宿齋戶部右曹元日賦三絕句寄呈子瞻兄  其二','蘇轍','宋','宋诗','song-poetry','','[]','今歲初辛日正三，明朝春氣漸東南。',32,'全唐诗/poet.song.48000.json','["今歲初辛日正三，明朝春氣漸東南。", "還家强作銀幡會，雪底蒿芹欲滿籃。"]'),
('b3b8ee4c-dda6-45c5-bfff-063f76082f9b','三日上辛祈穀除日宿齋戶部右曹元日賦三絕句寄呈子瞻兄  其三','蘇轍','宋','宋诗','song-poetry','','[]','北客南來歲欲除，燈山火急萬人扶。',32,'全唐诗/poet.song.48000.json','["北客南來歲欲除，燈山火急萬人扶。", "欲觀翠輦巡遊盛，深怯南宮鎖鑰拘。"]'),
('0f459eac-adfb-4ec3-ba73-0bad7e23ccab','次韵王欽臣祕監集英殿井','蘇轍','宋','宋诗','song-poetry','','[]','碧甃涵雲液，銅瓶響玉除。',48,'全唐诗/poet.song.48000.json','["碧甃涵雲液，銅瓶響玉除。", "汲花攢點罷，灑霧喚班初。", "龍餠煎無數，螭研滴有餘。", "從官方醉飽，一酌解清虛。"]'),
('593275f8-ee6c-4bfd-9c43-8d8f0bca2fa8','集賢殿考試罷二首  其一','蘇轍','宋','宋诗','song-poetry','','[]','振鷺紛紛未著行，初從江海覘清光。',64,'全唐诗/poet.song.48000.json','["振鷺紛紛未著行，初從江海覘清光。", "卷聲風雨中庭起，筆勢雲烟累幅長。", "病眼尚能分白黑，衆毛空復數驪黄。", "禁中已許公孫第，得失何私物自忙。"]'),
('882149c8-ec12-4e60-be5b-0ec25ec1ba0e','集賢殿考試罷二首  其二','蘇轍','宋','宋诗','song-poetry','','[]','衰病相侵眼漸昏，青燈細字苦勞神。',64,'全唐诗/poet.song.48000.json','["衰病相侵眼漸昏，青燈細字苦勞神。", "遍看大軸知無力，聽誦奇篇頼有人。", "前日鼓旗聞苦戰，明朝雷雨出潛鱗。", "殿廬困極唯思睡，却憶登科似後身。"]'),
('1ef42a64-9604-49ac-931f-cc1047ad24ea','問蔡肇求李公麟畫觀音德雲','蘇轍','宋','宋诗','song-poetry','','[]','好事桓靈寶，多才顧長康。',48,'全唐诗/poet.song.48000.json','["好事桓靈寶，多才顧長康。", "何嘗爲人畫，但可設奇將。", "久聚要當散，能分慰所望。", "清新二大士，畀我夜燒香。"]'),
('6871284e-90e8-4c84-a99c-ee1a42875c37','五月一日同子瞻轉對','蘇轍','宋','宋诗','song-poetry','','[]','羸病不堪金束腰，永懷江海舊漁樵。',64,'全唐诗/poet.song.48000.json','["羸病不堪金束腰，永懷江海舊漁樵。", "對床貪聽連宵雨，奏事驚同朔旦朝。", "大耿功名元自異，中茅服食舊相要。", "一封同上憐狂直，詔許昌言頼有堯。"]'),
('df96a78f-ddc5-4c0c-9eb2-592d1d4d5188','次韵劉貢父題文潞公草書','蘇轍','宋','宋诗','song-poetry','','[]','鷹揚不減少年時，墨作龍蛇紙上飛。',32,'全唐诗/poet.song.48000.json','["鷹揚不減少年時，墨作龍蛇紙上飛。", "應笑學書心力盡，臨池寫遍未裁衣。"]'),
('70ddc308-0a6e-441b-a8a8-541670310044','韓康公挽詞三首  其一','蘇轍','宋','宋诗','song-poetry','','[]','閥閱元高世，功名自發身。',48,'全唐诗/poet.song.48000.json','["閥閱元高世，功名自發身。", "堂堂揖真相，矯矯出稠人。", "許國心先定，輕財物自親。", "傳經比韋氏，世世得良臣。"]'),
('d13c7f07-d760-44a4-af15-42f21d733dcb','韓康公挽詞三首  其二','蘇轍','宋','宋诗','song-poetry','','[]','耆年時一二，新第闕西南。',48,'全唐诗/poet.song.48000.json','["耆年時一二，新第闕西南。", "好客心終在，忘懷日縱談。", "規模人共記，風味我猶諳。", "誰是羊曇首，回車意不堪。"]'),
('1c2f3751-c533-43dc-8ed4-0296eb264ce7','韓康公挽詞三首  其三','蘇轍','宋','宋诗','song-poetry','','[]','師曠聞弦日，相如作賦年。',48,'全唐诗/poet.song.48000.json','["師曠聞弦日，相如作賦年。", "雖慚衆人後，貪值主文賢。", "北道初聞召，南江正遠遷。", "平生闕親近，遺恨屬新阡。"]'),
('a782acd3-4c0c-49d5-b2e3-9f7455c02c26','送王宗望郎中赴河東漕','蘇轍','宋','宋诗','song-poetry','','[]','春初戎馬掠河壖，屬國倉皇不解鞍。',64,'全唐诗/poet.song.48000.json','["春初戎馬掠河壖，屬國倉皇不解鞍。", "未免驅民餽邊食，旋聞奉使輟郎官。", "年高轉覺精神勝，慮穩要令事業安。", "持節近看葱嶺雪，擁裘應慣雁門寒。"]'),
('4cd6c55c-ea97-4e9f-81dc-2fefbd6db96b','送高士敦赴成都兵鈐','蘇轍','宋','宋诗','song-poetry','','[]','揚雄老病久思歸，家在成都更向西。',64,'全唐诗/poet.song.48000.json','["揚雄老病久思歸，家在成都更向西。", "邂逅王孫馳驛騎，丁寧父老問耕犁。", "禪房何處不行樂，壁像君家有舊題。", "德厚不妨三世將，時平空見萬夫齊。"]'),
('e0ea04c0-5e88-4611-b88e-b1ced06d4553','盧鴻草堂圖','蘇轍','宋','宋诗','song-poetry','','[]','昔爲太室遊，盧巖在東麓。',120,'全唐诗/poet.song.48000.json','["昔爲太室遊，盧巖在東麓。", "直上登封壇，一夜繭生足。", "徑歸不復往，巒壑空在目。", "安知有十志，舒卷不盈幅。", "一處一盧生，裘褐蔭喬木。", "方爲世外人，行止何須錄。", "百年入篋笥，犬馬同一束。", "嗟予縛世累，歸來有茅屋。", "江干百畝田，清泉映修竹。", "尚將逃姓名，豈復上圖軸。"]'),
('d26c43bd-fb52-429b-b8a8-b9b5c7ac7a03','秦虢夫人走馬圖二絕  其一','蘇轍','宋','宋诗','song-poetry','','[]','秦虢風流本一家，豐枝穠葉映雙花。',32,'全唐诗/poet.song.48000.json','["秦虢風流本一家，豐枝穠葉映雙花。", "欲分妍醜都無處，夾道遊人空嘆嗟。"]'),
('9994b75b-dff0-4c81-8fcf-c8ea6940d8e3','秦虢夫人走馬圖二絕  其二','蘇轍','宋','宋诗','song-poetry','','[]','朱幩玉勒控飛龍，笑語喧嘩步驟同。',32,'全唐诗/poet.song.48000.json','["朱幩玉勒控飛龍，笑語喧嘩步驟同。", "馳入九重人不見，金鈿翠羽落泥中。"]'),
('979736d0-bb71-4fc2-8da3-226ed567df59','韓幹二馬','蘇轍','宋','宋诗','song-poetry','','[]','玉带胡奴騎且牽，銀騣白鼻兩爭先。',32,'全唐诗/poet.song.48000.json','["玉带胡奴騎且牽，銀騣白鼻兩爭先。", "八坊龍種知何數，乞與岐邠並錦韉。"]'),
('4dac383d-3464-4db1-876c-0773340c4ba5','試制舉人呈同舍諸公二首  其一','蘇轍','宋','宋诗','song-poetry','','[]','垣中不減臺端峻，池上來從柱下嚴。',64,'全唐诗/poet.song.48000.json','["垣中不減臺端峻，池上來從柱下嚴。", "同直舊曾連月久，蹔來還喜二公兼。", "直言已許侵彈奏，新告行聞振滯淹。", "顧我粗官何所與，西曹只合論茶鹽。"]'),
('9abef883-04c4-4f48-915a-67dd9b6d8e3b','試制舉人呈同舍諸公二首  其二','蘇轍','宋','宋诗','song-poetry','','[]','早歲同科止六人，中年零落半埃塵。',64,'全唐诗/poet.song.48000.json','["早歲同科止六人，中年零落半埃塵。", "却將舊學收新進，幾誤今生是後身。", "骯髒別都遺老驥，沉埋祕府愧潛鱗。", "憐君尚勝劉蕡在，白首諸侯呼上賓。"]'),
('f8cc4b40-f947-4a70-b1f3-fe06b85473fc','次韵張去華院中感懷','蘇轍','宋','宋诗','song-poetry','','[]','登朝已老似王陽，脫葉何堪霧雨凉。',64,'全唐诗/poet.song.48000.json','["登朝已老似王陽，脫葉何堪霧雨凉。", "案上細書憎蟻黑，禁中新酒愛鵝黄。", "臨階野菊偏能瘦，倚檻青松解許長。", "仕宦不由天祿閣，坐曹終日漫皇皇。"]'),
('a18e5044-6512-425d-a4a2-361c68ecac1c','送周思道朝議歸守漢州三絕  其一','蘇轍','宋','宋诗','song-poetry','','[]','早緣民事失茶官，解印重來十二年。',32,'全唐诗/poet.song.48000.json','["早緣民事失茶官，解印重來十二年。", "美惡一周還自復，始知東里解言天。"]'),
('8577b07d-60fb-46af-983e-1b390858786c','送周思道朝議歸守漢州三絕  其二','蘇轍','宋','宋诗','song-poetry','','[]','梓漢東西甲乙州，同時父子兩諸侯。',32,'全唐诗/poet.song.48000.json','["梓漢東西甲乙州，同時父子兩諸侯。", "它年我作西歸計，兄弟還能得此不。"]'),
('414408ce-bf46-4b93-b468-f1f9b67ad6c6','送周思道朝議歸守漢州三絕  其三','蘇轍','宋','宋诗','song-poetry','','[]','酒壓郫筒憶舊酤，花傳丘老出新圖。',32,'全唐诗/poet.song.48000.json','["酒壓郫筒憶舊酤，花傳丘老出新圖。", "此行真勝成都尹，直爲房公百頃湖。"]'),
('cf8db30c-7d69-4f20-bdab-4659aa99313c','程之元表弟奉使江西次前年送赴楚州韵戲別','蘇轍','宋','宋诗','song-poetry','','[]','送君守山陽，羨君食淮魚。',144,'全唐诗/poet.song.48000.json','["送君守山陽，羨君食淮魚。", "送君使鍾陵，羨君江上居。", "憐君喜爲吏，臨行不唏噓。", "紛紛出歌舞，綠髮照瓊梳。", "歸鞍踏凉月，倒盡清樽餘。", "嗟我病且衰，兀然守文書。", "齒疏懶食肉，一飯甘青蔬。", "愛水亦已乾，塵土生空渠。", "清貧雖非病，簡易由無儲。", "家使赤脚嫗，何煩短轅車。", "君船繫東橋，茲行尚徐徐。", "對我竟不飲，問君獨何歟。"]'),
('e5c6127c-d167-4fba-a94e-57a95f8f9bd3','表弟程之邵奉議知泗州','蘇轍','宋','宋诗','song-poetry','','[]','馬有千里足，所願百里程。',120,'全唐诗/poet.song.48000.json','["馬有千里足，所願百里程。", "馬心自爲計，安用終日行。", "何人志四方，欲買千金輕。", "吾弟有俊才，見事心眼明。", "二年坐北部，萬口傳佳聲。", "談笑頑狡伏，何曾用敲榜。", "艱難得銅虎，洗眼長淮清。", "民事不足爲，但當食魚烹。", "負重貴餘力，過飽多傷生。", "不見大路馬，垂頭畏繁纓。"]'),
('fe46394f-c850-4d10-bf70-8834b12b988c','次韵子瞻書黄庭內景卷後贈蹇道士拱辰','蘇轍','宋','宋诗','song-poetry','','[]','君誦黄庭內外篇，本欲洗心不求仙。',104,'全唐诗/poet.song.48000.json','["君誦黄庭內外篇，本欲洗心不求仙。", "夜視片月墮我前，黑氛剝盡朝日妍。", "一暑一寒久自堅，體中風行上通天。", "亭亭孤立孰傍緣，至哉道師昔云然。", "既已得之戒不傳，知我此心未虧騫。", "指我嬰兒藏谷淵，言未絕口行已旋，我思其言夜不眠。"]'),
('72967f14-dc8d-4534-addc-aa116db2a069','次韵子瞻好頭赤','蘇轍','宋','宋诗','song-poetry','','[]','沿邊壯士生食肉，小來騎馬不騎竹。',64,'全唐诗/poet.song.48000.json','["沿邊壯士生食肉，小來騎馬不騎竹。", "翩然赤手挑青絲，捷下巔崖試深谷。", "牽入故關榆葉赤，未慣中原暖風日。", "黄金絡頭依圉人，俯聽北風懷所歷。"]'),
('b1ed9543-cb2d-4699-aaa1-af4f32bc2777','送葆光蹇師遊廬山','蘇轍','宋','宋诗','song-poetry','','["\u5e90\u5c71"]','建城市中有狂人，縱酒駡市無與親。',128,'全唐诗/poet.song.48000.json','["建城市中有狂人，縱酒駡市無與親。", "敲門訪我何逡巡，頭蓬面垢氣甚真。", "截河引水登崑崙，下洗尺宅骨髓勻。", "告我入室要自門，仙翁道師豈遺君。", "歸來插足九陌塵，獨遊凝祥芳草春。", "蕭然孤鶴鳴鷄羣，子欲不死存谷神。", "海山微明朝日暾，丹成寄子勿妄云。", "出入無朕窮無垠，相思一笑君乃信。"]'),
('3fb4faea-e13c-466c-8523-6795688c3cca','同子瞻次梅聖俞舊韵題鄉舍木山','蘇轍','宋','宋诗','song-poetry','','[]','江槎出沒浮犀牛，波濤掀天谷爲洲。',112,'全唐诗/poet.song.48000.json','["江槎出沒浮犀牛，波濤掀天谷爲洲。", "江寒水落驚霜秋，危根瘦節鳴寒流。", "脆朽吹去誰鎸鎪，連峰疊嶂立酋酋。", "吾家此山不易得，十年棄置空自尤。", "猿號鶴唳豈無意，委蛇怪我懷羔裘。", "西歸父老拍手笑，笑憶翁子躬薪槱。", "去時三山今有五，不問故園惟一丘。"]'),
('4302829e-f348-44a8-90f6-8191d0ba511f','次韵子瞻送千乘千能','蘇轍','宋','宋诗','song-poetry','','[]','少年食糠覈，吐去願一官。',216,'全唐诗/poet.song.48000.json','["少年食糠覈，吐去願一官。", "躬耕遇斂穫，不知以爲歡。", "謂言一飛翔，要勝終屈蟠。", "朝廷未遑入，江海失所安。", "多憂變華髮，照影慚雙鸞。", "恩從萬里歸，獨喜大節完。", "日食太倉米，篋中有餘紈。", "奇窮不當爾，自信處此難。", "長女聞孀居，將食淚滴槃。", "老妻飽憂患，悲吒摧心肝。", "西飛問黄鵠，誰當救饑寒。", "二子憐我老，輦致心一寬。", "別久得會合，喜極成辛酸。", "忽聞倚門望，有書驚歲闌。", "深情見緩急，欲報非琅玕。", "勸爾勤孝友，慎毋慕衣冠。", "淵渟自成井，放瀉當生瀾。", "豈有白雪駒，舉足無和鑾。"]'),
('2b4b6b8d-6370-476b-b518-981b278f1ee9','題王詵都尉畫山水橫卷三首  其一','蘇轍','宋','宋诗','song-poetry','','["\u957f\u6c5f"]','摩詰本詞客，亦自名畫師。',220,'全唐诗/poet.song.48000.json','["摩詰本詞客，亦自名畫師。", "平生出入輞川上，鳥飛魚泳嫌人知。", "山光盎盎著眉睫，水聲活活流肝脾。", "行吟坐咏皆自見，飄然不作世俗詞。", "高情不盡落縑素，連峰絕澗開重帷。", "百年流落存一二，錦囊玉軸酬不訾。", "誰令食肉貴公子，不學父祖驅熊羆。", "細氈凈几讀文史，落筆璀璨傳新詩。", "青山長江豈君事，一揮水墨光淋漓。", "手中五尺小橫卷，天末萬里分毫釐。", "謫官南出止均潁，此心通達無不之。", "歸來纏裹任紈綺，天馬性在終難羈。", "人言摩詰是前世，欲比顧老疑不癡。", "桓公崔公不可與，但可與我寬衰遲。"]'),
('4704e772-78e7-412a-9da0-f4d4e3cda770','題王詵都尉畫山水橫卷三首  其二','蘇轍','宋','宋诗','song-poetry','','[]','憐君將帥雖有種，多君智慧初無師。',224,'全唐诗/poet.song.48000.json','["憐君將帥雖有種，多君智慧初無師。", "篇章俊發已可駭，丹青妙絕當誰知。", "自言五色苦亂目，況乃旨酒長傷脾。", "手狂但可時弄筆，口病未免多微詞。", "歌鐘一散任池館，幅巾靜坐空書帷。", "偶從禪老得真趣，此身不足非財訾。", "世間翻覆岸爲谷，猛獸相食虎與羆。", "逝將得意比春夢，獨取妙語傳清詩。", "眼看宮釀瀉酥酪，未與村酒分醇漓。", "解鞍駿馬空伏櫪，寄書黄狗閑生釐。", "江山平日偶有得，不自圖寫渾忘之。", "臨窗展卷聊自適，盤礴豈復冠裳羈。", "欲乘漁艇發吾興，願入野寺嗟兒癡。", "行纏布襪雖已具，山中父老應嫌遲。"]'),
('ab4909cb-4005-4d06-8da7-8e5f61ad090e','題王詵都尉畫山水橫卷三首  其三','蘇轍','宋','宋诗','song-poetry','','[]','我昔得罪遷南夷，性命頃刻存篙師。',224,'全唐诗/poet.song.48000.json','["我昔得罪遷南夷，性命頃刻存篙師。", "風吹波蕩到官舍，號呼誰復相聞知。", "小園畜蟻防橘蠹，空庭養蜂收蜜脾。", "讀書一生空自笑，賣鹽竟日那復詞。", "城中清溪可濯漱，城上連峰堪幕帷。", "十千薄俸聊足用，魚多米賤憂無訾。", "東坡居士最岑寂，岌然深藂見狐羆。", "坐隅止鵩偶成賦，槃中食蟆時作詩。", "憐君富貴可炙手，一時出走羞啜醨。", "澤傍憔悴凡幾歲，胸中芥蒂無一釐。", "江山別來今久矣，不獨能言能畫之。", "同朝執手不容久，笑我野馬方受羈。", "袖中短卷墨猶濕，傍人笑指吾儕癡。", "方求農圃救貧病，它年未用譏樊遲。"]'),
('55efab16-65fe-4bc7-afb8-10e7911c4821','次韵子瞻十一月旦日鎖院賜酒及燭','蘇轍','宋','宋诗','song-poetry','','[]','銅鐶玉鎖閉空堂，腕脫初驚筆札忙。',64,'全唐诗/poet.song.48000.json','["銅鐶玉鎖閉空堂，腕脫初驚筆札忙。", "紅燭遥憐風雪暗，黄封微瀉桂椒香。", "光明坐覺幽陰破，溫暖深知覆育長。", "明日白麻傳好語，曼聲微繞殿中央。"]'),
('647b123e-971b-44d9-a542-e90d8de346fe','送周正孺自考功郎中歸守梓潼兼簡呂元鈞三絕  其一','蘇轍','宋','宋诗','song-poetry','','[]','白髮熙寧老諍臣，凜然心膽大於身。',32,'全唐诗/poet.song.48000.json','["白髮熙寧老諍臣，凜然心膽大於身。", "吾儕坐看馮唐去，誰起雲中廢棄人。"]'),
('31aacc47-d8a6-4dcf-aadb-9e34e73d874d','送周正孺自考功郎中歸守梓潼兼簡呂元鈞三絕  其二','蘇轍','宋','宋诗','song-poetry','','[]','十年符竹守吾州，故吏相逢嘲土牛。',32,'全唐诗/poet.song.48000.json','["十年符竹守吾州，故吏相逢嘲土牛。", "毋謂徐公不堪用，諸人自與世沉浮。"]'),
('fbb94c36-a845-4f7d-9388-7c6c1c27ad78','送周正孺自考功郎中歸守梓潼兼簡呂元鈞三絕  其三','蘇轍','宋','宋诗','song-poetry','','[]','東道如聞近稍安，乘驄按部凜生寒。',32,'全唐诗/poet.song.48000.json','["東道如聞近稍安，乘驄按部凜生寒。", "忽逢太守能相下，俱是從來言事官。"]'),
('66b59183-6594-49b8-98c8-4e3294f394a3','雪中訪王定國感舊','蘇轍','宋','宋诗','song-poetry','','[]','昔游都城歲方除，飛雪紛紛落花絮。',128,'全唐诗/poet.song.48000.json','["昔游都城歲方除，飛雪紛紛落花絮。", "徑走城東求故人，馬蹄旋沒無尋處。", "翰林詞人呼巨源，笑談通夜倒清樽。", "住在城西不能返，醉卧吉祥朝日暾。", "相逢却說十年事，往事皆非隔生死。", "惟有飛霙似昔時，許君一醉那須起。", "蘭亭俯仰迹已陳，黄公酒壚愁殺人。", "君知聚散翻覆手，莫作吳楚乘朱輪。"]'),
('e6f13a3a-414a-43e2-bc93-4acd9edb3fe5','次韵王定國見贈','蘇轍','宋','宋诗','song-poetry','','[]','枯木無枝不記年，寒灰誰遣强吹然。',64,'全唐诗/poet.song.48000.json','["枯木無枝不記年，寒灰誰遣强吹然。", "南遷不折知非妄，未老求閒愈覺賢。", "屢出詩章新管籥，偶開畫卷小山川。", "簿書填委慚君甚，撥去歸來粗了眠。"]'),
('5aa9a6de-83aa-49c0-9ead-43674d3bf9c8','王子難龍圖挽詞','蘇轍','宋','宋诗','song-poetry','','[]','帝子乘鸞已列仙，遺芳留得衆孫賢。',64,'全唐诗/poet.song.48000.json','["帝子乘鸞已列仙，遺芳留得衆孫賢。", "俊科蚤與寒儒競，禁從終償白髮年。", "輦路聯鑣驚往事，圃田回首泣新阡。", "舊聞推曆知天命，看熟黄粱定洒然。"]'),
('419f5876-90d9-4629-98e8-3990e0582504','次韵李豸秀才來別子瞻仍謝惠馬','蘇轍','宋','宋诗','song-poetry','','[]','小床卧客笑元龍，彈鋏無輿下舍中。',64,'全唐诗/poet.song.48000.json','["小床卧客笑元龍，彈鋏無輿下舍中。", "五馬不辭分後乘，輕裘初許敝諸公。", "隨人射虎氣終在，徒步白頭心頗同。", "遥想據鞍橫槊處，新詩一一建安風。"]'),
('e1f45c8f-5a60-4f16-8df9-99a54e480cd8','呂司空挽詞三首  其一','蘇轍','宋','宋诗','song-poetry','','[]','少年輕富貴，一意在詩書。',48,'全唐诗/poet.song.48000.json','["少年輕富貴，一意在詩書。", "共恨經綸晚，纔收老病餘。", "寡言知德勝，善應本中虛。", "卒相承平業，謳歌元祐初。"]'),
('6d7fc75a-0ff7-42e8-9b77-d98eb3381467','呂司空挽詞三首  其二','蘇轍','宋','宋诗','song-poetry','','[]','將相家聲近，勳名晚歲隆。',48,'全唐诗/poet.song.48000.json','["將相家聲近，勳名晚歲隆。", "給扶安舊德，賜府壓羣公。", "不見彌縫迹，空推翼戴功。", "山公舊多可，寒士泣清風。"]'),
('a22f5416-e423-45b9-9c7f-41346761a645','呂司空挽詞三首  其三','蘇轍','宋','宋诗','song-poetry','','[]','罷郡來清潁，微官憶宛丘。',48,'全唐诗/poet.song.48000.json','["罷郡來清潁，微官憶宛丘。", "頹垣那可住，隠几若將休。", "復起民欣願，全歸天不留。", "世間反覆手，有德竟無憂。"]'),
('91986d32-3ba9-4354-849a-2142abf25a85','范蜀公挽詞三首  其一','蘇轍','宋','宋诗','song-poetry','','[]','能言人盡爾，有立世終稀。',48,'全唐诗/poet.song.48000.json','["能言人盡爾，有立世終稀。", "憂國常先衆，謀身亦勇歸。", "見奇初或笑，要極未應非。", "僅似西山老，終身止食薇。"]'),
('a95b01e7-33f5-4ab5-b536-6bc88482476d','范蜀公挽詞三首  其二','蘇轍','宋','宋诗','song-poetry','','[]','賦傳長嘯久，書奏鎛鐘新。',48,'全唐诗/poet.song.48000.json','["賦傳長嘯久，書奏鎛鐘新。", "共嘆文章手，終爲禮樂人。", "遺風滿臺閣，好語落簪紳。", "欲取褒雄比，終非骨鯁臣。"]'),
('844f57f1-89da-458f-bff5-8d13c42966fd','范蜀公挽詞三首  其三','蘇轍','宋','宋诗','song-poetry','','[]','劍外東來日，城西却住年。',48,'全唐诗/poet.song.48000.json','["劍外東來日，城西却住年。", "高齋留寓宿，旅食正蕭然。", "語愜聞投石，詩新看涌泉。", "清樽寄苦淚，一洒葉墳前。"]'),
('e26b62bd-d874-4b34-9491-4d0dc34521a2','范百嘉百歲昆仲挽詞二首  其一','蘇轍','宋','宋诗','song-poetry','','[]','少年何敏銳，才氣伏諸生。',48,'全唐诗/poet.song.48000.json','["少年何敏銳，才氣伏諸生。", "展卷五行下，揮毫萬字傾。", "百年殊未艾，一病竟無成。", "誰謂從夫子，同開鬰鬰城。"]'),
('2f1d9d82-c9c4-4530-8738-cf4dc58fdd1c','范百嘉百歲昆仲挽詞二首  其二','蘇轍','宋','宋诗','song-poetry','','[]','季子尤高爽，顔家早哭回。',48,'全唐诗/poet.song.48000.json','["季子尤高爽，顔家早哭回。", "白頭生便爾，黄壤遽相催。", "舊草誰收拾，新松剩插栽。", "悲傷有伯氏，諸子尚嬰孩。"]'),
('62f335e1-d539-4261-bc19-6d4a41028f0d','安厚卿樞密母夫人挽詞二首  其一','蘇轍','宋','宋诗','song-poetry','','[]','家起側微中，身兼富貴終。',48,'全唐诗/poet.song.48000.json','["家起側微中，身兼富貴終。", "慈仁本宜壽，勤約自成風。", "大府寧居久，名邦賜沐雄。", "共傳生子福，仍指讀書功。"]'),
('4ec6b81d-6a29-4258-99a1-487e3dca0884','安厚卿樞密母夫人挽詞二首  其二','蘇轍','宋','宋诗','song-poetry','','[]','早歲參戎幕，開門對粉牆。',48,'全唐诗/poet.song.48000.json','["早歲參戎幕，開門對粉牆。", "初聞寡兄弟，共羨好姑章。", "一別飛騰速，全歸福祿長。", "遺芳在子舍，它日望岩廊。"]'),
('cea1ce11-6bc3-46c1-af7d-309c4a0870d5','題李公麟山莊圖 建德館','蘇轍','宋','宋诗','song-poetry','','[]','龍眠淥凈中，微吟作雲雨。',24,'全唐诗/poet.song.48000.json','["龍眠淥凈中，微吟作雲雨。", "幽人建德居，知是清風主。"]'),
('fc5d1150-ec14-435e-861b-7bc9b5784e91','題李公麟山莊圖 墨禪堂','蘇轍','宋','宋诗','song-poetry','','[]','此心初無住，每與物皆禪。',24,'全唐诗/poet.song.48000.json','["此心初無住，每與物皆禪。", "如何一丸墨，舒卷化山川。"]'),
('a4232be8-b411-45b6-a38d-7dd40c2f7655','題李公麟山莊圖 華岩堂','蘇轍','宋','宋诗','song-poetry','','[]','佛口如瀾翻，初無一正定。',24,'全唐诗/poet.song.48000.json','["佛口如瀾翻，初無一正定。", "畫作正定看，於何是佛性。"]'),
('268f50a6-0b0b-42f7-99e5-609bd7b70f46','題李公麟山莊圖 雲薌閣','蘇轍','宋','宋诗','song-poetry','','[]','清溪便種稻，秋晚連雲熟。',24,'全唐诗/poet.song.48000.json','["清溪便種稻，秋晚連雲熟。", "不待見新舂，西風薌自足。"]'),
('764dde95-0b50-445e-984e-db17d96ea633','題李公麟山莊圖 發真塢','蘇轍','宋','宋诗','song-poetry','','[]','山開稍有路，水放亦成川。',24,'全唐诗/poet.song.48000.json','["山開稍有路，水放亦成川。", "游人得所息，真意方澹然。"]'),
('f702efb5-a6e9-4195-a0c0-1556109eac81','題李公麟山莊圖 薌茅館','蘇轍','宋','宋诗','song-poetry','','[]','山居少華麗，牽茅結凈屋。',24,'全唐诗/poet.song.48000.json','["山居少華麗，牽茅結凈屋。", "此間不受塵，幽人亦新沐。"]'),
('bd384f08-a38e-4ccb-8d0d-552f449ca638','題李公麟山莊圖 瓔珞岩','蘇轍','宋','宋诗','song-poetry','','[]','泉流逢石缺，脈散成寶網。',24,'全唐诗/poet.song.48000.json','["泉流逢石缺，脈散成寶網。", "水作瓔珞看，山是如來想。"]'),
('07026546-a2e0-449f-8bd9-dd0f6c643e9b','題李公麟山莊圖 棲雲室','蘇轍','宋','宋诗','song-poetry','','[]','石室空無主，浮雲自去來。',24,'全唐诗/poet.song.48000.json','["石室空無主，浮雲自去來。", "人間春雨足，歸意带風雷。"]'),
('e8ef6ac2-f0ee-4044-8310-172fe3d9a200','題李公麟山莊圖 秘全庵','蘇轍','宋','宋诗','song-poetry','','[]','世道自破碎，全理未嘗違。',24,'全唐诗/poet.song.48000.json','["世道自破碎，全理未嘗違。", "溪山亦何有，永覺平日非。"]'),
('50328687-6e8f-4bc5-9302-047da6b65b9b','題李公麟山莊圖 延華洞','蘇轍','宋','宋诗','song-poetry','','[]','共恨春不長，逡巡就摇落。',24,'全唐诗/poet.song.48000.json','["共恨春不長，逡巡就摇落。", "一見洞中天，真知世間惡。"]'),
('806d98ed-5e5d-4c8f-9257-f590b5166c95','題李公麟山莊圖 澄元谷','蘇轍','宋','宋诗','song-poetry','','[]','石門日不下，潭鏡月長臨。',24,'全唐诗/poet.song.48000.json','["石門日不下，潭鏡月長臨。", "細細溪風渡，相看識此心。"]'),
('a6334ad9-db03-41fb-9e9d-22daa0cbde0e','題李公麟山莊圖 雨花岩','蘇轍','宋','宋诗','song-poetry','','[]','岩花不可攀，翔蕊久未墮。',24,'全唐诗/poet.song.48000.json','["岩花不可攀，翔蕊久未墮。", "忽下幽人前，知子觀空坐。"]'),
('19dd0800-d327-4816-865d-02ed6c33fc06','題李公麟山莊圖 泠泠谷','蘇轍','宋','宋诗','song-poetry','','[]','層崖落飛泉，微風泛喬木。',24,'全唐诗/poet.song.48000.json','["層崖落飛泉，微風泛喬木。", "坐遣谷中人，家家有琴筑。"]'),
('871515c3-21da-4cb5-89ca-bea9ace84e13','題李公麟山莊圖 玉龍峽','蘇轍','宋','宋诗','song-poetry','','[]','白龍晝飲潭，修尾掛石壁。',24,'全唐诗/poet.song.48000.json','["白龍晝飲潭，修尾掛石壁。", "幽人欲下看，雨雹晴相射。"]'),
('2bbf99ec-c5f6-48a5-8e7c-820567cf497e','題李公麟山莊圖 觀音岩','蘇轍','宋','宋诗','song-poetry','','[]','倚崖開翠屏，臨潭置苔石。',24,'全唐诗/poet.song.48000.json','["倚崖開翠屏，臨潭置苔石。", "有所獨無人，君心得未得。"]'),
('9afb7c34-daf6-4620-bf7c-d72fd7e8cdb0','題李公麟山莊圖 垂雲沜','蘇轍','宋','宋诗','song-poetry','','[]','未見垂雲沜，其如歸興何。',24,'全唐诗/poet.song.48000.json','["未見垂雲沜，其如歸興何。", "路窮雙足熱，爲我洗磐陀。"]'),
('041a5e3a-0f5f-46ea-8756-aafcef77834e','題李公麟山莊圖 勝金岩','蘇轍','宋','宋诗','song-poetry','','[]','置馬步岩間，岩前得平地。',24,'全唐诗/poet.song.48000.json','["置馬步岩間，岩前得平地。", "肴蔬取行簏，粗飽有遺味。"]'),
('c497ca23-2ac2-4781-85d3-201977d197d8','題李公麟山莊圖 寶華岩','蘇轍','宋','宋诗','song-poetry','','[]','團團寶華岩，重重蔭珍木。',24,'全唐诗/poet.song.48000.json','["團團寶華岩，重重蔭珍木。", "歸來得商鼎，試鬻溪邊綠。"]'),
('67d9ccaf-19e2-4f3d-99c5-9a3883db85fa','題李公麟山莊圖 陳彭漈','蘇轍','宋','宋诗','song-poetry','','[]','蒼壁立精鐵，縣泉瀉天紳。',24,'全唐诗/poet.song.48000.json','["蒼壁立精鐵，縣泉瀉天紳。", "山行見已久，指與未來人。"]'),
('cbae6a7e-ade6-465c-ab6e-7e25e438fe28','題李公麟山莊圖 鵲源','蘇轍','宋','宋诗','song-poetry','','[]','溪深龜魚驕，石瘦椿楠勁。',24,'全唐诗/poet.song.48000.json','["溪深龜魚驕，石瘦椿楠勁。", "借子木蘭船，寬我芒鞋病。"]'),
('41199787-0716-4138-b4c2-2ddd499d1941','將使契丹九日對酒懷子瞻兄并示坐中','蘇轍','宋','宋诗','song-poetry','','[]','黄華已向初旬見，白酒相携九日嘗。',64,'全唐诗/poet.song.48000.json','["黄華已向初旬見，白酒相携九日嘗。", "萸少一枝心自覺，舂同斗粟味終長。", "蘭生庭下香時起，玉在人前坐亦凉。", "千里使胡須百日，蹔將中子治書囊。"]'),
('d8a7fc68-fa3c-44d0-932f-2c588e64ec68','題王詵都尉設色山卷後','蘇轍','宋','宋诗','song-poetry','','[]','還君橫卷空長嘆，問我何年便退休。',64,'全唐诗/poet.song.48000.json','["還君橫卷空長嘆，問我何年便退休。", "欲借岩阿著茅屋，還當溪口泊漁舟。", "經心蜀道雲生足，上馬胡天雪滿裘。", "萬里還朝徑歸去，江湖浩蕩一輕鷗。"]'),
('d7b2dc91-77aa-4f21-b0c0-69365b39db68','次韵子瞻相送使胡','蘇轍','宋','宋诗','song-poetry','','[]','朔雪胡沙試此身，青羅便面紫狐巾。',64,'全唐诗/poet.song.48000.json','["朔雪胡沙試此身，青羅便面紫狐巾。", "擁旜代北隨飛雁，頓足江東有卧麟。", "欺酒壺冰將送臘，照溪梅萼定先春。", "漢家五餌今方驗，更愧當年嘆息人。"]'),
('0450b34b-abcf-4ddb-9936-2db5b600780c','歐陽文忠公夫人挽詞二首  其一','蘇轍','宋','宋诗','song-poetry','','[]','先生才蓋世，家事少經心。',48,'全唐诗/poet.song.48000.json','["先生才蓋世，家事少經心。", "流落初相偶，委蛇志益深。", "功名入圖史，文字刻璆琳。", "有助知由內，騶虞欲重吟。"]'),
('5315945c-4d27-4d4e-94c3-1ee1b0da5808','歐陽文忠公夫人挽詞二首  其二','蘇轍','宋','宋诗','song-poetry','','[]','好禮忘耆老，持家歷盛衰。',48,'全唐诗/poet.song.48000.json','["好禮忘耆老，持家歷盛衰。", "謹嚴終致一，貧富各從宜。", "晚歲仍聞道，臨終竟不疑。", "外人傳一二，猶得載銘詩。"]'),
('ed6f5505-00f8-4794-bfb3-14e3a5370030','歐陽伯和仲純挽詞二首  其一','蘇轍','宋','宋诗','song-poetry','','[]','之人雖蚤病，對客每清言。',48,'全唐诗/poet.song.48000.json','["之人雖蚤病，對客每清言。", "不信疾爲累，要稱學有原。", "籧篨視名器，果遯指乾坤。", "長短何須問，傳家已抱孫。"]'),
('356ed990-1226-4301-b8f3-78293df59a3b','歐陽伯和仲純挽詞二首  其二','蘇轍','宋','宋诗','song-poetry','','[]','仲氏氣無前，爲文思涌泉。',48,'全唐诗/poet.song.48000.json','["仲氏氣無前，爲文思涌泉。", "飄然落筆地，時出疾邪篇。", "杶幹要經雪，驊騮行著鞭。", "凄凉悲故客，不及見華顛。"]'),
('72326f68-4945-408b-997d-3c5b50610af4','奉使契丹二十八首 次莫州通判劉涇韵二首 其一','蘇轍','宋','宋诗','song-poetry','','[]','北國亦知岐有夷，何嘗烽火報驚危。',64,'全唐诗/poet.song.48000.json','["北國亦知岐有夷，何嘗烽火報驚危。", "擁旜絕漠聞嘉語，緩带臨邊出好詩。", "約我一樽迎嗣歲，待君三館已多時。", "從今無事唯須飲，文字聲名人自知。"]'),
('64128ca6-5603-47eb-a04e-aea6b2fb3a62','奉使契丹二十八首 次莫州通判劉涇韵二首 其二','蘇轍','宋','宋诗','song-poetry','','[]','平世功名路甚夷，不勞談說更騎危。',64,'全唐诗/poet.song.48000.json','["平世功名路甚夷，不勞談說更騎危。", "早年拭目看成賦，近日收心聞琢詩。", "古錦屢開新得句，敝貂方競苦寒時。", "南還欲向春風飲，塞柳凋枯恐未知。"]'),
('75987bd8-8110-4588-a6a0-ad5e56b21cf5','奉使契丹二十八首 贈知雄州王崇拯二首 其一','蘇轍','宋','宋诗','song-poetry','','[]','趙北燕南古戰場，何年千里作方塘。',64,'全唐诗/poet.song.48000.json','["趙北燕南古戰場，何年千里作方塘。", "煙波坐覺胡塵遠，皮幣遥知國計長。", "勝處舊聞荷覆水，此行猶及蟹經霜。", "使君約我南來飲，人日河橋柳正黄。"]'),
('4a447f7e-24d4-4a5e-aa0b-6761df3ba573','奉使契丹二十八首 贈知雄州王崇拯二首 其二','蘇轍','宋','宋诗','song-poetry','','[]','城裏都無一寸閑，城頭野水四汗漫。',64,'全唐诗/poet.song.48000.json','["城裏都無一寸閑，城頭野水四汗漫。", "與君但對湖光飲，久病偏須酒令寬。", "何氏溝塍布棋局，李君智略走珠槃。", "應存父老猶能說，有意功名未必難。"]'),
('7a430536-68e9-479c-95be-05044c642a61','奉使契丹二十八首 贈右番趙侍郎','蘇轍','宋','宋诗','song-poetry','','[]','霜須顧我十年兄，朔漠陪公萬里行。',64,'全唐诗/poet.song.48000.json','["霜須顧我十年兄，朔漠陪公萬里行。", "駢馬貂裘寒自暖，連床龜息夜無聲。", "同心便可忘苛禮，異類猶應服至誠。", "行役雖勞思慮少，會看梨棗及春生。"]'),
('cf43ce55-e88d-4323-aa97-300ed09f5077','奉使契丹二十八首 古北口道中呈同事二首 其一','蘇轍','宋','宋诗','song-poetry','','[]','獨卧繩牀已七年，往來殊復少縈纏。',64,'全唐诗/poet.song.48000.json','["獨卧繩牀已七年，往來殊復少縈纏。", "心游幽闕烏飛處，身在中原山盡邊。", "梁市朝回塵滿馬，蜀江春近水浮天。", "枉將眼界疑心界，不見中宵氣浩然。"]'),
('63fecac2-4b55-49bd-9ca1-e9ca35fb034b','奉使契丹二十八首 古北口道中呈同事二首 其二','蘇轍','宋','宋诗','song-poetry','','[]','笑語相從正四人，不須嗟嘆久離羣。',64,'全唐诗/poet.song.48000.json','["笑語相從正四人，不須嗟嘆久離羣。", "及春煮菜過邊郡，賜火煎茶約細君。", "日暖山蹊冬未雪，寒生胡月夜無雲。", "明朝對飲思鄉嶺，夷漢封疆自此分。"]'),
('23780f58-8f82-4b26-b121-f5f6116bdade','奉使契丹二十八首 絕句二首 其一','蘇轍','宋','宋诗','song-poetry','','[]','亂山環合疑無路，小徑縈回長傍溪。',32,'全唐诗/poet.song.48000.json','["亂山環合疑無路，小徑縈回長傍溪。", "仿佛夢中尋蜀道，興州東谷鳳州西。"]'),
('2fc0f3c7-8613-44d6-9fea-3da54a9f2a63','奉使契丹二十八首 絕句二首 其二','蘇轍','宋','宋诗','song-poetry','','[]','日色映山才到地，雪花鋪草不曾消。',32,'全唐诗/poet.song.48000.json','["日色映山才到地，雪花鋪草不曾消。", "晴寒不及陰寒重，攬篋猶存未著貂。"]'),
('b3fdf5ca-8f2f-44b9-8a06-a23fe35f1b3c','奉使契丹二十八首 過楊無敵廟','蘇轍','宋','宋诗','song-poetry','','[]','行祠寂寞寄關門，野草猶知避血痕。',64,'全唐诗/poet.song.48000.json','["行祠寂寞寄關門，野草猶知避血痕。", "一敗可憐非戰罪，太剛嗟獨畏人言。", "馳驅本爲中原用，嘗享能令異域尊。", "我欲比君周子隠，誅彤聊足慰忠魂。"]'),
('d655005b-828b-4d36-8a37-add5ef35c5c1','奉使契丹二十八首 燕山','蘇轍','宋','宋诗','song-poetry','','[]','燕山如長蛇，千里限夷漢。',192,'全唐诗/poet.song.48000.json','["燕山如長蛇，千里限夷漢。", "首銜西山麓，尾掛東海岸。", "中開哆箕畢，末路牽一線。", "却顧沙漠平，南來獨飛雁。", "居民異風氣，自古習耕戰。", "上論召公奭，禮樂比姬旦。", "次稱望諸君，術略亞狐管。", "子丹號無策，亦數游俠冠。", "割棄何人斯，腥臊久不澣。", "哀哉漢唐餘，左衽今已半。", "玉帛非足云，子女罹蹈踐。", "區區用戎索，久爾縻郡縣。", "從來帝王師，要在侮亡亂。", "攻堅甚攻玉，乘瑕易冰泮。", "中原但常治，敵勢要自變。", "會當挽天河，洗此生齒萬。"]'),
('843fed4c-1d42-4f4b-9dac-977257b3a29b','奉使契丹二十八首 趙君偶以微恙乘駝車而行戲贈二絕句 其一','蘇轍','宋','宋诗','song-poetry','','[]','鄰國知公未可風，雙駝借與兩輪紅。',32,'全唐诗/poet.song.48000.json','["鄰國知公未可風，雙駝借與兩輪紅。", "它年出塞三千騎，卧畫輜車也要公。"]'),
('e396dbd5-2df4-4254-9683-16d22691ecd1','奉使契丹二十八首 趙君偶以微恙乘駝車而行戲贈二絕句 其二','蘇轍','宋','宋诗','song-poetry','','[]','高屋寬箱虎豹裀，相逢燕市不相親。',32,'全唐诗/poet.song.48000.json','["高屋寬箱虎豹裀，相逢燕市不相親。", "忽聞中有京華語，驚喜開簾笑殺人。"]'),
('c196bed7-0c11-41fe-9f64-fd247d9eead1','奉使契丹二十八首 會仙館二絕句 其一','蘇轍','宋','宋诗','song-poetry','','[]','北嶂南屏恰四周，西山微缺放溪流。',32,'全唐诗/poet.song.48000.json','["北嶂南屏恰四周，西山微缺放溪流。", "胡人置酒留連客，頗識峰巒是勝遊。"]'),
('07a876bd-bc34-40f0-b307-53d521edff4e','奉使契丹二十八首 會仙館二絕句 其二','蘇轍','宋','宋诗','song-poetry','','[]','嶺上西行雙石人，臨溪照水久逡巡。',32,'全唐诗/poet.song.48000.json','["嶺上西行雙石人，臨溪照水久逡巡。", "低頭似愧南來使，居處雖高已失身。"]'),
('cccdcf9e-54c2-41a3-ad20-aff41ca302ae','奉使契丹二十八首 出山','蘇轍','宋','宋诗','song-poetry','','[]','燕疆不過古北關，連山漸少多平田。',128,'全唐诗/poet.song.48000.json','["燕疆不過古北關，連山漸少多平田。", "奚人自作草屋住，契丹駢車依水泉。", "橐駝羊馬散川谷，草枯水盡時一遷。", "漢人何年被流徙，衣服漸變存語言。", "力耕分穫世爲客，賦役稀少聊偷安。", "漢奚單弱契丹橫，目視漢使心凄然。", "石瑭竊位不傳子，遺患燕薊逾百年。", "仰頭呼天問何罪，自恨遠祖從祿山。"]'),
('f37c2d99-ec2f-4189-9dd4-2eec1ec5cc78','奉使契丹二十八首 奚君','蘇轍','宋','宋诗','song-poetry','','[]','奚君五畝宅，封戶一成田。',48,'全唐诗/poet.song.48000.json','["奚君五畝宅，封戶一成田。", "故壘開都邑，遺民雜漢編。", "不知臣僕賤，漫喜殺生權。", "燕俗嗟猶在，婚姻未許連。"]'),
('eaa8601a-bcb7-495c-b48d-794da4746158','奉使契丹二十八首 惠州','蘇轍','宋','宋诗','song-poetry','','[]','孤城千室閉重闉，蒼莽平川絕四鄰。',64,'全唐诗/poet.song.48000.json','["孤城千室閉重闉，蒼莽平川絕四鄰。", "漢使塵來空極目，沙場雪重欲無春。", "羞歸應有李都尉，念舊可憐徐舍人。", "會逐單于渭橋下，歡呼齊拜屬車塵。"]'),
('f5db7ef1-2991-402d-9326-0edb7318dfdd','奉使契丹二十八首 神水館寄子瞻兄四絕 其一','蘇轍','宋','宋诗','song-poetry','','[]','少年病肺不禁寒，命出中朝敢避難。',32,'全唐诗/poet.song.48000.json','["少年病肺不禁寒，命出中朝敢避難。", "莫倚皂貂欺朔雪，更催靈火煮鉛丹。"]'),
('13e0de0a-efb7-4bf4-b0b9-39b012fa0d24','奉使契丹二十八首 神水館寄子瞻兄四絕 其二','蘇轍','宋','宋诗','song-poetry','','[]','夜雨從來相對眠，茲行萬里隔胡天。',32,'全唐诗/poet.song.48000.json','["夜雨從來相對眠，茲行萬里隔胡天。", "試依北斗看南斗，始覺吳山在目前。"]'),
('ee7a24ba-ed04-43c4-ac03-09d549c29736','奉使契丹二十八首 神水館寄子瞻兄四絕 其三','蘇轍','宋','宋诗','song-poetry','','[]','誰將家集過幽都，逢見胡人問大蘇。',32,'全唐诗/poet.song.48000.json','["誰將家集過幽都，逢見胡人問大蘇。", "莫把文章動蠻貊，恐妨談笑卧江湖。"]'),
('a403ec15-ff36-4cb5-84ce-1507366564e1','奉使契丹二十八首 神水館寄子瞻兄四絕 其四','蘇轍','宋','宋诗','song-poetry','','[]','虜廷一意向中原，言語綢繆禮亦虔。',32,'全唐诗/poet.song.48000.json','["虜廷一意向中原，言語綢繆禮亦虔。", "顧我何功慚陸賈，橐裝聊復助歸田。"]'),
('03903fbb-35cb-4679-85c3-cf466b674850','奉使契丹二十八首 木葉山','蘇轍','宋','宋诗','song-poetry','','[]','奚田可耕鑿，遼土直沙漠。',144,'全唐诗/poet.song.48000.json','["奚田可耕鑿，遼土直沙漠。", "蓬棘不復生，條幹何由作。", "茲山亦沙阜，短短見叢薄。", "冰霜葉墮盡，鳥獸紛無託。", "乾坤信廣大，一氣均美惡。", "胡爲獨窮陋，意似鄙夷落。", "民生亦復爾，垢汙不知怍。", "君看齊魯間，桑柘皆沃若。", "麥秋載萬箱，蠶老簇千箔。", "餘粱及狗彘，衣被遍城郭。", "天工本何心，地力不能博。", "遂令堯舜仁，獨不施禮樂。"]'),
('50580a7c-47a9-4b75-bf35-78d15c42f7d4','奉使契丹二十八首 虜帳','蘇轍','宋','宋诗','song-poetry','','[]','虜帳冬住沙陀中，索羊織葦稱行宮。',192,'全唐诗/poet.song.48000.json','["虜帳冬住沙陀中，索羊織葦稱行宮。", "從官星散依冢阜，氈廬窟室欺霜風。", "舂粱煮雪安得飽，擊兔射鹿夸强雄。", "朝廷經略窮海宇，歲遺繒絮消頑凶。", "我來致命適寒苦，積雪向日堅不融。", "聯翩歲旦有來使，屈指已復過奚封。", "禮成即日卷廬帳，釣魚射鵝滄海東。", "秋山既罷復來此，往返歲歲如旋蓬。", "彎弓射獵本天性，拱手朝會愁心胸。", "甘心五餌墮吾術，勢類畜鳥游樊籠。", "祥符聖人會天意，至今燕趙常耕農。", "爾曹飲食自謂得，豈識圖霸先和戎。"]'),
('b85cc973-97bc-44b3-a0d4-ac7fba5269af','奉使契丹二十八首 十日南歸馬上口占呈同事','蘇轍','宋','宋诗','song-poetry','','[]','南轅初喜去龍庭，入塞猶須閱月行。',64,'全唐诗/poet.song.48000.json','["南轅初喜去龍庭，入塞猶須閱月行。", "漢馬亦知歸意速，朝暘已作故人迎。", "經冬舞雪長相避，屈指新春旋復生。", "想見雄州饋生菜，菜盤酪粥任縱橫。"]'),
('03f1893f-910a-4666-a042-1237beaab894','奉使契丹二十八首 傷足','蘇轍','宋','宋诗','song-poetry','','[]','少年謬聞道，直往寡所疑。',192,'全唐诗/poet.song.48000.json','["少年謬聞道，直往寡所疑。", "不知避礙險，造次逢顛危。", "中歲飽憂患，進退每自持。", "長存鄙夫計，未免達士嗤。", "前日使胡罷，晝夜心南馳。", "中塗冰塞川，滉漾無津涯。", "僕夫執轡前，我亦忘止之。", "馬眩足不禁，拉然卧中坻。", "異域非所息，據鞍幾不支。", "昔嘗誦楞嚴，聞有乞食師。", "行乞遭毒刺，痛劇侵肝脾。", "念覺雖覺痛，無痛痛覺知。", "念極良有見，遂與凡夫辭。", "我今亦悟此，先佛豈見欺。", "但爾不即證，欲往常遲遲。", "咄哉後來心，當與初心期。"]'),
('1377a049-34a2-4b20-8e7e-447b64962605','奉使契丹二十八首 春日寄內','蘇轍','宋','宋诗','song-poetry','','[]','春到燕山冰亦消，歸驂迎日喜嫖姚。',64,'全唐诗/poet.song.48000.json','["春到燕山冰亦消，歸驂迎日喜嫖姚。", "久行胡地生華髮，初試東風脫敝貂。", "插髻小幡應正爾，點槃生菜爲誰挑。", "附書勤掃東園雪，到日青梅未滿條。"]'),
('4082c76c-0cab-4386-9ad7-ecfb2104947e','奉使契丹二十八首 渡桑乾','蘇轍','宋','宋诗','song-poetry','','[]','北渡桑乾冰欲結，心畏穹廬三尺雪。',128,'全唐诗/poet.song.48000.json','["北渡桑乾冰欲結，心畏穹廬三尺雪。", "南渡桑乾風始和，冰開易水應生波。", "穹廬雪落我未到，到時堅白如磐陀。", "會同出入凡十日，腥羶酸薄不可食。", "羊脩乳粥差便人，風隧沙場不宜客。", "相携走馬渡桑乾，旌旆一返無由還。", "胡人送客不忍去，久安和好依中原。", "年年相送桑乾上，欲話白溝一惆悵。"]'),
('120bd8aa-0662-49f8-9744-c12fd1028d1a','送文太師致仕還洛三首  其一','蘇轍','宋','宋诗','song-poetry','','[]','國老無心豈爲身，五年朝謁慰簪紳。',64,'全唐诗/poet.song.48000.json','["國老無心豈爲身，五年朝謁慰簪紳。", "元臣事業通三世，舊將威名服四鄰。", "遍閱後生真有道，欲談前事恐無人。", "比公惟有凌雲檜，歲歲何妨雨露新。"]'),
('089471cf-c87f-4ca1-86f1-36dadc007d9c','送文太師致仕還洛三首  其二','蘇轍','宋','宋诗','song-poetry','','[]','齊魯元勳古太師，寂寥千載恐無之。',64,'全唐诗/poet.song.48000.json','["齊魯元勳古太師，寂寥千載恐無之。", "昔歸蹔縮經邦手，復起還當問道時。", "入謁何曾須掖侍，到家依舊擁旌麾。", "孔公靈壽固應在，秋晚香山訪佛祠。"]'),
