('2430f356-8413-4056-af12-9a8a675b2296','學士院端午帖子二十七首 夫人閣四首 其四','蘇轍','宋','宋诗','song-poetry','','[]','御溝繞殿細無聲，飛灑彤墀曉氣清。',32,'全唐诗/poet.song.48000.json','["御溝繞殿細無聲，飛灑彤墀曉氣清。", "開到石榴花欲盡，陰陰高柳一蟬鳴。"]'),
('e097e2dc-d7de-4d54-abbf-147d7adc7bb6','次韵門下劉侍郎直宿寄蘇左丞','蘇轍','宋','宋诗','song-poetry','','[]','雷雨連年起卧龍，穆然臺閣有清風。',64,'全唐诗/poet.song.48000.json','["雷雨連年起卧龍，穆然臺閣有清風。", "一時畫諾雖云舊，此日都俞本自公。", "松竹經霜俱不改，鹽梅共鼎固非同。", "一篇和遍東西府，六律更成十二宮。"]'),
('31ee6a3c-c0b1-4950-a228-75a25e3ce7a0','次韵張耒學士病中二首  其一','蘇轍','宋','宋诗','song-poetry','','[]','一卧憐君三十朝，呼醫仍苦禁城遥。',64,'全唐诗/poet.song.48000.json','["一卧憐君三十朝，呼醫仍苦禁城遥。", "靈根自逐新陽發，病枿從經野火燒。", "吻燥未須尋麯糵，囊空誰與典絺蕉。", "何時匹馬隨街鼓，睡起頻驚髀肉消。"]'),
('7a9019e3-2ef1-4206-9ced-713742d5a409','次韵張耒學士病中二首  其二','蘇轍','宋','宋诗','song-poetry','','[]','塵垢汙人朝復朝，病中吟嘯夜方遥。',64,'全唐诗/poet.song.48000.json','["塵垢汙人朝復朝，病中吟嘯夜方遥。", "長空雁過疑相答，虛幌螢飛坐恐燒。", "稍覺新霜試松竹，未應寒雨敗梧蕉。", "從來百鍊身如劍，火滅重磨未遽銷。"]'),
('66710aa0-3d50-408d-98bb-6567b9d7dab1','次韵張君病起二首  其一','蘇轍','宋','宋诗','song-poetry','','[]','壯年得疾勢能支，不廢霜螯左手持。',64,'全唐诗/poet.song.48000.json','["壯年得疾勢能支，不廢霜螯左手持。", "漸喜一杯留好客，未應五斗似當時。", "口中舌在時聞句，雪裏心安不問師。", "去卧淮陽從病守，功名他日許君期。"]'),
('7a86b181-b77d-4344-a205-c3736ca9fbe1','次韵張君病起二首  其二','蘇轍','宋','宋诗','song-poetry','','[]','老去生經廢不行，鏡中白髮見空驚。',64,'全唐诗/poet.song.48000.json','["老去生經廢不行，鏡中白髮見空驚。", "解將沖氣通枯指，易甚新陽發舊莖。", "一悟少年難久恃，不妨多病却長生。", "文章繆忝追前輩，服食從來亦强名。"]'),
('adcc3532-e90d-4b52-9d40-b3a8ff03afe1','太白山祈雨詩五首  其一','蘇轍','宋','宋诗','song-poetry','','[]','田漫漫，耕挹挹。',37,'全唐诗/poet.song.49000.json','["田漫漫，耕挹挹。", "拔陳草，生九穀。", "人功盡，雨則違。", "苗不穗，莩不米，哀將饑兮。"]'),
('6a8e79d1-a372-453f-8789-f983d058de12','太白山祈雨詩五首  其二','蘇轍','宋','宋诗','song-poetry','','[]','山巖巖，奠南西。',37,'全唐诗/poet.song.49000.json','["山巖巖，奠南西。", "嗟我民，匪神依。", "伐山木，蓺稷黍。", "求既多，訴不已，猶我許兮。"]'),
('afebebe6-8c4b-44c4-9c7f-16df79cc1fad','太白山祈雨詩五首  其三','蘇轍','宋','宋诗','song-poetry','','[]','山爲灰，石爲炭。',37,'全唐诗/poet.song.49000.json','["山爲灰，石爲炭。", "水泉沸，百草爛。", "神予我，旱奪之。", "孰爲是，驕不威，尚可弛兮。"]'),
('5013a73e-c9f8-44db-9c02-a776a553aacc','太白山祈雨詩五首  其四','蘇轍','宋','宋诗','song-poetry','','[]','雷馮空，雨騰淵。',37,'全唐诗/poet.song.49000.json','["雷馮空，雨騰淵。", "誅孽妖，反豐年。", "顧千里，瞬三日。", "神在堂，龍爲役，是何惜兮。"]'),
('5a053005-44a8-4509-8a00-731f897984e5','太白山祈雨詩五首  其五','蘇轍','宋','宋诗','song-poetry','','[]','雨既止，百穀復。',37,'全唐诗/poet.song.49000.json','["雨既止，百穀復。", "築場壤，治囷簏。", "爲酒醴，伐豚羔。", "舞長袖，擊鳴鼉，匪以報兮。"]'),
('cf517ff0-f931-46d0-a720-5a72b840b100','舜泉詩','蘇轍','宋','宋诗','song-poetry','','[]','歷山岩岩，虞舜宅焉。',210,'全唐诗/poet.song.49000.json','["歷山岩岩，虞舜宅焉。", "虞舜徂矣，其神在天。", "其德在人，其物在泉。", "神不可親，德用不知。", "有冽斯泉，下民是祗。", "泉流無疆，有永我思。", "源發于山，施于北河。", "播于中逵，匯爲澄波。", "有鱉與魚，有菱與荷。", "藴毒是洩，污濁以流。", "埃𡏖消亡，風火滅收。", "叢木敷榮，勞者所休。", "誰爲旱災，靡物不傷。", "天地耗竭，泉亦淪亡。", "民咸不寧，曰不享耶。", "時雨既澍，百穀既登。", "有流泫然，彌坎而升。", "溝洫滿盈，鰕黽沸騰。", "匪泉實來，帝實顧余。", "執其羔豚，蘋藻是菹。", "帝今在堂，泉復如初。"]'),
('62de52d3-bce9-4005-8bb8-c9934662acb8','筠州聖祖殿詩  其一','蘇轍','宋','宋诗','song-poetry','','[]','高安在南，分自豫章。',40,'全唐诗/poet.song.49000.json','["高安在南，分自豫章。", "重山複江，魚鳥之鄉。", "俗野不文，吏亦怠荒。", "禮失不知，習爲舊常。"]'),
('db560b4a-038a-4c0a-91d5-ac4d23021d22','筠州聖祖殿詩  其二','蘇轍','宋','宋诗','song-poetry','','[]','於穆聖祖，宅神皇極。',40,'全唐诗/poet.song.49000.json','["於穆聖祖，宅神皇極。", "降鑒在下，子孫千億。", "羽衣玉佩，旗纛旄節。", "巍巍煌煌，秩祀萬國。"]'),
('0049f4b8-5d53-45f2-ac43-5cd6421b19d7','筠州聖祖殿詩  其三','蘇轍','宋','宋诗','song-poetry','','[]','如日在天，靡國不臨。',40,'全唐诗/poet.song.49000.json','["如日在天，靡國不臨。", "筠雖小邦，其有不歆。", "東廡西嚮，誰昔營之。", "民昏不知，神以不懷。"]'),
('0e1fae29-ba31-4a40-b476-f1206e2660fc','筠州聖祖殿詩  其四','蘇轍','宋','宋诗','song-poetry','','[]','深山之間，野水之濱。',40,'全唐诗/poet.song.49000.json','["深山之間，野水之濱。", "禮樂聲明，孰見孰聞。", "祖廟之嚴，君臣則存。", "失而不圖，民以罔觀。"]'),
('f496494c-4af2-4d85-a609-bf61d3a6d0eb','筠州聖祖殿詩  其五','蘇轍','宋','宋诗','song-poetry','','[]','毛侯始來，其則有意。',40,'全唐诗/poet.song.49000.json','["毛侯始來，其則有意。", "匪民之愚，禮教實墜。", "章聞於朝，帝曰俞哉。", "弗改弗營，何以示民。"]'),
('a81442f4-4faa-41fb-a469-f34a9a5476e8','筠州聖祖殿詩  其六','蘇轍','宋','宋诗','song-poetry','','[]','九峰之杉，逍遥之柟。',40,'全唐诗/poet.song.49000.json','["九峰之杉，逍遥之柟。", "易直且修，弗斫而堪。", "新堂有嚴，四星在南。", "朝廷之儀，萬民所祗。"]'),
('6fc8cc72-0453-43f4-94d8-248260e59809','次韵子瞻感舊','蘇轍','宋','宋诗','song-poetry','','[]','還朝正三伏，一再趨未央。',144,'全唐诗/poet.song.49000.json','["還朝正三伏，一再趨未央。", "久從江海游，苦此劍佩長。", "夢中驚和璞，起坐憐老房。", "爲我忝丞轄，置身願并凉。", "此心一自許，何暇憂陟岡。", "早歲發歸念，老來未嘗忘。", "淵明不久仕，黔婁足爲康。", "家有二頃田，歲辦十口糧。", "教敕諸子弟，編排舊文章。", "辛勤養松竹，遲莫多風霜。", "常恐先著鞭，獨引社酒嘗。", "火急報君恩，會合心則降。"]'),
('907f2621-a580-4789-8877-30f43f255dc6','次韵題畫卷四首 山陰陳迹','蘇轍','宋','宋诗','song-poetry','','[]','卧對郗人氣已真，晚依丘壑更無倫。',32,'全唐诗/poet.song.49000.json','["卧對郗人氣已真，晚依丘壑更無倫。", "不須復預清言侶，自是江東第一人。"]'),
('b8ae37d8-489d-4dbd-9538-7e6b47c707ba','次韵題畫卷四首 雪溪乘興','蘇轍','宋','宋诗','song-poetry','','[]','亟往遄歸真曠哉，聾人不信有驚雷。',32,'全唐诗/poet.song.49000.json','["亟往遄歸真曠哉，聾人不信有驚雷。", "雖云不必見安道，已誤扁舟犯雪來。"]'),
('50bf2d9a-04cb-49ab-9d6f-ab0fb57a62c5','次韵題畫卷四首 四明狂客','蘇轍','宋','宋诗','song-poetry','','[]','失脚來遊九陌塵，故溪何日定抽身。',32,'全唐诗/poet.song.49000.json','["失脚來遊九陌塵，故溪何日定抽身。", "便同賀老扁舟去，已笑西山鄭子真。"]'),
('768f46f9-b0ad-4a03-bfa4-72c9555e2c5c','次韵題畫卷四首 西塞風雨','蘇轍','宋','宋诗','song-poetry','','[]','雨細風斜欲暝時，淩波一葉去安歸。',32,'全唐诗/poet.song.49000.json','["雨細風斜欲暝時，淩波一葉去安歸。", "遥知夜宿蛟人室，浪卷波分不著衣。"]'),
('97c0ca3b-4ffc-48d3-82c2-b550d3cc909b','送侄邁赴河間令','蘇轍','宋','宋诗','song-poetry','','[]','老去那堪用，恩深未敢歸。',48,'全唐诗/poet.song.49000.json','["老去那堪用，恩深未敢歸。", "誰能告民病，一一指吾非。", "爾赴河間治，無嫌野老譏。", "仍將尺書報，勿復問從違。"]'),
('6769a1b2-3e0a-4ffe-bafc-370acd068f31','次韵門下呂相公車駕視學','蘇轍','宋','宋诗','song-poetry','','[]','未識吾君龍鳳章，諸儒望幸久南庠。',64,'全唐诗/poet.song.49000.json','["未識吾君龍鳳章，諸儒望幸久南庠。", "輦回原廟初移蹕，鷺集西雝已著行。", "執爵稍前疑問道，獻琛不日數來王。", "從官始悟熙寧意，遺我親臨見肯堂。"]'),
('3ad09254-2ef9-4506-baee-98488b93bc0e','傅銀青挽詞二首  其一','蘇轍','宋','宋诗','song-poetry','','[]','名自烏臺發，恩從鳳沼深。',48,'全唐诗/poet.song.49000.json','["名自烏臺發，恩從鳳沼深。", "鹽梅和衆口，金玉比誠心。", "澹泊平生事，彌留一病侵。", "遺言自無憾，朝野爲沾襟。"]'),
('6a68b565-f130-4b6d-8f79-8d5884773b59','傅銀青挽詞二首  其二','蘇轍','宋','宋诗','song-poetry','','[]','丹旐國西門，茅廬濟水深。',48,'全唐诗/poet.song.49000.json','["丹旐國西門，茅廬濟水深。", "官清貧似舊，名重歿猶存。", "臺閣傳遺懿，交遊拭淚痕。", "君恩不改故，延賞遍諸孫。"]'),
('51fda69b-94f1-482d-b557-6e9176f44502','大雪三絕句  其一','蘇轍','宋','宋诗','song-poetry','','[]','閏歲窮冬已是春，當寒却暖未宜人。',32,'全唐诗/poet.song.49000.json','["閏歲窮冬已是春，當寒却暖未宜人。", "陰風半夜催飛霰，稍凈天街一尺塵。"]'),
('f7ae4ac3-8e45-42ba-badb-e3e9abc5dc84','大雪三絕句  其二','蘇轍','宋','宋诗','song-poetry','','[]','玄冥留雪付勾芒，桃李雖憂麥未傷。',32,'全唐诗/poet.song.49000.json','["玄冥留雪付勾芒，桃李雖憂麥未傷。", "膏澤較遲三十日，問天此意亦茫茫。"]'),
('9eec0bae-511a-4920-b971-f792d590599f','大雪三絕句  其三','蘇轍','宋','宋诗','song-poetry','','[]','連歲金明不見冰，上春風雪氣稜稜。',32,'全唐诗/poet.song.49000.json','["連歲金明不見冰，上春風雪氣稜稜。", "臺中曾奏五行傳，到此施行愧未曾。"]'),
('ba234ba2-123f-4b5d-8a2b-2001380e68b2','和王晉卿都尉荼䕷二絕句  其一','蘇轍','宋','宋诗','song-poetry','','[]','春到都城曾未知，楸花時見萬年枝。',32,'全唐诗/poet.song.49000.json','["春到都城曾未知，楸花時見萬年枝。", "多情頼有王公子，解剪金槃寄所思。"]'),
('e97937bb-951d-4ac6-9578-5c9e64a4761e','和王晉卿都尉荼䕷二絕句  其二','蘇轍','宋','宋诗','song-poetry','','[]','後圃荼䕷手自栽，清於芍藥釅於梅。',32,'全唐诗/poet.song.49000.json','["後圃荼䕷手自栽，清於芍藥釅於梅。", "舊來詩客今無幾，三臭馨香懶舉杯。"]'),
('73bac816-9bba-4805-937c-1c0e6165d1ff','次韵門下呂相公同訪致政馮宣猷','蘇轍','宋','宋诗','song-poetry','','[]','懶從朝謁事驂騑，此去高眠罷倒衣。',64,'全唐诗/poet.song.49000.json','["懶從朝謁事驂騑，此去高眠罷倒衣。", "詔許敲門訪耆舊，天教築室俟來歸。", "肩輿尚肯追春色，鼓缶何妨傲夕暉。", "所至成家即安隠，武昌誰乞釣魚磯。"]'),
('1799e1fc-8799-4dd6-9092-2ce5a56c0e2d','滕達道龍圖挽詞二首  其一','蘇轍','宋','宋诗','song-poetry','','[]','才適邦家用，學非章句儒。',48,'全唐诗/poet.song.49000.json','["才適邦家用，學非章句儒。", "遭逢初莫測，流落一長吁。", "大節輕多難，深言究遠圖。", "收功太原守，談笑視羌胡。"]'),
('e89ccb36-1742-4024-bfd5-37ca2fbd5c6a','滕達道龍圖挽詞二首  其二','蘇轍','宋','宋诗','song-poetry','','[]','南竄逢公弄水亭，北歸留我闔閭城。',64,'全唐诗/poet.song.49000.json','["南竄逢公弄水亭，北歸留我闔閭城。", "壯年不見日千里，餘論猶驚敵萬兵。", "簡冊何人知造膝，邊防觸處竦先聲。", "傷心繫舸城東地，目斷安知有死生。"]'),
('4ecf529b-414b-4ede-85ca-351781ae34dd','魯元翰中大挽詞二首  其一','蘇轍','宋','宋诗','song-poetry','','[]','遺直誦家聲，持心本至誠。',48,'全唐诗/poet.song.49000.json','["遺直誦家聲，持心本至誠。", "何勞求皦察，所至自安平。", "氣象餘前輩，才華屬後生。", "飛騰看諸子，相繼亦公卿。"]'),
('804c6ea4-6903-4b75-b74f-19182c991663','魯元翰中大挽詞二首  其二','蘇轍','宋','宋诗','song-poetry','','[]','十年初見范公園，知與錢塘結弟昆。',64,'全唐诗/poet.song.49000.json','["十年初見范公園，知與錢塘結弟昆。", "樂易向人無不可，疏慵憐我正忘言。", "南遷却返逢北渡，遠聘相過適近藩。", "無復放懷嘩笑語，挽詩空寄淚潺湲。"]'),
('f40d14f7-36fc-41e3-9b2f-fdf3f8aa02c3','贈司空張公安道挽詞三首  其一','蘇轍','宋','宋诗','song-poetry','','[]','道廣中無競，才高治不煩。',48,'全唐诗/poet.song.49000.json','["道廣中無競，才高治不煩。", "安心本篤靜，憂世亦時言。", "壽考同儕盡，經綸故事存。", "猶應門下客，微論記根原。"]'),
('77397e47-a6b0-4a9b-97be-f60eb597f691','贈司空張公安道挽詞三首  其二','蘇轍','宋','宋诗','song-poetry','','[]','孤高出世學，豪邁謫仙人。',48,'全唐诗/poet.song.49000.json','["孤高出世學，豪邁謫仙人。", "早歲猶和俗，中年自識真。", "定餘時發照，塵盡四無鄰。", "聞道騎箕尾，還應事玉宸。"]'),
('4a1abf39-1159-493f-8019-eb9d1e53752e','贈司空張公安道挽詞三首  其三','蘇轍','宋','宋诗','song-poetry','','[]','西蜀識公初，南都從事餘。',48,'全唐诗/poet.song.49000.json','["西蜀識公初，南都從事餘。", "一言知我可，久好復誰如。", "學術留元嘆，家聲付伯魚。", "霜天近生日，聞挽重唏噓。"]'),
('1d04acba-7c76-48d6-a091-e81a29d21fd0','蔡州任氏閱世堂','蘇轍','宋','宋诗','song-poetry','','[]','朱君長桐鄉，死食桐鄉社。',120,'全唐诗/poet.song.49000.json','["朱君長桐鄉，死食桐鄉社。", "吏民安君德，君亦愛其下。", "遺言於斯葬，存沒勿相捨。", "自知得民深，千歲誰似者。", "任君治新息，寬惠洽鰥寡。", "强梁順教詔，桴鼓不鳴野。", "三年去復還，園木裁拱把。", "居人敬閭巷，禽鳥依屋瓦。", "蒼然百尺檜，直幹任大厦。", "相要勿剪伐，令尹昔所舍。"]'),
('292b6b7a-2fb3-4d1e-b2dc-cfbbaef12d98','次韵子瞻和淵明飲酒二十首  其一','蘇轍','宋','宋诗','song-poetry','','[]','我性本疏懶，父母强教之。',60,'全唐诗/poet.song.49000.json','["我性本疏懶，父母强教之。", "逡巡就科選，逮此年少時。", "幽憂二十年，懶性祗如茲。", "偶然踐黄闥，俯仰空自疑。", "乞身未敢言，常愧外物持。"]'),
('6c28942c-51b3-4654-8046-9d96c2658950','次韵子瞻和淵明飲酒二十首  其二','蘇轍','宋','宋诗','song-poetry','','[]','人言性本靜，不必林與山。',48,'全唐诗/poet.song.49000.json','["人言性本靜，不必林與山。", "世雖有此理，知誰非妄言。", "自我作歸計，於今十餘年。", "低回軒冕中，此語愧虛傳。"]'),
('856dfbff-cf00-436c-b481-4f3ee8198aa3','次韵子瞻和淵明飲酒二十首  其三','蘇轍','宋','宋诗','song-poetry','','[]','世人豈知我，兄弟得我情。',60,'全唐诗/poet.song.49000.json','["世人豈知我，兄弟得我情。", "少年喜文章，中年慕功名。", "自從落江湖，一意事養生。", "富貴非所求，寵辱未免驚。", "平生不解飲，欲醉何由成。"]'),
('72aa428f-7e44-4505-925e-b50bc425534e','次韵子瞻和淵明飲酒二十首  其四','蘇轍','宋','宋诗','song-poetry','','[]','秋鴻一何樂，空際乘風飛。',72,'全唐诗/poet.song.49000.json','["秋鴻一何樂，空際乘風飛。", "秋蟲一何憂，壁間終夜悲。", "憂樂本何有，力盡兩無依。", "物生逐所遇，久行不知歸。", "少年氣難回，老者百事衰。", "聊復沃以酒，永與狂心違。"]'),
('222a31bb-55b6-4148-98cb-9b2623f0dd5b','次韵子瞻和淵明飲酒二十首  其五','蘇轍','宋','宋诗','song-poetry','','[]','昔在建城市，鹽酒晝夜喧。',60,'全唐诗/poet.song.49000.json','["昔在建城市，鹽酒晝夜喧。", "夏潦恐天漏，冬雷知地偏。", "妻孥日告我，胡不反故山。", "一來朝廷上，七年不知還。", "有寓均建城，且志昔日言。"]'),
('1083ec19-1b6d-418c-93d7-863b71b59440','次韵子瞻和淵明飲酒二十首  其六','蘇轍','宋','宋诗','song-poetry','','[]','夢中見百怪，一一皆謂是。',48,'全唐诗/poet.song.49000.json','["夢中見百怪，一一皆謂是。", "醉中身已忘，萬事隨亦毀。", "此心不應然，外物妄使爾。", "安心十年後，此語知非綺。"]'),
('61f269cf-9e49-4e4d-8036-d80ea3fb296c','次韵子瞻和淵明飲酒二十首  其七','蘇轍','宋','宋诗','song-poetry','','[]','開卷觀古人，誰非一世英。',60,'全唐诗/poet.song.49000.json','["開卷觀古人，誰非一世英。", "骨肉委黄壚，泯滅俱無情。", "憧憧來無盡，擾擾相奪傾。", "驚雷震朱夏，鮮能及秋鳴。", "得酒且酣飲，問誰逃死生。"]'),
('c9e8c5db-05d1-4ba6-b801-33f86fd2148d','次韵子瞻和淵明飲酒二十首  其八','蘇轍','宋','宋诗','song-poetry','','[]','明月出東牆，萬物含餘姿。',60,'全唐诗/poet.song.49000.json','["明月出東牆，萬物含餘姿。", "孤蟬庇繁蔭，衆鳥棲高枝。", "解衣適少事，捫腹知亡奇。", "朝與羣動作，莫復何所爲。", "此時不自有，日出還受羈。"]'),
('bfd76a22-bda3-4755-ad4c-48e8212a38d1','次韵子瞻和淵明飲酒二十首  其九','蘇轍','宋','宋诗','song-poetry','','[]','尺書千里至，輟食手自開。',96,'全唐诗/poet.song.49000.json','["尺書千里至，輟食手自開。", "將卜東南居，故鄉非所懷。", "勿言湖山美，永與平生乖。", "鴻雁秋南來，及春思故棲。", "蛟龍乘風雲，既雨反其泥。", "兄弟通四海，叩門事雖諧。", "直道竟三黜，去國終恐迷。", "何如自衛反，闕里從參回。"]'),
('42f53a07-a73b-46c0-956d-11e514ab736b','次韵子瞻和淵明飲酒二十首  其一○','蘇轍','宋','宋诗','song-poetry','','[]','羌虜忘君恩，戰鼓驚四隅。',60,'全唐诗/poet.song.49000.json','["羌虜忘君恩，戰鼓驚四隅。", "邊候失晨夜，騎驛馳中塗。", "詔書止窮征，諸將守來驅。", "敵微勢可料，師競力無餘。", "防邊未云失，憂懷愧安居。"]'),
('e7181d8b-6d60-4c1f-a329-ff0cd177d100','次韵子瞻和淵明飲酒二十首  其一一','蘇轍','宋','宋诗','song-poetry','','[]','修己以安人，嗟古有此道。',72,'全唐诗/poet.song.49000.json','["修己以安人，嗟古有此道。", "平生妄謂得，忽忽恨衰老。", "年來亦見用，何益世枯槁。", "逡巡事朝謁，出入自媚好。", "報君要得人，被褐信懷寶。", "斯人何時見，即上歸耕表。"]'),
('280383af-232d-4f90-9d49-6f0fa96252c8','次韵子瞻和淵明飲酒二十首  其一二','蘇轍','宋','宋诗','song-poetry','','[]','春旱麥半死，夏雨欣及時。',72,'全唐诗/poet.song.49000.json','["春旱麥半死，夏雨欣及時。", "出郊視禾田，父老有好辭。", "秋陰結愁霖，似欲直敗茲。", "冥冥人天際，影響良不疑。", "精誠發中禁，愍默非有欺。", "鷄號日東出，乃令民信之。"]'),
('fb3986f9-6ee9-41a0-9f74-3c524002d683','次韵子瞻和淵明飲酒二十首  其一三','蘇轍','宋','宋诗','song-poetry','','[]','天厨釀冰池，摇振畏出境。',60,'全唐诗/poet.song.49000.json','["天厨釀冰池，摇振畏出境。", "年衰雜羸病，一釂百不醒。", "鸞臺異諸曹，有政非簿領。", "頹然雖無謫，因謝出囊穎。", "回首愧周行，羣英粲彪炳。"]'),
('56934685-2c59-4fb5-9de8-fbc1004933dd','次韵子瞻和淵明飲酒二十首  其一四','蘇轍','宋','宋诗','song-poetry','','[]','淮海老使君，受詔行當至。',60,'全唐诗/poet.song.49000.json','["淮海老使君，受詔行當至。", "當官不避事，無事輒徑醉。", "平生自相許，兄先弟亦次。", "東南豈徒往，多難嫌暴貴。", "白首六卿中，嚼蠟那復味。"]'),
('01ae66bc-5a73-4520-82a2-2cdd14af27fe','次韵子瞻和淵明飲酒二十首  其一五','蘇轍','宋','宋诗','song-poetry','','[]','去年旅都城，三月不求宅。',60,'全唐诗/poet.song.49000.json','["去年旅都城，三月不求宅。", "彼哉安知我，爭掃習禮迹。", "三已竟無怨，心伏鷙鳥百。", "無私心如丹，經患髮先白。", "功名已不求，餘事復何惜。"]'),
('d1f6cd5d-6edc-4e62-ae88-205b85d2c358','次韵子瞻和淵明飲酒二十首  其一六','蘇轍','宋','宋诗','song-poetry','','[]','家居簡餘事，猶讀內景經。',72,'全唐诗/poet.song.49000.json','["家居簡餘事，猶讀內景經。", "浮塵掃欲盡，火棗行當成。", "清晨委羣動，永夜依寒更。", "低帷閟重屋，微月流中庭。", "依松白露上，歷坎幽泉鳴。", "功從猛士得，不取兒女情。"]'),
('3a146785-7233-4f36-a8e6-f0e4abe434a8','次韵子瞻和淵明飲酒二十首  其一七','蘇轍','宋','宋诗','song-poetry','','[]','南方有貧士，狂怪如病風。',48,'全唐诗/poet.song.49000.json','["南方有貧士，狂怪如病風。", "垢面髮如葆，自污屠酒中。", "導我引河水，上與崑崙通。", "長箭挽不盡，不中無尤弓。"]'),
('d63bf2f1-f905-4c09-8b36-7c3206757161','次韵子瞻和淵明飲酒二十首  其一八','蘇轍','宋','宋诗','song-poetry','','[]','清秋九日近，菊酒皆可得。',60,'全唐诗/poet.song.49000.json','["清秋九日近，菊酒皆可得。", "永愧陶翁饑，雖饑心不惑。", "懷忠受正命，賦命本通塞。", "斯人今苟在，可與同事國。", "惜哉委荆榛，忍饑長默默。"]'),
('7d66f184-3872-4221-a57d-514df052a172','次韵子瞻和淵明飲酒二十首  其一九','蘇轍','宋','宋诗','song-poetry','','[]','我友二三子，兼有仕未仕。',84,'全唐诗/poet.song.49000.json','["我友二三子，兼有仕未仕。", "青松出林秀，豈獨私與己。", "斂然不求人，而我自罍耻。", "臨風忽長鳴，誰信日千里。", "江行視漁父，但自正綱紀。", "持綱起萬目，魴鱒皆可止。", "老成日就衰，所餘殆難恃。"]'),
('74466d84-2de9-438f-8d87-a50b6d573208','次韵子瞻和淵明飲酒二十首  其二○','蘇轍','宋','宋诗','song-poetry','','[]','諸妄不可頼，所頼惟一真。',120,'全唐诗/poet.song.49000.json','["諸妄不可頼，所頼惟一真。", "內欲求性命，油然反清淳。", "外將應物化，致一常日新。", "商於四父老，携手初逃秦。", "翻然感漢德，投足復踐塵。", "出處蓋有道，豈爲諸呂勤。", "嗟我千歲後，澹然與之親。", "還將山林姿，俯首要路津。", "囊中舊時物，布衣白綸巾。", "功成不歸去，愧此同心人。"]'),
('21aa75ee-4c05-467e-ba18-76b61ba6b1e1','次韵子瞻道中見寄','蘇轍','宋','宋诗','song-poetry','','[]','兄詩有味劇雋永，和者僅同如畫影。',96,'全唐诗/poet.song.49000.json','["兄詩有味劇雋永，和者僅同如畫影。", "短篇泉冽不容挹，長韵風吹忽千頃。", "經年淮海定成集，走書道路未遑請。", "相思半夜發清唱，醉墨平明照東省。", "南來應带蜀岡泉，西信近得蒙山茗。", "出郊一飯歡有餘，去歲此時初到潁。"]'),
('79eb0335-81c4-4e7a-a549-b50f9d8d2571','郊祀慶成','蘇轍','宋','宋诗','song-poetry','','[]','盛禮彌三祀，初元正七年。',288,'全唐诗/poet.song.49000.json','["盛禮彌三祀，初元正七年。", "祭兼天地報，儀自祖宗傳。", "講義金華久，齋心玉食鮮。", "秋成通四海，廩實到窮邊。", "塵卷跳疆寇，琛來渡海船。", "人和神亦答，物備禮誠全。", "廟室開深靚，郊丘對廣圜。", "翠帷新秘殿，寶仗溢通廛。", "周冕裘繒儉，唐車保介便。", "導前多舊德，迎拜或華顛。", "薦潔求陰燧，馳誠寄燎烟。", "垂精粲星斗，望秩遍山川。", "降輅追前躅，回班戒弗虔。", "徹絪深屈體，屏蓋切承天。", "嶰谷灰初應，扶桑日欲躔。", "旌旗逐風轉，歌舞送天旋。", "簾啟瞻宸極，鷄號識漏泉。", "矜愚開罪罟，釋欠靖民編。", "樂作波翻海，書行箭脫弦。", "東朝歸福胙，南極本高仙。", "有道知難犯，無私每得賢。", "劬勞就聖德，謙畏絕私權。", "治道初無象，神功竟莫宣。", "下臣叨進玉，隨見頌誠然。"]'),
('acef55e0-13df-41fa-8e43-ec3362234689','次韵姚道人二首  其一','蘇轍','宋','宋诗','song-poetry','','[]','西山學採薇，東坡學煮羹。',108,'全唐诗/poet.song.49000.json','["西山學採薇，東坡學煮羹。", "昔在建城市，豈復衣冠情。", "朋友日已疏，止接盲趙生。", "嗇智徇所安，元氣頼以存。", "時於星寂中，稍護亂與昏。", "河流發九地，欲挽升天門。", "枉用十年力，僅餘一燈溫。", "老病竟未除，驚呼欲狂奔。", "何日新雨餘，得就季主論。"]'),
('2d61c763-d46f-4edf-b8d4-43118c5b7407','次韵姚道人二首  其二','蘇轍','宋','宋诗','song-poetry','','[]','高人隠陋巷，至藥初無方。',132,'全唐诗/poet.song.49000.json','["高人隠陋巷，至藥初無方。", "心知無生妙，運轉開陰陽。", "才如淩雲松，豈受尺寸量。", "氣如幽谷蘭，時送清風香。", "嗟我本病肺，寒暑隨翕張。", "丹砂苦落落，青春去堂堂。", "清詩墮雲霧，至音叩琳琅。", "山海信多士，世俗非所望。", "遠遊居臨安，間出從諸王。", "他年解冠佩，共遊無邊疆。", "儀麟既委照，永謝過隙光。"]'),
('d2282c3b-494b-42d1-a76f-6940c132aa14','次韵子瞻上元扈從觀燈二首  其一','蘇轍','宋','宋诗','song-poetry','','[]','虜去邊城少奏章，雪殘中禁罷焚香。',32,'全唐诗/poet.song.49000.json','["虜去邊城少奏章，雪殘中禁罷焚香。", "都人知有新年喜，爭看琱輿金鳳凰。"]'),
('c33b3019-83a6-4cce-90df-3225369960a5','次韵子瞻上元扈從觀燈二首  其二','蘇轍','宋','宋诗','song-poetry','','[]','春來有意乞歸耕，足痹三年久未平。',32,'全唐诗/poet.song.49000.json','["春來有意乞歸耕，足痹三年久未平。", "忽記上元鑾輅出，起聽前殿曉鐘聲。"]'),
('924a16a9-529f-4b11-878c-e5ae8e795910','蔡州壺公觀劉道士）','蘇轍','宋','宋诗','song-poetry','','[]','思潁求歸今幾時，布衣猶在老劉師。',64,'全唐诗/poet.song.49000.json','["思潁求歸今幾時，布衣猶在老劉師。", "龍章舊有世人識，蟬蛻惟應野老知。", "昔葬衣冠今在否，近傳音問不須疑。", "曾聞圯上逢黄石，久矣留侯不見欺。"]'),
('54368208-9798-4beb-a22e-f450c31d6f0a','大行太皇太后挽詞二首  其一','蘇轍','宋','宋诗','song-poetry','','[]','內治隆三世，尊臨極九年。',48,'全唐诗/poet.song.49000.json','["內治隆三世，尊臨極九年。", "神孫克負荷，大業付安全。", "有道華夷靖，無心怨惡悛。", "和熹盛東漢，從此不稱賢。"]'),
('6370152b-690f-4e7b-a8e0-11603be73b41','大行太皇太后挽詞二首  其二','蘇轍','宋','宋诗','song-poetry','','[]','約己心全小，寬民德有餘。',48,'全唐诗/poet.song.49000.json','["約己心全小，寬民德有餘。", "外家恩澤少，先后禮容虛。", "原廟因前室，中朝避冊書。", "功名不勝紀，四謚嘆猶疏。"]'),
('04fb8734-3fec-4421-b080-3e50dc2843d0','次韵姚道人','蘇轍','宋','宋诗','song-poetry','','[]','道人偶許俗人知，法喜非妻解養兒。',64,'全唐诗/poet.song.49000.json','["道人偶許俗人知，法喜非妻解養兒。", "夜久金莖添沆瀣，室虛寶月映琉璃。", "遠來醉俠匆匆返，近出詩仙句句奇。", "獨怪區區踐繩墨，相逢未省角巾欹。"]'),
('d4665245-db57-463e-8403-c65fbd5494ec','次韵石芝','蘇轍','宋','宋诗','song-poetry','','[]','鷄鳴東海朝日新，光蒙洲島霧雨勻。',128,'全唐诗/poet.song.49000.json','["鷄鳴東海朝日新，光蒙洲島霧雨勻。", "一晞石上遍生耳，幽子自食無來賓。", "寄書乞取久未許，箬籠蕉囊海神戶。", "一掬誰令墮我前，無爲知我超諸數。", "此身不願清廟瑚，但願歸去隨樵蘇。", "龜龍百歲豈知道，養氣千息存其胡。", "塵中學仙定難脫，夢裏食芝空酷烈。", "中山軍府得安閑，更試朝霞磨鏡鐵。"]'),
('e0c1f8a3-9315-4cb1-bf52-2fb262736d10','故樞密簽書贈正議大夫王彥霖挽詞二首  其一','蘇轍','宋','宋诗','song-poetry','','[]','試吏有能名，升臺擅直聲。',48,'全唐诗/poet.song.49000.json','["試吏有能名，升臺擅直聲。", "雄飛極九載，修路止三城。", "壯志方凌厲，遺書忽嘆驚。", "老人殊可念，白首泣新塋。"]'),
('ad24070a-d390-4655-9cd9-fb95659aa016','故樞密簽書贈正議大夫王彥霖挽詞二首  其二','蘇轍','宋','宋诗','song-poetry','','[]','傾蓋晚相親，東西省戶鄰。',48,'全唐诗/poet.song.49000.json','["傾蓋晚相親，東西省戶鄰。", "聽君占諫草，繼我出詞綸。", "京尹聲初浹，樞廷迹尚新。", "邯鄲炊未熟，榮謝隔逡巡。"]'),
('29f0240f-eaea-419e-b1c9-1ca68c080481','讀史六首  其一','蘇轍','宋','宋诗','song-poetry','','[]','留侯决成敗，面折愧周昌。',24,'全唐诗/poet.song.49000.json','["留侯决成敗，面折愧周昌。", "垂老召商叟，鴻鵠自高翔。"]'),
('0d45cebd-2683-44d7-9ea1-ea40f7127b91','讀史六首  其二','蘇轍','宋','宋诗','song-poetry','','[]','諸呂更相王，陳平氣何索。',24,'全唐诗/poet.song.49000.json','["諸呂更相王，陳平氣何索。", "千金壽絳侯，劉宗知有託。"]'),
('ed87fdc7-f5bf-4bbf-8d2d-a3f04be5b361','讀史六首  其三','蘇轍','宋','宋诗','song-poetry','','[]','賈生料吳楚，竟斃大梁城。',24,'全唐诗/poet.song.49000.json','["賈生料吳楚，竟斃大梁城。", "一身不自保，痛哭空傷生。"]'),
('254232fd-050d-4c74-a032-65e84ea7dc72','讀史六首  其四','蘇轍','宋','宋诗','song-poetry','','[]','桓文服荆楚，安取破國都。',24,'全唐诗/poet.song.49000.json','["桓文服荆楚，安取破國都。", "孔明不料敵，一世空馳驅。"]'),
('5179dde4-1e5c-437d-9366-2c36a39054cc','讀史六首  其五','蘇轍','宋','宋诗','song-poetry','','[]','安石善談笑，揮麈却苻秦。',24,'全唐诗/poet.song.49000.json','["安石善談笑，揮麈却苻秦。", "妄起并吞意，終殘吳越人。"]'),
('b494882b-d827-4996-8749-5e0dfe3badb6','讀史六首  其六','蘇轍','宋','宋诗','song-poetry','','[]','江河浪如屋，要須滄海容。',24,'全唐诗/poet.song.49000.json','["江河浪如屋，要須滄海容。", "可憐狄仁傑，猶復負婁公。"]'),
('13965f4b-ef30-42a0-990d-ca9292e8b20f','和子瞻雪浪齋','蘇轍','宋','宋诗','song-poetry','','[]','謫居杜老嘗東屯，波濤繞屋知龍尊。',160,'全唐诗/poet.song.49000.json','["謫居杜老嘗東屯，波濤繞屋知龍尊。", "門前石岸立精鐵，潮汐洗盡莓苔昏。", "野人相望夾水住，扁舟時過江西村。", "窗中縞練舒眼界，枕上雷霆驚耳門。", "不堪水怪妄欺客，欲借楚些時招魂。", "人生出處固難料，流萍著水初無根。", "旌旗旋逐金鼓發，蓑笠尚带風雨痕。", "高齋雪浪卷蒼石，北叟未見疑戲論。", "激泉飛水行亦凍，窮邊臘雪如翻盆。", "一杯徑醉萬事足，江城氣味猶應存。"]'),
('cbdb7600-836c-4c3a-a073-0ca730d9c8ac','次韵子瞻生日見寄','蘇轍','宋','宋诗','song-poetry','','[]','日月中人照與芬，心虛慮盡氣則薰。',176,'全唐诗/poet.song.49000.json','["日月中人照與芬，心虛慮盡氣則薰。", "彤霞點空來羣羣，精誠上徹天無雲。", "寸田幽闕暖不焚，眇視中外絳錦紋。", "冥然物我無復分，不出不入常氤氳。", "道師東西指示君，乘此飛仙勿留墳。", "茅山隠居有遺文，世人心動隨虻蚊。", "不信成功如所云，蚤夜賓餞同華勛。", "爾來僅能破魔軍，我經生日當益勤。", "公稟正氣飲不醺，梨棗未實要鋤耘。", "日云莫矣收桑枌，西還閉門止紛紛。", "憂愁真能散凄焄，萬事過耳今不聞。"]'),
('d1b38792-ac5a-45a4-8767-121cc3e0fb40','蹇師嵩山圖','蘇轍','宋','宋诗','song-poetry','','[]','峻極登高二十年，汝州回望一依然。',32,'全唐诗/poet.song.49000.json','["峻極登高二十年，汝州回望一依然。", "君行亦是高秋後，試覓神清古洞天。"]'),
('fe5a94d0-a0ae-4319-8e21-927d429f53e3','望嵩樓','蘇轍','宋','宋诗','song-poetry','','[]','連山鄣吾北，二室分西東。',96,'全唐诗/poet.song.49000.json','["連山鄣吾北，二室分西東。", "東山幾何高，不爲太室容。", "西山爲我低，少室見諸峰。", "臨軒一長嘆，隠見由所逢。", "試問山中人，二室竟誰雄。", "雄雌久已定，分別徐亦空。", "可憐汝陽酒，味與上國同。", "遊心四山外，寄適杯酒中。"]'),
('6bc70f85-c2f9-4bba-82f4-b2cc8fa92bbb','思賢堂','蘇轍','宋','宋诗','song-poetry','','[]','楊公守臨汝，俯仰八十載。',96,'全唐诗/poet.song.49000.json','["楊公守臨汝，俯仰八十載。", "推遷城市非，散落篇章在。", "外物固難必，清名竟安頼。", "孤亭右洲渚，斜日到冠佩。", "飛翔棟宇回，滉蕩波流對。", "稍存楸梧高，大剪菰蒲穢。", "遺編訪諸子，翠石補前廢。", "吏民亦潸然，未替甘棠愛。"]'),
('d70cfff7-9c2c-47fd-9ebc-462b2f18df28','阻風','蘇轍','宋','宋诗','song-poetry','','[]','大水蔑洲浦，牽挽無復施。',144,'全唐诗/poet.song.49000.json','["大水蔑洲浦，牽挽無復施。", "我舟恃長風，風止將安爲。", "塌然委積水，坐被弱纜維。", "市井隔峰嶺，食盡行將饑。", "長嘯呼風伯，厄窮豈不知。", "蓬蓬起東南，旗尾西北馳。", "所望乃大謬，開門訊舟師。", "舟師掉頭笑，沿泝要有時。", "泝者不少息，沿者長嗟咨。", "飄風不終日，急雨常相隨。", "雨止風亦止，條條弄清漪。", "我言未見信，君行自見之。"]'),
('0304e25f-92fd-4a4c-86cb-1dbf43ac0d13','次韵子瞻遊羅浮山','蘇轍','宋','宋诗','song-poetry','','[]','客迷墮澗逢玉京，雲行夭喬風號鳴。',192,'全唐诗/poet.song.49000.json','["客迷墮澗逢玉京，雲行夭喬風號鳴。", "暗中過盡石髓滑，驚喜觀闕朝霞明。", "東坡南去類此客，擠者力盡非求生。", "偶然瀕海少氛氣，復有福地容躬耕。", "諸侯歷聘謝魯叟，茅檐燕坐師老彭。", "天樞旋結日珠重，人寰下視鴻毛輕。", "俗緣漸覺冰雪解，元氣乍復蛟虬獰。", "遠遊脫屣入蓋竹，初怪長史留家庭。", "後來玉斧小兒子，亦入真誥參仙經。", "試令子弟學諸許，還家不用劍閣銘。", "洞天聞亦有圖籍，但恐未免如公卿。", "此心願與世無事，不願與世平不平。"]'),
('f0171a22-5de2-40fe-9829-f72216a0ec23','次韵子瞻江西','蘇轍','宋','宋诗','song-poetry','','[]','許君馬老共一邦，西山斷處流蜀江。',64,'全唐诗/poet.song.49000.json','["許君馬老共一邦，西山斷處流蜀江。", "誰令十載重渡瀧，灘頭舊寺晨鐘撞。", "亂流赤脚記淙淙，道俗自謂丹霞龐。", "便令築室修畦矼，往還二老筇一雙。"]'),
('f2ba042b-aee9-4f23-a810-f841f9fe3164','雨中遊小雲居','蘇轍','宋','宋诗','song-poetry','','[]','賣酒高安市，早歲逢五秋。',192,'全唐诗/poet.song.49000.json','["賣酒高安市，早歲逢五秋。", "常懷簡書畏，未暇雲居遊。", "十載還上都，再謫仍此州。", "廢斥免羈束，登臨散幽憂。", "鄉黨二三子，結束同一舟。", "雨餘江漲高，林薄煩撐鉤。", "積陰薦雷作，兩山亂雲浮。", "雨點落飛鏃，江光濺輕漚。", "笑語曾未畢，風雲遽誰收。", "舟人指松檜，古剎依林丘。", "老僧昔還住，晚飯迎淹留。", "食菜吾自飽，饋肉煩賢侯。", "嚴城迫吹角，歸棹隨輕鷗。", "聯翩閱村塢，燈火明譙樓。", "肩輿踐積甃，塗潦分潛溝。", "居處方自適，未知厭拘囚。"]'),
('8cc97f8c-3fb3-4b1b-8460-03cad796e863','次韵子瞻上元見寄','蘇轍','宋','宋诗','song-poetry','','[]','誰憐東坡老，獨看南海燈。',120,'全唐诗/poet.song.49000.json','["誰憐東坡老，獨看南海燈。", "故人隠山麓，燕坐銷床稜。", "人生天運中，往返成廢興。", "炎起爨下薪，凍合瓶中冰。", "頼有不變處，寂如方定僧。", "建城亦巖邑，燈火高下層。", "頭陀舊所識，天寒髮鬅鬙。", "問我何時來，嗟哉谷爲陵。", "幸此米方賤，日食聊一升。", "夜出隨衆樂，餔糟共騰騰。"]'),
('1ebb132f-9f42-493f-b31b-06863fcc53a2','次韵子瞻連雨江漲二首  其一','蘇轍','宋','宋诗','song-poetry','','[]','南過庾嶺更千山，烝潤由來共一天。',64,'全唐诗/poet.song.49000.json','["南過庾嶺更千山，烝潤由來共一天。", "雲塞虛空雨翻甕，江侵城市屋浮船。", "東郊晚稻須重插，西舍原蠶未及眠。", "獨棹扁舟趁申卯，米鹽奔走笑當年。"]'),
('84a1aa81-68ca-48a3-9382-e7f00054266d','次韵子瞻連雨江漲二首  其二','蘇轍','宋','宋诗','song-poetry','','[]','客到炎陬喜暫凉，江吹虛閣雨侵廊。',64,'全唐诗/poet.song.49000.json','["客到炎陬喜暫凉，江吹虛閣雨侵廊。", "回看野寺山溪隔，卧覺晨炊稻飯香。", "荔餉深紅陋櫻棗，桂醅淳白比琳琅。", "思移嶠北應非晚，未省南遷日月長。"]'),
('4b43993e-3d21-4108-beb5-0991432e7fdf','次韵侄過江漲','蘇轍','宋','宋诗','song-poetry','','[]','陰淫夏爲秋，雨暴溪作瀆。',120,'全唐诗/poet.song.49000.json','["陰淫夏爲秋，雨暴溪作瀆。", "缺防舊通市，流潦幾入屋。", "雖幸廩粟空，猶惜畦蔬綠。", "鹿駭不擇音，鴻羈分遵陸。", "室誚曾子還，城謳華元衄。", "中情久岑寂，外物競排蹙。", "設心等一慈，開懷受諸毒。", "道力雖未究，游波偶然伏。", "糧須三月聚，艾要七年蓄。", "君恩許北還，從此當退縮。"]'),
('bea662e0-6067-44ad-8914-aacd0d7aa582','亡嫂靖安君蒲氏挽詞二首  其一','蘇轍','宋','宋诗','song-poetry','','[]','家風足圖史，婦德儼蘋蘩。',48,'全唐诗/poet.song.49000.json','["家風足圖史，婦德儼蘋蘩。", "湯沐從夫寵，冠衣席弟恩。", "克家傳衆子，有後慶多孫。", "追養心何極，增封禮尚存。"]'),
('b53959ca-c39e-4242-94ec-9d09a6f51e01','亡嫂靖安君蒲氏挽詞二首  其二','蘇轍','宋','宋诗','song-poetry','','[]','宦遊非不遂，流落自粗疏。',48,'全唐诗/poet.song.49000.json','["宦遊非不遂，流落自粗疏。", "宗黨半天末，存亡驚素書。", "佳城東嶺外，茂木故阡餘。", "遥想千車送，臨江涕滿裾。"]'),
('6cf5c298-9e2a-4b63-8171-57959c7532f8','寄題武陵柳氏所居二首 天真堂','蘇轍','宋','宋诗','song-poetry','','[]','宦遊閱盡山川勝，歸老方知氣味真。',64,'全唐诗/poet.song.49000.json','["宦遊閱盡山川勝，歸老方知氣味真。", "歌哭不移身自穩，往還無間語尤親。", "永懷前輩無因見，猶喜諸郎有此人。", "千歲展禽風未改，不加雕琢世稱珍。"]'),
('6bee4e82-c13e-46b1-a0ab-3258a9e867d7','寄題武陵柳氏所居二首 康樂樓','蘇轍','宋','宋诗','song-poetry','','[]','邑居欲盡溪山好，不作層樓無奈何。',64,'全唐诗/poet.song.49000.json','["邑居欲盡溪山好，不作層樓無奈何。", "岩谷滿前收蠟屐，漪漣極目卷漁蓑。", "安心已得安身法，樂土偏令樂事多。", "千里筠陽猶靜治，還家一笑定無他。"]'),
('4f0e5f09-645f-458a-9208-a64b411792ad','筠州州宅雙蓮','蘇轍','宋','宋诗','song-poetry','','[]','綠蓋紅房共一池，一雙遊女巧追隨。',64,'全唐诗/poet.song.49000.json','["綠蓋紅房共一池，一雙遊女巧追隨。", "鏡中比並新妝後，風際携扶欲舞時。", "露蕊暗開香自倍，霜蓬漸老折猶疑。", "殷勤畫手傳真態，道院生綃數幅垂。"]'),
('14fda77c-0821-43ce-a9d4-5ff4179f74c8','奉同子瞻荔支嘆','蘇轍','宋','宋诗','song-poetry','','[]','蜀中荔支止嘉州，餘波及眉半有不。',176,'全唐诗/poet.song.49000.json','["蜀中荔支止嘉州，餘波及眉半有不。", "稻糠宿火却霜霰，結子僅與黄金侔。", "近聞閩尹傳種法，移種成都出巴峽。", "名園競擷絳紗苞，蜜漬瓊膚甘且滑。", "北遊京洛墮紅塵，箬籠白曬稱最珍。", "思歸不復爲蓴菜，欲及炎風朝露勻。", "平居著鞭苦不早，東坡南竄嶺南道。", "海邊百物非平生，獨數山前荔支好。", "荔支色味巧留人，不管年來白髮新。", "得歸便擬尋鄉路，棗栗園林不須顧。", "青枝丹實須十株，丁寧附書老農圃。"]'),
('3fa9d94c-45b6-4735-8316-99b7272c9890','次韵子瞻梳頭','蘇轍','宋','宋诗','song-poetry','','[]','水上有車車自翻，懸霤如線垂前軒。',64,'全唐诗/poet.song.49000.json','["水上有車車自翻，懸霤如線垂前軒。", "霜蓬已枯不再綠，有客勸我抽其根。", "枯根一去紫茸茁，珍重已試幽人言。", "紛紛華髮何足道，當返六十過去魂。"]'),
('25297c0e-0c1a-456b-9bc4-b85432de296b','勸子瞻修無生法','蘇轍','宋','宋诗','song-poetry','','[]','除却靈明一一空，年來丹竈漫施功。',64,'全唐诗/poet.song.49000.json','["除却靈明一一空，年來丹竈漫施功。", "掌中定有庵摩在，雲際懸知霧雨濛。", "已頼信心留掣電，要須凈戒拂昏銅。", "誰言逐客江南岸，身世雖窮心不窮。"]'),
('572e3960-9966-4636-b5d0-3dd62d7c5304','石盆種菖蒲甚茂忽開八九華或言此華壽祥也遠因生日作頌亦爲賦此','蘇轍','宋','宋诗','song-poetry','','[]','石盆攢石養菖蒲，沮洳沙泉韮葉鋪。',64,'全唐诗/poet.song.49000.json','["石盆攢石養菖蒲，沮洳沙泉韮葉鋪。", "世說華開難值遇，天將壽考報勤劬。", "心中本有長生藥，根底暗添無限鬚。", "更爾屈蟠增瘦硬，他年老病要相扶。"]'),
('aa85dd21-5f3f-4927-810b-1f2441f80d01','子瞻和陶公讀山海經詩欲同作而未成夢中得數句覺而補之','蘇轍','宋','宋诗','song-poetry','','[]','此心淡無著，與物常欣然。',60,'全唐诗/poet.song.49000.json','["此心淡無著，與物常欣然。", "虛閑偶有見，白雲在空間。", "愛之欲吐玩，恐爲時俗傳。", "逡巡自失去，雲散空長天。", "永愧陶彭澤，佳句如珠圓。"]'),
('52fb526a-d261-48a9-881d-fa88d209058d','成都僧法舟爲其祖師寶月求塔銘於惠州還過高安送歸','蘇轍','宋','宋诗','song-poetry','','[]','少年能講大乘經，法施堂中不出扃。',64,'全唐诗/poet.song.49000.json','["少年能講大乘經，法施堂中不出扃。", "爲許先師傳後世，徑從西海集南溟。", "忘身直犯黄茅瘴，滿意初成白塔銘。", "寄我淚痕歸萬里，遥知露滴澗松青。"]'),
('447782cf-3ddc-4790-9435-648f1768e089','東西京二絕  其一','蘇轍','宋','宋诗','song-poetry','','[]','親祀甘泉歲一終，屬車徐動不驚風。',32,'全唐诗/poet.song.49000.json','["親祀甘泉歲一終，屬車徐動不驚風。", "宓妃何預詞臣事，指點譏呵豹尾中。"]'),
('f86c009c-6807-461d-b777-613e95d332d2','東西京二絕  其二','蘇轍','宋','宋诗','song-poetry','','[]','犀箸金槃不暇嘗，更須石上擣黄粱。',32,'全唐诗/poet.song.49000.json','["犀箸金槃不暇嘗，更須石上擣黄粱。", "數錢未免河東舊，不識前朝大練光。"]'),
('3bcd7746-aabf-4ce5-a683-b2683487b1dd','唐相二絕  其一','蘇轍','宋','宋诗','song-poetry','','[]','楊王滅後少英雄，猶自澄思却月中。',32,'全唐诗/poet.song.49000.json','["楊王滅後少英雄，猶自澄思却月中。", "已得惠妃歡喜見，方頭笑殺曲江公。"]'),
('7e12e9dd-b050-4354-8653-83193ee83e67','唐相二絕  其二','蘇轍','宋','宋诗','song-poetry','','[]','朝中寂寂少名卿，晚歲雄猜氣益橫。',32,'全唐诗/poet.song.49000.json','["朝中寂寂少名卿，晚歲雄猜氣益橫。", "心怕無鬚少年士，可憐未識玉奴兄。"]'),
('908204e8-2741-462f-815f-436c55a05f01','寓居六咏  其一','蘇轍','宋','宋诗','song-poetry','','[]','手植天隨菊，晨添苜蓿盤。',48,'全唐诗/poet.song.49000.json','["手植天隨菊，晨添苜蓿盤。", "叢長憐夏苦，花晚怯秋寒。", "素食舊所愧，長齋今未闌。", "殷勤拾落蕊，眼暗讀書難。"]'),
('05d34966-66c7-4afd-955b-bb82192f456f','寓居六咏  其二','蘇轍','宋','宋诗','song-poetry','','[]','山丹炫南土，盈尺愧西京。',48,'全唐诗/poet.song.49000.json','["山丹炫南土，盈尺愧西京。", "所至曾無比，知非浪得名。", "未須求別種，尚欠剝繁英。", "行復春風度，天涯眼暫明。"]'),
('dfbce668-7f58-4495-8c4d-22de41568115','寓居六咏  其三','蘇轍','宋','宋诗','song-poetry','','[]','鄰家三畝竹，蕭散倚東牆。',48,'全唐诗/poet.song.49000.json','["鄰家三畝竹，蕭散倚東牆。", "誰謂非吾有，時能惠我凉。", "雪深聞毀折，風作任披猖。", "事過還依舊，相看意愈長。"]'),
('96858481-bf7d-4b79-ba11-7dc84579309e','寓居六咏  其四','蘇轍','宋','宋诗','song-poetry','','[]','弱榴生掩冉，插竹强支叉。',48,'全唐诗/poet.song.49000.json','["弱榴生掩冉，插竹强支叉。", "旋疊封根石，能開著子花。", "扶持物遂性，綴緝我成家。", "故國田園少，何須恨海涯。"]'),
('84fad151-c413-44be-a5e0-2882074f4600','寓居六咏  其五','蘇轍','宋','宋诗','song-poetry','','[]','大雞如人立，小雞三寸長。',48,'全唐诗/poet.song.49000.json','["大雞如人立，小雞三寸長。", "造物均付予，危冠兩昂藏。", "出欄風易倒，依草枯不僵。", "後庭花草盛，憐汝計興亡。"]'),
('096bbd9c-9347-4ade-b1d8-c111d0d635af','寓居六咏  其六','蘇轍','宋','宋诗','song-poetry','','[]','西鄰分半井，十口無渴憂。',48,'全唐诗/poet.song.49000.json','["西鄰分半井，十口無渴憂。", "歲旱百泉竭，日供八家求。", "艱難念生理，沾足愧寒流。", "比聞山田婦，出汲爭羣牛。"]'),
('17ed341e-ebcf-4515-915c-305991101f19','和子瞻新居欲成二首  其一','蘇轍','宋','宋诗','song-poetry','','[]','老罷子卿還屬國，功成定遠恨陽關。',64,'全唐诗/poet.song.49000.json','["老罷子卿還屬國，功成定遠恨陽關。", "漂流豈必風波際，顛沛何妨枕席間。", "伏臘便應隨俚俗，室廬聞似勝家山。", "因緣宿世非今日，頼有陰功許旋還。"]'),
('fa583b8e-7b91-46ad-a8bd-170a04e49d50','和子瞻新居欲成二首  其二','蘇轍','宋','宋诗','song-poetry','','[]','山連上帝朱明府，心是南宗無盡燈。',64,'全唐诗/poet.song.49000.json','["山連上帝朱明府，心是南宗無盡燈。", "過此欹危空比夢，年來瘴毒冷如冰。", "圖書一笑寧勞客，音信頻來尚有僧。", "梨棗功夫三歲辦，不緣憂患亦何曾。"]'),
('2a35477e-65c5-4f18-b488-45868f189c87','次遲韵二首  其一','蘇轍','宋','宋诗','song-poetry','','[]','老謫江南岸，萬里修烝嘗。',96,'全唐诗/poet.song.49000.json','["老謫江南岸，萬里修烝嘗。", "三子留二子，嵩少道路長。", "累以二孀女，辛勤具餱糧。", "誰令南飛鴻，送汝至我旁。", "饑寒不能病，氣紓色亦康。", "拊背問家事，嗟我久已忘。", "力耕當及春，無爲久南方。", "還家語諸女，素剛非王章。"]'),
('16073dcb-04e3-498e-b9ff-ebef06176daf','次遲韵二首  其二','蘇轍','宋','宋诗','song-poetry','','[]','世事非吾憂，物理有必至。',120,'全唐诗/poet.song.49000.json','["世事非吾憂，物理有必至。", "常暘百川竭，顧亦防雨耳。", "陰陽相糾纏，反覆更自治。", "幽懷澹不起，默坐識其意。", "長子念衰老，遠行重慚愧。", "疏慵身似僧，岑寂家近寺。", "但聞事日新，未覺吾有異。", "器鍠本自出，藩角徒不遂。", "得失衆共知，窮達佛所記。", "要令北歸日，粗究一大事。"]'),
('0906870f-46c9-4920-9dbd-cf6a67031d08','次遠韵','蘇轍','宋','宋诗','song-poetry','','[]','萬里謫南荒，三子從一幼。',120,'全唐诗/poet.song.49000.json','["萬里謫南荒，三子從一幼。", "謬追春秋餘，頼爾牛馬走。", "憂病多所忘，問學非復舊。", "借書里諸生，疑事誰當叩。", "吾兒雖懶教，擢穎既冠後。", "求友卷中人，玩心竹間岫。", "時令檢遺闕，相對忘昏晝。", "兄來試謳吟，句法漸翹秀。", "暫時鴻雁飛，迭發塤篪奏。", "更念宛丘子，頎然何時覯。"]'),
('909f3025-f5cd-47d4-999e-5ad0557563a8','次韵子瞻和陶公止酒','蘇轍','宋','宋诗','song-poetry','','[]','少年無大過，臨老重復止。',120,'全唐诗/poet.song.49000.json','["少年無大過，臨老重復止。", "自言衰病根，恐在酒杯裏。", "今年各南遷，百事付諸子。", "誰言瘴霧中，乃有相逢喜。", "連床聞動息，一夜再三起。", "泝流俯仰得，此病竟何理。", "平生不尤人，未免亦求己。", "非酒猶止之，其餘真止矣。", "飄然從孔公，乘桴南海涘。", "路逢安期生，一笑千萬祀。"]'),
('829a5985-f67c-4ad5-8b0f-e608c317fad8','次韵子瞻過海','蘇轍','宋','宋诗','song-poetry','','[]','我遷海康郡，猶在寰海中。',168,'全唐诗/poet.song.49000.json','["我遷海康郡，猶在寰海中。", "送君渡海南，風帆若張弓。", "笑揖彼岸人，回首平生空。", "平生定何有，此去未可窮。", "惜無好勇夫，從此乘桴翁。", "幽子疑龍蝦，牙須竟誰雄。", "閉門亦勿見，一嗅同香風。", "晨朝飽粥飯，洗鉢隨僧鐘。", "有問何時歸，茲焉若將終。", "居家出家人，豈復懷兒童。", "老聃真吾師，出入初猶龍。", "籠樊顧甚密，俯首姑爾容。", "衆人指我笑，韁鎖無此工。", "一瞬千佛土，相期兜率宮。"]'),
('1cf85244-2b48-4bec-90bb-c706111a32f5','過侄寄椰冠','蘇轍','宋','宋诗','song-poetry','','[]','衰髮秋來半是絲，幅巾緇撮强爲儀。',64,'全唐诗/poet.song.49000.json','["衰髮秋來半是絲，幅巾緇撮强爲儀。", "垂空旋取海棕子，束髮裝成老法師。", "變化密移人不悟，壞成相續我心知。", "茅檐竹屋南溟上，亦似當年廊廟時。"]'),
('f82253a5-e64b-4067-b02b-382252a6a4a3','寓居二首 東亭','蘇轍','宋','宋诗','song-poetry','','[]','十口南遷粗有歸，一軒臨路閱奔馳。',64,'全唐诗/poet.song.49000.json','["十口南遷粗有歸，一軒臨路閱奔馳。", "市人不慣頻回首，坐客相諳便解頤。", "慚愧天涯善知識，增添城外小茅茨。", "華嚴未讀河沙偈，偃仰明窗手自披。"]'),
('74be3ade-345b-4497-a8b3-cd837eeb5d0a','寓居二首 東樓','蘇轍','宋','宋诗','song-poetry','','[]','月從海上湧金盆，直入東樓照病身。',64,'全唐诗/poet.song.49000.json','["月從海上湧金盆，直入東樓照病身。", "久已無心問南北，時能閉目待儀麟。", "颶風不作三農喜，舶客初來百物新。", "歸去有時無定在，漫隨俚俗共欣欣。"]'),
('b76856f8-ddbd-4a19-9116-60f79e8cd117','所寓堂後月季再生與遠同賦','蘇轍','宋','宋诗','song-poetry','','[]','客背有芳藂，開花不遺月。',132,'全唐诗/poet.song.49000.json','["客背有芳藂，開花不遺月。", "何人縱尋斧，害意肯留枿。", "偶乘秋雨滋，冒土見微茁。", "猗猗抽條穎，頗欲傲寒冽。", "勢窮雖云病，根大未容拔。", "我行天涯遠，幸此城南茇。", "小堂劣容卧，幽閣粗可躡。", "中無一尋空，外有四鄰市。", "窺牆數柚實，隔屋看椰葉。", "葱蒨獨茲苗，愍愍待其活。", "及春見開敷，三嗅何忍折。"]'),
('34ac718e-dee9-4d48-9494-bf0145f9b7b7','浴罷','蘇轍','宋','宋诗','song-poetry','','[]','逐客例幽憂，多年不洗沐。',168,'全唐诗/poet.song.49000.json','["逐客例幽憂，多年不洗沐。", "予髮櫛無垢，身垢要須浴。", "顛隮本天運，憤恨當誰復。", "茅檐容病軀，稻飯飽枵腹。", "形骸但癯瘁，氣血尚豐足。", "微陽閱九地，浮彩見雙目。", "枯槁如束薪，堅緻比溫玉。", "長齋雖云凈，閱月聊一沃。", "石泉澣巾帨，土釜煮桃竹。", "南窗日未移，困卧久彌熟。", "華嚴有餘帙，默坐心自讀。", "諸塵忽消盡，法界了無矚。", "恍如仰山翁，欲就溈叟卜。", "猶恐墮聲聞，大願勤自督。"]'),
('7815fc49-7b6e-4fce-b133-f467b187043c','次遠韵齒痛','蘇轍','宋','宋诗','song-poetry','','[]','元明散諸根，外與六塵合。',72,'全唐诗/poet.song.49000.json','["元明散諸根，外與六塵合。", "流中積緣氣，虛妄無可託。", "敝陋少空明，婦姑相攘奪。", "日出暵焦牙，風來動危蘀。", "喜汝因病悟，或免終身著。", "更須誦楞嚴，從此脫纏縛。"]'),
('251820e9-1cf3-4dbc-9b04-6a1b782c764d','子瞻聞瘦以詩見寄次韵','蘇轍','宋','宋诗','song-poetry','','[]','多生習氣未除肉，長夜安眠懶食粥。',128,'全唐诗/poet.song.49000.json','["多生習氣未除肉，長夜安眠懶食粥。", "屈伸久已效熊虎，倒掛漸擬同蝙蝠。", "衆笑忍饑長杜門，自恐莫年還入俗。", "經旬輒瘦駭鄰父，未信腦滿添黄玉。", "海夷旋覺似齊魯，山蕨仍堪嘗菽粟。", "孤船會復見洲渚，小車未用安羊鹿。", "海南老兄行尤苦，樵爨長須同一僕。", "此身所至即所安，莫同歸期兩黄鵠。"]'),
('e7925051-7edb-4718-aec8-a2d29155c869','次韵子瞻獨覺','蘇轍','宋','宋诗','song-poetry','','[]','咄咄書空中有怪，內熱搜膏發癰疥。',96,'全唐诗/poet.song.49000.json','["咄咄書空中有怪，內熱搜膏發癰疥。", "羹藜飯芋如固然，飽食安眠真一快。", "午鷄鳴屋呼不起，欠伸吉貝重衾裏。", "此身南北付天工，竹杖芒鞋即行李。", "夜長却對一燈明，上池溢流微有聲。", "幻中非幻人不見，本來日月無陰晴。"]'),
('e5226364-379d-4bad-8033-48c9b64337ea','次韵子瞻夜坐','蘇轍','宋','宋诗','song-poetry','','[]','月入虛窗疑欲旦，香凝幽室久猶薰。',64,'全唐诗/poet.song.49000.json','["月入虛窗疑欲旦，香凝幽室久猶薰。", "清風巧爲吹餘瘴，疏雨時來報斷雲。", "南海炎凉身已慣，北方毀譽耳誰聞。", "遥知掛壁瓢無酒，歸舶還將一酌分。"]'),
('fc717f5c-c19c-4ad7-bb43-a942656886cb','次韵子瞻寄賀生日','蘇轍','宋','宋诗','song-poetry','','[]','弟兄本三人，懷抱喪其一。',120,'全唐诗/poet.song.49000.json','["弟兄本三人，懷抱喪其一。", "頎然仲與叔，耆老天所騭。", "師心每獨往，可否輒自必。", "折足非所恨，所恨覆鼎實。", "上頼吾君仁，議止海濱黜。", "凄酸念母氏，此恨何時畢。", "平生賢孟博，苟生不謂吉。", "歸心天若許，定卜老泉室。", "凄凉百年後，事付何人筆。", "于今兄獨知，言之泣生日。"]'),
('2356e291-d30f-41ac-9034-d288f9760b50','次韵子瞻寄黄子木杖','蘇轍','宋','宋诗','song-poetry','','[]','老至亦有漸，五十惟杖始。',96,'全唐诗/poet.song.49000.json','["老至亦有漸，五十惟杖始。", "行年日辰匝，幸免鄉閭耻。", "罪重瘡難平，餘痂未脫疻。", "登山足猶健，不用扶兒子。", "我兄念辛勤，贈此携且倚。", "他年賜環日，田舍尤須此。", "早收藤節杯，旋綴烏皮几。", "茅檐數間足，不用伐桐杞。"]'),
('bebecd4b-58c9-4b3b-b9f3-3403d16e8b3f','次韵子瞻謫居三適 旦起理髮','蘇轍','宋','宋诗','song-poetry','','[]','道人鷄鳴起，趺坐存九宮。',120,'全唐诗/poet.song.49000.json','["道人鷄鳴起，趺坐存九宮。", "靈液流下田，伏苓抱長松。", "顛毛得餘潤，冉冉欺霜風。", "俯就無數櫛，九九爲一通。", "洗沐廢已久，徐之勿匆匆。", "氣來自涌泉，至此知幾重。", "近聞西邊將，袒裼擁馬鬃。", "歸來建赤油，不復儕伍同。", "笑我守尋尺，求與真源逢。", "人生各有安，未肯易三公。"]'),
('18eaa256-e58c-4dac-a45b-9f3047e77f9a','次韵子瞻謫居三適 午窗坐睡','蘇轍','宋','宋诗','song-poetry','','[]','定中龍眠膝，定起柳生肘。',120,'全唐诗/poet.song.49000.json','["定中龍眠膝，定起柳生肘。", "心無出入異，三昧亦何有。", "晴窗午陰轉，坐睡一何久。", "頹然擁褐身，剝啄叩門手。", "褰帷顧我笑，疑我困宿酒。", "不知吾喪我，冰消不遺壽。", "空虛無一物，彼物自枯朽。", "夢中得靈藥，此藥從誰受。", "侵尋入四支，欲洗自無垢。", "從今百不欠，只欠歸田叟。"]'),
('3b7ad1fa-2795-4fad-97d8-98ffa4bb4666','次韵子瞻謫居三適 夜卧濯足','蘇轍','宋','宋诗','song-poetry','','[]','海民慢寒備，不畜衾與裯。',120,'全唐诗/poet.song.49000.json','["海民慢寒備，不畜衾與裯。", "雖苦地氣泄，亦無徒跣憂。", "逐客久未安，集舍占鵂鶹。", "念昔使胡中，車馳卒不留。", "貂裘溯北風，十襲猶颼颼。", "中塗履冰河，馬倒身自投。", "宛足費馮翼，千里煩帣韝。", "十年事湯劑，風雨氣輒浮。", "南來足憂慮，此病何時瘳。", "名身孰親疏，慎勿求封侯。"]'),
('5cc419b9-a698-452f-9b2d-0afadae8dfcb','同子瞻次過遠重字韵','蘇轍','宋','宋诗','song-poetry','','["\u897f\u6e56"]','孟子自誇心不動，未試永嘉鐵輪重。',160,'全唐诗/poet.song.49000.json','["孟子自誇心不動，未試永嘉鐵輪重。", "弟兄六十老病餘，萬里同遭海隅送。", "長披羊裘類嚴子，罷食豬肝同閔仲。", "大男留處事田畝，幼子隨行躬釜甕。", "低眉語笑接鄰父，彈指吁嗟到蠻洞。", "茅茨一日敢忘葺，桑柘十年須勉種。", "來時邂逅得相携，歸去逡巡應復從。", "莫驚憂患爾來同，久知出處平生共。", "雖令子孫治家學，休炫文章供世用。", "潁川築室久未成，夜來忽作西湖夢。"]'),
('6067dc51-9720-408a-8c67-a6d15c123822','次韵子瞻和淵明擬古九首  其一','蘇轍','宋','宋诗','song-poetry','','[]','客居遠林薄，依牆種楊柳。',84,'全唐诗/poet.song.49000.json','["客居遠林薄，依牆種楊柳。", "歸期未可必，成陰定非久。", "邑中有佳士，忠信可與友。", "相逢話禪寂，落日共杯酒。", "艱難本何求，緩急肯相負。", "故人在萬里，不復爲薄厚。", "米盡鬻衣衾，時勞問無有。"]'),
('f9febdce-669f-4de0-bc07-65b4a247d02e','次韵子瞻和淵明擬古九首  其二','蘇轍','宋','宋诗','song-poetry','','[]','閉門不復出，茲焉若將終。',72,'全唐诗/poet.song.49000.json','["閉門不復出，茲焉若將終。", "蕭然環堵間，乃復有爲戎。", "我師柱下史，久以雌守雄。", "金刀雖云利，未聞能斫風。", "世人欲困我，我已安長窮。", "窮甚當辟穀，徐觀百年中。"]'),
('cb18cc2e-a311-4cac-8c06-1d5103af5014','次韵子瞻和淵明擬古九首  其三','蘇轍','宋','宋诗','song-poetry','','[]','蕭蕭髮垂素，晡日迫西隅。',72,'全唐诗/poet.song.49000.json','["蕭蕭髮垂素，晡日迫西隅。", "道人愍我老，元氣時卷舒。", "歲惡風雨交，何不完子廬。", "萬法滅無餘，方寸可久居。", "將掃道上塵，先拔庭中蕪。", "一凈百亦凈，我物皆如如。"]'),
('67623184-53dc-4d65-ab44-67fc403bfa55','次韵子瞻和淵明擬古九首  其四','蘇轍','宋','宋诗','song-poetry','','[]','夜夢被髮翁，騎驎下大荒。',96,'全唐诗/poet.song.49000.json','["夜夢被髮翁，騎驎下大荒。", "獨行無與遊，闖然款我堂。", "高論何崢嶸，微言何渺茫。", "我徐聽其說，未離翰墨場。", "平生氣如虹，宜不葬北邙。", "少年慕遺文，奇姿揖昂昂。", "衰罷百無用，漸以圜斫方。", "隠約就所安，老退還自傷。"]'),
('45f08cdb-630e-4645-a9ab-422f6fbe77cc','次韵子瞻和淵明擬古九首  其五','蘇轍','宋','宋诗','song-poetry','','[]','海康雜蠻蜒，禮俗久未完。',96,'全唐诗/poet.song.49000.json','["海康雜蠻蜒，禮俗久未完。", "我居近閭閻，願先化衣冠。", "衣冠一有耻，其下胡爲顔。", "東鄰有一士，讀書寄賢關。", "歸來奉親友，跬步行必端。", "慨然顧流俗，嘆息未敢彈。", "提提烏鳶中，見此孤翔鸞。", "漸能衣裘褐，袒裼知惡寒。"]'),
('252b49b9-4a10-4761-a062-3e08c27e9e48','次韵子瞻和淵明擬古九首  其六','蘇轍','宋','宋诗','song-poetry','','[]','佛法行中原，儒者耻論茲。',108,'全唐诗/poet.song.49000.json','["佛法行中原，儒者耻論茲。", "功施冥冥中，亦何負當時。", "此方舊雜染，渾渾無名緇。", "治生守家室，坐使斯人疑。", "未知酒肉非，能與生死辭。", "熾哉吳閩間，佛事不可思。", "生子多穎悟，得報豈汝欺。", "時俾正法眼，一出照曜之。", "誰爲邑中豪，勤誦我此詩。"]'),
('ff966daf-0f2d-4cae-bf0e-9f34ae9cf3ef','次韵子瞻和淵明擬古九首  其七','蘇轍','宋','宋诗','song-poetry','','[]','憂來感人心，悒悒久未和。',60,'全唐诗/poet.song.49000.json','["憂來感人心，悒悒久未和。", "呼兒具濁酒，酒酣起長歌。", "歌罷還獨舞，黍麥力誠多。", "憂長酒易消，脫去如風花。", "不悟萬法空，子如此心何。"]'),
('e81b5582-1464-4def-9a1e-a0bc8f0ca8c6','次韵子瞻和淵明擬古九首  其八','蘇轍','宋','宋诗','song-poetry','','[]','杜門人笑我，不知有天遊。',72,'全唐诗/poet.song.49000.json','["杜門人笑我，不知有天遊。", "光明遍十方，咫尺陋九州。", "此觀一日成，衮衮通法流。", "竿木常自隨，何必返故丘。", "老聃白髮年，青牛去西周。", "不遇關尹喜，履迹誰能求。"]'),
('992b3442-a159-4da4-aca5-0809b1c8661b','次韵子瞻和淵明擬古九首  其九','蘇轍','宋','宋诗','song-poetry','','[]','鉏田種紫芝，有根未堪採。',60,'全唐诗/poet.song.49000.json','["鉏田種紫芝，有根未堪採。", "逡巡歲月度，太息毛髮改。", "晨朝玉露下，滴瀝投滄海。", "鬚牙忽長茂，枝葉行可待。", "夜燒沉水香，持戒勿中悔。"]'),
('457b4f45-6679-4803-a504-263c481ebc28','雨中招吳子野先生','蘇轍','宋','宋诗','song-poetry','','[]','柴門不出蓬生徑，暑雨無時水及堂。',32,'全唐诗/poet.song.49000.json','["柴門不出蓬生徑，暑雨無時水及堂。", "辟穀頼君能作客，暫來煎蜜餉桃康。"]'),
('d65fbba1-d957-4794-90ca-2fb6392a3581','答吳和二絕  其一','蘇轍','宋','宋诗','song-poetry','','[]','三間浰水小茅屋，不比麻田新草堂。',32,'全唐诗/poet.song.49000.json','["三間浰水小茅屋，不比麻田新草堂。", "問我秋來氣如火，此間何事得安康。"]'),
('dde8421f-1861-4ad2-a8f8-d5ac15008f3d','答吳和二絕  其二','蘇轍','宋','宋诗','song-poetry','','[]','慣從李叟遊都市，久伴藍翁醉畫堂。',32,'全唐诗/poet.song.49000.json','["慣從李叟遊都市，久伴藍翁醉畫堂。", "不似蘇門但長嘯，一生留恨與嵇康。"]'),
('42aafe5b-1ec9-4e39-9eb7-79a68c739fbc','閏九月重九與父老小飲四絕  其一','蘇轍','宋','宋诗','song-poetry','','[]','九日龍山霜露凝，龍川九日氣如烝。',32,'全唐诗/poet.song.49000.json','["九日龍山霜露凝，龍川九日氣如烝。", "偶逢閏月還重九，酒熟風高喜不勝。"]'),
('ae5f167d-2c88-487c-937d-472427df5d86','閏九月重九與父老小飲四絕  其二','蘇轍','宋','宋诗','song-poetry','','[]','獲罪清時世共憎，龍川父老尚相尋。',32,'全唐诗/poet.song.49000.json','["獲罪清時世共憎，龍川父老尚相尋。", "直須便作鄉關看，莫起天涯萬里心。"]'),
('ac76ba38-2c65-45c3-b85e-332c24c3a442','閏九月重九與父老小飲四絕  其三','蘇轍','宋','宋诗','song-poetry','','[]','客主俱年六十餘，紫萸黄菊映霜鬚。',32,'全唐诗/poet.song.49000.json','["客主俱年六十餘，紫萸黄菊映霜鬚。", "山深瘴重多寒勢，老大須將酒自扶。"]'),
('4b5e4315-305b-4809-8950-a2eaf2466758','閏九月重九與父老小飲四絕  其四','蘇轍','宋','宋诗','song-poetry','','[]','尉佗城下兩重陽，白酒黄鷄意自長。',32,'全唐诗/poet.song.49000.json','["尉佗城下兩重陽，白酒黄鷄意自長。", "卯飲下床虛已散，老年不似少年忙。"]'),
('9888ca91-9692-4fb2-85f4-571ee29c87c8','求黄家紫竹杖','蘇轍','宋','宋诗','song-poetry','','[]','曾家紫竹君家種，曾園竹與荒藤共。',128,'全唐诗/poet.song.49000.json','["曾家紫竹君家種，曾園竹與荒藤共。", "藤驕竹瘁如畏人，不似君家竹森聳。", "我來買宅非爲宅，愛此風梢時一弄。", "磨刀向藤久未忍，樹倒藤披真自送。", "繁陰一豁新笋地，狂鞭欲向青春動。", "我身病後少筋力，遍求拄杖扶腰痛。", "蕭蕭瘦幹未能任，一畝君家知足用。", "一枝遺我拄尋君，老酒仍煩爲開甕。"]'),
('7a25facb-b5b9-45a7-9bce-63300ae64b72','賦豐城劍','蘇轍','宋','宋诗','song-poetry','','[]','劍氣夜干斗，精誠初莫隔。',96,'全唐诗/poet.song.49000.json','["劍氣夜干斗，精誠初莫隔。", "全身寄獄戶，隠約還自得。", "張雷彼知我，勉爲汝一出。", "腰間雜環佩，亦既報之德。", "凜凜天地間，要非手中物。", "躍入延平水，三日飛霹靂。", "出當乘風雷，歸當卧泉石。", "千年故穴在，三嘆泉上客。"]'),
('e7993809-39dc-44e3-b577-73653de93c4e','范丞相堯夫挽詞二首  其一','蘇轍','宋','宋诗','song-poetry','','[]','持身守忠恕，臨事耻浮沉。',48,'全唐诗/poet.song.49000.json','["持身守忠恕，臨事耻浮沉。", "直道更三黜，平生惟一心。", "家風來自遠，國論老彌深。", "令德真如玉，泥沙枉見侵。"]'),
('5f864b50-519a-4823-a59d-9db22d7cf74d','范丞相堯夫挽詞二首  其二','蘇轍','宋','宋诗','song-poetry','','[]','南遷頭已白，北返病初加。',48,'全唐诗/poet.song.49000.json','["南遷頭已白，北返病初加。", "君意知無罪，天心許到家。", "同朝曾忝舊，握手一長嗟。", "時事紛無已，還應付棣華。"]'),
('710af6e1-94b7-4237-bcb6-a9fbb8024886','卜居','蘇轍','宋','宋诗','song-poetry','','[]','我歸萬里初無宅，鳳去千年尚有臺。',64,'全唐诗/poet.song.49000.json','["我歸萬里初無宅，鳳去千年尚有臺。", "誰爲繞池先種竹，可憐當砌已栽梅。", "囊資只數腰金在，歸計長遭鬢雪催。", "欲就草堂終歲事，落成鄰舍許銜杯。"]'),
('658bf765-69dd-4f49-8a25-73b374c9cb0a','和子瞻過嶺','蘇轍','宋','宋诗','song-poetry','','[]','山林瘴霧老難堪，歸去中原荼亦甘。',64,'全唐诗/poet.song.49000.json','["山林瘴霧老難堪，歸去中原荼亦甘。", "有命誰令終返北，無心自笑欲巢南。", "蠻音慣習疑傖語，脾病縈纏带嶺嵐。", "手挹祖師清凈水，不嫌白髮照毿毿。"]'),
('9a40e405-5fd8-4f47-a38d-f9199326067e','子瞻贈嶺上老人次韵代老人答','蘇轍','宋','宋诗','song-poetry','','[]','嶺頭盧老一爐灰，長短根莖各自栽。',32,'全唐诗/poet.song.49000.json','["嶺頭盧老一爐灰，長短根莖各自栽。", "輕賤已消先世業，知君海上去仍回。"]'),
('938f8f79-857b-4ff9-be5c-8bf8deecba8f','大行皇太后挽詞二首  其一','蘇轍','宋','宋诗','song-poetry','','[]','累朝宗內治，晚歲擅鴻勛。',48,'全唐诗/poet.song.49000.json','["累朝宗內治，晚歲擅鴻勛。", "立子得元聖，收簾奉長君。", "一言消橫逆，多難弭紛紜。", "仙馭曾非遠，長瞻鞏洛雲。"]'),
('5d73a4e3-754e-4392-ae87-20405721737d','大行皇太后挽詞二首  其二','蘇轍','宋','宋诗','song-poetry','','[]','家風承舊相，國體繼皇姑。',48,'全唐诗/poet.song.49000.json','["家風承舊相，國體繼皇姑。", "定策從中禁，傳聲震海隅。", "春風開閉蟄，朝露濕焦枯。", "萬里生還客，冠纓淚雨濡。"]'),
('ca863f06-8c71-4495-b959-4e8f95fbcecd','追尊皇太后挽詞二首  其一','蘇轍','宋','宋诗','song-poetry','','[]','月缺年何久，龍飛事一新。',48,'全唐诗/poet.song.49000.json','["月缺年何久，龍飛事一新。", "追崇名號正，同袝禮容均。", "鳳翣低迎日，龍輴細起塵。", "都人知舜孝，擁紼盡霑巾。"]'),
('ad22cd37-9482-4235-8ef7-fb1c4daad1b0','追尊皇太后挽詞二首  其二','蘇轍','宋','宋诗','song-poetry','','[]','德美鍾岐嶷，榮華倍感傷。',48,'全唐诗/poet.song.49000.json','["德美鍾岐嶷，榮華倍感傷。", "一時朝野恨，百世本支長。", "出祖悲無憾，因山儉有光。", "他年過嵩洛，望拜裕陵旁。"]'),
('d0ef581a-7e94-452c-a503-899dee5e6bb9','贈史文通奉議二首  其一','蘇轍','宋','宋诗','song-poetry','','[]','牆北史居士，掛冠心轉閑。',48,'全唐诗/poet.song.49000.json','["牆北史居士，掛冠心轉閑。", "頂開人共怪，神去夜深還。", "白雪微侵鬢，丹砂久駐顔。", "從君欲問道，何日徑開關。"]'),
('4c341748-7c7c-4657-a752-b0292df55fd6','贈史文通奉議二首  其二','蘇轍','宋','宋诗','song-poetry','','[]','有叟住東野，畏人希入城。',48,'全唐诗/poet.song.49000.json','["有叟住東野，畏人希入城。", "君時共還往，我欲問修行。", "早歲識岩客，近時逢絳生。", "真能訪茅屋，屣履試將迎。"]'),
('26fd07a3-7129-4ae4-b585-b0f4bc16e9e4','次前韵示楊明二首  其一','蘇轍','宋','宋诗','song-poetry','','[]','晚歲有餘樂，天教一向閑。',48,'全唐诗/poet.song.49000.json','["晚歲有餘樂，天教一向閑。", "嵩陽百口住，嶺外七年還。", "卜宅先鄰晏，携瓢欲飲顔。", "吳僧來不久，相約叩禪關。"]'),
('183b12f2-b0b8-47fa-b169-acc85dcb12a1','次前韵示楊明二首  其二','蘇轍','宋','宋诗','song-poetry','','[]','甘井元依廟，平湖亦近城。',48,'全唐诗/poet.song.49000.json','["甘井元依廟，平湖亦近城。", "幅巾朝食罷，芒屩雨中行。", "擾擾初何事，悠悠畢此生。", "欲邀東郭叟，煩子作郊迎。"]'),
('d2de6ca8-902c-45b2-bba3-198b9f97f949','唐修撰義問挽詞二首  其一','蘇轍','宋','宋诗','song-poetry','','[]','家風臺柏老，遺直故依然。',48,'全唐诗/poet.song.49000.json','["家風臺柏老，遺直故依然。", "節見南遷後，神凝未瞑前。", "臨民舊有法，訓子適成篇。", "九轉今猶在，參同豈妄傳。"]'),
('919c7881-3d2d-460f-bb60-1871c63a9594','唐修撰義問挽詞二首  其二','蘇轍','宋','宋诗','song-poetry','','[]','我返南荒日，君臨舊許初。',48,'全唐诗/poet.song.49000.json','["我返南荒日，君臨舊許初。", "笑談寬老病，旌旆擁茅廬。", "酒盞開雖數，溪堂到尚疏。", "誰言生死隔，近在浹旬餘。"]'),
('fae76107-c117-4a82-b733-b750b7708918','寄題登封揖仙亭','蘇轍','宋','宋诗','song-poetry','','[]','靈王太子本讀書，縱談穀洛參諸儒。',144,'全唐诗/poet.song.49000.json','["靈王太子本讀書，縱談穀洛參諸儒。", "生來不見全盛初，老成遺訓誰楷模。", "心知漸失文武餘，蕭然直入山中居。", "山間吹笙鳳凰呼，升天白日乘龍車。", "周人聚觀拜路隅，明月爲佩雲爲裾。", "歸來千歲孰在無，赤松老彭自爲徒。", "上侍玉宸臨九區，烜赫不類山澤癯。", "依山作邑賢大夫，夜中焚香溯空虛。", "我欲從之駕肩輿，秋風八月來徐徐。"]'),
('28c97c76-ecdf-4126-809d-7aceb2c63e97','吳沖卿夫人秦國挽詞二首  其一','蘇轍','宋','宋诗','song-poetry','','[]','國老相隨盡，家風慨獨存。',48,'全唐诗/poet.song.49000.json','["國老相隨盡，家風慨獨存。", "見夫成相業，聽子得忠言。", "氣節慚多士，聲華盛一門。", "平生高義重，未易俗人論。"]'),
('dfd4a3de-9d23-4097-9288-fdf63dedb29b','吳沖卿夫人秦國挽詞二首  其二','蘇轍','宋','宋诗','song-poetry','','[]','雅頌成章早，春秋發論長。',48,'全唐诗/poet.song.49000.json','["雅頌成章早，春秋發論長。", "風規留叔向，文采似中郎。", "覽古明興廢，臨危喜激昂。", "南遷初不恨，李杜得從滂。"]'),
('c41795a3-7345-42d7-bf11-4e1f6ae7bf44','十一月十三日雪','蘇轍','宋','宋诗','song-poetry','','[]','南方霜露多，雖寒雪不作。',144,'全唐诗/poet.song.49000.json','["南方霜露多，雖寒雪不作。", "北歸亦何喜，三年雪三落。", "我田在城西，禾麥敢嫌薄。", "今年陳宋災，水旱更爲虐。", "閉糴斯不仁，逐熟自難却。", "饑寒雖吾患，尚可省鹽酪。", "飛蝗昨過野，遺種遍陂濼。", "春陽百日至，鬧若蠶生箔。", "得雪流土中，及泉盡魚躍。", "美哉豐年祥，不待炎火灼。", "呼兒具樽酒，對婦同一酌。", "誤認屋瓦鳴，更願聞雪脚。"]'),
('88ff11e0-18c0-4f93-8c9e-9df32016f1bf','補子瞻贈姜唐佐秀才','蘇轍','宋','宋诗','song-poetry','','[]','生長茅間有異芳，風流稷下古諸姜。',64,'全唐诗/poet.song.49000.json','["生長茅間有異芳，風流稷下古諸姜。", "適從瓊管魚龍窟，秀出羊城翰墨場。", "滄海何曾斷地脈，白袍端合破天荒。", "錦衣他日千人看，始信東坡眼目長。"]'),
('7d008d00-8882-4936-8729-ad24a8c999d7','遷居汝南','蘇轍','宋','宋诗','song-poetry','','[]','我昔還自南，從此適舊許。',192,'全唐诗/poet.song.49000.json','["我昔還自南，從此適舊許。", "再歲常杜門，壁觀無與語。", "何人自驚顧，未聽即安處。", "亟逃潁州籍，來貫汝南戶。", "妻孥不及將，童僕具樽俎。", "身如孤棲鵲，夜起三繞樹。", "故人樂安生，風節似其父。", "忻然暫一笑，捨我西南去。", "去已還閉門，時作野田步。", "蕭條古僧舍，遺像得顔魯。", "精神凜如生，今昔吾與女。", "已同羈窮厄，但脫生死怖。", "幸世方和平，有土非寇虜。", "春寒燒黄茅，晝飯煮青茹。", "何必潩上田，幸此足粳稌。", "歸心念狂簡，裁製時已莫。"]'),
('fe0025df-884a-4e30-99e7-111d7c13f428','索居三首  其一','蘇轍','宋','宋诗','song-poetry','','[]','索居非謫地，垂老更窮途。',48,'全唐诗/poet.song.49000.json','["索居非謫地，垂老更窮途。", "去住看人意，幽憂頼我無。", "小園花草穢，陋巷犬羊俱。", "近覺根塵離，忘言日益愚。"]'),
('f5939188-d747-46d6-8c9c-d5a627f107fe','索居三首  其二','蘇轍','宋','宋诗','song-poetry','','[]','平生亦何事，十載苦顛隮。',48,'全唐诗/poet.song.49000.json','["平生亦何事，十載苦顛隮。", "夢嶮曾非嶮，覺迷終不迷。", "客居兼壯子，別久愧良妻。", "稍訝音書闊，春陰道路泥。"]'),
('86efc8b4-230b-46aa-a096-0ec18d816ebf','索居三首  其三','蘇轍','宋','宋诗','song-poetry','','[]','許蔡古鄰國，風煙相雜和。',48,'全唐诗/poet.song.49000.json','["許蔡古鄰國，風煙相雜和。", "蕭然客舍靜，不願主人過。", "野薺春將老，淮魚夏漸多。", "街南病居士，有酒對酣歌。"]'),
('a1c34dca-07fe-4402-868c-9d8ae345fea3','聞諸子欲再質卞氏宅','蘇轍','宋','宋诗','song-poetry','','[]','我生髮半白，四海無尺椽。',168,'全唐诗/poet.song.49000.json','["我生髮半白，四海無尺椽。", "卞氏昔冠冕，子孫今蕭然。", "願以棟宇餘，救此朝夕懸。", "顧我亦何有，較子差尚賢。", "傾囊不復惜，掃地幸見捐。", "南鄰隔短牆，兩孫存故廛。", "松竹手自種，風霜歲逾堅。", "幽花亂蜂蝶，古木嘶蜩蟬。", "垂陰可數畝，成功幾百年。", "人心苦無厭，隠居恨未圓。", "得之苟有命，老矣聊息肩。", "畚土填隙穴，結茅苴漏穿。", "粗爾容偃息，豈復求華鮮。", "西歸信已乎，永雜孫陳編。"]'),
('037c4255-6f3d-4e33-9917-5b65d1eb3181','任氏閱世堂前大檜','蘇轍','宋','宋诗','song-poetry','','[]','君家大檜長百尺，根如車輪身弦直。',160,'全唐诗/poet.song.49000.json','["君家大檜長百尺，根如車輪身弦直。", "壯夫連臂不能抱，孤鶴高飛直上立。", "狂風動地舞枝幹，大雪翻空洗顔色。", "人言此檜三百年，未知昔是何人植。", "君家大夫老不遇，一生使氣未嘗屈。", "沒身不說歸故里，遺愛自知懷舊邑。", "此翁此檜兩相似，相與閱世何終極。", "汝南山淺無良材，櫟柱棟椽聊障日。", "便令殺身起大厦，亦恐衆材無匹敵。", "且留枝葉撓雲霓，猶得世人長太息。"]'),
('b7a3d0e4-1e32-43c9-8c97-1bb97c273526','贈蔡駜居士','蘇轍','宋','宋诗','song-poetry','','[]','結茅汝上只三間，種稻城西僅一廛。',64,'全唐诗/poet.song.49000.json','["結茅汝上只三間，種稻城西僅一廛。", "梅老外生詩律在，秀公弟子佛心傳。", "埋盆疊石常幽坐，留客開樽輒醉眠。", "聞道鄰僧乞米送，時無韓子定誰憐。"]'),
('a424b927-3729-43d8-9c1a-56be92cdd5e3','癸未生日','蘇轍','宋','宋诗','song-poetry','','[]','我生本無生，安有六十五。',144,'全唐诗/poet.song.49000.json','["我生本無生，安有六十五。", "生來逐世法，妄謂得此數。", "隨流登中朝，失脚墮南土。", "人言我當喜，亦言我當懼。", "我心終頹然，喜懼不入故。", "歸來二頃田，且復種禾黍。", "或疑潁川好，又使汝南去。", "汝南亦何爲，均是食粟處。", "兒言生日至，可就瞿曇語。", "平生不爲惡，今日安所訴。", "老聃西入胡，孔子東歸魯。", "我命不在天，世人汝何預。"]');
